INSERT INTO public.recipes VALUES (0, 'Apple-Cranberry Crostada', NULL, NULL, NULL, '8', '6 to 8 - servings', '3 tablespoons butter, 2 pounds Granny Smith apples (or other firm, crisp apples), peeled, quartered, cored and sliced 1/4-inch thick, 1 pound Macintosh apples (or other soft-textured apples that fall apart when cooked), peeled, quartered, cored, and sliced 1/4-inch thick, ½ cup sugar, ½ cup dried cranberries, 1 sheet frozen puff pastry, thawed but still cold (follow package directions), 1  egg white, lightly beaten, 1 tablespoon sugar, 1 cup Optional: Ice cream or lightly sweetened whipped cream', 'Heat butter in a large skillet over medium-high heat. Add apples, 1/2 cup sugar and cranberries; cover and cook until apples release their liquid, about 5 minutes. Remove lid and continue to cook, stirring frequently, until soft apples fall apart and juices thicken to a thin-syrup consistency, about 5 minutes longer. Pour onto a large-lipped cookie sheet or jellyroll pan and cool to room temperature. (Can be refrigerated in an airtight container up to 5 days.)
INSERT INTO public.recipes VALUES (284, 'Watermelon Pie', NULL, NULL, NULL, '8', '1 to 9 - inch pie', '1 (3 ounce) package watermelon flavored Jell-O®, ¼ cup water, 1 (12 ounce) container frozen whipped topping, thawed, 2 cups watermelon, 1 (9 inch) prepared graham cracker crust', 'Mix together the watermelon gelatin and water. Fold gelatin mixture into the dessert topping. Add cut watermelon.
INSERT INTO public.recipes VALUES (37, 'Easy Apple Cider', '10 mins', '1 hrs', '1 hrs 10 mins', '8', NULL, '1 (64 fluid ounce) bottle apple cider, 3  cinnamon sticks, 1 teaspoon whole allspice, 1 teaspoon whole cloves, ⅓ cup brown sugar', 'Combine apple cider and cinnamon sticks in a slow cooker.
INSERT INTO public.recipes VALUES (53, 'Apple Hand Pies', '25 mins', '35 mins', '1 hrs 15 mins', '4', '4 hand pies', '2 tablespoons butter, 2 large green apples - peeled, cored, and cut into chunks, 2 tablespoons brown sugar, ¼ cup white sugar, ¼ teaspoon salt, 1 ½ teaspoons ground cinnamon, or to taste, 1 teaspoon water, or more if needed (Optional), 1 pound prepared pie dough, cut into 4 pieces, 1  egg, 2 teaspoons milk, 1 teaspoon white sugar, or as needed', 'Melt butter in a large skillet over medium heat; let butter brown to a light golden color and smell toasted, about 1 minute. Stir apples into hot butter; sprinkle with 1/4 cup white sugar, brown sugar, and salt. Cook and stir apple mixture until apples are softened, about 5 minutes. Mix in cinnamon and water; continue cooking until apples are soft and sticky, 1 to 2 more minutes. Spread apple filling onto a plate to cool.
INSERT INTO public.recipes VALUES (71, 'Southern Fried Apples', '10 mins', '10 mins', '20 mins', '4', NULL, '½ cup butter, ½ cup white sugar, 2 tablespoons ground cinnamon, 4  Granny Smith apples - peeled, cored, and sliced', 'Melt butter in a large skillet over medium heat. Add sugar and cinnamon; stir until sugar dissolves.
INSERT INTO public.recipes VALUES (649, 'Caribbean Health Drink', '10 mins', NULL, '10 mins', '2', '3 cups', '1 cup chopped carrot, 1  banana, 1  kiwi, peeled, 1  apple - peeled, cored, and sliced, 1 cup chopped pineapple, 1 cup ice cubes', 'Blend the carrot, banana, kiwi, apple, pineapple, and ice cubes in a blender until smooth.', '3.9', 'https://www.allrecipes.com/recipe/204423/caribbean-health-drink/', '/Cuisine/Latin American/Caribbean/', 'Total Fat 1g 1%, Saturated Fat 0g 1%, Sodium 47mg 2%, Total Carbohydrate 45g 17%, Dietary Fiber 7g 26%, Total Sugars 29g, Protein 2g, Vitamin C 86mg 429%, Calcium 52mg 4%, Iron 1mg 4%, Potassium 695mg 15%', 'Prep Time: 10 mins, Total Time: 10 mins, Servings: 2, Yield: 3 cups', 'https://www.allrecipes.com/thmb/D5qQ-c61-FpTIRQPBdDPOlYMC5w=/1500x0/filters:no_upscale():max_bytes(150000):strip_icc()/737839-a8ce31ef9b1346a7bd324b2c0b7aef9e.jpg');
INSERT INTO public.recipes VALUES (138, 'Instant Pot Meatloaf', '20 mins', '40 mins', '1 hrs 5 mins', '8', NULL, '2 pounds ground beef, 1 cup dry bread crumbs, ½ cup diced onion, ½  apple - peeled, cored, and diced, 1  egg, 2 teaspoons garlic powder, ½ teaspoon salt, ½ teaspoon ground black pepper', 'Make the meatloaf: Mix beef, bread crumbs, onion, apple, egg, garlic powder, salt, and pepper in a large bowl until evenly blended.
INSERT INTO public.recipes VALUES (40, 'Southern Fried Apples', '10 mins', '10 mins', '20 mins', '4', NULL, '½ cup butter, ½ cup white sugar, 2 tablespoons ground cinnamon, 4  Granny Smith apples - peeled, cored, and sliced', 'Melt butter in a large skillet over medium heat. Add sugar and cinnamon; stir until sugar dissolves.
INSERT INTO public.recipes VALUES (181, 'Cherry Ham Glaze', '5 mins', '5 mins', '10 mins', '12', '12 servings', '3 tablespoons water, ¼ cup white vinegar, 2 tablespoons light corn syrup, 1 (12 ounce) jar cherry preserves, ¼ teaspoon ground cinnamon, ¼ teaspoon ground cloves, ¼ teaspoon ground nutmeg', 'Stir together water, vinegar, corn syrup, preserves, cinnamon, cloves, and nutmeg in a saucepan over medium-high heat. Bring to a boil, then reduce heat to low and simmer for 2 minutes.
INSERT INTO public.recipes VALUES (115, 'Apple Hand Pies', '25 mins', '35 mins', '1 hrs 15 mins', '4', '4 hand pies', '2 tablespoons butter, 2 large green apples - peeled, cored, and cut into chunks, 2 tablespoons brown sugar, ¼ cup white sugar, ¼ teaspoon salt, 1 ½ teaspoons ground cinnamon, or to taste, 1 teaspoon water, or more if needed (Optional), 1 pound prepared pie dough, cut into 4 pieces, 1  egg, 2 teaspoons milk, 1 teaspoon white sugar, or as needed', 'Melt butter in a large skillet over medium heat; let butter brown to a light golden color and smell toasted, about 1 minute. Stir apples into hot butter; sprinkle with 1/4 cup white sugar, brown sugar, and salt. Cook and stir apple mixture until apples are softened, about 5 minutes. Mix in cinnamon and water; continue cooking until apples are soft and sticky, 1 to 2 more minutes. Spread apple filling onto a plate to cool.
INSERT INTO public.recipes VALUES (116, 'Amazing Apple Butter', '10 mins', '10 hrs 25 mins', '10 hrs 40 mins', '48', '6 cups', '10 pounds apples, quartered, 4 cups unsweetened apple juice, 1 cup white sugar, 1 tablespoon apple cider vinegar, 1 ½ teaspoons ground cinnamon, ½ teaspoon ground cloves, ½ teaspoon ground allspice, 6  half-pint canning jars with lids and rings', 'Combine apples and apple juice in a stockpot; bring to a boil. Reduce heat and cook at a simmer until apples are soft and mushy, 20 to 30 minutes.
INSERT INTO public.recipes VALUES (130, 'Apple Oatmeal Crisp', '20 mins', '40 mins', '1 hrs', '8', '1 8-inch pan', '1 cup brown sugar, 1 cup rolled oats, 1 cup all-purpose flour, ½ cup butter, melted, 3 cups apples - peeled, cored and chopped, ½ cup white sugar, 2 teaspoons ground cinnamon', 'Preheat the oven to 350 degrees F (175 degrees C). Lightly grease an 8-inch square pan.
INSERT INTO public.recipes VALUES (303, 'Old-Fashioned Lemonade', '10 mins', NULL, '10 mins', '6', NULL, '6  lemons, 1 cup white sugar, 6 cups water, or more as needed', 'Juice lemons; you should have 1 cup juice.
INSERT INTO public.recipes VALUES (272, 'Heavenly Honeydew Juice', '10 mins', NULL, '10 mins', '6', NULL, '1 (5 pound) honeydew melon, quartered and seeded, 2 cups ice cubes, 1 cup water, 3 tablespoons white sugar', 'Scrape flesh from honeydew melon quarters into a blender; add ice cubes, water, and sugar. Blend until smooth and sugar has dissolved. Serve immediately.', '4.4', 'https://www.allrecipes.com/recipe/232448/heavenly-honeydew-juice/', '/Cuisine/Latin American/Mexican/', 'Total Fat 1g 1%, Saturated Fat 0g 1%, Sodium 69mg 3%, Total Carbohydrate 40g 15%, Dietary Fiber 3g 11%, Total Sugars 37g, Protein 2g, Vitamin C 68mg 338%, Calcium 24mg 2%, Iron 1mg 3%, Potassium 856mg 18%', 'Prep Time: 10 mins, Total Time: 10 mins, Servings: 6', 'https://www.allrecipes.com/thmb/9DlP30efJXIDc_IBm3AY7hQtiAU=/1500x0/filters:no_upscale():max_bytes(150000):strip_icc()/2008368-95e7267d4756420fb450b12cdd29a4f5.jpg');
INSERT INTO public.recipes VALUES (278, 'Quick Cantaloupe Juice', '10 mins', NULL, '10 mins', '2', NULL, '½  cantaloupe - peeled, seeded, and cubed, ¾ cup milk, 1 tablespoon white sugar', 'Place cantaloupe in a blender and top with milk and sugar. Cover and blend until smooth.', '4.8', 'https://www.allrecipes.com/recipe/234301/quick-cantaloupe-juice/', '/Drinks Recipes/Smoothie Recipes/', 'Total Fat 2g 3%, Saturated Fat 1g 6%, Cholesterol 7mg 2%, Sodium 60mg 3%, Total Carbohydrate 22g 8%, Dietary Fiber 1g 4%, Total Sugars 21g, Protein 4g, Vitamin C 51mg 254%, Calcium 120mg 9%, Iron 0mg 2%, Potassium 506mg 11%', 'Prep Time: 10 mins, Total Time: 10 mins, Servings: 2', 'https://www.allrecipes.com/thmb/vDdH4mEzUFiBCzqProbFmGEkgzQ=/1500x0/filters:no_upscale():max_bytes(150000):strip_icc()/2328228-6987e3251f414ab1958efb25a07f2806.jpg');
INSERT INTO public.recipes VALUES (198, 'Marshmallow Log', '15 mins', NULL, '45 mins', '12', NULL, '2 cups flaked coconut, 2 cups miniature colored marshmallows, 2 cups crushed graham crackers, 1 (14 ounce) can sweetened condensed milk, 1 cup chopped walnuts, 10  candied cherries, quartered', 'Sprinkle coconut evenly on a sheet of waxed paper.
INSERT INTO public.recipes VALUES (320, 'Fresh Orange Juice', '5 mins', NULL, '5 mins', '3', '1 1/2 cups', '4  oranges', 'Lightly smack each orange on the counter. Cut each orange in half and squeeze juice into a glass.', '4.4', 'https://www.allrecipes.com/recipe/89229/fresh-orange-juice/', '/Drinks Recipes/', 'Total Fat 0g 0%, Sodium 1mg 0%, Total Carbohydrate 12g 4%, Dietary Fiber 0g 1%, Total Sugars 9g, Protein 1g, Vitamin C 55mg 276%, Calcium 12mg 1%, Iron 0mg 1%, Potassium 220mg 5%', 'Prep Time: 5 mins, Total Time: 5 mins, Servings: 3, Yield: 1 1/2 cups', 'https://www.allrecipes.com/thmb/qXBaEIkAqDpDWqAVJbPZs9TxcZw=/1500x0/filters:no_upscale():max_bytes(150000):strip_icc()/4513616-d1b91430eaab44e49230b21d22b88ba2.jpg');
INSERT INTO public.recipes VALUES (380, 'Peach Banana Smoothie', '5 mins', NULL, '5 mins', '4', '5 cups', '1 cup plain yogurt, 1 (15.25 ounce) can peaches, 2  bananas, sliced, ¼ cup orange juice, ¼ cup white sugar, or to taste, 2 cubes  ice', 'Blend yogurt, peaches, bananas, orange juice, sugar, and ice in a blender on high until the ice is crushed and the smoothie is to your desired consistency.', '4.7', 'https://www.allrecipes.com/recipe/232903/peach-banana-smoothie/', '/Drinks Recipes/Smoothie Recipes/Orange/', 'Total Fat 1g 2%, Saturated Fat 1g 4%, Cholesterol 4mg 1%, Sodium 48mg 2%, Total Carbohydrate 44g 16%, Dietary Fiber 3g 11%, Total Sugars 36g, Protein 5g, Vitamin C 17mg 87%, Calcium 124mg 10%, Iron 1mg 3%, Potassium 524mg 11%', 'Prep Time: 5 mins, Total Time: 5 mins, Servings: 4, Yield: 5 cups', 'https://www.allrecipes.com/thmb/yZAFM4KKtttZjdBEScqeW_I3q44=/1500x0/filters:no_upscale():max_bytes(150000):strip_icc()/1115853-f61b636e115c4f31a46b8e1be44435ca.jpg');
INSERT INTO public.recipes VALUES (5, 'Easy Apple Crisp with Oat Topping', '20 mins', '40 mins', '1 hrs', '4', NULL, '6  apples - peeled, cored, and sliced, 2 tablespoons white sugar, 1 ½ teaspoons ground cinnamon, divided, 1 cup brown sugar, ¾ cup old-fashioned oats, ¾ cup all-purpose flour, ½ cup cold butter', 'Preheat the oven to 350 degrees F (175 degrees C).
INSERT INTO public.recipes VALUES (418, 'Frangipane Pear Tart', '30 mins', '1 hrs 15 mins', '2 hrs 15 mins', '8', '1 9-inch tart', '4 cups water, 1 cup white sugar, 2 tablespoons honey, 1  vanilla bean, split lengthwise, 1  cinnamon stick, 5 pods cardamom, crushed, 4  Conference pears - peeled, halved, and cored', 'Combine water, 1 cup white sugar, honey, vanilla bean, cinnamon stick, and cardamom in a large saucepan. Bring to a simmer over medium heat. Add pears; reduce heat and simmer until pears are translucent or easily pierced with a knife, about 10 minutes. Remove from heat and cool to room temperature.
INSERT INTO public.recipes VALUES (6, 'Easy Apple Cider', '10 mins', '1 hrs', '1 hrs 10 mins', '8', NULL, '1 (64 fluid ounce) bottle apple cider, 3  cinnamon sticks, 1 teaspoon whole allspice, 1 teaspoon whole cloves, ⅓ cup brown sugar', 'Combine apple cider and cinnamon sticks in a slow cooker.
INSERT INTO public.recipes VALUES (229, 'Orange, Fig, and Gorgonzola Salad', '15 mins', NULL, '15 mins', '4', '4 servings', '2 heads romaine lettuce, chopped, 2  oranges - peeled, pith removed, and cut into segments, ½ cup crumbled Gorgonzola cheese, 2  fresh figs, cut into 1-inch cubes, ¼ cup vinaigrette dressing, or to taste', 'Combine lettuce, oranges, Gorgonzola cheese, and figs in a large bowl. Drizzle dressing over salad and toss to coat.', '4.7', 'https://www.allrecipes.com/recipe/234219/orange-fig-and-gorgonzola-salad/', '/Salad/Fruit Salad Recipes/Orange Salad Recipes/', 'Total Fat 7g 8%, Saturated Fat 4g 19%, Cholesterol 23mg 8%, Sodium 468mg 20%, Total Carbohydrate 15g 5%, Dietary Fiber 4g 15%, Total Sugars 10g, Protein 7g, Vitamin C 41mg 204%, Calcium 177mg 14%, Iron 2mg 9%, Potassium 481mg 10%', 'Prep Time: 15 mins, Total Time: 15 mins, Servings: 4, Yield: 4 servings', 'https://www.allrecipes.com/thmb/_qqHaDK6ZWLhH1a2HGVFI_bBhFk=/1500x0/filters:no_upscale():max_bytes(150000):strip_icc()/1044911-f6351628dccb47349e1673c4cfcbfc0c.jpg');
INSERT INTO public.recipes VALUES (247, 'Watermelon Lemonade', '10 mins', '5 mins', '15 mins', '12', '6 cups', '½ cup white sugar, ½ cup water, 4 cups cubed watermelon, 3 cups cold water, ½ cup fresh lemon juice, 6 cups ice cubes', 'Place the watermelon into a blender. Cover, and puree until smooth. Strain through a fine mesh sieve.
INSERT INTO public.recipes VALUES (7, 'Apple-Cranberry Crisp', '25 mins', '40 mins', '1 hrs 5 mins', '8', '1 8-inch crisp', '2 pounds Granny Smith apples - peeled, cored and thinly sliced, ¾ cup cranberries, ¼ cup white sugar, 1 tablespoon ground cinnamon, 1 teaspoon ground nutmeg', 'Preheat the oven to 375 degrees F (190 degrees C.) Butter an 8-inch square baking dish.
INSERT INTO public.recipes VALUES (510, 'Homemade Grenadine', '1 mins', '10 mins', '11 mins', '12', '12 servings', '1 cup white sugar, ½ cup pomegranate juice', 'Pour sugar and pomegranate juice into a sauce pan and warm over low heat, whisking continuously until the sugar dissolves. Cool, pour into a bottle or jar, and store sealed in the refrigerator.', '4.3', 'https://www.allrecipes.com/recipe/217210/homemade-grenadine/', '/Side Dish/Sauces and Condiments/Syrup Recipes/', 'Sodium 0mg 0%, Total Carbohydrate 18g 7%, Total Sugars 18g, Calcium 0mg 0%, Potassium 0mg 0%', 'Prep Time: 1 mins, Cook Time: 10 mins, Total Time: 11 mins, Servings: 12, Yield: 12 servings', 'https://www.allrecipes.com/thmb/98DuipYVjdGFXpEiBF8AzOyuf5k=/1500x0/filters:no_upscale():max_bytes(150000):strip_icc()/4574288-02fdfc6b50da438fa3d984c46fd763ea.jpg');
INSERT INTO public.recipes VALUES (248, 'Watermelon Ice Pops', '10 mins', NULL, '2 hrs 10 mins', '6', '6 ice pops', '1 ½ cups watermelon, seeded and diced, ½ cup water, 1 tablespoon honey, 1 tablespoon fresh lemon juice, 1 tablespoon white sugar', 'Blend watermelon, water, honey, lemon juice, and sugar together in a blender until smooth. Pour mixture into ice pop molds and freeze until solid, about 2 hours.
INSERT INTO public.recipes VALUES (131, 'Veronica''s Apple Pancakes', '10 mins', '25 mins', '35 mins', '4', NULL, '1 cup shredded tart apple, 1 cup milk, ¼ cup butter, melted, 1 large egg, 1 ¼ cups all-purpose flour, 1 tablespoon white sugar, 1 ¼ teaspoons baking powder, ¼ teaspoon ground cinnamon', 'Combine apple, milk, butter, and egg in a large bowl. Sift together flour, sugar, baking powder, and cinnamon in a separate bowl. Stir flour mixture into apple mixture until just combined.
INSERT INTO public.recipes VALUES (464, 'Plum Pudding Sauce', '5 mins', '20 mins', '25 mins', '4', '4 servings', '2 tablespoons margarine, ¾ cup white sugar, 1  egg, 2 cups milk, 2 teaspoons all-purpose flour, 1 teaspoon vanilla extract', 'In a small saucepan over medium heat combine margarine, sugar and the egg. Pour in milk and cook until mixture begins to bubble; be careful not to scald. Stir in flour and vanilla; mix well and serve.', '4.9', 'https://www.allrecipes.com/recipe/23222/plum-pudding-sauce/', '/Side Dish/Sauces and Condiments/Sauces/Dessert Sauce Recipes/', 'Total Fat 9g 12%, Saturated Fat 3g 14%, Cholesterol 56mg 19%, Sodium 130mg 6%, Total Carbohydrate 45g 16%, Total Sugars 44g, Protein 6g, Vitamin C 0mg 2%, Calcium 152mg 12%, Iron 0mg 2%, Potassium 206mg 4%', 'Prep Time: 5 mins, Cook Time: 20 mins, Total Time: 25 mins, Servings: 4, Yield: 4 servings', 'https://www.allrecipes.com/thmb/7t2PIZl_9z9oZX5Bh0nIvn9pdvE=/1500x0/filters:no_upscale():max_bytes(150000):strip_icc()/7938641-6be810de25e643f6b35c45da03e671bf.jpg');
