INSERT INTO public.recipes VALUES (741, 'Pineapple Cleanser Smoothie', '10 mins', NULL, '10 mins', '1', NULL, '1 cup coconut water, or to taste, 1 cup chopped fresh pineapple, 1 stalk celery, ½  cucumber, peeled, ½  lemon, peeled, ⅓ bunch fresh parsley, 1 (1 inch) piece fresh ginger root', 'Blend coconut water, pineapple, celery, cucumber, lemon, parsley, and ginger together in a blender until smooth.', '4.9', 'https://www.allrecipes.com/recipe/236413/pineapple-cleanser-smoothie/', '/Breakfast and Brunch/Drinks/', 'Total Fat 1g 2%, Saturated Fat 1g 3%, Sodium 301mg 13%, Total Carbohydrate 43g 15%, Dietary Fiber 10g 34%, Total Sugars 17g, Protein 5g, Vitamin C 159mg 794%, Calcium 172mg 13%, Iron 3mg 17%, Potassium 1248mg 27%', 'Prep Time: 10 mins, Total Time: 10 mins, Servings: 1', 'https://www.allrecipes.com/thmb/qZ6PJIPEOlOrtCWZyjyve-v84Xc=/1500x0/filters:no_upscale():max_bytes(150000):strip_icc()/1110076-62f3d9b1ee2149cfb0b0222fa2bee456.jpg');
INSERT INTO public.recipes VALUES (484, 'Judy''s Brown Sauce', '2 hrs', '3 hrs', '6 hrs', '200', '15 half-pint jars', '10 cups peeled, cored, and roughly chopped tart apples, 10 cups pitted and halved fresh prune plums, 5 cups chopped onions, 6 cups malt vinegar, 5 cups white sugar, ½ cup salt, ½ cup Worcestershire sauce, 4 cloves garlic, minced, 2 teaspoons ground ginger, 2 teaspoons ground nutmeg, 2 teaspoons ground allspice, 2 teaspoons ground cayenne pepper, 15  half-pint canning jars with lids and rings', 'Working in batches, place the apples, plums and onions into the work bowl of a food processor, and grind until fine. Transfer the ground fruit and onions into a large pot, and stir in the malt vinegar, sugar, salt, Worcestershire sauce, garlic, ginger, nutmeg, allspice, and cayenne pepper until the mixture is well combined. Bring to a simmer over low heat, and simmer until brown and thickened, about 3 to 4 hours.
INSERT INTO public.recipes VALUES (620, 'Easy Mango Banana Smoothie', '10 mins', NULL, '10 mins', '8', NULL, '2  mangos - peeled, seeded, and sliced, 2  bananas, 2 cups vanilla yogurt, 2 cups milk', 'Combine mangos, banana, vanilla yogurt, and milk in a blender; blend until smooth.', '4.5', 'https://www.allrecipes.com/recipe/231851/easy-mango-banana-smoothie/', '/Drinks Recipes/Smoothie Recipes/Mango/', 'Total Fat 2g 3%, Saturated Fat 1g 7%, Cholesterol 8mg 3%, Sodium 67mg 3%, Total Carbohydrate 24g 9%, Dietary Fiber 1g 5%, Total Sugars 21g, Protein 6g, Vitamin C 14mg 68%, Calcium 181mg 14%, Iron 0mg 1%, Potassium 390mg 8%', 'Prep Time: 10 mins, Total Time: 10 mins, Servings: 8', 'https://www.allrecipes.com/thmb/kxoD3dghe_cR58zI2pccBfAe-Dk=/1500x0/filters:no_upscale():max_bytes(150000):strip_icc()/6236089-780238d875594b00871a5cbbd37a8a36.jpg');
INSERT INTO public.recipes VALUES (38, 'Apple-Cranberry Crisp', '25 mins', '40 mins', '1 hrs 5 mins', '8', '1 8-inch crisp', '2 pounds Granny Smith apples - peeled, cored and thinly sliced, ¾ cup cranberries, ¼ cup white sugar, 1 tablespoon ground cinnamon, 1 teaspoon ground nutmeg', 'Preheat the oven to 375 degrees F (190 degrees C.) Butter an 8-inch square baking dish.
INSERT INTO public.recipes VALUES (54, 'Amazing Apple Butter', '10 mins', '10 hrs 25 mins', '10 hrs 40 mins', '48', '6 cups', '10 pounds apples, quartered, 4 cups unsweetened apple juice, 1 cup white sugar, 1 tablespoon apple cider vinegar, 1 ½ teaspoons ground cinnamon, ½ teaspoon ground cloves, ½ teaspoon ground allspice, 6  half-pint canning jars with lids and rings', 'Combine apples and apple juice in a stockpot; bring to a boil. Reduce heat and cook at a simmer until apples are soft and mushy, 20 to 30 minutes.
INSERT INTO public.recipes VALUES (148, 'Pork Tenderloin with Apples and Onions', '15 mins', '45 mins', '1 hrs', '6', NULL, '2 (1 1/2 pound) pork tenderloins, 2 teaspoons vegetable oil, 1 teaspoon sea salt, 2 tablespoons vegetable oil, divided, or more as needed, 3 medium Granny Smith apples - peeled, cored, and sliced into eighths, 2 medium sweet onions, sliced vertically, 3 teaspoons chopped fresh thyme, divided, ¼ teaspoon ground black pepper, or to taste, 1 tablespoon Dijon mustard, 1 cup chicken stock, 1 tablespoon butter', 'Preheat the oven to 425 degrees F (220 degrees C).
INSERT INTO public.recipes VALUES (154, 'Old Fashioned Cocktail', '5 mins', NULL, '5 mins', '1', NULL, '1  sugar cube, 1 teaspoon water, 1 dash bitters, 2 fluid ounces whiskey (rye or bourbon), 1  lemon twist, ½ cup ice cubes, or as needed, 1  orange slice, for garnish, 1  maraschino cherry, for garnish', 'Muddle sugar cube, water, and bitters in an old fashioned glass for 1 minute. Pour in whiskey; stir for 1 minute.
INSERT INTO public.recipes VALUES (17, 'Easy Apple Pie', '20 mins', '40 mins', '1 hrs', '8', '1 9-inch pie', '1 (14.1 ounce) package pastry for a 9-inch double-crust pie, ¾ cup white sugar, or more to taste, 1 teaspoon ground cinnamon, 6 cups thinly sliced apples, 1 tablespoon butter', 'Preheat the oven to 450 degrees F (230 degrees C).
INSERT INTO public.recipes VALUES (23, 'Amazing Apple Butter', '10 mins', '10 hrs 25 mins', '10 hrs 40 mins', '48', '6 cups', '10 pounds apples, quartered, 4 cups unsweetened apple juice, 1 cup white sugar, 1 tablespoon apple cider vinegar, 1 ½ teaspoons ground cinnamon, ½ teaspoon ground cloves, ½ teaspoon ground allspice, 6  half-pint canning jars with lids and rings', 'Combine apples and apple juice in a stockpot; bring to a boil. Reduce heat and cook at a simmer until apples are soft and mushy, 20 to 30 minutes.
INSERT INTO public.recipes VALUES (527, 'Holiday Pomegranate Mignonette', '10 mins', NULL, '1 hrs 10 mins', '4', '4 servings', '3 tablespoons champagne vinegar, 1 tablespoon pomegranate juice, ½  shallot, minced, ½ teaspoon fresh cracked pepper, 1 pinch white sugar, 1 tablespoon pomegranate seeds', 'Whisk vinegar, pomegranate juice, shallot, pepper, and white sugar together in a bowl until sugar dissolves. Add pomegranate seeds, cover the bowl with plastic wrap, and refrigerate until chilled, about 1 hour.', '5.0', 'https://www.allrecipes.com/recipe/236576/holiday-pomegranate-mignonette/', '/Side Dish/Sauces and Condiments/Sauces/', 'Sodium 2mg 0%, Total Carbohydrate 4g 1%, Dietary Fiber 0g 0%, Total Sugars 2g, Protein 0g, Vitamin C 1mg 4%, Calcium 4mg 0%, Iron 0mg 1%, Potassium 40mg 1%', 'Prep Time: 10 mins, Additional Time: 1 hrs, Total Time: 1 hrs 10 mins, Servings: 4, Yield: 4 servings', 'https://www.allrecipes.com/thmb/kFPiZkjgJ9Dtz8iOINCLwwZPJ60=/1500x0/filters:no_upscale():max_bytes(150000):strip_icc()/1670332-86a0fb143ab54ffbb760214f03850b72.jpg');
INSERT INTO public.recipes VALUES (60, 'Delicious Cinnamon Baked Apples', '15 mins', '45 mins', '1 hrs', '6', NULL, '1 teaspoon butter, 2 tablespoons brown sugar, 3 teaspoons vanilla sugar, 3 teaspoons ground cinnamon, 1 teaspoon ground nutmeg, 6 large apples - peeled, cored, and sliced, 3 ½ tablespoons water', 'Preheat the oven to 350 degrees F (175 degrees C). Grease a large baking dish with butter.
INSERT INTO public.recipes VALUES (709, 'Mango Topping', '10 mins', '15 mins', '25 mins', '4', '3 cups', '3 cups mangos, peeled, seeded and chopped, 1 tablespoon butter, 1 tablespoon brown sugar, 1 teaspoon lemon juice, 1 teaspoon orange juice, 3 tablespoons water', 'In a saucepan over medium heat, combine the mangoes, butter, brown sugar, lemon juice, orange juice, and water. Stir until the mixture thickens. Remove from heat and serve.', '4.6', 'https://www.allrecipes.com/recipe/20612/mango-topping/', '/Side Dish/Sauces and Condiments/Sauces/Dessert Sauce Recipes/', 'Total Fat 3g 4%, Saturated Fat 2g 10%, Cholesterol 8mg 3%, Sodium 24mg 1%, Total Carbohydrate 25g 9%, Dietary Fiber 2g 8%, Total Sugars 22g, Protein 1g, Vitamin C 36mg 178%, Calcium 17mg 1%, Iron 0mg 1%, Potassium 203mg 4%', 'Prep Time: 10 mins, Cook Time: 15 mins, Total Time: 25 mins, Servings: 4, Yield: 3 cups', 'https://www.allrecipes.com/thmb/5SPNDUjRNxx08Ni0YO8YrZ4aTmQ=/1500x0/filters:no_upscale():max_bytes(150000):strip_icc()/5825972-6046cd825c724d32ade19b2512931927.jpg');
INSERT INTO public.recipes VALUES (710, 'Mango Cherry Smoothie', '10 mins', NULL, '10 mins', '2', NULL, '2 cups pitted cherries, 1 cup chopped mango, 1 cup water, 1 cup ice cubes', 'Blend cherries, mango, water, and ice cubes in a blender until smooth.', '4.7', 'https://www.allrecipes.com/recipe/238484/mango-cherry-smoothie/', '/Breakfast and Brunch/Drinks/', 'Total Fat 2g 2%, Saturated Fat 0g 2%, Sodium 9mg 0%, Total Carbohydrate 38g 14%, Dietary Fiber 5g 17%, Total Sugars 33g, Protein 2g, Vitamin C 33mg 165%, Calcium 37mg 3%, Iron 1mg 4%, Potassium 456mg 10%', 'Prep Time: 10 mins, Total Time: 10 mins, Servings: 2', 'https://www.allrecipes.com/thmb/hW1TIA-cJZYeRzg6mHAIizx28z0=/1500x0/filters:no_upscale():max_bytes(150000):strip_icc()/1273039-957ce4fc16c24dba9c4fa8353fd56ee6.jpg');
INSERT INTO public.recipes VALUES (61, 'Waldorf Salad', '20 mins', NULL, '20 mins', '6', NULL, '½ cup mayonnaise, 1 tablespoon white sugar, 1 teaspoon lemon juice, ⅛ teaspoon salt, 3  apples -- peeled, cored, and chopped, 1 cup thinly sliced celery, ½ cup chopped walnuts, ½ cup raisins (Optional)', 'Whisk together mayonnaise, sugar, lemon juice, and salt in a serving bowl.
INSERT INTO public.recipes VALUES (560, 'Freezer Persimmon Jam', '10 mins', '30 mins', '40 mins', '48', '6 cups', '5 cups pureed persimmons, 3 cups white sugar, ¼ cup fresh lemon juice, ½ teaspoon grated orange zest, 1 pinch ground nutmeg', 'In a large saucepan over medium-high heat, combine persimmon puree, sugar, lemon juice, orange zest and nutmeg. Boil for 30 minutes, or until slightly thickened.
INSERT INTO public.recipes VALUES (1056, 'Bacon Wrapped Dates Stuffed with Blue Cheese', '20 mins', '40 mins', '1 hrs', '32', '32 appetizers', '1 pound sliced bacon, cut in half, 1 pound pitted dates, 4 ounces blue cheese', 'Preheat the oven to 375 degrees F (190 degrees C).
INSERT INTO public.recipes VALUES (666, 'Tart Tropical Parfait', '5 mins', NULL, '5 mins', '1', '1 parfait', '1 (5.3 ounce) container low-fat vanilla Greek yogurt, ½ cup chopped kiwi, 2 tablespoons chopped macadamia nuts, 1 teaspoon agave nectar, 1 teaspoon chopped fresh mint', 'Spoon 1/3 cup yogurt into a 6- to 8-ounce parfait glass or jar. Top yogurt with 1/2 of the kiwi, 1/2 of the macadamia nuts, 1/2 of the agave. Repeat layers with the remaining yogurt, kiwi, nuts, and agave. Top parfait with mint.', '5.0', 'https://www.allrecipes.com/recipe/285020/tart-tropical-parfait/', '/Desserts/Specialty Dessert Recipes/Parfait Recipes/', 'Total Fat 13g 17%, Saturated Fat 2g 11%, Cholesterol 9mg 3%, Sodium 74mg 3%, Total Carbohydrate 37g 13%, Dietary Fiber 4g 16%, Total Sugars 28g, Protein 15g, Vitamin C 83mg 413%, Calcium 46mg 4%, Iron 1mg 5%, Potassium 339mg 7%', 'Prep Time: 5 mins, Total Time: 5 mins, Servings: 1, Yield: 1 parfait', 'https://www.allrecipes.com/thmb/RsFsSIETjBv5YlmZoZQbnMlLBT4=/1500x0/filters:no_upscale():max_bytes(150000):strip_icc()/9314803-c93055df2b164632a81c231ca4a35882.jpg');
INSERT INTO public.recipes VALUES (62, 'Apple-Cranberry Crostada', NULL, NULL, NULL, '8', '6 to 8 - servings', '3 tablespoons butter, 2 pounds Granny Smith apples (or other firm, crisp apples), peeled, quartered, cored and sliced 1/4-inch thick, 1 pound Macintosh apples (or other soft-textured apples that fall apart when cooked), peeled, quartered, cored, and sliced 1/4-inch thick, ½ cup sugar, ½ cup dried cranberries, 1 sheet frozen puff pastry, thawed but still cold (follow package directions), 1  egg white, lightly beaten, 1 tablespoon sugar, 1 cup Optional: Ice cream or lightly sweetened whipped cream', 'Heat butter in a large skillet over medium-high heat. Add apples, 1/2 cup sugar and cranberries; cover and cook until apples release their liquid, about 5 minutes. Remove lid and continue to cook, stirring frequently, until soft apples fall apart and juices thicken to a thin-syrup consistency, about 5 minutes longer. Pour onto a large-lipped cookie sheet or jellyroll pan and cool to room temperature. (Can be refrigerated in an airtight container up to 5 days.)
INSERT INTO public.recipes VALUES (24, 'Easy Apple Cinnamon Muffins', '20 mins', '25 mins', '45 mins', '6', '6 large muffins', '1 ½ cups all-purpose flour, ¾ cup white sugar, 2 teaspoons baking powder, 1 teaspoon ground cinnamon, ½ teaspoon salt, 1  egg, ⅓ cup vegetable oil, ⅓ cup milk, 2  apples - peeled, cored and chopped', 'Preheat the oven to 400 degrees F (200 degrees C). Grease 6 large muffin cups or line with paper muffin liners.
INSERT INTO public.recipes VALUES (904, 'Aileen''s Punch', '5 mins', NULL, '5 mins', '30', '30 servings', '1 (46 fluid ounce) can pineapple juice, 1 (46 fluid ounce) can apricot nectar, 1 (6 ounce) can frozen limeade concentrate, 2 liters lemon-lime flavored carbonated beverage', 'In a punch bowl combine pineapple juice, apricot nectar and limeade; finally, pour in the lemon-lime soda.', '4.7', 'https://www.allrecipes.com/recipe/20310/aileens-punch/', '/Drinks Recipes/Punch Recipes/Non-Alcoholic Punch Recipes/', 'Total Fat 0g 0%, Sodium 9mg 0%, Total Carbohydrate 23g 9%, Dietary Fiber 0g 1%, Total Sugars 15g, Protein 0g, Vitamin C 6mg 29%, Calcium 10mg 1%, Iron 0mg 2%, Potassium 114mg 2%', 'Prep Time: 5 mins, Total Time: 5 mins, Servings: 30, Yield: 30 servings', 'https://www.allrecipes.com/thmb/Hb-7pqKPUNr-HtV8ORWYSjsf7H4=/1500x0/filters:no_upscale():max_bytes(150000):strip_icc()/5459486-ce04517971154e2a8ab3eaa0e6134d71.jpg');
INSERT INTO public.recipes VALUES (155, 'Pineapple Upside-Down Bundt Cake', '30 mins', '35 mins', '1 hrs 15 mins', '12', '1 10-inch bundt cake', '  cooking spray with flour, ½ cup melted butter, ½ cup packed brown sugar, 1 (8 ounce) can pineapple rings, 1 (4 ounce) jar maraschino cherries, 1 (15.25 ounce) package yellow cake mix, 1 (3.5 ounce) package instant vanilla pudding mix, ¼ cup whole milk, or more as needed, ⅓ cup vegetable oil, 3 large eggs', 'Preheat the oven to 350 degrees F (175 degrees C). Grease a 10-inch fluted tube pan (such as Bundt) with cooking spray with flour.
INSERT INTO public.recipes VALUES (69, 'Apple-Cranberry Crisp', '25 mins', '40 mins', '1 hrs 5 mins', '8', '1 8-inch crisp', '2 pounds Granny Smith apples - peeled, cored and thinly sliced, ¾ cup cranberries, ¼ cup white sugar, 1 tablespoon ground cinnamon, 1 teaspoon ground nutmeg', 'Preheat the oven to 375 degrees F (190 degrees C.) Butter an 8-inch square baking dish.
INSERT INTO public.recipes VALUES (980, 'Coconut Rice', '5 mins', '25 mins', '30 mins', '7', '6 to 8 servings', '2 ½ cups Basmati rice, 4 (10 ounce) cans coconut milk, 1 pinch salt', 'In a large saucepan over high heat, combine rice, coconut milk and salt; bring to a boil.
INSERT INTO public.recipes VALUES (85, 'Amazing Apple Butter', '10 mins', '10 hrs 25 mins', '10 hrs 40 mins', '48', '6 cups', '10 pounds apples, quartered, 4 cups unsweetened apple juice, 1 cup white sugar, 1 tablespoon apple cider vinegar, 1 ½ teaspoons ground cinnamon, ½ teaspoon ground cloves, ½ teaspoon ground allspice, 6  half-pint canning jars with lids and rings', 'Combine apples and apple juice in a stockpot; bring to a boil. Reduce heat and cook at a simmer until apples are soft and mushy, 20 to 30 minutes.
INSERT INTO public.recipes VALUES (67, 'Easy Apple Crisp with Oat Topping', '20 mins', '40 mins', '1 hrs', '4', NULL, '6  apples - peeled, cored, and sliced, 2 tablespoons white sugar, 1 ½ teaspoons ground cinnamon, divided, 1 cup brown sugar, ¾ cup old-fashioned oats, ¾ cup all-purpose flour, ½ cup cold butter', 'Preheat the oven to 350 degrees F (175 degrees C).
INSERT INTO public.recipes VALUES (68, 'Easy Apple Cider', '10 mins', '1 hrs', '1 hrs 10 mins', '8', NULL, '1 (64 fluid ounce) bottle apple cider, 3  cinnamon sticks, 1 teaspoon whole allspice, 1 teaspoon whole cloves, ⅓ cup brown sugar', 'Combine apple cider and cinnamon sticks in a slow cooker.
INSERT INTO public.recipes VALUES (677, 'Lela''s Protein Mango Smoothie', '10 mins', NULL, '10 mins', '1', '1 smoothie', '½  mango, chopped, or more to taste, ½ cup low-fat vanilla yogurt, ½ cup almond milk, ½ cup ice, 1 scoop vanilla whey protein powder, 1 teaspoon honey, or to taste (Optional)', 'Blend mango, yogurt, almond milk, ice, protein powder, and honey together in a blender until smooth.', '4.8', 'https://www.allrecipes.com/recipe/238647/lelas-protein-mango-smoothie/', '/Breakfast and Brunch/Drinks/', 'Total Fat 4g 6%, Saturated Fat 2g 12%, Cholesterol 19mg 6%, Sodium 379mg 16%, Total Carbohydrate 49g 18%, Dietary Fiber 2g 9%, Total Sugars 43g, Protein 45g, Vitamin C 30mg 149%, Calcium 331mg 25%, Iron 0mg 2%, Potassium 531mg 11%', 'Prep Time: 10 mins, Total Time: 10 mins, Servings: 1, Yield: 1 smoothie', 'https://www.allrecipes.com/thmb/FAcnxOHeCkDOZaJ1D8kYzux-d4I=/1500x0/filters:no_upscale():max_bytes(150000):strip_icc()/2384098-lelas-protein-mango-smoothie-Buckwheat-Queen-4x3-1-f261e42cdaf34c91bf3459030b54f0e8.jpg');
INSERT INTO public.recipes VALUES (93, 'Apple-Cranberry Crostada', NULL, NULL, NULL, '8', '6 to 8 - servings', '3 tablespoons butter, 2 pounds Granny Smith apples (or other firm, crisp apples), peeled, quartered, cored and sliced 1/4-inch thick, 1 pound Macintosh apples (or other soft-textured apples that fall apart when cooked), peeled, quartered, cored, and sliced 1/4-inch thick, ½ cup sugar, ½ cup dried cranberries, 1 sheet frozen puff pastry, thawed but still cold (follow package directions), 1  egg white, lightly beaten, 1 tablespoon sugar, 1 cup Optional: Ice cream or lightly sweetened whipped cream', 'Heat butter in a large skillet over medium-high heat. Add apples, 1/2 cup sugar and cranberries; cover and cook until apples release their liquid, about 5 minutes. Remove lid and continue to cook, stirring frequently, until soft apples fall apart and juices thicken to a thin-syrup consistency, about 5 minutes longer. Pour onto a large-lipped cookie sheet or jellyroll pan and cool to room temperature. (Can be refrigerated in an airtight container up to 5 days.)
INSERT INTO public.recipes VALUES (25, 'Debbie''s Amazing Apple Bread', '15 mins', '1 hrs', '1 hrs 15 mins', '10', '1 9x5-inch loaf', '2  eggs, 2 cups white sugar, ½ cup vegetable oil, 2 teaspoons vanilla extract, 2 cups apples, peeled and diced, 2 cups all-purpose flour, 1 ½ teaspoons salt, 1 teaspoon baking powder, ½ teaspoon ground cinnamon, or more to taste', 'Preheat the oven to 350 degrees F (175 degrees C). Grease a 9x5-inch loaf pan.
INSERT INTO public.recipes VALUES (716, 'Mango Relish', '15 mins', NULL, '15 mins', '4', NULL, '1  mango - peeled, seeded and diced, 1 teaspoon extra virgin olive oil, ½  red bell pepper, chopped, 2  green onion, thinly sliced, 1 tablespoon chopped cilantro, 1  lime, juiced, ¼ teaspoon salt, 1 pinch cracked black pepper, 1 teaspoon honey', 'Combine mango, oil, bell pepper, scallions, cilantro, and lime juice in a small bowl. Stir to combine. Season with salt, pepper, and honey. Refrigerate or serve immediately.', '4.8', 'https://www.allrecipes.com/recipe/50188/mango-relish/', '/Side Dish/Sauces and Condiments/Relish Recipes/', 'Total Fat 1g 2%, Saturated Fat 0g 1%, Sodium 149mg 6%, Total Carbohydrate 14g 5%, Dietary Fiber 2g 7%, Total Sugars 10g, Protein 1g, Vitamin C 40mg 200%, Calcium 19mg 1%, Iron 0mg 2%, Potassium 158mg 3%', 'Prep Time: 15 mins, Total Time: 15 mins, Servings: 4', 'https://www.allrecipes.com/thmb/TK-8B6tv9bjLNqjw059t4EMH1VY=/1500x0/filters:no_upscale():max_bytes(150000):strip_icc()/4395543-3e69cabafe07453a867e0ecff65b6224.jpg');
INSERT INTO public.recipes VALUES (1021, 'Fruit and Yogurt Smoothie', '5 mins', NULL, '5 mins', '2', NULL, '1 cup strawberries, 1  banana, ½ cup yogurt, ¼ cup pineapple juice, 1 ½ teaspoons white sugar, 1 teaspoon orange juice, 1 teaspoon milk', 'Combine strawberries, banana, yogurt, pineapple juice, sugar, orange juice, and milk in a blender; blend until smooth.', '4.7', 'https://www.allrecipes.com/recipe/215189/fruit-and-yogurt-smoothie/', '/Drinks Recipes/Smoothie Recipes/Strawberry/', 'Total Fat 1g 2%, Saturated Fat 1g 4%, Cholesterol 4mg 1%, Sodium 45mg 2%, Total Carbohydrate 31g 11%, Dietary Fiber 3g 11%, Total Sugars 22g, Protein 5g, Vitamin C 56mg 278%, Calcium 132mg 10%, Iron 1mg 3%, Potassium 519mg 11%', 'Prep Time: 5 mins, Total Time: 5 mins, Servings: 2', 'https://www.allrecipes.com/thmb/nXTnAdimMBtkQieZhloU45cM1V0=/1500x0/filters:no_upscale():max_bytes(150000):strip_icc()/441727-fruit-and-yogurt-smoothie-Alberta-Rose-4x3-1-aa04390dac11483aaeeec142dff1f6c7.jpg');
INSERT INTO public.recipes VALUES (1, 'Apple Pie by Grandma Ople', '30 mins', '1 hrs', '1 hrs 30 mins', '8', '1 9-inch pie', '8 small Granny Smith apples, or as needed, ½ cup unsalted butter, 3 tablespoons all-purpose flour, ½ cup white sugar, ½ cup packed brown sugar, ¼ cup water, 1 (9 inch) double-crust pie pastry, thawed', 'Peel and core apples, then thinly slice. Set aside.
INSERT INTO public.recipes VALUES (2, 'Sarah''s Homemade Applesauce', '10 mins', '15 mins', '25 mins', '4', NULL, '4  apples - peeled, cored and chopped, ¾ cup water, ¼ cup white sugar, ½ teaspoon ground cinnamon', 'Combine apples, water, sugar, and cinnamon in a saucepan; cover and cook over medium heat until apples are soft, about 15 to 20 minutes.
INSERT INTO public.recipes VALUES (3, 'Apple Crisp', '30 mins', '45 mins', '1 hrs 15 mins', '12', '1 9x13-inch pan', '10 cups all-purpose apples, peeled, cored and sliced, 1 cup white sugar, 1 tablespoon all-purpose flour, 1 teaspoon ground cinnamon, ½ cup water, 1 cup quick-cooking oats, 1 cup all-purpose flour, 1 cup packed brown sugar, ¼ teaspoon baking powder, ¼ teaspoon baking soda, ½ cup butter, melted', 'Preheat the oven to 350 degrees F (175 degrees C).
INSERT INTO public.recipes VALUES (4, 'Apple Pie Filling', '20 mins', '20 mins', '2 hrs 40 mins', '40', '5 9-inch pies', '18 cups thinly sliced apples, 3 tablespoons lemon juice, 10 cups water, 4 ½ cups white sugar, 1 cup cornstarch, 2 teaspoons ground cinnamon, 1 teaspoon salt, ¼ teaspoon ground nutmeg', 'Toss apples with lemon juice in a large bowl and set aside.
INSERT INTO public.recipes VALUES (8, 'Old-Fashioned Apple Dumplings', '30 mins', '1 hrs', '1 hrs 30 mins', '6', NULL, '1 recipe pastry for double-crust pie, 6 large Granny Smith apples, peeled and cored, ½ cup butter, ¾ cup brown sugar, 1 teaspoon ground cinnamon, ½ teaspoon ground nutmeg, 3 cups water, 2 cups white sugar, 1 teaspoon vanilla extract', 'Preheat the oven to 400 degrees F (200 degrees C). Butter a 9x13-inch pan.
INSERT INTO public.recipes VALUES (9, 'Southern Fried Apples', '10 mins', '10 mins', '20 mins', '4', NULL, '½ cup butter, ½ cup white sugar, 2 tablespoons ground cinnamon, 4  Granny Smith apples - peeled, cored, and sliced', 'Melt butter in a large skillet over medium heat. Add sugar and cinnamon; stir until sugar dissolves.
INSERT INTO public.recipes VALUES (722, 'Blue Hawaiian Cocktail', '5 mins', NULL, '5 mins', '1', '1 cocktail', '1 cup crushed ice, 2 fluid ounces pineapple juice, 1 fluid ounce light rum, 1 fluid ounce blue Curacao liqueur, 1 fluid ounce cream of coconut, 1  pineapple slice, 1  maraschino cherry', 'Combine crushed ice, pineapple juice, rum, blue Curacao, and cream of coconut in a blender. Puree on high speed until smooth. Pour into a chilled highball glass.
INSERT INTO public.recipes VALUES (10, 'Apple Turnovers', '30 mins', '25 mins', '55 mins', '8', '8 turnovers', '2 tablespoons lemon juice, 4 cups water, 4  Granny Smith apples - peeled, cored and sliced, 2 tablespoons butter, 1 cup brown sugar, 1 teaspoon ground cinnamon, 1 tablespoon cornstarch, 1 tablespoon water, 1 (17.25 ounce) package frozen puff pastry sheets, thawed, 1 cup confectioners'' sugar, 1 tablespoon milk, 1 teaspoon vanilla extract', 'Combine the lemon and 4 cups water in a large bowl. Place the sliced apples in the water to keep them from browning.
INSERT INTO public.recipes VALUES (11, 'Apple Crisp - Perfect and Easy', '20 mins', '40 mins', '1 hrs', '6', '1 8-inch square dish', '2 ½ cups apples - peeled, cored, and sliced, 1 cup sifted all-purpose flour, 1 cup white sugar, ½ teaspoon ground cinnamon, ¼ teaspoon salt, ½ cup butter, softened', 'Preheat the oven to 375 degrees F (190 degrees C). Lightly grease an 8-inch square baking dish.
INSERT INTO public.recipes VALUES (12, 'The Best Caramel Apples', '15 mins', '30 mins', '2 hrs 15 mins', '8', NULL, '8 large tart apples, 8  wooden chopsticks for handles, 2 cups packed brown sugar, 1 (14 ounce) can sweetened condensed milk, 1 cup light corn syrup, 1 cup butter, 2 teaspoons vanilla extract', 'Bring a large saucepan of water to a boil. Dip apples in boiling water for a few seconds, using a slotted spoon, then dry with paper towels to remove any wax from the peels. Set apples aside to cool completely, about 30 minutes.
INSERT INTO public.recipes VALUES (13, 'Mulligatawny Soup', '20 mins', '1 hrs', '1 hrs 20 mins', '6', NULL, '½ cup chopped onion, 2 stalks celery, chopped, 1  carrot, diced, ¼ cup butter, 1 ½ tablespoons all-purpose flour, 1 ½ teaspoons curry powder, 4 cups chicken broth, ½  apple, cored and chopped, ¼ cup white rice, 1  skinless, boneless chicken breast half - cut into cubes, 1 pinch dried thyme,   salt and ground black pepper to taste, ½ cup heavy cream, heated', 'Melt butter in a large soup pot over medium heat. Add onions, celery, and carrot and sauté until soft, 5 to 7 minutes. Add flour and curry, and cook 5 more minutes, stirring frequently. Add chicken broth, mix well, and bring to a boil. Reduce heat and simmer for about 30 minutes.
INSERT INTO public.recipes VALUES (14, 'Sauteed Apples', '5 mins', '15 mins', '20 mins', '8', '4 cups', '¼ cup butter, 4 large tart apples - peeled, cored and sliced 1/4 inch thick, ½ cup cold water, 2 teaspoons cornstarch, ½ cup brown sugar, ½ teaspoon ground cinnamon', 'Melt butter in a large skillet or saucepan over medium heat; add apples and cook, stirring constantly, until almost tender, 6 to 7 minutes.
INSERT INTO public.recipes VALUES (15, 'Homemade Apple Cider', '15 mins', '3 hrs', '7 hrs 15 mins', '16', '1 gallon', '10 large apples, quartered,   water, to cover, ¾ cup white sugar, 1 tablespoon ground cinnamon, 1 tablespoon ground allspice', 'Place apples in a large stockpot; cover with water by at least 2 inches. Stir in sugar, cinnamon, and allspice. Bring to a boil over medium-high heat. Boil, uncovered, for 1 hour. Reduce heat; cover and simmer for 2 hours.
INSERT INTO public.recipes VALUES (16, 'Canned Apple Pie Filling', '30 mins', '10 mins', '1 hrs', '56', '7 quarts', '4 ½ cups white sugar, 1 cup cornstarch, 2 teaspoons ground cinnamon, ¼ teaspoon ground nutmeg, 10 cups water, 2 teaspoons salt, 3 tablespoons lemon juice, 2 drops yellow food coloring, 6 pounds apples', 'Mix sugar, cornstarch, cinnamon, and nutmeg in a large pan. Add water and salt and mix well. Bring to a boil and cook until thick and bubbly. Remove from heat and add lemon juice and food coloring.
INSERT INTO public.recipes VALUES (18, 'Apple Crumb Pie', '30 mins', '50 mins', '1 hrs 20 mins', '8', '1 9-inch pie', '6 cups thinly sliced apples, 1 tablespoon lemon juice (Optional), ¾ cup white sugar, 2 tablespoons all-purpose flour, ½ teaspoon ground cinnamon, ⅛ teaspoon ground nutmeg, ½ cup raisins (Optional), ½ cup chopped walnuts (Optional), 1 (9 inch) pie shell, ½ cup all-purpose flour, ½ cup packed brown sugar, 3 tablespoons butter', 'Preheat the oven to 375 degrees F (190 degrees C).
INSERT INTO public.recipes VALUES (19, 'Caramel Apples', '8 mins', '2 mins', '25 mins', '6', '6 caramel apples', '6  apples, 6  wooden craft sticks,   cooking spray, 1 (14 ounce) package individually wrapped caramels, unwrapped, 2 tablespoons milk', 'Remove the stem from each apple and press a craft stick into the top. Spray a baking sheet with cooking spray.
INSERT INTO public.recipes VALUES (20, 'German Apple Cake', '15 mins', '45 mins', '1 hrs', '24', '1 9x13-inch cake', '1 cup vegetable oil, 2  eggs, 2 cups white sugar, 1 teaspoon vanilla extract, 2 cups all-purpose flour, 2 teaspoons ground cinnamon, 1 teaspoon baking soda, ½ teaspoon salt, 4 cups apples - peeled, cored and diced', 'Preheat the oven to 350 degrees F (175 degrees C). Grease and flour a 9x13-inch cake pan.
INSERT INTO public.recipes VALUES (21, 'Awesome Sausage, Apple and Cranberry Stuffing', '15 mins', '15 mins', '1 hrs 30 mins', '10', NULL, '3 ¾ cups cubed white bread, 1 ½ cups cubed whole wheat bread, 1 pound ground turkey sausage, 1 cup chopped onion, ¾ cup chopped celery, 2 ½ teaspoons dried sage, 1 ½ teaspoons dried rosemary, ½ teaspoon dried thyme, 1  Golden Delicious apple, cored and chopped, ¾ cup dried cranberries, ⅓ cup minced fresh parsley, 1  cooked turkey liver, finely chopped, ¾ cup turkey stock, 4 tablespoons unsalted butter, melted', 'Preheat the oven to 350 degrees F (175 degrees C).
INSERT INTO public.recipes VALUES (22, 'Apple Hand Pies', '25 mins', '35 mins', '1 hrs 15 mins', '4', '4 hand pies', '2 tablespoons butter, 2 large green apples - peeled, cored, and cut into chunks, 2 tablespoons brown sugar, ¼ cup white sugar, ¼ teaspoon salt, 1 ½ teaspoons ground cinnamon, or to taste, 1 teaspoon water, or more if needed (Optional), 1 pound prepared pie dough, cut into 4 pieces, 1  egg, 2 teaspoons milk, 1 teaspoon white sugar, or as needed', 'Melt butter in a large skillet over medium heat; let butter brown to a light golden color and smell toasted, about 1 minute. Stir apples into hot butter; sprinkle with 1/4 cup white sugar, brown sugar, and salt. Cook and stir apple mixture until apples are softened, about 5 minutes. Mix in cinnamon and water; continue cooking until apples are soft and sticky, 1 to 2 more minutes. Spread apple filling onto a plate to cool.
INSERT INTO public.recipes VALUES (26, 'Mom''s Apple Fritters', '20 mins', '15 mins', '35 mins', '24', NULL, '1 quart vegetable oil for deep-frying, 1 ½ cups all-purpose flour, 1 tablespoon white sugar, 2 teaspoons baking powder, ½ teaspoon salt, ⅔ cup milk, 2 large eggs, beaten, 1 tablespoon vegetable oil, 3 cups apples - peeled, cored and chopped, 1 cup cinnamon sugar', 'Heat oil in a deep fryer or electric skillet to 375 degrees F (190 degrees C).
INSERT INTO public.recipes VALUES (27, 'Easy Apple Crisp with Pie Filling', '10 mins', '20 mins', '30 mins', '6', '1 8x8-inch dish', '1 (21 ounce) can apple pie filling, ½ teaspoon ground cinnamon, ½ teaspoon ground nutmeg, 1 cup margarine, ¼ cup brown sugar, 2 cups all-purpose flour', 'Preheat the oven to 350 degrees F (175 degrees C).
INSERT INTO public.recipes VALUES (28, 'Apple Strudel Muffins', '20 mins', '20 mins', '45 mins', '12', '12 muffins', '2 cups all-purpose flour, 1 teaspoon baking powder, ½ teaspoon baking soda, ½ teaspoon salt, 1 cup white sugar, ½ cup butter, 2 large eggs, 1 ¼ teaspoons vanilla, 1 ½ cups chopped apples', 'Preheat the oven to 375 degrees F (190 degrees C). Grease a 12-cup muffin pan.
INSERT INTO public.recipes VALUES (29, 'Delicious Cinnamon Baked Apples', '15 mins', '45 mins', '1 hrs', '6', NULL, '1 teaspoon butter, 2 tablespoons brown sugar, 3 teaspoons vanilla sugar, 3 teaspoons ground cinnamon, 1 teaspoon ground nutmeg, 6 large apples - peeled, cored, and sliced, 3 ½ tablespoons water', 'Preheat the oven to 350 degrees F (175 degrees C). Grease a large baking dish with butter.
INSERT INTO public.recipes VALUES (30, 'Waldorf Salad', '20 mins', NULL, '20 mins', '6', NULL, '½ cup mayonnaise, 1 tablespoon white sugar, 1 teaspoon lemon juice, ⅛ teaspoon salt, 3  apples -- peeled, cored, and chopped, 1 cup thinly sliced celery, ½ cup chopped walnuts, ½ cup raisins (Optional)', 'Whisk together mayonnaise, sugar, lemon juice, and salt in a serving bowl.
INSERT INTO public.recipes VALUES (31, 'Apple-Cranberry Crostada', NULL, NULL, NULL, '8', '6 to 8 - servings', '3 tablespoons butter, 2 pounds Granny Smith apples (or other firm, crisp apples), peeled, quartered, cored and sliced 1/4-inch thick, 1 pound Macintosh apples (or other soft-textured apples that fall apart when cooked), peeled, quartered, cored, and sliced 1/4-inch thick, ½ cup sugar, ½ cup dried cranberries, 1 sheet frozen puff pastry, thawed but still cold (follow package directions), 1  egg white, lightly beaten, 1 tablespoon sugar, 1 cup Optional: Ice cream or lightly sweetened whipped cream', 'Heat butter in a large skillet over medium-high heat. Add apples, 1/2 cup sugar and cranberries; cover and cook until apples release their liquid, about 5 minutes. Remove lid and continue to cook, stirring frequently, until soft apples fall apart and juices thicken to a thin-syrup consistency, about 5 minutes longer. Pour onto a large-lipped cookie sheet or jellyroll pan and cool to room temperature. (Can be refrigerated in an airtight container up to 5 days.)
INSERT INTO public.recipes VALUES (32, 'Apple Pie by Grandma Ople', '30 mins', '1 hrs', '1 hrs 30 mins', '8', '1 9-inch pie', '8 small Granny Smith apples, or as needed, ½ cup unsalted butter, 3 tablespoons all-purpose flour, ½ cup white sugar, ½ cup packed brown sugar, ¼ cup water, 1 (9 inch) double-crust pie pastry, thawed', 'Peel and core apples, then thinly slice. Set aside.
INSERT INTO public.recipes VALUES (33, 'Sarah''s Homemade Applesauce', '10 mins', '15 mins', '25 mins', '4', NULL, '4  apples - peeled, cored and chopped, ¾ cup water, ¼ cup white sugar, ½ teaspoon ground cinnamon', 'Combine apples, water, sugar, and cinnamon in a saucepan; cover and cook over medium heat until apples are soft, about 15 to 20 minutes.
INSERT INTO public.recipes VALUES (88, 'Mom''s Apple Fritters', '20 mins', '15 mins', '35 mins', '24', NULL, '1 quart vegetable oil for deep-frying, 1 ½ cups all-purpose flour, 1 tablespoon white sugar, 2 teaspoons baking powder, ½ teaspoon salt, ⅔ cup milk, 2 large eggs, beaten, 1 tablespoon vegetable oil, 3 cups apples - peeled, cored and chopped, 1 cup cinnamon sugar', 'Heat oil in a deep fryer or electric skillet to 375 degrees F (190 degrees C).
INSERT INTO public.recipes VALUES (34, 'Apple Crisp', '30 mins', '45 mins', '1 hrs 15 mins', '12', '1 9x13-inch pan', '10 cups all-purpose apples, peeled, cored and sliced, 1 cup white sugar, 1 tablespoon all-purpose flour, 1 teaspoon ground cinnamon, ½ cup water, 1 cup quick-cooking oats, 1 cup all-purpose flour, 1 cup packed brown sugar, ¼ teaspoon baking powder, ¼ teaspoon baking soda, ½ cup butter, melted', 'Preheat the oven to 350 degrees F (175 degrees C).
INSERT INTO public.recipes VALUES (35, 'Apple Pie Filling', '20 mins', '20 mins', '2 hrs 40 mins', '40', '5 9-inch pies', '18 cups thinly sliced apples, 3 tablespoons lemon juice, 10 cups water, 4 ½ cups white sugar, 1 cup cornstarch, 2 teaspoons ground cinnamon, 1 teaspoon salt, ¼ teaspoon ground nutmeg', 'Toss apples with lemon juice in a large bowl and set aside.
