INSERT INTO public.recipes VALUES (41, 'Apple Turnovers', '30 mins', '25 mins', '55 mins', '8', '8 turnovers', '2 tablespoons lemon juice, 4 cups water, 4  Granny Smith apples - peeled, cored and sliced, 2 tablespoons butter, 1 cup brown sugar, 1 teaspoon ground cinnamon, 1 tablespoon cornstarch, 1 tablespoon water, 1 (17.25 ounce) package frozen puff pastry sheets, thawed, 1 cup confectioners'' sugar, 1 tablespoon milk, 1 teaspoon vanilla extract', 'Combine the lemon and 4 cups water in a large bowl. Place the sliced apples in the water to keep them from browning.
INSERT INTO public.recipes VALUES (42, 'Apple Crisp - Perfect and Easy', '20 mins', '40 mins', '1 hrs', '6', '1 8-inch square dish', '2 ½ cups apples - peeled, cored, and sliced, 1 cup sifted all-purpose flour, 1 cup white sugar, ½ teaspoon ground cinnamon, ¼ teaspoon salt, ½ cup butter, softened', 'Preheat the oven to 375 degrees F (190 degrees C). Lightly grease an 8-inch square baking dish.
