INSERT INTO public.recipes VALUES (43, 'The Best Caramel Apples', '15 mins', '30 mins', '2 hrs 15 mins', '8', NULL, '8 large tart apples, 8  wooden chopsticks for handles, 2 cups packed brown sugar, 1 (14 ounce) can sweetened condensed milk, 1 cup light corn syrup, 1 cup butter, 2 teaspoons vanilla extract', 'Bring a large saucepan of water to a boil. Dip apples in boiling water for a few seconds, using a slotted spoon, then dry with paper towels to remove any wax from the peels. Set apples aside to cool completely, about 30 minutes.
INSERT INTO public.recipes VALUES (994, 'Guyanese Coconut Buns', NULL, NULL, NULL, '24', '2 dozen', '2 cups all-purpose flour, 1 cup white sugar, 1 teaspoon baking powder, ½ teaspoon salt, 1 cup butter, cut into pieces, 2  eggs, ½ cup milk, 1 teaspoon vanilla extract, ½ teaspoon almond extract, ¾ cup flaked coconut', 'Preheat the oven to 350 degrees F (175 degrees C).
INSERT INTO public.recipes VALUES (44, 'Mulligatawny Soup', '20 mins', '1 hrs', '1 hrs 20 mins', '6', NULL, '½ cup chopped onion, 2 stalks celery, chopped, 1  carrot, diced, ¼ cup butter, 1 ½ tablespoons all-purpose flour, 1 ½ teaspoons curry powder, 4 cups chicken broth, ½  apple, cored and chopped, ¼ cup white rice, 1  skinless, boneless chicken breast half - cut into cubes, 1 pinch dried thyme,   salt and ground black pepper to taste, ½ cup heavy cream, heated', 'Melt butter in a large soup pot over medium heat. Add onions, celery, and carrot and sauté until soft, 5 to 7 minutes. Add flour and curry, and cook 5 more minutes, stirring frequently. Add chicken broth, mix well, and bring to a boil. Reduce heat and simmer for about 30 minutes.
