INSERT INTO public.recipes VALUES (94, 'Apple Pie by Grandma Ople', '30 mins', '1 hrs', '1 hrs 30 mins', '8', '1 9-inch pie', '8 small Granny Smith apples, or as needed, ½ cup unsalted butter, 3 tablespoons all-purpose flour, ½ cup white sugar, ½ cup packed brown sugar, ¼ cup water, 1 (9 inch) double-crust pie pastry, thawed', 'Peel and core apples, then thinly slice. Set aside.
INSERT INTO public.recipes VALUES (95, 'Sarah''s Homemade Applesauce', '10 mins', '15 mins', '25 mins', '4', NULL, '4  apples - peeled, cored and chopped, ¾ cup water, ¼ cup white sugar, ½ teaspoon ground cinnamon', 'Combine apples, water, sugar, and cinnamon in a saucepan; cover and cook over medium heat until apples are soft, about 15 to 20 minutes.
INSERT INTO public.recipes VALUES (96, 'Apple Crisp', '30 mins', '45 mins', '1 hrs 15 mins', '12', '1 9x13-inch pan', '10 cups all-purpose apples, peeled, cored and sliced, 1 cup white sugar, 1 tablespoon all-purpose flour, 1 teaspoon ground cinnamon, ½ cup water, 1 cup quick-cooking oats, 1 cup all-purpose flour, 1 cup packed brown sugar, ¼ teaspoon baking powder, ¼ teaspoon baking soda, ½ cup butter, melted', 'Preheat the oven to 350 degrees F (175 degrees C).
