INSERT INTO public.recipes VALUES (98, 'Easy Apple Crisp with Oat Topping', '20 mins', '40 mins', '1 hrs', '4', NULL, '6  apples - peeled, cored, and sliced, 2 tablespoons white sugar, 1 ½ teaspoons ground cinnamon, divided, 1 cup brown sugar, ¾ cup old-fashioned oats, ¾ cup all-purpose flour, ½ cup cold butter', 'Preheat the oven to 350 degrees F (175 degrees C).
