INSERT INTO public.recipes VALUES (102, 'Southern Fried Apples', '10 mins', '10 mins', '20 mins', '4', NULL, '½ cup butter, ½ cup white sugar, 2 tablespoons ground cinnamon, 4  Granny Smith apples - peeled, cored, and sliced', 'Melt butter in a large skillet over medium heat. Add sugar and cinnamon; stir until sugar dissolves.
INSERT INTO public.recipes VALUES (103, 'Apple Turnovers', '30 mins', '25 mins', '55 mins', '8', '8 turnovers', '2 tablespoons lemon juice, 4 cups water, 4  Granny Smith apples - peeled, cored and sliced, 2 tablespoons butter, 1 cup brown sugar, 1 teaspoon ground cinnamon, 1 tablespoon cornstarch, 1 tablespoon water, 1 (17.25 ounce) package frozen puff pastry sheets, thawed, 1 cup confectioners'' sugar, 1 tablespoon milk, 1 teaspoon vanilla extract', 'Combine the lemon and 4 cups water in a large bowl. Place the sliced apples in the water to keep them from browning.
INSERT INTO public.recipes VALUES (104, 'Apple Crisp - Perfect and Easy', '20 mins', '40 mins', '1 hrs', '6', '1 8-inch square dish', '2 ½ cups apples - peeled, cored, and sliced, 1 cup sifted all-purpose flour, 1 cup white sugar, ½ teaspoon ground cinnamon, ¼ teaspoon salt, ½ cup butter, softened', 'Preheat the oven to 375 degrees F (190 degrees C). Lightly grease an 8-inch square baking dish.
INSERT INTO public.recipes VALUES (105, 'The Best Caramel Apples', '15 mins', '30 mins', '2 hrs 15 mins', '8', NULL, '8 large tart apples, 8  wooden chopsticks for handles, 2 cups packed brown sugar, 1 (14 ounce) can sweetened condensed milk, 1 cup light corn syrup, 1 cup butter, 2 teaspoons vanilla extract', 'Bring a large saucepan of water to a boil. Dip apples in boiling water for a few seconds, using a slotted spoon, then dry with paper towels to remove any wax from the peels. Set apples aside to cool completely, about 30 minutes.
INSERT INTO public.recipes VALUES (106, 'Mulligatawny Soup', '20 mins', '1 hrs', '1 hrs 20 mins', '6', NULL, '½ cup chopped onion, 2 stalks celery, chopped, 1  carrot, diced, ¼ cup butter, 1 ½ tablespoons all-purpose flour, 1 ½ teaspoons curry powder, 4 cups chicken broth, ½  apple, cored and chopped, ¼ cup white rice, 1  skinless, boneless chicken breast half - cut into cubes, 1 pinch dried thyme,   salt and ground black pepper to taste, ½ cup heavy cream, heated', 'Melt butter in a large soup pot over medium heat. Add onions, celery, and carrot and sauté until soft, 5 to 7 minutes. Add flour and curry, and cook 5 more minutes, stirring frequently. Add chicken broth, mix well, and bring to a boil. Reduce heat and simmer for about 30 minutes.
INSERT INTO public.recipes VALUES (107, 'Sauteed Apples', '5 mins', '15 mins', '20 mins', '8', '4 cups', '¼ cup butter, 4 large tart apples - peeled, cored and sliced 1/4 inch thick, ½ cup cold water, 2 teaspoons cornstarch, ½ cup brown sugar, ½ teaspoon ground cinnamon', 'Melt butter in a large skillet or saucepan over medium heat; add apples and cook, stirring constantly, until almost tender, 6 to 7 minutes.
INSERT INTO public.recipes VALUES (108, 'Homemade Apple Cider', '15 mins', '3 hrs', '7 hrs 15 mins', '16', '1 gallon', '10 large apples, quartered,   water, to cover, ¾ cup white sugar, 1 tablespoon ground cinnamon, 1 tablespoon ground allspice', 'Place apples in a large stockpot; cover with water by at least 2 inches. Stir in sugar, cinnamon, and allspice. Bring to a boil over medium-high heat. Boil, uncovered, for 1 hour. Reduce heat; cover and simmer for 2 hours.
INSERT INTO public.recipes VALUES (109, 'Canned Apple Pie Filling', '30 mins', '10 mins', '1 hrs', '56', '7 quarts', '4 ½ cups white sugar, 1 cup cornstarch, 2 teaspoons ground cinnamon, ¼ teaspoon ground nutmeg, 10 cups water, 2 teaspoons salt, 3 tablespoons lemon juice, 2 drops yellow food coloring, 6 pounds apples', 'Mix sugar, cornstarch, cinnamon, and nutmeg in a large pan. Add water and salt and mix well. Bring to a boil and cook until thick and bubbly. Remove from heat and add lemon juice and food coloring.
INSERT INTO public.recipes VALUES (110, 'Easy Apple Pie', '20 mins', '40 mins', '1 hrs', '8', '1 9-inch pie', '1 (14.1 ounce) package pastry for a 9-inch double-crust pie, ¾ cup white sugar, or more to taste, 1 teaspoon ground cinnamon, 6 cups thinly sliced apples, 1 tablespoon butter', 'Preheat the oven to 450 degrees F (230 degrees C).
INSERT INTO public.recipes VALUES (111, 'Apple Crumb Pie', '30 mins', '50 mins', '1 hrs 20 mins', '8', '1 9-inch pie', '6 cups thinly sliced apples, 1 tablespoon lemon juice (Optional), ¾ cup white sugar, 2 tablespoons all-purpose flour, ½ teaspoon ground cinnamon, ⅛ teaspoon ground nutmeg, ½ cup raisins (Optional), ½ cup chopped walnuts (Optional), 1 (9 inch) pie shell, ½ cup all-purpose flour, ½ cup packed brown sugar, 3 tablespoons butter', 'Preheat the oven to 375 degrees F (190 degrees C).
INSERT INTO public.recipes VALUES (112, 'Caramel Apples', '8 mins', '2 mins', '25 mins', '6', '6 caramel apples', '6  apples, 6  wooden craft sticks,   cooking spray, 1 (14 ounce) package individually wrapped caramels, unwrapped, 2 tablespoons milk', 'Remove the stem from each apple and press a craft stick into the top. Spray a baking sheet with cooking spray.
