INSERT INTO public.recipes VALUES (119, 'Mom''s Apple Fritters', '20 mins', '15 mins', '35 mins', '24', NULL, '1 quart vegetable oil for deep-frying, 1 ½ cups all-purpose flour, 1 tablespoon white sugar, 2 teaspoons baking powder, ½ teaspoon salt, ⅔ cup milk, 2 large eggs, beaten, 1 tablespoon vegetable oil, 3 cups apples - peeled, cored and chopped, 1 cup cinnamon sugar', 'Heat oil in a deep fryer or electric skillet to 375 degrees F (190 degrees C).
INSERT INTO public.recipes VALUES (182, 'No Bake Fruitcake', NULL, NULL, NULL, '18', '1 to 12 - x inch cake', '1 pound halved candied cherries, 4 cups chopped pecans, 1 (14 ounce) can sweetened condensed milk, 1 (14 ounce) can coconut milk, 1 cup flaked coconut, 1 cup raisins, 1 teaspoon vanilla extract, 1 (12 ounce) package vanilla wafers, crushed', 'In a large bowl mix the candied cherries, chopped pecans, sweetened condensed milk, coconut milk, flaked coconut, raisins, vanilla, and crushed vanilla wafers. Batter will be very stiff. Place into pan and store in the refrigerator.', '4.3', 'https://www.allrecipes.com/recipe/7605/no-bake-fruitcake/', '/Desserts/Fruit Desserts/Cherry Dessert Recipes/', 'Total Fat 29g 37%, Saturated Fat 9g 44%, Cholesterol 7mg 2%, Sodium 116mg 5%, Total Carbohydrate 53g 19%, Dietary Fiber 4g 13%, Total Sugars 32g, Protein 6g, Vitamin C 1mg 6%, Calcium 92mg 7%, Iron 3mg 14%, Potassium 335mg 7%', 'Servings: 18, Yield: 1 to 12 - x inch cake', 'https://www.allrecipes.com/thmb/1qlddljmpoy-xpPh41PbQCofNjM=/1500x0/filters:no_upscale():max_bytes(150000):strip_icc()/6061307-fc76d0e30e374133bcb0a60809ecd1c0.jpg');
