INSERT INTO public.recipes VALUES (183, 'Vanilla Cherry Ice Cream', '3 hrs 15 mins', NULL, '5 hrs 15 mins', '8', '4 cups', '2 cups heavy cream, 1 cup milk, ¾ cup white sugar, 1 tablespoon vanilla extract, 1 teaspoon almond extract, 2 cups fresh cherries, pits removed and cut in half', 'Combine the cream, milk, and sugar in a bowl. Stir until the sugar is completely dissolved. Stir in the vanilla and almond extract. Add the cherries. Pour the mixture into an ice cream maker and churn according to the manufacturer''s instructions. Transfer to a freezer-safe container and freeze for at least 2 hours before serving.', '4.6', 'https://www.allrecipes.com/recipe/143665/vanilla-cherry-ice-cream/', '/Desserts/Fruit Desserts/Cherry Dessert Recipes/', 'Total Fat 23g 29%, Saturated Fat 14g 71%, Cholesterol 84mg 28%, Sodium 35mg 2%, Total Carbohydrate 28g 10%, Dietary Fiber 1g 3%, Total Sugars 26g, Protein 3g, Vitamin C 3mg 15%, Calcium 80mg 6%, Iron 0mg 1%, Potassium 174mg 4%', 'Prep Time: 3 hrs 15 mins, Additional Time: 2 hrs, Total Time: 5 hrs 15 mins, Servings: 8, Yield: 4 cups', 'https://www.allrecipes.com/thmb/OiMFIw0kkzkMEADen9wh5fT5N0U=/1500x0/filters:no_upscale():max_bytes(150000):strip_icc()/2373290-ebc2c24878ba494f9fc54a89eb064dd3.jpg');
