INSERT INTO public.recipes VALUES (125, 'German Apple Pancake', '15 mins', '30 mins', '1 hrs 15 mins', '4', '4 servings', '4  eggs, ½ cup unbleached all-purpose flour, 1 tablespoon sugar, ½ teaspoon baking powder, 1 pinch salt, 1 cup milk, 1 teaspoon vanilla extract, 2 tablespoons unsalted butter, melted, ½ teaspoon ground nutmeg, ¼ cup unsalted butter, ½ cup white sugar, divided, ½ teaspoon ground cinnamon, ½ teaspoon ground nutmeg, 1 large tart apple - peeled, cored and sliced', 'Combine eggs, flour, 1 tablespoon sugar, baking powder, and salt in a large bowl; gradually mix in milk, stirring constantly. Add vanilla, melted butter, and 1/2 teaspoon nutmeg. Let batter stand for 30 minutes or overnight.
