INSERT INTO public.recipes VALUES (127, 'Applesauce Pork Chops', '15 mins', '45 mins', '1 hrs', '2', NULL, '1 tablespoon butter, 1  apple - peeled, cored, and sliced, ¼ cup chopped onion, 2  (1/2-inch thick) pork chops, ½ teaspoon salt,   ground black pepper to taste, ¾ cup applesauce, 2 tablespoons brown sugar, ½ teaspoon ground mustard, ⅛ teaspoon ground cinnamon', 'Preheat the oven to 375 degrees F (190 degrees C).
