INSERT INTO public.recipes VALUES (133, 'Baked Apple Roses', '25 mins', '45 mins', '1 hrs 15 mins', '2', '2 apple roses', '1 large red apple, cored and very thinly sliced, ¼ cup white sugar, 1 teaspoon ground cinnamon, 1 sheet frozen puff pastry, thawed, ¼ cup melted butter, 1 large egg, 2 teaspoons water, 1 teaspoon confectioners'' sugar (Optional)', 'Preheat the oven to 400 degrees F (200 degrees C). Adjust an oven rack to the middle position. Butter two (6 to 8-ounce) ramekins and dust with white sugar.
