INSERT INTO public.recipes VALUES (135, 'Dutch Apple Pie with Oatmeal Streusel', '15 mins', '45 mins', '1 hrs', '8', '1 9-inch pie', '5 cups apples - peeled, cored and sliced, ⅔ cup white sugar, 2 tablespoons all-purpose flour, ½ teaspoon ground cinnamon, ¼ teaspoon ground nutmeg, ¼ teaspoon ground allspice, 1 (9 inch) frozen pie crust, 2 tablespoons butter,   aluminum foil', 'Preheat the oven to 425 degrees F (220 degrees C).
INSERT INTO public.recipes VALUES (136, 'Baked Apples', '15 mins', '15 mins', '30 mins', '4', NULL, '4  tart green apples, ½ cup brown sugar, 4 tablespoons butter, 2 teaspoons ground cinnamon', 'Preheat the oven to 350 degrees F (175 degrees C). Remove core from the top of each apple, leaving a well.
INSERT INTO public.recipes VALUES (137, 'Mincemeat', '10 mins', '10 mins', '50 mins', '24', '2 12-ounce jars', '1 teaspoon ground cinnamon, 1 teaspoon ground cloves, 1 teaspoon ground ginger, 1 teaspoon ground nutmeg, 1 teaspoon ground allspice', 'Prepare mixed spice: Combine cinnamon, cloves, ginger, nutmeg, and allspice in a bowl. Reserve 1 heaped teaspoon for the mincemeat. Store the rest in a small jar for a later use.
INSERT INTO public.recipes VALUES (139, 'Old Fashioned Apple Pie', '20 mins', '50 mins', '1 hrs 10 mins', '8', '1 9-inch pie', '2 (9 inch)  unbaked pie crusts, 7 cups peeled, cored and sliced apples, 1 cup white sugar, 2 tablespoons all-purpose flour, 1 teaspoon ground cinnamon, ¼ teaspoon salt, ⅛ teaspoon ground nutmeg, 2 tablespoons butter', 'Preheat the oven to 425 degrees F (220 degrees C). Line a 9-inch pie plate with bottom crust.
INSERT INTO public.recipes VALUES (140, 'Quick Puff Pastry Apple Strudel', '15 mins', '25 mins', '40 mins', '8', NULL, '4 medium apples - peeled, cored, and chopped, ¾ cup white sugar, ½ cup raisins, ½ cup chopped walnuts, 2 teaspoons ground cinnamon, 1 tablespoon all-purpose flour, ½ (17.5 ounce) package frozen puff pastry, thawed, 1 large egg, lightly beaten, 1 tablespoon white sugar, or to taste', 'Preheat the oven to 400 degrees F (200 degrees C).
INSERT INTO public.recipes VALUES (141, 'Fried Apple Pies', '15 mins', '15 mins', '1 hrs', '8', NULL, '2 cups all-purpose flour, 1 teaspoon salt, ½ cup shortening, chilled, ½ cup cold water', 'Make pastry: Sift flour and salt together in a large bowl. Cut in shortening with 2 knives or a pastry blender until mixture resembles coarse crumbs. Add cold water, 1 tablespoon at a time, tossing with a fork, until flour mixture is moistened. Do not add more water than you need: when you squeeze a handful of moistened pastry mixture, it should form a ball. Wrap in plastic wrap and refrigerate for 30 minutes.
INSERT INTO public.recipes VALUES (142, 'Skillet Apples with Cinnamon', '10 mins', '10 mins', '20 mins', '6', NULL, '¼ cup butter, 8  apples, cored and chopped, ½ cup brown sugar, ¼ teaspoon ground cinnamon, ¼ teaspoon nutmeg', 'Melt butter in a large, heavy skillet over medium heat. Add apples, brown sugar, cinnamon, and nutmeg. Sauté in hot butter until tender and golden, 10 to 15 minutes.', '4.8', 'https://www.allrecipes.com/recipe/236250/skillet-apples-with-cinnamon/', '/Side Dish/', 'Total Fat 8g 10%, Saturated Fat 5g 25%, Cholesterol 20mg 7%, Sodium 62mg 3%, Total Carbohydrate 44g 16%, Dietary Fiber 5g 16%, Total Sugars 37g, Protein 1g, Vitamin C 9mg 43%, Calcium 30mg 2%, Iron 0mg 2%, Potassium 224mg 5%', 'Prep Time: 10 mins, Cook Time: 10 mins, Total Time: 20 mins, Servings: 6', 'https://www.allrecipes.com/thmb/i29DdNsqG4jePtesgRsVfZtwprU=/1500x0/filters:no_upscale():max_bytes(150000):strip_icc()/1124805-ca226adf276146879795b45e07142e6d.jpg');
