INSERT INTO public.recipes VALUES (145, 'Apple Jelly', '20 mins', '40 mins', '1 day 1 hrs', '100', NULL, '3 ½ pounds apples, cored and diced, 3 cups water, or as needed, 7 ½ cups white sugar, ½ teaspoon butter, 1 (2 ounce) package powdered fruit pectin', 'Place apples in a large pot; cover with water. Bring to a boil; reduce heat, cover, and simmer until apples are slightly tender, about 5 minutes. Crush cooked apples and simmer for 5 more minutes.
INSERT INTO public.recipes VALUES (146, 'Easy Apple Coleslaw', '25 mins', NULL, '25 mins', '6', NULL, '3 cups chopped cabbage, 1  unpeeled red apple, cored and chopped, 1  unpeeled Granny Smith apple, cored and chopped, 1  carrot, grated, ½ cup finely chopped red bell pepper, 2  green onions, finely chopped, ⅓ cup mayonnaise, ⅓ cup brown sugar, 1 tablespoon lemon juice, or to taste', 'Combine cabbage, red apple, green apple, carrot, red bell pepper, and green onions in a large bowl.
INSERT INTO public.recipes VALUES (147, 'Easy Apple Strudel', '20 mins', '35 mins', '55 mins', '6', NULL, '1  Granny Smith apple - peeled, cored and coarsely shredded, 3  Granny Smith apples - peeled, cored and sliced, 1 cup brown sugar, 1 cup golden raisins, 1 sheet frozen puff pastry, thawed, 1  egg, ¼ cup milk', 'Preheat the oven to 400 degrees F (200 degrees C). Line a baking sheet with parchment paper.
INSERT INTO public.recipes VALUES (149, 'Oliebollen (Dutch Doughnuts)', '20 mins', '10 mins', '1 hrs 35 mins', '12', '1 dozen', '1 (0.6 ounce) cake compressed fresh yeast, 1 cup lukewarm milk, 2 ¼ cups all-purpose flour, 2 teaspoons salt, 1 large egg, ¾ cup dried currants, ¾ cup raisins, 1 medium Granny Smith apple - peeled, cored and finely chopped, 1 quart vegetable oil for deep-frying, 1 cup confectioners'' sugar for dusting', 'Break up compressed yeast and stir into warm milk. Let stand for a few minutes to dissolve.
INSERT INTO public.recipes VALUES (150, 'Classic Cherries Jubilee', '10 mins', '20 mins', '30 mins', '6', NULL, '½ cup white sugar, 2 tablespoons cornstarch, ¼ cup cold water, ¼ cup orange juice, 1 pound Bing or other dark, sweet cherries, rinsed and pitted (or use frozen pitted cherries), ½ teaspoon finely grated orange zest, 3 cups vanilla bean ice cream, ¼ teaspoon cherry extract, ¼ cup brandy', 'Whisk sugar and cornstarch together in a wide saucepan. Stir in water and orange juice; bring to a boil over medium-high heat, whisking until thickened. Stir in cherries and orange zest; return to a boil, then reduce heat, and simmer for 10 minutes. While cherries are cooking, spoon ice cream into serving bowls.
INSERT INTO public.recipes VALUES (151, 'Fresh Cherry Cobbler', '1 hrs', '1 hrs', '2 hrs', '12', NULL, '½ cup butter, 1 cup all-purpose flour, 1 ¾ cups white sugar, divided, 1 teaspoon baking powder, 1 cup milk, 2 cups pitted sour cherries, 1 tablespoon all-purpose flour', 'Preheat the oven to 350 degrees F (175 degrees C). Place butter in a 9x13-inch baking dish, and place in the oven to melt while the oven is preheating. Remove as soon as butter has melted, about 5 minutes.
INSERT INTO public.recipes VALUES (152, 'Cherry Pie Filling', '25 mins', '15 mins', '40 mins', '6', '4 cups', '4 cups pitted tart red cherries, 1 cup white sugar, ¼ cup cornstarch', 'Place cherries into a saucepan over medium heat. Cover and cook, stirring often, until cherries release their juices and come to a simmer, 10 to 15 minutes.
INSERT INTO public.recipes VALUES (153, 'Best Boiled Fruitcake', '15 mins', '2 hrs 20 mins', '2 hrs 40 mins', '10', '1 8-inch cake', '1 ½ cups white sugar, 12 ounces candied mixed fruit, 1 cup milk, ¾ cup butter, 5 ounces glace cherries, roughly chopped, 2 ounces candied mixed citrus peel, 2 ounces chopped walnuts, 1 teaspoon ground allspice, ½ teaspoon baking soda, 12 ounces sifted self-rising flour, 2 large eggs', 'Preheat the oven to 325 degrees F (160 degrees C). Line an 8-inch deep cake pan with parchment paper.
INSERT INTO public.recipes VALUES (156, 'Grandma''s Skillet Pineapple Upside-Down Cake', '15 mins', '45 mins', '1 hrs 10 mins', '12', '1 cake', '1 stick butter, 1 ½ cups packed brown sugar, 1 (20 ounce) can sliced pineapple, 1 (4 ounce) jar cherries, 1 ½ cups all-purpose flour, 2 ½ teaspoons baking powder, ½ teaspoon salt, 1 ½ cups white sugar, ½ cup butter, 2 large eggs, 1 cup milk, 2 teaspoons vanilla extract', 'Preheat the oven to 375 degrees F (190 degrees C).
INSERT INTO public.recipes VALUES (157, 'Chocolate-Covered Cherries', '1 hrs', NULL, '1 hrs 30 mins', '60', '60 pieces', '60  maraschino cherries with stems, 3 tablespoons butter, softened, 3 tablespoons corn syrup, 2 cups sifted confectioners'' sugar, 1 pound chocolate confectioners'' coating ', 'Drain cherries and set on paper towels to dry.
INSERT INTO public.recipes VALUES (158, 'Thirty Day Friendship Cake', '1 hrs', '1 hrs', '19 days 19 hrs 2 mins', '48', '2 9x13-inch cakes', '  2 cups Friendship Fruit Starter, 1 (15 ounce) can sliced peaches with juice, 2 ½ cups white sugar, 1 (15 ounce) can pineapple chunks with juice, ½ cup white sugar, 2 (10 ounce) jars maraschino cherries, 2 ½ cups white sugar, 2 (18.25 ounce) packages yellow cake mix, 2 (3.4 ounce) packages instant vanilla pudding mix, 1 ⅓ cups vegetable oil, 8  eggs, 2 cups golden raisins, 2 cups chopped walnuts, 2 cups flaked coconut', 'Day One: In a large glass jar or bowl, combine 2 cups of the starter with 1 can of the sliced peaches and their juice (each slice chopped into 4 pieces). Add 2 1/2 cups of the white sugar and stir once every day for 10 days. When not stirring mixture, keep it covered with a paper towel, foil, or a loose lid. Let sit at room temperature. Don''t refrigerate it or cover it airtight. A pan of water underneath the jar or bowl will keep the ants out.
INSERT INTO public.recipes VALUES (159, 'Old Time Mincemeat Pie', '45 mins', '40 mins', '7 days 1 hrs 25 mins', '8', '1 9-inch pie', '1 ¼ pounds round steak, cut into small pieces, 1 cup apple cider, 4  Granny Smith apples - peeled, cored and finely diced, 1 ⅓ cups white sugar, 2 ½ cups dried currants, 2 ½ cups raisins, ½ pound chopped candied mixed fruit peel, ½ cup butter, 1 (16 ounce) jar sour cherry preserves, 1 teaspoon ground ginger, ½ teaspoon ground cloves, ½ teaspoon ground nutmeg, ½ teaspoon ground cinnamon, ½ teaspoon salt, 1 (16 ounce) can pitted sour cherries, drained with liquid reserved, 1 recipe pastry for a 9 inch double crust pie, 2 tablespoons heavy cream', 'In a Dutch oven, combine beef and apple cider. Bring to a boil, then reduce heat to a simmer. Cover and cook for about 20 minutes, or until meat is tender. Remove meat and coarsely chop, then return it to the pot.
INSERT INTO public.recipes VALUES (160, 'Baked Ham with Sweet Glaze', '20 mins', '2 hrs 30 mins', '3 hrs', '20', '1 10-pound ham', '1 (10 pound) fully-cooked, bone-in ham, 4 cups boiling water, or as needed, 1 cup packed brown sugar, 2 tablespoons all-purpose flour, 2 tablespoons dry mustard powder, ¼ cup honey, 1 teaspoon fresh lemon juice, or as needed, 1 (20 ounce) can pineapple chunks, drained, 1 (10 ounce) jar maraschino cherries, drained,   toothpicks', 'Preheat oven to 400 degrees F (200 degrees C). Place ham on a rack set in a roasting pan, and carefully pour about 1/2 inch of boiling water into the pan beneath the ham.
INSERT INTO public.recipes VALUES (161, 'Fresh Cherry Muffins', '20 mins', '20 mins', '40 mins', '12', '1 dozen', '1 ½ cups all-purpose flour, ¾ cup white sugar, 2 teaspoons baking powder, ½ teaspoon salt, ⅓ cup vegetable oil, ⅓ cup milk, 1  egg, ½ teaspoon almond extract, 1 cup fresh pitted and quartered sweet cherries, 1 tablespoon white sugar', 'Preheat oven to 400 degrees F (200 degrees C). Line a muffin tin with paper liners.
INSERT INTO public.recipes VALUES (162, 'Easy Fruit Cobbler', '15 mins', '1 hrs', '1 hrs 15 mins', '8', '1 to 9 - inch cobbler', '1 cup all-purpose flour, 2 teaspoons baking powder, ¾ cup white sugar, ¾ cup milk, ¼ cup butter, 2 cups sliced fresh peaches', 'Preheat oven to 325 degrees F (165 degrees C). Melt butter in a 9 x 9 inch baking dish.
INSERT INTO public.recipes VALUES (163, 'Pineapple Glaze for Ham', '10 mins', '5 mins', '15 mins', '14', '3 cups', '1 (15.25 ounce) can sliced pineapple, drained with juice reserved, 1 (4 ounce) jar maraschino cherries, drained, 1 cup brown sugar', 'Before baking ham, place pineapple slices on ham with toothpicks and place cherries in center of pineapple.
INSERT INTO public.recipes VALUES (164, 'Door County Cherry Bounce', '10 mins', NULL, '19 days 17 hrs 12 mins', '10', '1 quart', '2 cups pitted tart cherries (such as Door County cherries), ⅓ cup white sugar, or to taste, 1 cup vodka, or as needed', 'Put cherries in a clean, 1-quart glass jar; add sugar. Fill the rest of the jar with vodka. Place lid on jar and shake.
INSERT INTO public.recipes VALUES (165, 'English Trifle', NULL, NULL, NULL, '14', '1 bowl', '2 (8 or 9 inch) white cake layers, baked and cooled, 2 pints fresh strawberries, ¼ cup white sugar, 1 pint fresh blueberries, 2  bananas, ¼ cup orange juice, 1 (3.5 ounce) package instant vanilla pudding mix, 2 cups milk, 1 cup heavy whipping cream, ¼ cup blanched slivered almonds, 12  maraschino cherries', 'Slice strawberries and sprinkle them with sugar. Cut the bananas into slices and toss with orange juice. Combine pudding mix with milk and mix until smooth. Cut the cake into 1 inch cubes.
INSERT INTO public.recipes VALUES (166, 'Simple Summer Smoothie', '10 mins', NULL, '10 mins', '4', '4 cups', '1  banana, 1 cup frozen strawberries, 1 cup frozen blueberries, 1 cup frozen cherries, 4  ice cubes, ½ cup orange juice, ¾ cup vanilla yogurt, ½ teaspoon honey (Optional)', 'Place the banana, strawberries, blueberries, cherries, and ice cubes into a blender. Pour in the orange juice, vanilla yogurt, and honey. Puree until smooth.', '4.5', 'https://www.allrecipes.com/recipe/172463/simple-summer-smoothie/', '/Breakfast and Brunch/Drinks/', 'Total Fat 1g 2%, Saturated Fat 1g 3%, Cholesterol 2mg 1%, Sodium 34mg 1%, Total Carbohydrate 31g 11%, Dietary Fiber 4g 13%, Total Sugars 23g, Protein 4g, Vitamin C 43mg 214%, Calcium 101mg 8%, Iron 1mg 5%, Potassium 420mg 9%', 'Prep Time: 10 mins, Total Time: 10 mins, Servings: 4, Yield: 4 cups', 'https://www.allrecipes.com/thmb/LTfr8Z4Pq79_FgbP6A3AJAASPTg=/1500x0/filters:no_upscale():max_bytes(150000):strip_icc()/4883666-simple-summer-smoothie-Chef-V-4x3-1-f08fef2c92ff488ba3178dc4330e04f8.jpg');
INSERT INTO public.recipes VALUES (167, 'The Best Cherry Pie', '15 mins', '48 mins', '1 hrs 23 mins', '8', '1 pie', '1 (15 ounce) package double crust ready-to-use pie crust, 3 cups cherries, pitted, ¾ cup white sugar, 3 tablespoons cornstarch, ¼ teaspoon almond extract, 2 tablespoons salted butter, cut into bits', 'Preheat oven to 400 degrees F (200 degrees C). Line a baking sheet with aluminum foil. Place bottom pie crust into a 9-inch pie pan; made pricks along the bottom with a fork.
INSERT INTO public.recipes VALUES (168, 'Homemade Old Fashioned Mix', '10 mins', NULL, '1 hrs 10 mins', '48', '48 servings', '3 cups water, 3 cups white sugar, 3  clementine oranges, quartered, 5  maraschino cherries, or more to taste, 1  cinnamon stick, 2 tablespoons bitters, or to taste', 'Bring water and sugar to a boil in a saucepan; remove from heat. Stir oranges, cherries, and cinnamon stick into sugar mixture. Cover saucepan and steep for 1 hour.
INSERT INTO public.recipes VALUES (169, 'Fresh Cherry Crisp', '15 mins', '45 mins', '1 hrs', '8', '1 - 9x13 inch dish', '4 cups pitted sour cherries, 1 ½ cups white sugar, 4 tablespoons all-purpose flour, 1 ½ cups all-purpose flour, 1 cup old-fashioned oats, 1 cup brown sugar, ½ cup butter, ½ cup shortening', 'Preheat oven to 375 degrees F (190 degrees C).
INSERT INTO public.recipes VALUES (170, 'Monte Carlo Cocktail', '5 mins', NULL, '5 mins', '1', '1 cocktail', '  ice, 2 fluid ounces rye whiskey, ¾ fluid ounce Benedictine liqueur, 2 dashes aromatic bitters (such as Peychaud''s®, 1  maraschino cherry', 'Fill a cocktail shaker with ice. Pour in whiskey and Benedictine. Shake in bitters. Cover and shake well. Strain into a chilled glass. Garnish with maraschino cherry.', '5.0', 'https://www.allrecipes.com/recipe/217221/monte-carlo-cocktail/', '/Drinks Recipes/Cocktail Recipes/Whiskey Drinks Recipes/', 'Sodium 8mg 0%, Total Carbohydrate 7g 3%, Dietary Fiber 0g 0%, Calcium 8mg 1%, Potassium 13mg 0%', 'Prep Time: 5 mins, Total Time: 5 mins, Servings: 1, Yield: 1 cocktail', 'https://www.allrecipes.com/thmb/yDYt9QvVrzRz0LzP2Irp-Ee41O4=/1500x0/filters:no_upscale():max_bytes(150000):strip_icc()/5990112-monte-carlo-cocktail-Diana-Moutsopoulos-4x3-1-9258774a472e4056af14558b6f3bf91a.jpg');
INSERT INTO public.recipes VALUES (171, 'Cherry Dump Cake', '10 mins', '35 mins', '45 mins', '12', '1 9x13-inch cake', '2 (21 ounce) cans cherry pie filling, 1 (15.25 ounce) package white cake mix, ¼ cup butter, melted, ½ cup coarsely chopped pecans', 'Preheat the oven to 350 degrees F (175 degrees C).
INSERT INTO public.recipes VALUES (172, 'Chocolate Covered Cherry Cookies', '20 mins', '10 mins', '30 mins', '18', '18 cookies', '1 cup white sugar, ½ cup butter, 1  egg, 1 ½ teaspoons vanilla extract, 1 ½ cups all-purpose flour, ½ cup unsweetened cocoa powder, ¼ teaspoon salt, ¼ teaspoon baking soda, ¼ teaspoon baking powder, 1 (10 ounce) jar maraschino cherries, ½ cup sweetened condensed milk, 1 cup semisweet chocolate chips', 'Preheat the oven to 350 degrees F (180 degrees C).
INSERT INTO public.recipes VALUES (173, 'Baked Fresh Cherry Pie', '30 mins', '50 mins', '3 hrs 20 mins', '8', '1 9-inch pie', '1 recipe pastry for a 9 inch double crust pie, 4 tablespoons quick-cooking tapioca, ⅛ teaspoon salt, 1 cup white sugar, 4 cups pitted cherries, ¼ teaspoon almond extract, ½ teaspoon vanilla extract, 1 ½ tablespoons butter', 'Preheat oven to 400 degrees F (205 degrees C). Place bottom crust in pie pan. Set top crust aside, covered.
INSERT INTO public.recipes VALUES (174, 'Dried Cherry Cake', NULL, NULL, NULL, '12', '1 to 9 - inch round cake', '½ cup chopped dried cherries, ½ cup hot water, ½ teaspoon almond extract, 1 ½ cups all-purpose flour, 2 teaspoons baking powder, ¼ teaspoon salt, 1 cup white sugar, 1 (8 ounce) container vanilla yogurt, ½ cup vegetable oil, 1  egg, 1  egg white, ¼ cup chopped pecans, 1 tablespoon white sugar', 'Combine cherries, hot water, and almond extract: let stand 20 minutes. Drain cherries, and pat dry between layers of paper towels. Set aside.
INSERT INTO public.recipes VALUES (175, 'Chef John''s Classic Rice Pudding', '5 mins', '30 mins', '3 hrs 35 mins', '4', '4 servings', '½ cup uncooked long-grain white rice, ¼ teaspoon kosher salt, 1 cup water, ¼ cup white sugar, 1 ⅓ cups milk, ½ teaspoon vanilla extract, ⅛ teaspoon ground cinnamon, 1  large egg yolk, 1 tablespoon cold butter, 2 tablespoons dried cherries, chopped', 'Place rice, salt, and water into a saucepan. Bring to a boil over medium-high heat. Reduce heat to low, cover, and cook until tender, about 20 minutes. Remove from heat; sprinkle with sugar and pour in milk. Stir with a whisk until until the thin layer of cooked-on starch at the bottom of the pan is cleared and incorporated into the mixture, 2 or 3 minutes.
INSERT INTO public.recipes VALUES (176, 'BC Cherry Jam', '30 mins', '20 mins', '50 mins', '40', '4 half pints', '3 cups pitted, chopped fresh cherries, ½ cup unsweetened apple juice, 2 teaspoons lemon juice, 2 (2 ounce) packages powdered fruit pectin, 3 cups white sugar, 4  half pint canning jars with lids and rings', 'Place cherries, apple juice, lemon juice, and pectin into a large saucepan over medium heat; bring to a boil, and mix in the sugar. Cook the jam at a rolling boil for 2 minutes, stirring constantly. Remove from heat and skim off any foam.
INSERT INTO public.recipes VALUES (177, 'Cherry Chicken Salad', '15 mins', NULL, '45 mins', '4', '4 servings', '3  cooked, boneless chicken breast halves, diced, ⅓ cup  dried cherries, ⅓ cup diced celery, ⅓ cup toasted, chopped pecans, ⅓ cup low-fat mayonnaise, 1 tablespoon buttermilk, ½ teaspoon salt, ½ teaspoon ground black pepper, ⅓ cup cubed apples (Optional)', 'In a large bowl, combine the chicken, dried cherries, celery, nuts, mayonnaise, milk, salt and pepper and apple if desired. Toss together well and refrigerate until chilled. Serve on toasted cracked wheat bread or croissants.', '4.7', 'https://www.allrecipes.com/recipe/16225/cherry-chicken-salad/', '/Salad/', 'Total Fat 13g 16%, Saturated Fat 2g 12%, Cholesterol 62mg 21%, Sodium 356mg 15%, Total Carbohydrate 12g 4%, Dietary Fiber 2g 8%, Total Sugars 8g, Protein 24g, Vitamin C 1mg 5%, Calcium 34mg 3%, Iron 1mg 7%, Potassium 230mg 5%', 'Prep Time: 15 mins, Additional Time: 30 mins, Total Time: 45 mins, Servings: 4, Yield: 4 servings', 'https://www.allrecipes.com/thmb/aKCKs0GrF4JY1s3kTEqZgsx8wf0=/1500x0/filters:no_upscale():max_bytes(150000):strip_icc()/39072-ddc963c7bc114cedad71d6420951c314.jpg');
INSERT INTO public.recipes VALUES (178, 'Clafoutis aux Cerises (Classic Clafouti)', '15 mins', '45 mins', '2 hrs', '8', '1 8-inch dessert', '1 ½ cups milk, ½  vanilla bean, split (Optional), 1 teaspoon unsalted butter, 4 cups cherries (with pits), ½ cup all-purpose flour, 1 pinch salt, ½ cup white sugar, 3  eggs, 3 tablespoons heavy cream, 2 tablespoons white sugar', 'Combine milk and vanilla bean in a pot and steep for at least 1 hour.
INSERT INTO public.recipes VALUES (179, 'Sweet Polish Cherry Cake', '15 mins', '50 mins', '1 hrs 5 mins', '12', '1 9x12-inch cake', '1 cup white sugar, 2 ½ cups all-purpose flour, 1 tablespoon baking powder, 1 teaspoon baking soda, 1 tablespoon butter, 2 cups pitted sweet cherries, 1 tablespoon white sugar, ½ cup olive oil, 4  eggs, 1 (6 ounce) container plain yogurt, 1 tablespoon olive oil', 'Preheat oven to 350 degrees F (175 degrees C). In a mixing bowl, whisk 1 cup sugar, flour, baking powder, and baking soda together until evenly combined.
INSERT INTO public.recipes VALUES (185, 'Ice Box Fruitcake', '20 mins', NULL, '20 mins', '14', '1 to 10 - inch ring', '1 cup chopped pecans, 1 cup chopped walnuts, 1 cup chopped raisins, 1 (4 ounce) jar maraschino cherries, drained and chopped, 1 (14 ounce) can sweetened condensed milk, 1 (12 ounce) package vanilla wafers, crushed', 'In a medium bowl, stir together the pecans, raisins, walnuts, cherries, condensed milk and vanilla wafers. Dough will be very thick, you will need to use your hands.
INSERT INTO public.recipes VALUES (186, 'Crushed Pineapple Fruitcake', '15 mins', '2 hrs 30 mins', '10 hrs 45 mins', '14', '1 tube cake', '¾ cup butter, 1 cup white sugar, 2  eggs, 2 cups all-purpose flour, 2 teaspoons baking powder, 1 teaspoon salt, 1 teaspoon almond extract, 3 cups golden raisins, ½ cup red candied cherries, 1 cup candied mixed fruit peel, 1 (15 ounce) can crushed pineapple with juice', 'Line an angel food pan with parchment paper and brush with melted butter.
INSERT INTO public.recipes VALUES (192, 'Maraschino Cherry Nut Cake', '30 mins', '20 mins', '2 hrs 20 mins', '12', '1 9-inch cake', '1 (10 ounce) jar maraschino cherries, 2 ¼ cups sifted cake flour, 2 ½ teaspoons baking powder, ½ teaspoon salt, divided, ½ cup shortening, 1 ⅓ cups white sugar, 3  egg whites, room temperature, ⅔ cup milk, room temperature, ½ cup chopped pecans, ¾ cup butter, room temperature, 6 cups sifted confectioners'' sugar, divided, ⅓ cup milk, 6 drops red food coloring, 1 ½ teaspoons vanilla extract, 12  maraschino cherries, with stems', 'Preheat the oven to 350 degrees F (175 degrees C). Grease and lightly flour two 8- or 9-inch round cake pans or one 9x13-inch cake pan.
INSERT INTO public.recipes VALUES (187, 'Cherry Pound Cake', '20 mins', '1 hrs 20 mins', '1 hrs 40 mins', '12', '1 to 8 inch tube pan', '2 cups all-purpose flour, 3 teaspoons baking powder, ½ teaspoon salt, 1 cup butter, 1 (8 ounce) package cream cheese, 1 ½ cups white sugar, 4  eggs, 1 teaspoon vanilla extract, 1 teaspoon almond extract, 1 cup maraschino cherries, drained and halved, ¼ cup all-purpose flour', 'Preheat oven to 325 degrees F (165 degrees C). Grease and flour an 8 inch tube pan. Mix together the flour, baking powder, and salt; set aside.
INSERT INTO public.recipes VALUES (188, 'Almond Tortoni', '35 mins', NULL, '8 hrs 35 mins', '8', '8 servings', '1  egg white, ¼ cup confectioners'' sugar, 1 cup heavy cream, 1 teaspoon sherry wine or Marsala, 1 teaspoon almond extract, 1 cup almond macaroon crumbs, ½ cup ground almonds, 6  red maraschino cherries, chopped, 6  green maraschino cherries, chopped, ¼ cup slivered almonds, 4  maraschino cherries, halved for garnish', 'In a small bowl, beat egg white until foamy. Gradually beat in sugar, and continue beating until thick and glossy; set aside.
INSERT INTO public.recipes VALUES (189, 'Ground Cherry Pie II', '15 mins', '40 mins', '55 mins', '8', '1 to 9 - inch pie', '2 ½ cups ground cherries, ½ cup packed brown sugar, 1 tablespoon all-purpose flour, 2 tablespoons water, 1 (9 inch) pie shell, 3 tablespoons all-purpose flour, 3 tablespoons white sugar, 2 tablespoons butter', 'Preheat oven to 425 degrees F (220 degrees C).
INSERT INTO public.recipes VALUES (190, 'Paleo Almond Date Cookies', '25 mins', '15 mins', '50 mins', '24', '2 dozen', '2 ½ cups blanched almond flour, 1 cup pitted and chopped dates, ½ cup chopped dried cherries, ½ cup chopped walnuts, 2 tablespoons chia seeds, or more to taste, ½ teaspoon baking soda, ½ teaspoon sea salt, ½ cup coconut oil, 1  egg, 2 tablespoons maple syrup, 1 tablespoon vanilla extract', 'Preheat oven to 350 degrees F (175 degrees C). Line 2 baking sheets with parchment paper.
INSERT INTO public.recipes VALUES (191, 'Cherry Cream Cheese Cake', NULL, NULL, NULL, '14', '1 tube cake', '1 (8 ounce) package cream cheese, softened, 1 cup butter, softened, 1 ½ cups white sugar, 1 ½ teaspoons vanilla extract, 4  eggs, 2 ¼ cups all-purpose flour, 1 ½ teaspoons baking powder, ⅛ teaspoon salt, 1 cup candied cherries, halved, ¼ cup all-purpose flour, ½ cup chopped pecans', 'Preheat oven to 325 degrees F (165 degrees C).
INSERT INTO public.recipes VALUES (193, 'Bing Cherry Congealed Salad', NULL, NULL, NULL, '9', '6 to 10 servings', '1 (16.5 ounce) can pitted Bing cherries, drained, juice reserved, 1 (15 ounce) can crushed pineapple, drained with juice reserved, 1 (6 ounce) package cherry Jell-O®, 1 (3 ounce) package cream cheese, 6 fluid ounces cola-flavored carbonated beverage, 1 cup chopped pecans', 'In a sauce pan, combine reserved cherry juice and pineapple juice to equal 1 cup. Bring to boil, add gelatin and whisk together. Remove from heat and add cream cheese and blend together until smooth.
INSERT INTO public.recipes VALUES (194, 'Cherry Cheese Pie I', '15 mins', NULL, '2 hrs 15 mins', '8', '1 9-inch pie', '1 (9 inch) prepared graham cracker crust, 1 (8 ounce) package cream cheese, softened, ½ cup white sugar, 2 cups frozen whipped topping, thawed, 1 (21 ounce) can cherry pie filling', 'In a medium mixing bowl, beat together softened cream cheese and sugar until light and fluffy. Fold in whipped topping and blend until mixture is smooth. Spread into graham cracker crust and spoon pie filling over top. Cover with plastic wrap and chill 2 hours before serving.', '4.7', 'https://www.allrecipes.com/recipe/17584/cherry-cheese-pie-i/', '/Desserts/Pies/No-Bake Pie Recipes/', 'Total Fat 21g 27%, Saturated Fat 12g 58%, Cholesterol 31mg 10%, Sodium 251mg 11%, Total Carbohydrate 56g 20%, Dietary Fiber 1g 3%, Total Sugars 27g, Protein 4g, Vitamin C 3mg 14%, Calcium 37mg 3%, Iron 1mg 6%, Potassium 138mg 3%', 'Prep Time: 15 mins, Additional Time: 2 hrs, Total Time: 2 hrs 15 mins, Servings: 8, Yield: 1 9-inch pie', 'https://www.allrecipes.com/thmb/kR6MtuJJYCbAe3d4MAf9mkMS3ZU=/1500x0/filters:no_upscale():max_bytes(150000):strip_icc()/6487070-d3824bef8ac7482eabd33e6f43da6157.jpg');
INSERT INTO public.recipes VALUES (195, 'Cherry Pie with Almond Crumb Topping', '20 mins', '1 hrs 15 mins', '1 hrs 50 mins', '8', '1 9-inch pie', '1  1 (9 inch) unbaked pie crust (see footnote for recipe link), ½ cup slivered almonds, ½ cup light brown sugar, ⅓ cup rolled oats, ⅓ cup all-purpose flour, ¾ teaspoon salt, 6 tablespoons cold, unsalted butter, cut into pieces, 2 pounds cherries, pitted, ½  lemon, juiced, ⅓ cup white sugar, or more to taste, ¼ cup cornstarch', 'Preheat oven to 350 degrees F (175 degrees C). Line a baking sheet with aluminum foil.
INSERT INTO public.recipes VALUES (196, 'Cherry Cheesecake Brownies', '15 mins', '35 mins', '1 hrs 50 mins', '18', NULL, '1 cup butter, 2 cups white sugar, ⅔ cup cocoa powder, 4  eggs, 2 teaspoons vanilla extract, 1 cup gluten-free all purpose baking flour, ½ teaspoon gluten-free baking powder, ¼ teaspoon salt', 'Preheat the oven to 350 degrees F (175 degrees C). Grease a 9x13-inch baking pan.
INSERT INTO public.recipes VALUES (197, 'Fruity Sweet and Sour Sauce', '1 mins', '9 mins', '10 mins', '16', '2 cups', '½ cup white sugar, or to taste, ½ cup white vinegar, or more to taste, ½ cup maraschino cherry juice, ½ cup pineapple juice, 1 ½ tablespoons cornstarch, ¼ cup cold water', 'Mix the sugar, vinegar, maraschino cherry juice, and pineapple juice in a saucepan over medium-low heat, stirring to dissolve the sugar.
INSERT INTO public.recipes VALUES (199, 'Preserved Cherries', NULL, NULL, NULL, '16', '4 half-pint jars', '2 pounds fresh cherries, stems removed, 4 cups water, ¾ cup white sugar', 'Inspect 8 half-pint jars for cracks and rings for rust, discarding any defective ones. Immerse in simmering water for 10 minutes to sterilize. Wash new, unused lids and rings in warm soapy water.
INSERT INTO public.recipes VALUES (200, 'Cherry Chicken', '15 mins', '30 mins', '45 mins', '4', NULL, '3 tablespoons vegetable oil, 1 (4 pound) whole chicken, cut into 8 pieces,   salt and pepper to taste, ½ cup all-purpose flour for dusting, 1 (15 ounce) can pitted dark cherries packed in water, ½ cup white sugar, 1 tablespoon cornstarch, 1  orange - with peel, quartered and thinly sliced, ½ cup slivered almonds, toasted', 'Heat oil in a large skillet over medium-high heat. Season chicken with salt and pepper, then coat with flour. Fry in hot oil until browned, turning as needed. Reduce heat to medium, cover, and cook until meat is tender and juices run clear, about 25 minutes.
INSERT INTO public.recipes VALUES (201, 'Hawaiian Millionaire Pie', '15 mins', NULL, '1 hrs 15 mins', '8', '1 9-inch pie', '1 (9 inch) pie crust, baked, 1 (15 ounce) can crushed pineapple, drained, ¼ cup lemon juice, 1 (12 ounce) container frozen whipped topping, thawed, ½ cup maraschino cherries, chopped, 1 (14 ounce) can sweetened condensed milk, 1 cup chopped walnuts', 'In a large mixing bowl, fold pineapple, lemon juice, whipped topping, cherries, condensed milk, and walnuts together. Pour into pie shell and chill for at least one hour before serving.', '4.5', 'https://www.allrecipes.com/recipe/15568/hawaiian-millionaire-pie/', '/Desserts/Pies/No-Bake Pie Recipes/', 'Total Fat 30g 38%, Saturated Fat 14g 72%, Cholesterol 17mg 6%, Sodium 176mg 8%, Total Carbohydrate 60g 22%, Dietary Fiber 2g 6%, Total Sugars 45g, Protein 8g, Vitamin C 10mg 50%, Calcium 170mg 13%, Iron 1mg 6%, Potassium 364mg 8%', 'Prep Time: 15 mins, Additional Time: 1 hrs, Total Time: 1 hrs 15 mins, Servings: 8, Yield: 1 9-inch pie', 'https://www.allrecipes.com/thmb/5f2ORPEscH9_Q8t52esUwoUbxHQ=/1500x0/filters:no_upscale():max_bytes(150000):strip_icc()/902086-c35df260c9434518a143c634888f41f2.jpg');
INSERT INTO public.recipes VALUES (202, 'Sour Cherry Pudding Cake', '15 mins', '30 mins', '45 mins', '12', '1 9x13-inch cake', '2 cups all-purpose flour, 1 cup white sugar, 1 cup milk, 2 tablespoons vegetable oil, 1 tablespoon baking powder, 3 cups pitted tart red cherries, 1 cup white sugar, ¼ teaspoon almond extract', 'Preheat the oven to 375 degrees F (190 degrees C). Grease a 9x13-inch baking dish.
INSERT INTO public.recipes VALUES (203, 'Black Forest Cheesecakes', '20 mins', '20 mins', '2 hrs 40 mins', '12', NULL, '12  chocolate sandwich cookies with creme filling, 2 (8 ounce) packages cream cheese, softened, ¾ cup white sugar, ⅓ cup baking cocoa, 1 teaspoon vanilla extract, 2 large eggs, 1 (21 ounce) can cherry pie filling, ½ cup whipped topping', 'Preheat the oven to 325 degrees F (160 degrees C). Line muffin cups with paper or foil liners.
INSERT INTO public.recipes VALUES (204, 'Fresh Fig Cake', '40 mins', '30 mins', '1 hrs 10 mins', '8', '1 8-inch layer cake', '¼ cup butter, softened, 1 cup white sugar, 1  egg, 2 cups all-purpose flour, ½ teaspoon salt, 2 teaspoons baking powder, 1 cup fat-free evaporated milk, 1 teaspoon vanilla extract, ¼ teaspoon almond extract, 1 cup chopped fresh figs, 2 cups chopped fresh figs, ¼ cup packed brown sugar, ¼ cup water, 1 tablespoon lemon juice', 'Preheat oven to 350 degrees F (175 degrees C). Spray two 8-inch round cake pans with vegetable oil spray.
INSERT INTO public.recipes VALUES (205, 'Fig Preserves', '10 mins', '1 hrs 20 mins', '2 hrs 30 mins', '64', '64 servings', '16 cups fresh figs, 1 tablespoon baking soda, 12 cups boiling water, 8 cups white sugar, 4 cups water, 1  lemon, sliced', 'In a large mixing bowl place figs and sprinkle with baking soda. Pour the boiling water over the figs and soak for 1 hour.
INSERT INTO public.recipes VALUES (206, 'Elegant Fig Appetizers with Goat Cheese and Almonds', '15 mins', '3 mins', '18 mins', '12', '24 appetizers', '12  fresh figs, halved, 4 ounces herbed goat cheese (chevre), 24  almonds, 1 tablespoon honey, 2 teaspoons balsamic vinegar', 'Preheat the oven broiler for high heat.
INSERT INTO public.recipes VALUES (207, 'Fig and Arugula Salad', '15 mins', NULL, '15 mins', '4', '4 servings', '4 cups arugula, 8  fresh figs, quartered, ¼ cup grated Parmesan cheese, 2 tablespoons toasted pine nuts, 2 tablespoons honey, 2 tablespoons balsamic vinegar', 'Toss arugula, figs, Parmesan cheese, and pine nuts together in a large bowl.
INSERT INTO public.recipes VALUES (208, 'Fig Smoothie', '5 mins', NULL, '5 mins', '2', '2 servings', '2  frozen bananas, peeled and chopped, 6  fresh figs, halved, ¾ cup milk, ¾ cup orange juice', 'Place the bananas, figs, milk, and orange juice into a blender. Cover, and puree until smooth. Pour into glasses to serve.', '4.4', 'https://www.allrecipes.com/recipe/190893/fig-smoothie/', '/Breakfast and Brunch/Drinks/', 'Total Fat 3g 4%, Saturated Fat 1g 7%, Cholesterol 7mg 2%, Sodium 42mg 2%, Total Carbohydrate 78g 28%, Dietary Fiber 9g 31%, Total Sugars 58g, Protein 6g, Vitamin C 61mg 304%, Calcium 190mg 15%, Iron 1mg 7%, Potassium 1191mg 25%', 'Prep Time: 5 mins, Total Time: 5 mins, Servings: 2, Yield: 2 servings', 'https://www.allrecipes.com/thmb/uAiq8BMgn7zW-BDv_Hwc6ecUa8w=/1500x0/filters:no_upscale():max_bytes(150000):strip_icc()/6863836-fig-smoothie-Allrecipes-Magazine-4x3-1-fd36de8f9b304832adad243a42ead48e.jpg');
INSERT INTO public.recipes VALUES (235, 'Fig and Rosemary Cranberry Sauce', '10 mins', '15 mins', '35 mins', '8', '8 servings', '1 cup water, 1 cup dark brown sugar, 2 teaspoons maple extract, 1 (12 ounce) package fresh cranberries, 10  dried Mission figs, chopped, 1 (5 inch) fresh rosemary sprig', 'Bring water, brown sugar, and maple extract to a boil in a non-reactive saucepan. Add cranberries and figs. Cook over medium heat, stirring frequently, until slightly thickened, about 5 minutes. Add rosemary and cook until sauce is thickened, about 5 minutes more.
INSERT INTO public.recipes VALUES (209, 'Strawberry Fig Preserve', '10 mins', '5 mins', '30 mins', '48', '6 half pints', '3 cups mashed fresh ripe figs, 3 cups white sugar, 2 (3 ounce) packages strawberry flavored gelatin (such as Jell-O®), 6  half pint canning jars with lids and rings', 'Heat figs, sugar, and strawberry gelatin together in a saucepan over medium-high heat; bring to a rolling boil. Cook fig mixture, stirring frequently, for 4 minutes; remove from heat.
INSERT INTO public.recipes VALUES (210, 'Fig and Onion Spread', '10 mins', '35 mins', '45 mins', '24', '24 servings', '¼ cup olive oil, 1 large red onion, chopped, 2 cups chopped fresh Black Mission figs, ¼ cup aged balsamic vinegar, 2 tablespoons white sugar, or to taste', 'Heat olive oil in a saucepan over medium heat; stir onion in the hot oil. Reduce heat to medium-low, cover saucepan, and cook, stirring occasionally, until onion is softened and caramel-colored, 20 to 25 minutes.
INSERT INTO public.recipes VALUES (211, 'Figs and Toasted Almonds Brie', '10 mins', '25 mins', '35 mins', '12', '12 servings', '½ cup brown sugar, 2 tablespoons water, 6  fresh figs, stemmed and quartered, 1 (14 ounce) round 4 1/4-inch diameter round Brie cheese, ½ cup toasted almonds, ½ teaspoon vanilla extract', 'Preheat oven to 325 degrees F (165 C).
INSERT INTO public.recipes VALUES (212, 'Fresh Fig Oatmeal Muffins', '20 mins', '20 mins', '40 mins', '24', '24 muffins', '1 ¾ cups fresh figs, 3  eggs, ½ cup applesauce, ½ cup white sugar, ½ cup brown sugar, 1 cup all-purpose flour, ¼ cup flax seed meal, 1 teaspoon ground cinnamon, 1 teaspoon pumpkin pie spice, 1 teaspoon baking soda, ½ teaspoon baking powder, 1 ¼ cups old-fashioned oats', 'Preheat oven to 350 degrees F (175 degrees C). Grease 24 muffin cups or line with paper muffin liners.
INSERT INTO public.recipes VALUES (213, 'Fresh Figs and Chicken Thighs in Shallot-Balsamic Reduction', '15 mins', '30 mins', '45 mins', '8', '8 chicken thighs', '8  skinless, boneless chicken thighs,   salt and ground black pepper to taste, 3 tablespoons extra-virgin olive oil, 10  fresh figs, stemmed and quartered, 1 ½ cups chicken broth, ¼ cup balsamic vinegar, 1 large shallot, sliced lengthwise, 1 tablespoon minced fresh rosemary,   fresh rosemary, for garnish', 'Pat chicken thighs dry and season both sides with salt and pepper.
INSERT INTO public.recipes VALUES (214, 'Fig and Honey Jam with Walnuts', '15 mins', '1 hrs 35 mins', '1 hrs 50 mins', '48', '48 servings', '4 cups Mission figs, stemmed, 2 cups honey, 1 cup water, ¼ cup butter, 3 tablespoons lemon juice, 2 teaspoons ground cinnamon, 1 ½ teaspoons vanilla extract, 1 teaspoon ground cloves, 1 teaspoon salt, ½ teaspoon grated fresh ginger , 1 cup chopped walnuts', 'Combine figs, honey, water, butter, lemon juice, cinnamon, vanilla extract, cloves, salt, and ginger in a large pot; bring to a boil. Reduce heat and simmer until figs are soft, about 1 hour 15 minutes.
INSERT INTO public.recipes VALUES (215, 'Fresh Fig Freezer Jam', '15 mins', NULL, '30 mins', '96', '96 servings', '5 cups white sugar, 3 cups stemmed and coarsely chopped figs, ⅓ cup lemon juice, 2 (3 ounce) pouches liquid pectin (such as CERTO®)', 'Mix sugar and figs together in a large glass or plastic bowl; set aside for sugar to slightly dissolve, stirring occasionally, about 15 minutes.
INSERT INTO public.recipes VALUES (216, 'Fig-Ricotta Cake', '20 mins', '45 mins', '1 hrs 25 mins', '10', '1 9-inch loaf cake', '  nonstick cooking spray, 1 ½ cups all-purpose flour, 2 ½ teaspoons baking powder, 1 teaspoon salt, 1 ½ cups whole-milk ricotta cheese, 1 cup white sugar, ¾ cup unsalted butter, softened, 3 large eggs, at room temperature, 1 ½ teaspoons almond extract, 4  fresh figs, chopped into 1/2-inch pieces, 1 tablespoon all-purpose flour, 4  fresh fig slices, 1 teaspoon confectioners'' sugar, or as needed (Optional)', 'Preheat the oven to 350 degrees F (175 degrees C). Spray a 9-inch loaf pan with nonstick cooking spray.
INSERT INTO public.recipes VALUES (217, 'August Fig Cookies', '20 mins', '15 mins', '35 mins', '12', '2 dozen cookies', '½ cup butter, softened, ½ cup white sugar, ¼ cup golden brown sugar, 1  egg, 1 teaspoon vanilla extract, 1 ½ cups all-purpose flour, ½ teaspoon baking powder, ¼ teaspoon ground cinnamon, ⅛ teaspoon salt, ½ cup fresh figs, halved, ½ cup chopped walnuts', 'Preheat oven to 375 degrees F (190 degrees C). Grease two baking sheets.
INSERT INTO public.recipes VALUES (218, 'Fig and Prosciutto Appetizer Bites', '10 mins', NULL, '2 hrs 10 mins', '25', '25 bites', '4 ounces honey-flavored goat cheese, 3 ounces prosciutto, 2  fresh figs, thinly sliced, 2 leaves fresh basil, cut into thin strips, ⅛ teaspoon freshly ground black pepper', 'Place goat cheese on a sheet of plastic wrap. Top with another sheet of plastic wrap and use a rolling pin to flatten into a 4x8-inch rectangle.
INSERT INTO public.recipes VALUES (249, 'Tomato Watermelon Salad', '20 mins', NULL, '20 mins', '12', NULL, '1 large seedless watermelon, cut into 1-inch cubes, 4  tomatoes, cut into 1-inch dice, 1 cup crumbled feta cheese, 1 large sweet onion, thinly sliced, 12  mint leaves, sliced thinly, ¼ cup olive oil, 2 tablespoons white balsamic vinegar, 1 pinch coarse salt, or to taste, 1 pinch ground black pepper, or to taste', 'Gently mix watermelon, tomatoes, feta cheese, onion, and mint in a large bowl.
INSERT INTO public.recipes VALUES (219, 'Fig Cake I', '30 mins', '1 hrs 30 mins', '2 hrs', '18', '1 - 9x13 inch pan', '2 cups all-purpose flour, 1 teaspoon ground cinnamon, 1 teaspoon ground cloves, 1 teaspoon ground nutmeg, 1 teaspoon baking soda, 1 teaspoon baking powder, ½ teaspoon salt, 1 ½ cups white sugar, 1 cup butter, 3  eggs, beaten, 1 cup buttermilk, 1 cup chopped fresh figs, 1 cup chopped pecans, ½ cup butter, ½ cup white sugar, ½ cup evaporated milk, ½ teaspoon baking soda', 'Preheat oven to 300 degrees F (150 degrees C). Grease a 9x13 inch pan. Mix together the flour, cinnamon, cloves, nutmeg, 1 teaspoon baking soda, baking powder and salt. Set aside.
INSERT INTO public.recipes VALUES (220, 'Blueberry-Fig Jam', '15 mins', '25 mins', '50 mins', '12', '1 jar', '¼ cup blueberries, 2 cups quartered fresh figs, ¾ cup white sugar, ½ cup water, 1 tablespoon lime juice, ½ teaspoon balsamic vinegar', 'Mash blueberries with a fork in a small bowl. Transfer to a 3 1/2-quart pot. Add figs, sugar, water, lime juice, and balsamic vinegar. Lightly pulse with an immersion blender until mostly smooth, with some chunks remaining for texture.
INSERT INTO public.recipes VALUES (221, 'Pear-Fig Salad', '20 mins', NULL, '20 mins', '4', '4 servings', '2 cups torn romaine lettuce, 6  fresh figs, quartered, 1  large ripe but firm pear, peeled and thinly sliced, ¼ cup toasted pecans, chopped, ¼ cup shredded Gruyere cheese, 1 small red onion, thinly sliced, 3 tablespoons extra-virgin olive oil, 3 tablespoons balsamic vinegar,   salt and freshly ground black pepper to taste', 'Combine romaine lettuce, figs, pear, pecans, Gruyere cheese, and onion in a large bowl. Drizzle evenly with olive oil and vinegar. Season with salt and pepper. Toss lightly and serve.', '4.0', 'https://www.allrecipes.com/recipe/263850/pear-fig-salad/', '/Salad/', 'Total Fat 18g 23%, Saturated Fat 4g 18%, Cholesterol 9mg 3%, Sodium 73mg 3%, Total Carbohydrate 27g 10%, Dietary Fiber 5g 18%, Total Sugars 20g, Protein 4g, Vitamin C 9mg 43%, Calcium 131mg 10%, Iron 1mg 4%, Potassium 340mg 7%', 'Prep Time: 20 mins, Total Time: 20 mins, Servings: 4, Yield: 4 servings', 'https://www.allrecipes.com/thmb/j-Ojnpdt88BmZ6VRBHjMMjZ2s_Q=/1500x0/filters:no_upscale():max_bytes(150000):strip_icc()/6909110-a1ff47e920ca46b2b6d92d4d1e5e62a3.jpg');
INSERT INTO public.recipes VALUES (222, 'Stuffed Leg of Lamb with Balsamic-Fig-Basil Sauce', '50 mins', '1 hrs', '2 hrs', '6', '1 lamb roast', '½ cup coarsely chopped prunes, ¼ cup currants, 2 tablespoons creme de cassis liqueur, 1 ½ tablespoons minced fresh rosemary, 1 ½ tablespoons minced fresh thyme, ½ teaspoon ground coriander, 1 ¼ teaspoons salt, 1 teaspoon freshly ground black pepper, 1 (4 pound) boneless leg of lamb, rolled and tied, ½ cup chopped roasted and salted almonds, 2 tablespoons chopped fresh mint, 3 cloves garlic, cut into thirds, 2 tablespoons olive oil, ½ cup balsamic vinegar, 5 tablespoons butter, 3 tablespoons honey, ⅓ cup thinly sliced, stemmed Calimyrna figs, 5 teaspoons chopped fresh basil, 6 leaves mint, 6 leaves basil', 'Preheat oven to 400 degrees F (200 degrees C).
INSERT INTO public.recipes VALUES (223, 'Bourbon Fig Compote', '10 mins', '30 mins', '40 mins', '12', '12 servings', '7 ounces dried Mission figs, diced, ¼ cup white sugar, ¼ cup bourbon whiskey, ¼ cup balsamic vinegar, 1 tablespoon lemon juice, 1 pinch salt', 'Combine figs, sugar, whiskey, balsamic vinegar, lemon juice, and salt in a small saucepan; bring to a boil. Reduce heat and simmer until liquid reduces by half, about 30 minutes. Cool before serving.', '4.8', 'https://www.allrecipes.com/recipe/232620/bourbon-fig-compote/', '/Appetizers and Snacks/Dips and Spreads Recipes/', 'Total Fat 0g 0%, Sodium 3mg 0%, Total Carbohydrate 16g 6%, Dietary Fiber 2g 7%, Total Sugars 14g, Protein 1g, Vitamin C 1mg 4%, Calcium 26mg 2%, Iron 0mg 2%, Potassium 124mg 3%', 'Prep Time: 10 mins, Cook Time: 30 mins, Total Time: 40 mins, Servings: 12, Yield: 12 servings', 'https://www.allrecipes.com/thmb/ZjGJdXQfMcpW-H8VTXAXpDwtKms=/1500x0/filters:no_upscale():max_bytes(150000):strip_icc()/4205750-3803477ec2bb4aa8a1a96501a9c399b9.jpg');
INSERT INTO public.recipes VALUES (250, 'Melon Smoothie', '5 mins', NULL, '5 mins', '4', '4 servings', '¼  cantaloupe - peeled, seeded and cubed, ¼  honeydew melon - peeled, seeded and cubed, 1  lime, juiced, 2 tablespoons sugar', 'In a blender, combine cantaloupe, honeydew, lime juice and sugar. Blend until smooth. Pour into glasses and serve.', '4.5', 'https://www.allrecipes.com/recipe/32450/melon-smoothie/', '/Drinks Recipes/Smoothie Recipes/', 'Total Fat 0g 0%, Saturated Fat 0g 1%, Sodium 20mg 1%, Total Carbohydrate 18g 7%, Dietary Fiber 1g 5%, Total Sugars 16g, Protein 1g, Vitamin C 32mg 160%, Calcium 14mg 1%, Iron 0mg 2%, Potassium 292mg 6%', 'Prep Time: 5 mins, Total Time: 5 mins, Servings: 4, Yield: 4 servings', 'https://www.allrecipes.com/thmb/fYxUu453NnTl5dAZlweMmvFPLrM=/1500x0/filters:no_upscale():max_bytes(150000):strip_icc()/14238-3677ab96cf16492b8e21311e73edd729.jpg');
INSERT INTO public.recipes VALUES (224, 'Chicken Tenders with Balsamic-Fig Sauce', '15 mins', '20 mins', '35 mins', '4', '4 servings', '1 pound chicken tenders,   salt and ground black pepper to taste, ¼ cup all-purpose flour, 2 tablespoons olive oil, 1 tablespoon butter', 'Season chicken with salt and pepper on both sides and lightly coat with flour, shaking off excess.
INSERT INTO public.recipes VALUES (225, 'Fabulous Fig Scones', '15 mins', '30 mins', '45 mins', '8', '8 scones', '1 cup whole wheat pastry flour, ½ cup old-fashioned rolled oats, 2 teaspoons baking powder, ½ teaspoon salt, ¼ cup canola oil, 1  egg, lightly beaten, ¼ cup honey, ¼ cup white sugar, 1 cup diced fresh figs', 'Preheat oven to 350 degrees F (175 degrees C). Line a baking sheet with parchment paper and lightly sprinkle flour over paper.
INSERT INTO public.recipes VALUES (226, 'Burrata Bruschetta with Figs', '10 mins', '5 mins', '15 mins', '4', '4 servings', '12  Black Mission figs, halved lengthwise, 2 tablespoons balsamic vinegar, 2 tablespoons extra virgin olive oil, 6 ounces Burrata cheese, thickly sliced, 6 (1/2 inch thick) slices Italian bread, toasted,   sea salt and ground black pepper to taste', 'Preheat an outdoor grill for high heat, and lightly oil the grate.
INSERT INTO public.recipes VALUES (227, 'Fig Cake II', '30 mins', '1 hrs 15 mins', '1 hrs 45 mins', '16', '1 to 10 - inch tube pan', '2 cups all-purpose flour, 1 teaspoon salt, 1 teaspoon ground cinnamon, 1 teaspoon ground nutmeg, 1 teaspoon ground allspice, 1 teaspoon vanilla extract, 3  eggs, 1 ½ cups white sugar, 1 cup vegetable oil, 1 cup buttermilk, 1 teaspoon baking soda, 2 teaspoons hot water, 1 teaspoon vanilla extract, 1 cup canned figs with juice, chopped, 1 cup chopped pecans, 1 cup white sugar, ½ cup buttermilk, ½ teaspoon baking soda, 1 tablespoon light corn syrup, ¼ cup butter, 1 teaspoon vanilla extract', 'Preheat oven to 350 degrees F (175 degrees C). Grease and flour a 10 inch tube pan. Sift together the flour, salt, cinnamon, nutmeg and allspice. Set aside. Dissolve 1 teaspoon baking soda in 2 teaspoons hot water; set aside.
INSERT INTO public.recipes VALUES (228, 'Delish Black Mission Figs!', '10 mins', '5 mins', '15 mins', '4', '4 servings', '8  Black Mission figs, cut in half, ¼ cup crumbled goat cheese, or as needed, 3 slices prosciutto, trimmed of all fat and cut into strips, 2 tablespoons honey, or to taste', 'Set oven rack about 6 inches from the heat source and preheat the oven''s broiler.
INSERT INTO public.recipes VALUES (230, 'Black Mission Fig Preserves', '15 mins', '20 mins', '1 hrs', '18', '1 13-ounce jar', '2 cups fresh Black Mission figs, stemmed and halved, 1 cup white sugar, 1 cup water, 1 tablespoon lime juice, ½ teaspoon ground cinnamon, ¼ teaspoon ground ginger, ⅛ teaspoon ground white pepper, 1  13-ounce jar with lid', 'Scoop the flesh from the figs with a spoon and discard the peels. Bring sugar and water to a boil in a large saucepan over medium-high heat, stirring until sugar has dissolved. Stir in fig pulp, lime juice, cinnamon, ginger, and white pepper. Cook, stirring often, until a candy thermometer reads 210 degrees F (100 degrees C), about 20 minutes.
INSERT INTO public.recipes VALUES (231, 'Summer Sweet Smoothies', '5 mins', NULL, '5 mins', '4', '4 servings', '2 cups cranberry juice, 2 cups strawberries, 1 cup blueberries, 1 cup watermelon chunks, 1  banana, 2  fresh figs', 'Process the cranberry juice, strawberries, blueberries, watermelon, banana, and figs in a blender until smooth and creamy. Enjoy immediately or keep cool in refrigerator.', '4.8', 'https://www.allrecipes.com/recipe/215581/summer-sweet-smoothies/', '/Drinks Recipes/Smoothie Recipes/Strawberry/', 'Total Fat 1g 1%, Saturated Fat 0g 1%, Sodium 5mg 0%, Total Carbohydrate 42g 15%, Dietary Fiber 4g 14%, Total Sugars 32g, Protein 2g, Vitamin C 106mg 528%, Calcium 30mg 2%, Iron 1mg 4%, Potassium 362mg 8%', 'Prep Time: 5 mins, Total Time: 5 mins, Servings: 4, Yield: 4 servings', 'https://www.allrecipes.com/thmb/l8m4T-6zTUsn8Oni8B1P1wguLjI=/1500x0/filters:no_upscale():max_bytes(150000):strip_icc()/664244-f870eee08fab43ee950ee74ebeca917a.jpg');
INSERT INTO public.recipes VALUES (232, 'Zurie''s Fresh Fig Compote Over Cream Cheese', '10 mins', '10 mins', '25 mins', '8', '8 servings', '⅔ cup brown sugar, ¼ cup water, 1 pinch salt, 2 cups fresh figs, stemmed and quartered, 1 teaspoon vanilla extract, 1 (8 ounce) package cream cheese', 'Heat a saucepan over medium heat; add brown sugar, water, salt, and figs. Cook and stir until sugar has dissolved and figs have softened, about 10 minutes. Remove from heat; stir in vanilla extract. Cool for 5 minutes.
INSERT INTO public.recipes VALUES (233, 'Fig and Ricotta Crostini', '25 mins', '10 mins', '35 mins', '12', '24 crostini', '1  French baguette, cut into 1/2 inch slices, 1 (15 ounce) container ricotta cheese, 12  fresh basil leaves, cut into thin strips, 8  black mission figs, cut in quarters , ¼ cup aged balsamic vinegar', 'Preheat oven to 375 degrees F (190 degrees C).
INSERT INTO public.recipes VALUES (234, 'Risotto with Fresh Figs and Prosciutto', '10 mins', '20 mins', '30 mins', '4', '4 servings', '4 cups vegetable broth, 6 tablespoons butter, divided, 1 tablespoon extra-virgin olive oil, 1  green onion, finely chopped, 1 (12 ounce) package Arborio rice, ½ cup dry white wine, 14  small fresh figs, divided, 4 thin slices  prosciutto, finely chopped, 1 cup grated Pecorino-Romano cheese, or to taste', 'Heat vegetable stock in a large pot and keep warm over low heat.
INSERT INTO public.recipes VALUES (251, 'Watermelon Milkshake', '10 mins', NULL, '10 mins', '4', '4 servings', '1 ½ cups diced watermelon, 2 ¼ cups milk, 2 teaspoons white sugar', 'Process the watermelon and milk together in a blender until smooth. Add the sugar and blend another 10 seconds to incorporate. Serve immediately.', '4.0', 'https://www.allrecipes.com/recipe/215579/watermelon-milkshake/', '/Drinks Recipes/Smoothie Recipes/', 'Total Fat 3g 4%, Saturated Fat 2g 9%, Cholesterol 11mg 4%, Sodium 57mg 2%, Total Carbohydrate 13g 5%, Dietary Fiber 0g 1%, Total Sugars 12g, Protein 5g, Vitamin C 5mg 25%, Calcium 165mg 13%, Iron 0mg 1%, Potassium 271mg 6%', 'Prep Time: 10 mins, Total Time: 10 mins, Servings: 4, Yield: 4 servings', 'https://www.allrecipes.com/thmb/V6D_OFJ-7s5q6o8HgHa2DDEoO-E=/1500x0/filters:no_upscale():max_bytes(150000):strip_icc()/687260-4d95ba38deaa4581b073d186f2fd4be6.jpg');
INSERT INTO public.recipes VALUES (236, 'Mamma K''s Fig Preserves with a Twist', '30 mins', '35 mins', '2 hrs 5 mins', '36', '3 1-pint jars', '3 cups fresh figs, stemmed and quartered, 3 cups white sugar, 1  lemon, thinly sliced and seeds removed, 2 (3 ounce) packages strawberry-flavored Jell-O® mix, 3  1-pint canning jars with lids and rings, or as needed', 'Mix figs, sugar, lemon slices, and strawberry gelatin in a large pot. Let stand for 1 hour. Bring to a boil and cook over medium heat, stirring often to prevent burning, until foam has disappeared and the preserves are thickened, 25 to 40 minutes.
INSERT INTO public.recipes VALUES (237, 'Prosciutto-Wrapped Chicken with Figs and Goat Cheese', '20 mins', '45 mins', '1 hrs 10 mins', '6', '6 servings', '2 tablespoons olive oil, divided, 2  shallots, chopped, 1 clove garlic, minced, 1 teaspoon chopped fresh thyme, ¼ teaspoon salt, ¼ teaspoon ground black pepper, ¾ cup soft goat cheese, ½ cup shredded mozzarella cheese, ½ (8 ounce) package cream cheese, 6  figs, chopped, 1 tablespoon chopped fresh basil, 6  skinless, boneless chicken breast halves, 12  large, thin slices prosciutto', 'Preheat oven to 350 degrees F (175 degrees C). Spread 1 tablespoon olive oil on a baking sheet.
INSERT INTO public.recipes VALUES (238, 'Fresh Fig and Prosciutto Pasta Sauce', '10 mins', '10 mins', '20 mins', '4', '4 servings', '2 tablespoons butter, 2 tablespoons all-purpose flour, ½ teaspoon salt, 1 cup milk, 6 thin slices  prosciutto, cut into thin strips, 6  fresh figs, stemmed and quartered, 1 tablespoon lemon zest, ¼ teaspoon lemon pepper seasoning, or to taste', 'Heat butter in a saucepan over low heat; gradually stir flour into melted butter until smooth and bubbly, 2 to 4 minutes. Add salt; stir to combine. Remove from heat; gradually stir in milk until smooth.
INSERT INTO public.recipes VALUES (239, 'Momma''s Fresh Fig Preserves', '15 mins', '3 hrs 5 mins', '15 hrs 35 mins', '40', '5 half pint-sized jars', '6 cups quartered fresh figs, 3 cups white sugar, 1 tablespoon lemon juice, ½ teaspoon grated fresh ginger , ½ teaspoon ground cinnamon, ½ teaspoon vanilla extract, ¼ teaspoon salt', 'Bring figs, sugar, lemon juice, ginger, cinnamon, vanilla, and salt to a simmer in a saucepan over medium heat. Reduce heat and cook at a low simmer, stirring every 20 minutes, until desired consistency, 3 to 4 hours.
INSERT INTO public.recipes VALUES (240, 'Fig and Whiskey Cupcakes', '30 mins', '15 mins', '1 hrs 45 mins', '12', '12 cupcakes', '½ cup fresh figs, finely chopped, ½ cup whiskey, 1 ⅔ cups all-purpose flour, 1 teaspoon baking powder, ½ teaspoon baking soda, ½ teaspoon salt, ½ teaspoon ground cinnamon, ¼ teaspoon cream of tartar, ⅛ teaspoon ground cloves, ½ cup white sugar, ⅓ cup vegetable oil, ¼ cup brown sugar, 1  egg, ½ cup buttermilk, 1 teaspoon vanilla extract', 'Soak figs in whiskey in a bowl for at least 30 minutes.
INSERT INTO public.recipes VALUES (241, 'Figs with Caramelized Onions and Goat Cheese', '15 mins', '45 mins', '1 hrs', '40', '40 crackers', '¼ cup canola oil, 1 large yellow onion, cut into thin slices, ¼ cup small dried Mission figs, 6 ounces goat cheese, softened, 40  crackers', 'Heat a skillet over medium heat; add oil. Add onion; cook and stir until onion has softened and turned translucent, about 5 minutes. Reduce heat to low and continue cooking and stirring until onion is very tender and dark brown, about 40 minutes more. Remove from heat and cool.
INSERT INTO public.recipes VALUES (242, 'Arugula-Fig Salad with Creamy Gorgonzola', '15 mins', NULL, '15 mins', '6', '6 servings', '¼ cup extra-virgin olive oil, 2 tablespoons lemon juice, 1 tablespoon orange blossom water, or more to taste, 1 tablespoon orange juice, 1 teaspoon grated orange zest', 'Combine olive oil, lemon juice, orange blossom water, orange juice, and orange zest in a glass jar and shake dressing until emulsified.
INSERT INTO public.recipes VALUES (243, 'Sweet and Spicy Fig Compote', '5 mins', '20 mins', '25 mins', '6', '6 servings', '1 cup sliced dried figs, 1 cup red wine, ¼ cup white sugar, 1 tablespoon honey, 1 teaspoon red pepper flakes, or to taste, 1 pinch salt', 'Heat figs, red wine, sugar, honey, red pepper flakes, and salt in a small saucepan over medium heat. Simmer until wine is reduced and thickened, about 20 minutes, stirring occasionally.', '5.0', 'https://www.allrecipes.com/recipe/230512/sweet-and-spicy-fig-compote/', '/Appetizers and Snacks/Spicy/', 'Total Fat 1g 1%, Saturated Fat 0g 1%, Sodium 6mg 0%, Total Carbohydrate 34g 12%, Dietary Fiber 4g 15%, Total Sugars 29g, Protein 1g, Vitamin C 1mg 4%, Calcium 52mg 4%, Iron 1mg 6%, Potassium 298mg 6%', 'Prep Time: 5 mins, Cook Time: 20 mins, Total Time: 25 mins, Servings: 6, Yield: 6 servings', 'https://www.allrecipes.com/thmb/n0mjE3Li4XKAJ25mIrKc_CbXjuc=/1500x0/filters:no_upscale():max_bytes(150000):strip_icc()/1087434-2161480a2be34e4e8f8d7b9cbc9f6d3d.jpg');
INSERT INTO public.recipes VALUES (244, 'Slow Cooker Cranberry Fig Pork', '10 mins', '4 hrs 10 mins', '4 hrs 20 mins', '4', '4 servings', '4 (4 ounce) pork chops, 1 cup frozen cranberries, 3  canned figs, 1/4 cup juice reserved, ½ cup apple juice, 2 tablespoons brown sugar, ¼ teaspoon salt, ¼ teaspoon ground black pepper, ¼ teaspoon dried rosemary', 'Heat a skillet over medium-high heat. Sear pork chops in the hot skillet until lightly browned, about 1 minute per side. Transfer seared pork chops to the slow cooker.
INSERT INTO public.recipes VALUES (245, 'Dolce Pesca (Sweet Peaches)', '15 mins', '15 mins', '30 mins', '8', '8 servings', '4  fresh figs, ½ cup pine nuts, 4  peaches, halved and pitted, ¼ cup white sugar, 1 cup white wine, ½ cup brandy', 'Preheat an oven to 375 degrees F (190 degrees C). Line a baking sheet with foil.
INSERT INTO public.recipes VALUES (246, 'Simple Cantaloupe Smoothie', '10 mins', NULL, '10 mins', '1', '1 smoothie', '1 cup vanilla yogurt (such as Dannon® Light and Fit®), ½ cup orange juice, ½ cup sliced cantaloupe, 4  ice cubes, crushed, or as needed', 'Blend yogurt, orange juice, cantaloupe, and ice cubes in a blender until smooth, about 30 seconds.', '4.7', 'https://www.allrecipes.com/recipe/238339/simple-cantaloupe-smoothie/', '/Drinks Recipes/Smoothie Recipes/Orange/', 'Total Fat 4g 4%, Saturated Fat 2g 10%, Cholesterol 12mg 4%, Sodium 178mg 8%, Total Carbohydrate 53g 19%, Dietary Fiber 1g 3%, Total Sugars 50g, Protein 14g, Vitamin C 93mg 467%, Calcium 442mg 34%, Iron 1mg 3%, Potassium 999mg 21%', 'Prep Time: 10 mins, Total Time: 10 mins, Servings: 1, Yield: 1 smoothie', 'https://www.allrecipes.com/thmb/q3ceS6BCGDtgXIXkhnUxwtC32lk=/1500x0/filters:no_upscale():max_bytes(150000):strip_icc()/1221609-2f1489bc6ec24e39842465b25a76ee23.jpg');
INSERT INTO public.recipes VALUES (277, 'Watermelon Cooler Slushy', '10 mins', NULL, '10 mins', '5', '5 cups', '4 cups cubed seedless watermelon, 10  ice cubes, ⅓ cup fresh lime juice, ¼ cup white sugar, ⅛ teaspoon salt', 'Place watermelon and ice into a blender. Pour in lime juice, sugar, and salt. Blend until smooth.', '4.4', 'https://www.allrecipes.com/recipe/141371/watermelon-cooler-slushy/', '/Drinks Recipes/Slushie Recipes/', 'Total Fat 0g 0%, Sodium 61mg 3%, Total Carbohydrate 21g 7%, Dietary Fiber 1g 2%, Total Sugars 18g, Protein 1g, Vitamin C 15mg 74%, Calcium 12mg 1%, Iron 0mg 2%, Potassium 156mg 3%', 'Prep Time: 10 mins, Total Time: 10 mins, Servings: 5, Yield: 5 cups', 'https://www.allrecipes.com/thmb/nSNR9z9ZI8sJ89yzkIMoGAwL7Jc=/1500x0/filters:no_upscale():max_bytes(150000):strip_icc()/watermelon-cooler-slushy-4x3-1-2000-4938c16097054f4282181864a149a707.jpg');
INSERT INTO public.recipes VALUES (252, 'Simple Watermelon Sorbet', '10 mins', '5 mins', '2 hrs 45 mins', '8', '8 servings', '1 cup white sugar, ½ cup water, ¼ cup lemon juice, 3 cups cubed seeded watermelon', 'Combine sugar, water, and lemon juice in a saucepan over medium heat; cook and stir until sugar is dissolved, about 5 minutes. Remove from heat and refrigerate until cooled, about 30 minutes.
INSERT INTO public.recipes VALUES (253, 'Refreshing Cucumber Watermelon Salad', '15 mins', NULL, '25 mins', '10', '10 servings', '1 small red onion, halved and sliced into thin half-moons, 2 tablespoons lime juice, or more to taste, 2 tablespoons extra-virgin olive oil, 1  seedless watermelon, cut into cubes, 3  baby cucumbers, seeded and cut into cubes, 1 cup crumbled feta cheese, ½ cup mint leaves, sliced thinly', 'Mix red onion with lime juice in a bowl; set side to marinate at least 10 minutes. Stir olive oil into mixture.
INSERT INTO public.recipes VALUES (254, 'Refreshing Watermelon Salad', '20 mins', NULL, '20 mins', '15', '15 servings', '3 tablespoons lime juice, 1 cup sliced red onion, cut lengthwise, 15 cups cubed watermelon, 3 cups cubed English cucumber, 1 (8 ounce) package feta cheese, crumbled, ½ cup chopped fresh cilantro,   cracked black pepper,   sea salt', 'In a small bowl, pour lime juice over red onions. Allow to marinate while assembling the salad.
INSERT INTO public.recipes VALUES (255, 'Watermelon Basil Salad', '20 mins', NULL, '50 mins', '4', '4 servings', '¼ cup basil leaves, 4 cups 1/2-inch cubes watermelon, 2 teaspoons lemon juice, ¼ teaspoon kosher salt, ¼ teaspoon chili powder', 'Stack basil leaves on top of each other and roll tightly into a log. Slice lengthwise into thin ribbons.
INSERT INTO public.recipes VALUES (256, 'Spicy Watermelon', '10 mins', NULL, '10 mins', '2', '2 servings', '¼ teaspoon ground cumin, ¼ teaspoon ground coriander, ¼ teaspoon chili powder, ¼ teaspoon salt, ⅛ teaspoon cayenne pepper, 2 cups cubed seeded watermelon, ½  lime, juiced', 'Mix cumin, coriander, chili powder, salt, and cayenne pepper together in a bowl.
INSERT INTO public.recipes VALUES (257, 'Watermelon Sherbet', '15 mins', '5 mins', '4 hrs 50 mins', '8', '1 quart', '4 cups diced seedless watermelon, 1 cup white sugar, 3 tablespoons lemon juice, 1 dash salt, ¼ cup cold water, 1 (.25 ounce) envelope unflavored gelatin, 1 cup chilled heavy cream', 'Combine the watermelon, sugar, lemon juice, and salt in a large mixing bowl; stir to coat evenly. Cover the bowl with plastic wrap and refrigerator for 30 minutes.
INSERT INTO public.recipes VALUES (258, 'Watermelon Caprese Appetizer', '30 mins', NULL, '30 mins', '4', '4 servings', '3 sprigs fresh basil, stems removed, 1 small watermelon, fruit removed with a melon baller, 1 (8 ounce) package fresh mozzarella cheese, cut into small pieces, 2 tablespoons olive oil, 2 tablespoons balsamic vinegar,   salt and ground black pepper to taste', 'Trim basil leaves into small circles about 1 inch in diameter.
INSERT INTO public.recipes VALUES (259, 'Watermelon Soup', '15 mins', NULL, '2 hrs 15 mins', '3', '3 servings', '4 cups cubed seeded watermelon, 2 tablespoons lemon juice, 1 tablespoon chopped fresh mint, 1 tablespoon honey', 'Blend watermelon, lemon juice, mint, and honey in a blender until smooth. Refrigerate 2 hours before serving.', '4.6', 'https://www.allrecipes.com/recipe/228229/watermelon-soup/', '/Soups, Stews and Chili Recipes/Soup Recipes/Fruit Soup Recipes/', 'Total Fat 0g 0%, Sodium 2mg 0%, Total Carbohydrate 22g 8%, Dietary Fiber 1g 3%, Total Sugars 19g, Protein 1g, Vitamin C 21mg 107%, Calcium 16mg 1%, Iron 1mg 3%, Potassium 244mg 5%', 'Prep Time: 15 mins, Additional Time: 2 hrs, Total Time: 2 hrs 15 mins, Servings: 3, Yield: 3 servings', 'https://www.allrecipes.com/thmb/6t6q-UzMXIz-SB3Lb8sVWeK3LtQ=/1500x0/filters:no_upscale():max_bytes(150000):strip_icc()/869962-71aaac6737c44265ac4885e6049701a5.jpg');
INSERT INTO public.recipes VALUES (260, 'Watermelon and Feta Salad with Arugula and Spinach', '20 mins', NULL, '20 mins', '4', '8 cups', '3 tablespoons extra-virgin olive oil, 2 teaspoons white balsamic vinegar, ½ teaspoon kosher salt, 2 cups arugula, 2 cups baby spinach leaves, 1 cup thinly sliced red onion, 1 cup grape tomatoes, halved, ½ cup crumbled feta cheese, 2 cups bite sized watermelon chunks', 'Whisk the olive oil, white balsamic vinegar, and salt together in a small bowl; set aside.
INSERT INTO public.recipes VALUES (261, 'Watermelon Feta Salad', '20 mins', NULL, '20 mins', '8', NULL, '3 tablespoons olive oil, 2 teaspoons white balsamic vinegar, ½ teaspoon kosher salt, 8 ounces grape tomatoes, halved, 3 cups arugula, 1 cup sliced red onion, 2 pounds watermelon, cubed, 4 ounces feta cheese, cut into 1/4-inch cubes', 'Whisk olive oil, vinegar, and salt together in a large mixing bowl. Add tomatoes, arugula, and red onion; toss to coat. Gently stir in watermelon and feta cheese to serve.', '4.7', 'https://www.allrecipes.com/recipe/215044/watermelon-feta-salad/', '/Salad/Fruit Salad Recipes/', 'Total Fat 8g 11%, Saturated Fat 3g 15%, Cholesterol 13mg 4%, Sodium 284mg 12%, Total Carbohydrate 12g 5%, Dietary Fiber 1g 4%, Total Sugars 9g, Protein 3g, Vitamin C 15mg 77%, Calcium 96mg 7%, Iron 1mg 3%, Potassium 237mg 5%', 'Prep Time: 20 mins, Total Time: 20 mins, Servings: 8', 'https://www.allrecipes.com/thmb/Cy2GfFn1GdlsFhkX5m4funEP-J8=/1500x0/filters:no_upscale():max_bytes(150000):strip_icc()/watermelon-feta-salad-france-c-4x3-1-2000-9fce019e8ca24116b29835f41ac8fb1f.jpg');
INSERT INTO public.recipes VALUES (262, 'Jewel''s Watermelon Margaritas', '10 mins', '5 mins', '45 mins', '4', '4 servings', '½ cup white sugar, ½ cup water, 3 strips orange zest, 2 cups cubed seeded watermelon, ¾ cup white tequila, ¼ cup lime juice, 1 pinch salt or sugar for rimming glasses, 1  lime, cut into wedges, 2 cups crushed ice, or as needed', 'Bring 1/2 cup sugar, water, and orange zest in a small saucepan to boil, stirring constantly. Simmer until sugar is dissolved, about 3 minutes. Remove simple syrup from heat and allow to cool completely.
INSERT INTO public.recipes VALUES (263, 'Watermelon Preserves', '15 mins', '14 hrs 10 mins', '14 hrs 25 mins', '40', '5 cups', '2 pounds watermelon, 3 cups white sugar, 3  lemons - rinsed, sliced and seeded', 'Remove the green rind from watermelon, and dice white part into small cubes, leaving the red flesh mostly intact. Remove seeds.
INSERT INTO public.recipes VALUES (264, 'Herb Watermelon Feta Salad', '20 mins', NULL, '20 mins', '12', '12 servings', '½ large chilled seedless watermelon, cut into 1-inch cubes, 1 small red onion, sliced, 1 cup thinly sliced fresh basil leaves, 1 cup chopped fresh cilantro, ½ cup minced fresh mint leaves, 2  limes, juiced, 1 (4 ounce) package crumbled feta cheese, 3 tablespoons olive oil, 2 tablespoons balsamic vinegar, or more to taste,   salt and ground black pepper to taste', 'Gently toss watermelon, onion, basil, cilantro, mint, lime juice, feta cheese, olive oil, balsamic vinegar, salt, and black pepper together in a large bowl.', '4.7', 'https://www.allrecipes.com/recipe/222512/herb-watermelon-feta-salad/', '/Salad/Fruit Salad Recipes/', 'Total Fat 6g 8%, Saturated Fat 2g 10%, Cholesterol 8mg 3%, Sodium 112mg 5%, Total Carbohydrate 31g 11%, Dietary Fiber 2g 8%, Total Sugars 25g, Protein 4g, Vitamin C 36mg 182%, Calcium 89mg 7%, Iron 1mg 7%, Potassium 480mg 10%', 'Prep Time: 20 mins, Total Time: 20 mins, Servings: 12, Yield: 12 servings', 'https://www.allrecipes.com/thmb/1BR8gIPQAcDhR4ydhkXrAj-FjNc=/1500x0/filters:no_upscale():max_bytes(150000):strip_icc()/4527045-da962325de534ed6b02542bb4fbfbbd2.jpg');
INSERT INTO public.recipes VALUES (265, 'Polynesian Watermelon Drink (''Otai)', '15 mins', NULL, '15 mins', '12', '12 servings', '1  seedless watermelon, halved and sliced, 3 cups water, 1 (15.25 ounce) can crushed pineapple, 1 (12 fluid ounce) can evaporated milk, ½ cup shredded coconut, 2 tablespoons white sugar, or to taste, ½  lime, juiced', 'Grate watermelon with a fork from the rind into a large bowl, leaving no large chunks. Stir water, pineapple, evaporated milk, and coconut into the grated watermelon. Add sugar; stir until dissolved. Squeeze lime juice into the watermelon mixture.', '4.3', 'https://www.allrecipes.com/recipe/222172/polynesian-watermelon-drink-otai/', '/Drinks Recipes/Punch Recipes/Non-Alcoholic Punch Recipes/', 'Total Fat 4g 5%, Saturated Fat 2g 12%, Cholesterol 9mg 3%, Sodium 48mg 2%, Total Carbohydrate 41g 15%, Dietary Fiber 2g 8%, Total Sugars 35g, Protein 5g, Vitamin C 35mg 176%, Calcium 117mg 9%, Iron 1mg 6%, Potassium 574mg 12%', 'Prep Time: 15 mins, Total Time: 15 mins, Servings: 12, Yield: 12 servings', 'https://www.allrecipes.com/thmb/xUHKbJSrgk0EoruEUDA7jzdwk-w=/1500x0/filters:no_upscale():max_bytes(150000):strip_icc()/1228621-2ccb9fcfc4e2436696f29e2ff5414e57.jpg');
INSERT INTO public.recipes VALUES (266, 'Summer Fruit Salad with a Lemon, Honey, and Mint Dressing', '20 mins', NULL, '1 hrs 20 mins', '8', '8 servings', '4 cups cubed seeded watermelon, 2 cups sliced fresh strawberries, 2 large  fresh peaches, cut into cubes, 2 large  nectarines, cut into cubes, 1  red Anjou pear, cut into cubes, 1 cup seedless grapes, halved, 2  lemons, juiced, ¼ cup minced fresh mint (chocolate mint preferred), ½  lemon, zested, 1 tablespoon honey (fireweed honey preferred)', 'Combine watermelon, strawberries, peaches, nectarines, pear, and grapes in a large mixing bowl.
INSERT INTO public.recipes VALUES (267, '100% Fruit "Cake"', '30 mins', NULL, '30 mins', '8', '8 servings', '1  seedless watermelon, 2 cups strawberries, hulled and sliced, 1  cantaloupe - seeded, peeled, and sliced (Optional), 1  fresh pineapple - peeled, cored, and sliced (Optional)', 'To create the base tier of the cake, cut 3 slices of watermelon, 1 to 2 inches thick, crossways through the center of the melon. Trim the rind from the watermelon slices, and place the largest slice onto a cake plate. Alternate layering sliced strawberries, slices of cantaloupe, and slices of fresh pineapple; follow with the second-largest watermelon slice. Repeat once more to make a layered fruit stack that looks like a cake.
INSERT INTO public.recipes VALUES (268, 'Watermelon Lime Agua Fresca', '15 mins', NULL, '1 hrs 15 mins', '10', '2 1/2 quarts', '8 cups water, divided, 5 cups peeled, cubed, and seeded watermelon, ½ cup white sugar, or more to taste, ⅓ cup lime juice, or more to taste', 'Combine 1 cup water, watermelon, and sugar in a blender; process until smooth. Pour into a large pitcher; stir in lime juice and remaining 7 cups water. Taste; adjust sugar or lime juice. Refrigerate until chilled, about 1 hour.', '4.6', 'https://www.allrecipes.com/recipe/246117/watermelon-lime-agua-fresca/', '/Drinks Recipes/Juice Recipes/', 'Total Fat 0g 0%, Sodium 7mg 0%, Total Carbohydrate 16g 6%, Dietary Fiber 0g 1%, Total Sugars 15g, Protein 1g, Vitamin C 9mg 43%, Calcium 12mg 1%, Iron 0mg 1%, Potassium 97mg 2%', 'Prep Time: 15 mins, Additional Time: 1 hrs, Total Time: 1 hrs 15 mins, Servings: 10, Yield: 2 1/2 quarts', 'https://www.allrecipes.com/thmb/s-4VmOHbQXLMlU3gzbUZVTRs-Lo=/1500x0/filters:no_upscale():max_bytes(150000):strip_icc()/5472590-0a8182a4b4024c42a8e48c48bbf9483d.jpg');
INSERT INTO public.recipes VALUES (269, 'Watermelon Goat Cheese Salad', '10 mins', NULL, '10 mins', '8', '8 serving', '¼ cup extra-virgin olive oil, 2 tablespoons lemon juice, 2 tablespoons red wine vinegar, ¼ teaspoon salt,   Ground pepper, to taste, 4 cups spring mix, 4 cups seedless watermelon, diced, ½ (4 ounce) log Montchevre® honey goat cheese , ½ cup hazelnuts, chopped', 'Whisk together olive oil, lemon juice, vinegar, salt, and pepper.
INSERT INTO public.recipes VALUES (270, 'Watermelon Fruit Bowl', '30 mins', '5 mins', '50 mins', '20', '20 servings', '1  large watermelon, 1  cantaloupe, halved and seeded, 1  honeydew melon, halved and seeded, 2 (15 ounce) cans mandarin oranges, drained, 2 (20 ounce) cans pineapple chunks, drained, 2 cups halved fresh strawberries, 2 cups seedless grapes , ½ cup water, ¼ cup white sugar, 2 tablespoons grated lemon zest', 'With a large, sharp knife, remove the top 1/4 section of the watermelon. With a melon baller, scoop flesh from inside of watermelon, removing as many seeds as possible. Leave 1/2 inch of flesh inside the shell of the watermelon. Scoop cantaloupe and honeydew in the same manner, removing as much flesh as possible, and discarding the rinds. Refrigerate fruits separately until ready to assemble.
INSERT INTO public.recipes VALUES (271, 'Watermelon and Cucumber Juice with a Spritz of Lime', '10 mins', NULL, '10 mins', '4', NULL, '½ (4 pound) watermelon, seeded and cubed, 4  cucumbers, trimmed and cut into chunks, 2  limes, juiced', 'Run watermelon and cucumber pieces through a juicer following the manufacturer''s instructions, and place the juice into a pitcher. Stir in lime juice, and serve.
INSERT INTO public.recipes VALUES (273, 'Watermelon Summer Salad', '30 mins', NULL, '30 mins', '6', '6 servings', '¾ cup halved, thinly sliced red onion, 1 tablespoon fresh lime juice, 1 ½ quarts seeded, cubed watermelon, ¾ cup crumbled feta cheese, ½ cup pitted black olive halves, 1 cup chopped fresh mint, 2 tablespoons olive oil', 'Place the onion slices in a small bowl with the lime juice. The acid of the lime will mellow the flavor of the raw onion. Let stand for 10 minutes.
INSERT INTO public.recipes VALUES (274, 'Cantaloupe Crunch', '15 mins', '45 mins', '1 hrs', '9', '1 9-inch pan', '3 cups cubed cantaloupe, ½ cup white sugar, ⅓ cup lemon juice, 2 tablespoons unsalted butter, melted, 1 tablespoon all-purpose flour, ½ teaspoon vanilla extract, ½ teaspoon ground cinnamon, ¼ teaspoon ground nutmeg, 1 (15.25 ounce) package white cake mix, ½ cup unsalted butter, melted', 'Preheat the oven to 350 degrees F (175 degrees C).
INSERT INTO public.recipes VALUES (275, 'Chewy Watermelon Rind Candy', '20 mins', '10 mins', '6 hrs 30 mins', '12', '12 servings', '1  watermelon rind, peeled, 4 cups water, 4 cups white sugar, ½ cup spearmint leaves, coarsely chopped, 1 tablespoon dried sweet basil', 'Cut watermelon rind into 2-inch long, 1-inch wide, and 1/2-inch thick pieces.
INSERT INTO public.recipes VALUES (276, 'Watermelon Margaritas', '10 mins', NULL, '10 mins', '4', '4 margaritas', '2 cups cubed seeded watermelon, 2 cups crushed ice, ⅓ cup tequila, ¼ cup white sugar, ¼ cup lime juice, 1 tablespoon vodka, 1 tablespoon orange liqueur ', 'Combine watermelon, ice, tequila, sugar, lime juice, vodka, and orange liqueur in a blender; blend well. Pour margaritas into glasses.', '4.5', 'https://www.allrecipes.com/recipe/257444/watermelon-margaritas/', '/Drinks Recipes/Cocktail Recipes/Tequila Drinks Recipes/', 'Total Fat 0g 0%, Sodium 2mg 0%, Total Carbohydrate 21g 8%, Dietary Fiber 0g 1%, Total Sugars 19g, Protein 1g, Vitamin C 11mg 54%, Calcium 8mg 1%, Iron 0mg 1%, Potassium 104mg 2%', 'Prep Time: 10 mins, Total Time: 10 mins, Servings: 4, Yield: 4 margaritas', 'https://www.allrecipes.com/thmb/t-Lg-F6E2TgUcBq1SORFxxWwU6I=/1500x0/filters:no_upscale():max_bytes(150000):strip_icc()/4487369-99ac34317610445a9637fd48d63ab150.jpg');
INSERT INTO public.recipes VALUES (279, 'Watermelon Rind Candy', '1 hrs', '15 mins', '10 days 1 hrs 15 mins', '100', '14 to 1 - pint jars', '2 ½ gallons water, 1 tablespoon salt, 2 gallons watermelon rind, white part only, cut into 1-inch cubes, 1 quart cider vinegar, 26 cups white sugar, divided, 28  whole cloves, 14 (3 inch) cinnamon stick', 'Bring the water and salt to a boil in a large, enamel stockpot over high heat. Add the watermelon rinds, and return to a boil. Cook for 20 minutes, then drain the rinds in a colander. Bring the vinegar to a boil with 6 cups of sugar. Remove from the heat, stir in the watermelon rinds, cover, and let stand overnight.
INSERT INTO public.recipes VALUES (280, 'Agua Fresca', '5 mins', NULL, '5 mins', '2', '2 servings', '1 ½ cups water, 3 slices cantaloupe, peeled and seeded, 6 tablespoons white sugar, 1 cup ice cubes', 'Place water, cantaloupe, and sugar in a blender; blend until smooth. Divide ice into two glasses and pour cantaloupe mixture over ice.', '4.6', 'https://www.allrecipes.com/recipe/230153/agua-fresca/', '/Cuisine/Latin American/Mexican/', 'Total Fat 0g 0%, Saturated Fat 0g 1%, Sodium 22mg 1%, Total Carbohydrate 46g 17%, Dietary Fiber 1g 3%, Total Sugars 45g, Protein 1g, Vitamin C 38mg 190%, Calcium 15mg 1%, Iron 0mg 1%, Potassium 279mg 6%', 'Prep Time: 5 mins, Total Time: 5 mins, Servings: 2, Yield: 2 servings', 'https://www.allrecipes.com/thmb/TiD-Hm1zuZSd2SuVu4Bj9cb13UU=/1500x0/filters:no_upscale():max_bytes(150000):strip_icc()/968743-cbb7407ec83a44e7acd996928f81fc6b.jpg');
INSERT INTO public.recipes VALUES (281, 'Watermelon-Cucumber Agua Fresca', '15 mins', NULL, '1 hrs 15 mins', '4', '4 agua frescas', '4 cups cubed seeded watermelon, 2 ½ cups water, divided, 1 cup peeled, chopped cucumber, ¼ cup freshly squeezed lime juice, 1 tablespoon white sugar, 1 teaspoon chili-lime seasoning (such as Tajin®), 1 wedge fresh lime,   ice as needed, 4 slices watermelon, 4 slices  lime', 'Place watermelon and 1 1/2 cups water in a blender, and process at high speed until combined, about 1 minute. Add cucumber, lime juice, and sugar; blend until smooth. Pour mixture through a fine mesh strainer and using a spatula, press to remove the pulp. Don''t skip this step, it''s important.
INSERT INTO public.recipes VALUES (282, 'Watermelon and Strawberry Lemonade', '15 mins', NULL, '15 mins', '8', '2 quarts', '8 cups cubed seeded watermelon, 1 cup fresh strawberries, halved, ½ cup fresh lemon juice, 1 cup white sugar, 2 cups water', 'Combine watermelon, strawberries, lemon juice, sugar, and water in a blender. Blend until smooth.', '4.4', 'https://www.allrecipes.com/recipe/143452/watermelon-and-strawberry-lemonade/', '/Drinks Recipes/Lemonade Recipes/', 'Total Fat 0g 0%, Sodium 4mg 0%, Total Carbohydrate 39g 14%, Dietary Fiber 1g 4%, Total Sugars 36g, Protein 1g, Vitamin C 31mg 154%, Calcium 17mg 1%, Iron 1mg 3%, Potassium 220mg 5%', 'Prep Time: 15 mins, Total Time: 15 mins, Servings: 8, Yield: 2 quarts', 'https://www.allrecipes.com/thmb/oRyW4Ph9XjouCPhTAAqS-b5Gd14=/1500x0/filters:no_upscale():max_bytes(150000):strip_icc()/5500158-1c4d896279be408e899bbf4e32fb00d9.jpg');
INSERT INTO public.recipes VALUES (283, 'Cantaloupe Bread with Praline Glaze', '15 mins', '1 hrs 5 mins', '2 hrs 20 mins', '20', '2 9x5-inch loaves', '2 cups white sugar, 2 cups cantaloupe - peeled, seeded and pureed, 1 cup vegetable oil, 3 large eggs, 1 tablespoon vanilla extract, 3 cups all-purpose flour, 2 teaspoons ground cinnamon, 1 teaspoon baking soda, 1 teaspoon salt, ¾ teaspoon baking powder, ½ teaspoon ground ginger', 'Preheat the oven to 325 degrees F (165 degrees C). Lightly grease and flour two 9x5-inch loaf pans.
INSERT INTO public.recipes VALUES (382, 'Peach Upside Down Cake I', '20 mins', '35 mins', '1 hrs', '9', '8 inch square cake', '¼ cup butter, ½ cup packed light brown sugar, ¼ teaspoon ground nutmeg, 5  fresh peaches - peeled, pitted and halved, ½ cup butter, softened, ½ cup white sugar, 1  egg, 1 ¼ cups all-purpose flour, 2 teaspoons baking powder, ½ teaspoon salt, ½ cup milk', 'Preheat oven to 375 degrees F (190 degrees C).
INSERT INTO public.recipes VALUES (285, 'Cantaloupe Pie I', '30 mins', '1 hrs', '1 hrs 30 mins', '8', '1 to 9 - inch pie', '1  cantaloupe, ½ cup white sugar, 8 tablespoons all-purpose flour, ¼ teaspoon salt, 3  egg yolks, 2 tablespoons water, 1 tablespoon butter, ¼ teaspoon butter flavored extract, 3  egg whites, ¼ teaspoon cream of tartar, 6 tablespoons white sugar, 1 (9 inch) pie crust, baked', 'Select a cantaloupe of good quality. Cut in half, remove seeds, and scoop pulp into a saucepan. Place pulp over medium heat until it comes to a gentle boil. Mash the cantaloupe as it heats. This should make about 2 cups of pulp.
INSERT INTO public.recipes VALUES (286, 'Avocado Watermelon Salad', '15 mins', NULL, '15 mins', '6', '12 cups', '4 cups cubed watermelon, 4 cups fresh baby spinach, torn, 2 large avocados - peeled, pitted, and diced, ¼ cup walnut oil, ¼ cup olive oil, 1  lime, juiced, ½ teaspoon sweet paprika', 'Combine watermelon, spinach, and avocados together in a bowl.
INSERT INTO public.recipes VALUES (287, 'Chilled Cantaloupe Soup', '20 mins', NULL, '1 hrs 20 mins', '6', '6 servings', '1  cantaloupe - peeled, seeded and cubed, 2 cups orange juice, 1 tablespoon fresh lime juice, ¼ teaspoon ground cinnamon', 'Peel, seed, and cube the cantaloupe.
INSERT INTO public.recipes VALUES (288, 'Watermelon and Blue Cheese Salad', '20 mins', NULL, '20 mins', '12', '12 servings', '½ cup light olive oil, ¼ cup white balsamic vinegar,   salt and ground black pepper to taste, 5 pounds watermelon, cut into bite-size cubes, 1 small sweet onion (such as Vidalia®), thinly sliced, 2 tablespoons chopped fresh mint, or more to taste, 6 ounces crumbled blue cheese', 'Whisk olive oil, vinegar, salt, and pepper together in a bowl until smooth.
INSERT INTO public.recipes VALUES (289, 'Watermelon Fire and Ice Salsa', '15 mins', NULL, '15 mins', '32', '4 cups', '3 cups chopped watermelon, ½ cup chopped green bell pepper, 2 tablespoons lime juice, 2 tablespoons chopped fresh cilantro, 1 tablespoon chopped green onions, 1 tablespoon chopped jalapeno pepper, ½ teaspoon garlic salt', 'In a large bowl, combine the watermelon, green bell pepper, lime juice, cilantro, green onions, jalapeno and garlic salt. Mix well and serve.', '4.6', 'https://www.allrecipes.com/recipe/20846/watermelon-fire-and-ice-salsa/', '/Appetizers and Snacks/Dips and Spreads Recipes/Salsa Recipes/Watermelon Salsa Recipes/', 'Sodium 29mg 1%, Total Carbohydrate 1g 0%, Dietary Fiber 0g 0%, Total Sugars 1g, Protein 0g, Vitamin C 4mg 18%, Calcium 2mg 0%, Iron 0mg 1%, Potassium 23mg 0%', 'Prep Time: 15 mins, Total Time: 15 mins, Servings: 32, Yield: 4 cups', 'https://www.allrecipes.com/thmb/Itc242nlB56Af5mz5M8tAWxXHfg=/1500x0/filters:no_upscale():max_bytes(150000):strip_icc()/665565-2a80c7d67cdb404db042e2f453113c3e.jpg');
INSERT INTO public.recipes VALUES (290, 'Chef John''s Watermelon Agua Fresca', '10 mins', NULL, '50 mins', '6', '1 2-quart pitcher', '½  seedless watermelon, 2 cups cold water, ½ cup white sugar, or to taste, ½ cup water', 'Scoop flesh from watermelon half and transfer watermelon to a blender. Add 2 cups cold water. Place a folded towel on blender lid and blend until liquefied, about 1 minute. Strain through a fine mesh strainer into a large bowl to remove fibers. Discard fibers left in strainer. Skim and discard excess foam from juice if desired.
INSERT INTO public.recipes VALUES (291, 'Green Gazpacho', '25 mins', NULL, '55 mins', '2', NULL, '2 cups diced honeydew melon, 1  English (seedless) cucumber, peeled and diced, 1 small onion, diced, 1  avocado - peeled, pitted, and chopped, 1  jalapeno pepper, seeded and coarsely chopped, 1 clove garlic, chopped, ¼ cup white balsamic vinegar, 1 tablespoon lime juice,   salt and freshly ground black pepper to taste', 'Blend honeydew melon, cucumber, onion, avocado, jalapeño pepper, garlic, white balsamic vinegar, lime juice, salt, and black pepper in a blender until smooth. Adjust seasonings if desired and chill before serving.', '4.8', 'https://www.allrecipes.com/recipe/223507/green-gazpacho/', '/Soups, Stews and Chili Recipes/Soup Recipes/Vegetable Soup Recipes/Gazpacho Recipes/', 'Total Fat 15g 19%, Saturated Fat 2g 11%, Sodium 47mg 2%, Total Carbohydrate 36g 13%, Dietary Fiber 10g 37%, Total Sugars 22g, Protein 5g, Vitamin C 56mg 281%, Calcium 44mg 3%, Iron 1mg 7%, Potassium 980mg 21%', 'Prep Time: 25 mins, Additional Time: 30 mins, Total Time: 55 mins, Servings: 2', 'https://www.allrecipes.com/thmb/0VjocwvF6fAcUHRF_5H8bob62H8=/1500x0/filters:no_upscale():max_bytes(150000):strip_icc()/861843-5cac12f200d74a3eaa49fef360d30615.jpg');
INSERT INTO public.recipes VALUES (292, 'Mojito Fruit Salad', '20 mins', NULL, '1 hrs 20 mins', '6', '6 servings', '1 cup cubed seeded watermelon, 1 cup seedless grapes , 1 cup cubed cantaloupe, 1 cup hulled and quartered strawberries, 1 cup peeled and quartered kiwi, 1 cup fresh blueberries, 3 sprigs fresh mint, 2 teaspoons white sugar, 3 tablespoons fresh lime juice', 'Mix the watermelon, grapes, cantaloupe, strawberries, and kiwi in a bowl with a tight-fitting lid; top with the blueberries.
INSERT INTO public.recipes VALUES (293, 'Watermelon Juice', '5 mins', NULL, '5 mins', '4', '4 cups', '2 cups diced seedless watermelon, 2 cups water, 1 tablespoon white sugar, or more to taste', 'Blend watermelon, water, and sugar in a blender until smooth.', '4.1', 'https://www.allrecipes.com/recipe/228280/watermelon-juice/', '/Drinks Recipes/Juice Recipes/', 'Total Fat 0g 0%, Sodium 4mg 0%, Total Carbohydrate 9g 3%, Dietary Fiber 0g 1%, Total Sugars 8g, Protein 1g, Vitamin C 6mg 31%, Calcium 9mg 1%, Iron 0mg 1%, Potassium 86mg 2%', 'Prep Time: 5 mins, Total Time: 5 mins, Servings: 4, Yield: 4 cups', 'https://www.allrecipes.com/thmb/xvW54TDL73gz_EoQ8VJt6yP4MMU=/1500x0/filters:no_upscale():max_bytes(150000):strip_icc()/1132046-5ac3764ad90a4714a7b9804762bdb25f.jpg');
INSERT INTO public.recipes VALUES (294, 'Watermelon Gin and Tonic', '5 mins', NULL, '5 mins', '1', '1 cocktail', '¼  lime, juiced, ¼ cup chopped seedless watermelon, ½ cup ice, or as needed, 2 tablespoons gin, or to taste, 2 cups tonic water', 'Squeeze lime into cocktail glass and drop lime wedge into the juice; add watermelon and enough ice to fill glass to top. Pour gin and tonic water over the watermelon and ice; stir.', '3.0', 'https://www.allrecipes.com/recipe/237801/watermelon-gin-and-tonic/', '/Drinks Recipes/Cocktail Recipes/Gin Drinks Recipes/', 'Total Fat 0g 0%, Sodium 58mg 3%, Total Carbohydrate 45g 16%, Dietary Fiber 0g 1%, Total Sugars 44g, Protein 0g, Vitamin C 6mg 30%, Calcium 9mg 1%, Iron 0mg 1%, Potassium 54mg 1%', 'Prep Time: 5 mins, Total Time: 5 mins, Servings: 1, Yield: 1 cocktail', 'https://www.allrecipes.com/thmb/YSf53f282q3OYbE0AqMfuBeGN-E=/1500x0/filters:no_upscale():max_bytes(150000):strip_icc()/8015285-d8659a26c8fb45588c15e31fcd3e2f77.jpg');
INSERT INTO public.recipes VALUES (295, 'Easy Watermelon Martini', '10 mins', NULL, '10 mins', '1', '1 martini', '1 slice watermelon, rind removed, ½ cup ice cubes, or as needed, 1 (1.5 fluid ounce) jigger vodka', 'Place watermelon in a cocktail shaker and crush with a muddler; add ice cubes and vodka. Cover shaker and shake well. Strain cocktail into a martini glass.', '4.4', 'https://www.allrecipes.com/recipe/234333/easy-watermelon-martini/', '/Drinks Recipes/Cocktail Recipes/Vodka Drinks Recipes/', 'Total Fat 0g 1%, Sodium 3mg 0%, Total Carbohydrate 22g 8%, Dietary Fiber 1g 4%, Total Sugars 18g, Protein 2g, Vitamin C 23mg 116%, Calcium 20mg 2%, Iron 1mg 4%, Potassium 321mg 7%', 'Prep Time: 10 mins, Total Time: 10 mins, Servings: 1, Yield: 1 martini', 'https://www.allrecipes.com/thmb/yAxLWD94pcthtGSDdZ_gGDWKRDY=/1500x0/filters:no_upscale():max_bytes(150000):strip_icc()/1153240-c722ca743fa04e53858831f3ee0063a5.jpg');
INSERT INTO public.recipes VALUES (296, 'Lemon Drop Shots', '10 mins', NULL, '10 mins', '1', '1 serving', '¾ fluid ounce vodka (such as Absolut®), ¾ fluid ounce lemon juice, 2 ½ teaspoons white sugar, divided, or more to taste, 1  lemon, cut into wedges', 'Combine vodka and lemon juice in a shot glass. Sprinkle 1/2 teaspoon sugar on top.
INSERT INTO public.recipes VALUES (297, 'Perfect Summer Fruit Salad', '25 mins', '5 mins', '3 hrs 30 mins', '10', NULL, '⅔ cup fresh orange juice, ⅓ cup fresh lemon juice, ⅓ cup packed brown sugar, ½ teaspoon grated orange zest, ½ teaspoon grated lemon zest, 1 teaspoon vanilla extract', 'For the sauce: Bring orange juice, lemon juice, brown sugar, orange zest, and lemon zest to a boil in a saucepan over medium-high heat. Reduce heat to medium-low and simmer until slightly thickened, about 5 minutes. Remove from heat and stir in vanilla extract. Set aside to cool.
INSERT INTO public.recipes VALUES (298, 'Perfect Lemon Curd', '10 mins', '5 mins', '15 mins', '12', NULL, '¾ cup fresh lemon juice, ¾ cup white sugar, ½ cup unsalted butter, cubed, 3 large eggs, 1 tablespoon grated lemon zest', 'Combine lemon juice, sugar, butter, eggs, and lemon zest in a 2-quart saucepan.
INSERT INTO public.recipes VALUES (299, 'Tom Collins Cocktail', '5 mins', NULL, '5 mins', '1', NULL, '2 ½ cups ice, divided, 2 fluid ounces gin, ¾ fluid ounce lemon juice, ½ fluid ounce simple syrup, 2 fluid ounces club soda, 1  lemon wedge', 'Fill a Collins glass with 1 1/2 cups ice; set aside in the freezer.
INSERT INTO public.recipes VALUES (300, 'Cornish Game Hens with Garlic and Rosemary', '20 mins', '1 hrs', '1 hrs 20 mins', '4', '4 hens', '4  Cornish game hens, 3 tablespoons olive oil, divided,   salt and pepper to taste, 1  lemon, quartered, 8 sprigs fresh rosemary, divided, 24 cloves garlic, ⅓ cup white wine, ⅓ cup low-sodium chicken broth', 'Preheat the oven to 450 degrees F (230 degrees C). Rub hens with 1 tablespoon olive oil; lightly season with salt and pepper. Stuff 1 lemon quarter and 1 rosemary sprig into each cavity. Place hens in a large, heavy roasting pan and arrange garlic cloves around them.
INSERT INTO public.recipes VALUES (301, 'Easy Garlic-Lemon Scallops', '10 mins', '5 mins', '15 mins', '6', NULL, '¾ cup butter, 3 tablespoons minced garlic, 2 pounds large sea scallops, 2 tablespoons fresh lemon juice, 1 teaspoon salt, ⅛ teaspoon pepper', 'Melt butter in a large skillet over medium heat. Stir in garlic and cook for a few seconds until fragrant.
INSERT INTO public.recipes VALUES (302, 'Greek-Style Lemon Roasted Potatoes', '15 mins', '1 hrs', '1 hrs 15 mins', '6', NULL, '3 pounds potatoes, peeled and cut into thick wedges, ⅓ cup olive oil, 2  lemons, juiced, 2 teaspoons salt, 1 teaspoon oregano, ½ teaspoon ground black pepper, 3 cups chicken broth', 'Preheat the oven to 400 degrees F (200 degrees C).
INSERT INTO public.recipes VALUES (304, 'Easy Lemon-Pepper Chicken Wings', '10 mins', '10 mins', '20 mins', '4', '12 chicken wings', '2 cups oil, or as needed, 2 tablespoons extra-virgin olive oil, 1 tablespoon lemon-pepper seasoning, 12  chicken wings', 'Heat oil in a deep-fryer or large saucepan to 375 degrees F (190 degrees C).
INSERT INTO public.recipes VALUES (305, 'Famous Chicken Française', '20 mins', '15 mins', '35 mins', '6', NULL, '1 large egg, beaten, 1 ½ medium lemons, juiced, divided, 1 cup all-purpose flour, 1 pinch garlic powder, 1 pinch paprika, 6  skinless, boneless chicken breast halves, 2 tablespoons butter, 1 (14.5 ounce) can chicken broth, 6 slices  lemon, for garnish, 2 sprigs fresh parsley, for garnish', 'Mix together egg and 1/3 of the lemon juice in a shallow dish or bowl. Mix together flour, garlic powder, and paprika in another shallow dish or bowl.
INSERT INTO public.recipes VALUES (306, 'Lemon Icing', '5 mins', NULL, '5 mins', '12', '2 cups', '½ cup unsalted butter, at room temperature, 2 tablespoons lemon juice, ½ teaspoon vanilla extract, 3 cups confectioners'' sugar', 'Combine butter, lemon juice, vanilla, and confectioners'' sugar in a large mixing bowl and beat until light and fluffy. Add more confectioners'' sugar, or lemon juice to adjust the consistency as needed.', '4.5', 'https://www.allrecipes.com/recipe/7770/lemon-icing/', '/Desserts/Frostings and Icings/Lemon/', 'Total Fat 8g 10%, Saturated Fat 5g 25%, Cholesterol 20mg 7%, Sodium 55mg 2%, Total Carbohydrate 32g 11%, Total Sugars 31g, Protein 0g, Vitamin C 1mg 6%, Calcium 3mg 0%, Potassium 6mg 0%', 'Prep Time: 5 mins, Total Time: 5 mins, Servings: 12, Yield: 2 cups', 'https://www.allrecipes.com/thmb/ZQiBMoN7SLQFR1Lobe2q-8Zf-Ic=/1500x0/filters:no_upscale():max_bytes(150000):strip_icc()/9152419-lemon-icing-Nishall-4x3-1-99babf88c6144fb18a41ea2013f4aa7e.jpg');
INSERT INTO public.recipes VALUES (307, 'The Best Lemon Vinaigrette', '10 mins', NULL, '10 mins', '8', '1 cup', '¼ cup red wine vinegar, 2 tablespoons Dijon mustard, 1 clove garlic, minced, 1 teaspoon dried oregano, ½ teaspoon kosher salt, ¼ teaspoon ground black pepper, ½ cup olive oil, 2 tablespoons fresh lemon juice', 'Whisk red wine vinegar, Dijon mustard, garlic, oregano, salt, and pepper together in a small bowl. Slowly stream olive oil into vinegar mixture, whisking continuously, until well combined. Add lemon juice and whisk to combine.
INSERT INTO public.recipes VALUES (308, 'Frog Eye Salad', '15 mins', '20 mins', '9 hrs 35 mins', '10', NULL, '1 ¾ cups unsweetened pineapple juice, 1 cup white sugar, 2  eggs, beaten, 2 tablespoons all-purpose flour, 2 ½ teaspoons salt, divided, 1 tablespoon lemon juice, 1 tablespoon vegetable oil, 1 (16 ounce) package acini di pepe pasta, 3 (11 ounce) cans mandarin oranges, drained, 2 (20 ounce) cans pineapple tidbits, drained, 1 (20 ounce) can crushed pineapple, drained, 1 (8 ounce) container frozen whipped topping, thawed, 1 cup miniature marshmallows, 1 cup shredded coconut', 'Combine pineapple juice, sugar, eggs, flour, and 1/2 teaspoon salt in a saucepan. Stir and cook over medium heat until thickened. Remove from heat; stir in lemon juice. Let cool to room temperature, about 1 hour.
INSERT INTO public.recipes VALUES (334, 'Lemon-Orange Orange Roughy', '10 mins', '5 mins', '15 mins', '4', NULL, '1 tablespoon olive oil, 4 (4 ounce) fillets orange roughy, 1  orange, juiced, 1  lemon, juiced, ½ teaspoon lemon pepper', 'Heat oil in a large skillet over medium-high heat.
INSERT INTO public.recipes VALUES (309, 'Air Fryer Lobster Tails with Lemon-Garlic Butter', '10 mins', '10 mins', '20 mins', '2', '2 lobster tails', '2 (4 ounce) lobster tails, 4 tablespoons butter, 1 teaspoon lemon zest, 1 clove garlic, grated,   salt and ground black pepper to taste, 1 teaspoon chopped fresh parsley, 2 wedges lemon', 'Preheat an air fryer to 380 degrees F (195 degrees C).
INSERT INTO public.recipes VALUES (310, 'Baked Fish Fillets', '10 mins', '20 mins', '30 mins', '6', NULL, '1 tablespoon vegetable oil, or to taste, 2 pounds mackerel fillets, 1 teaspoon salt, ⅛ teaspoon ground black pepper, ¼ cup butter, melted, 2 tablespoons lemon juice, ⅛ teaspoon ground paprika', 'Preheat the oven to 350 degrees F (175 degrees C). Grease a baking pan with vegetable oil.
INSERT INTO public.recipes VALUES (311, 'Vietnamese Grilled Lemongrass Chicken', '10 mins', '10 mins', '40 mins', '4', NULL, '2 tablespoons canola oil, 2 tablespoons finely chopped lemongrass, 1 tablespoon lemon juice, 2 teaspoons soy sauce, 2 teaspoons light brown sugar, 2 teaspoons minced garlic, 1 teaspoon fish sauce, 1 ½ pounds chicken thighs, or more to taste, pounded to an even thickness', 'Mix together canola oil, lemongrass, lemon juice, soy sauce, brown sugar, garlic, and fish sauce in a glass bowl until sugar is dissolved; add chicken and turn to coat in marinade.
INSERT INTO public.recipes VALUES (312, 'Orange Crush! Fresh Squeezed Orange and Vodka Cocktail', '10 mins', NULL, '10 mins', '1', '1 cocktail', '2 cups ice cubes, or as needed, 2 fluid ounces orange-flavored vodka, 1 fluid ounce triple sec liqueur, 2  Valencia oranges, juiced, 1 splash lemon-lime soda (such as Sprite®), 1 slice orange ', 'Fill a pint glass with ice cubes. Pour in orange-flavored vodka, triple sec, and orange juice, then top with lemon-lime soda. Mix well and garnish with orange slice.
INSERT INTO public.recipes VALUES (313, 'The Ultimate Berry Crumble', '15 mins', '40 mins', '1 hrs 25 mins', '8', '1 2-quart baking dish', '2 cups all-purpose flour, ¾ cup white sugar, ¾ teaspoon baking powder, ¼ teaspoon fine salt, ¾ cup frozen unsalted butter, 2 large egg yolks, 1 ½ teaspoons vanilla extract, 1 teaspoon apple cider vinegar, or as needed', 'Preheat the oven to 375 degrees F (190 degrees C).
INSERT INTO public.recipes VALUES (314, 'Mandarin Orange Cake', '20 mins', '1 hrs', '1 hrs 50 mins', '18', '1 9x13-inch cake', '1 (15.25 ounce) package yellow cake mix, 1 (11 ounce) can mandarin orange segments, 4 large eggs, 1 cup vegetable oil, 1 (20 ounce) can crushed pineapple with juice, 1 (8 ounce) container frozen whipped topping, thawed, 1 (3.5 ounce) package instant vanilla pudding mix', 'Preheat the oven to 350 degrees F (175 degrees C). Grease and flour a 9x13-inch baking pan.
INSERT INTO public.recipes VALUES (315, 'Warm Lemon, Honey, and Ginger Soother', '5 mins', NULL, '10 mins', '4', '4 cups', '¼ cup honey, or to taste, 1  lemon, juiced, 1 tablespoon finely grated ginger root, ¼ teaspoon ground cinnamon, 3 ½ cups boiling water', 'Place honey, lemon juice, ginger, and cinnamon in a teapot or 4-cup glass measuring beaker with spout. Pour boiling water over mixture; stir until honey is dissolved.
INSERT INTO public.recipes VALUES (316, 'Candied Lemon Peel', '10 mins', '1 hrs', '1 hrs 40 mins', '15', NULL, '3  lemons, 8 cups cold water, or as needed, 2 cups white sugar, or as needed', 'Cut lemons into slices about 1/4-inch thick and remove the fruit pulp. Cut the rings in half so the peels are in long strips.
INSERT INTO public.recipes VALUES (317, 'Baked Salmon in Foil', '20 mins', '20 mins', '40 mins', '6', NULL, '½ cup olive oil, 5 cloves cloves garlic, minced or pressed through a garlic press, 2 ½ tablespoons fresh lemon juice, or more to taste, 1 tablespoon brown sugar, 1 teaspoon dried oregano, 1 teaspoon dried thyme,   salt and freshly ground black pepper to taste,   aluminum foil, 1 teaspoon olive oil, 1 (3 pound) salmon fillet, ¼ cup chopped fresh parsley, 1  lemon, sliced', 'Preheat the oven to 375 degrees F (190 degrees C).
INSERT INTO public.recipes VALUES (318, 'Cranberry Orange Bread', '15 mins', '1 hrs', '1 hrs 25 mins', '8', '1 loaf', '2 cups flour, ¾ cup white sugar, 1 ½ teaspoons baking powder, ¾ teaspoon salt, ½ teaspoon baking soda, ¼ cup unsalted butter, cut into pieces and softened, ¾ cup orange juice, 1 tablespoon grated orange zest, 1 large egg, beaten, 1 cup chopped cranberries, ½ cup chopped walnuts (Optional)', 'Preheat the oven to 350 degrees F (175 degrees C). Grease an 8 1/2x4 1/2-inch loaf pan.
INSERT INTO public.recipes VALUES (319, 'Raspberry Jam without Pectin', '5 mins', '20 mins', '8 hrs 30 mins', '56', '7 8-ounce jars', '4 cups mashed raspberries, 4 cups white sugar, 1 tablespoon freshly squeezed lemon juice', 'Bring raspberries to a boil in a very large pot. Cook for 4 minutes. Add sugar and lemon juice; stir well. Bring back to a boil, stirring constantly. Cook for another 4 minutes.
INSERT INTO public.recipes VALUES (321, 'Lemon Chicken Orzo Soup', '20 mins', '1 hrs', '1 hrs 20 mins', '12', '6 quarts', '8 ounces orzo pasta, 1 teaspoon olive oil, 3 medium carrots, chopped, or more to taste, 3 ribs celery, chopped, 1 medium onion, chopped, 2 cloves garlic, minced, ½ teaspoon dried thyme, ½ teaspoon dried oregano,   salt and ground black pepper to taste, 1  bay leaf, 3 (32 ounce) cartons fat-free, low-sodium chicken broth, ½ cup fresh lemon juice, 1  lemon, zested, 8 ounces cooked chicken breast, chopped, 1 (8 ounce) package baby spinach leaves, 1  lemon, sliced for garnish (Optional), ¼ cup grated Parmesan cheese (Optional)', 'Bring a large pot of lightly salted water to a boil. Stir in orzo and return to a boil. Cook pasta uncovered until partially cooked through but not yet soft, about 5 minutes; drain and rinse with cold water until cooled completely.
INSERT INTO public.recipes VALUES (322, 'Simple Lemon Cake', '10 mins', '35 mins', '45 mins', '10', '1 9-inch square cake', '1 cup white sugar, ½ cup butter, 2 large eggs, 2 teaspoons vanilla extract, 1 ½ cups all-purpose flour, 1 ¾ teaspoons baking powder, ¾ cup milk, 1 tablespoon lemon zest, 1 tablespoon lemon juice', 'Preheat the oven to 350 degrees F (175 degrees C). Grease a 9-inch square baking pan.
INSERT INTO public.recipes VALUES (323, 'Greek Lemon Chicken Soup', '25 mins', '40 mins', '1 hrs 5 mins', '16', NULL, '8 cups chicken broth, ½ cup fresh lemon juice, ½ cup shredded carrots, ½ cup chopped onion, ½ cup chopped celery, 6 tablespoons chicken soup base, ¼ teaspoon ground white pepper, ¼ cup margarine, ¼ cup all-purpose flour, 8  egg yolks, 1 cup cooked white rice, 1 cup diced, cooked chicken meat, 16 slices  lemon', 'Combine chicken broth, lemon juice, carrots, onions, celery, soup base, and white pepper in a large pot. Bring to a boil over high heat, then reduce heat and simmer for 20 minutes.
INSERT INTO public.recipes VALUES (335, 'Olive Oil Roasted Eggplant with Lemon', '15 mins', '25 mins', '40 mins', '4', NULL, '1  large eggplant, 3 tablespoons extra virgin olive oil,   salt and pepper to taste, 2 tablespoons fresh lemon juice', 'Preheat the oven to 400 degrees F (200 degrees C). Line a baking sheet with parchment paper or lightly grease.
INSERT INTO public.recipes VALUES (324, 'Lemon Cookies from Scratch', '15 mins', '15 mins', '1 hrs', '20', '20 cookies', '1 cup white sugar, ½ cup butter, softened, 2 tablespoons fresh lemon zest, 2  eggs, 1 tablespoon fresh lemon juice, ½ teaspoon vanilla extract, 1 ¾ cups all-purpose flour, 1 ½ teaspoons baking powder, ¼ teaspoon salt, ¼ cup powdered sugar', 'Cream sugar, butter, and lemon zest together in a large bowl using an electric mixer until light and fluffy, about 3 minutes.
INSERT INTO public.recipes VALUES (325, 'Orange Gelatin Salad', '10 mins', NULL, '40 mins', '7', NULL, '1 (11 ounce) can mandarin oranges, drained, 1 (8 ounce) can crushed pineapple, drained, 1 (6 ounce) package orange flavored Jell-O® mix, 16 ounces cottage cheese, 8 ounces frozen whipped topping, thawed', 'Combine oranges, pineapple, and gelatin mix in a mixing bowl. Mix well and chill for 30 minutes.
INSERT INTO public.recipes VALUES (326, 'Quick and Easy Chicken', '15 mins', '30 mins', '45 mins', '4', NULL, '2 tablespoons olive oil, 1  onion, chopped, 4  skinless, boneless chicken breast halves, 3 tablespoons ketchup, 3 tablespoons white sugar, 2 tablespoons soy sauce, 2 tablespoons lemon juice, 1 teaspoon ground black pepper', 'Warm oil in a large skillet over medium heat. Sauté onion in oil until translucent, 3 to 4 minutes.
INSERT INTO public.recipes VALUES (327, 'Parchment Baked Salmon', '15 mins', '25 mins', '40 mins', '2', NULL, '1 (8 ounce) salmon fillet,   salt and ground black pepper to taste, ¼ cup chopped basil leaves,   olive oil cooking spray, 1  lemon, thinly sliced', 'Preheat the oven to 400 degrees F (200 degrees C). Move an oven rack to the lowest position.
INSERT INTO public.recipes VALUES (328, 'Pan-Fried Shrimp', '5 mins', '5 mins', '10 mins', '4', '1 pound shrimp', '8 tablespoons butter, divided, 1 pound peeled and deveined bay shrimp, 1 tablespoon lemon juice, divided, 1 pinch garlic salt, or to taste,   salt and ground black pepper to taste', 'Melt 6 tablespoons butter in a large skillet over high heat. Add shrimp; cook and stir in hot butter until browned, about 2 minutes. Reduce heat to medium-low.
INSERT INTO public.recipes VALUES (329, 'Chicken with Lemon-Caper Sauce', '10 mins', '20 mins', '30 mins', '2', NULL, '½ cup all-purpose flour, 1 pinch salt, 2 (6 ounce) skinless, boneless chicken breast halves, 2 tablespoons olive oil, ¼ cup dry white wine, ¼ cup lemon juice, ¼ cup cold unsalted butter, cut into pieces, 2 tablespoons capers, drained, 2  lemon wedges', 'Mix together flour and salt in a medium dish or resealable plastic bag. Coat chicken in flour mixture; shake off excess.
INSERT INTO public.recipes VALUES (330, 'Butterflied Roast Chicken with Lemon and Rosemary', '10 mins', '50 mins', '1 hrs', '6', NULL, '1 tablespoon olive oil, or as needed, 1 (3 pound) whole chicken, backbone removed,   kosher salt and ground black pepper to taste, 1  lemon, sliced into rounds, 4 sprigs fresh rosemary, ½ cup white wine', 'Preheat the oven to 400 degrees F (200 degrees C). Line a rimmed baking pan with aluminum foil. Place a rack on top of foil.
INSERT INTO public.recipes VALUES (331, 'Honey Lemon Tea', '5 mins', '5 mins', '10 mins', '1', NULL, '1 cup water, 2 teaspoons honey, 1 teaspoon fresh lemon juice, 1 teaspoon white sugar, or to taste', 'Pour water into a mug. Add honey and heat in the microwave for 1 minute 30 seconds.
INSERT INTO public.recipes VALUES (332, 'Lemon Cream Cheese Frosting', '15 mins', NULL, '15 mins', '15', '3 2/3 cups', '1 (8 ounce) package cream cheese, softened, ¼ cup butter, 2 tablespoons lemon juice, 2 teaspoons lemon zest, 1 teaspoon vanilla extract, 5 cups confectioners'' sugar', 'Beat cream cheese, butter, lemon juice, lemon zest, and vanilla together in a large bowl using an electric mixer until smooth and fluffy; gradually beat in confectioners'' sugar, 1 cup at a time, until desired consistency is reached.', '4.6', 'https://www.allrecipes.com/recipe/7556/lemon-cream-cheese-frosting/', '/Desserts/Frostings and Icings/Lemon/', 'Total Fat 8g 11%, Saturated Fat 5g 26%, Cholesterol 25mg 8%, Sodium 67mg 3%, Total Carbohydrate 41g 15%, Total Sugars 39g, Protein 1g, Vitamin C 1mg 7%, Calcium 14mg 1%, Iron 0mg 1%, Potassium 23mg 0%', 'Prep Time: 15 mins, Total Time: 15 mins, Servings: 15, Yield: 3 2/3 cups', 'https://www.allrecipes.com/thmb/2bI6q35h3UN-wU-mphHbPOwnEdI=/1500x0/filters:no_upscale():max_bytes(150000):strip_icc()/7569212-72c90c55c2794c8f8438b4122828988f.jpg');
INSERT INTO public.recipes VALUES (333, 'Lemon Cream Cheese Bars', '15 mins', '30 mins', '2 hrs 5 mins', '24', '1 9x13-inch baking dish', '  cooking spray, 2 (8 ounce) packages refrigerated crescent roll dough (such as Pillsbury® Recipe Creations®), divided, 2  lemons, zested and juiced, divided, 2 (8 ounce) packages cream cheese, softened, ½ cup white sugar, 2 tablespoons butter, melted, 3 tablespoons white sugar', 'Preheat the oven to 350 degrees F (175 degrees C). Line the bottom of a 9x13-inch baking dish with aluminum foil and coat with cooking spray.
INSERT INTO public.recipes VALUES (336, 'Wine Sauce for Seafood', '10 mins', '5 mins', '15 mins', '4', NULL, '3 tablespoons butter, 2 tablespoons minced shallots, 2 cloves garlic, minced, 1 teaspoon dried tarragon, ¼ teaspoon salt, ¼ teaspoon white pepper, ¼ cup white wine, 1  lemon, juiced, 1 tablespoon fresh parsley', 'Melt butter in a small saucepan over medium-low heat. Add shallots and garlic; cook and stir until shallots are translucent, about 3 minutes. Season with tarragon, salt, and white pepper.
INSERT INTO public.recipes VALUES (337, 'Easy Lemon Cookies', '10 mins', '10 mins', '20 mins', '36', '36 cookies', '1 (15.25 ounce) package lemon cake mix, 2 large eggs, ⅓ cup vegetable oil, 1 teaspoon lemon extract, ⅓ cup confectioners'' sugar for decoration', 'Preheat the oven to 375 degrees F (190 degrees C).
INSERT INTO public.recipes VALUES (338, 'Lemon Rosemary Salmon', '10 mins', '20 mins', '30 mins', '2', NULL, '1  lemon, thinly sliced, 4 sprigs fresh rosemary, 2  salmon fillets, bones and skin removed,   coarse salt to taste, 1 tablespoon olive oil, or as needed', 'Preheat the oven to 400 degrees F (200 degrees C).
INSERT INTO public.recipes VALUES (339, 'Sautéed Swiss Chard with Parmesan Cheese', '15 mins', '10 mins', '25 mins', '4', NULL, '2 tablespoons olive oil, 2 tablespoons butter, ½ small red onion, diced, 1 tablespoon minced garlic, 1 bunch Swiss chard, stems and center ribs cut out and chopped together, leaves coarsely chopped separately, ½ cup dry white wine, 1 tablespoon fresh lemon juice, or to taste, 2 tablespoons freshly grated Parmesan cheese, 1 pinch salt to taste', 'Heat olive oil and butter together in a large skillet over medium-high heat. Stir in onion and garlic and sauté until fragrant, about 30 seconds. Add chard stems and white wine; simmer until the stems begin to soften, about 5 minutes. Stir in the chard leaves and cook until just wilted.
INSERT INTO public.recipes VALUES (340, 'Old Fashioned Cocktail', '5 mins', NULL, '5 mins', '1', NULL, '1  sugar cube, 1 teaspoon water, 1 dash bitters, 2 fluid ounces whiskey (rye or bourbon), 1  lemon twist, ½ cup ice cubes, or as needed, 1  orange slice, for garnish, 1  maraschino cherry, for garnish', 'Muddle sugar cube, water, and bitters in an old fashioned glass for 1 minute. Pour in whiskey; stir for 1 minute.
INSERT INTO public.recipes VALUES (341, 'Lemon Meringue Cheesecake', '20 mins', '1 hrs 10 mins', '5 hrs 30 mins', '16', '1 9-inch cake', '2 cups shortbread cookie crumbs, ¼ cup melted butter', 'Preheat the oven to 325 degrees F (165 degrees C).
INSERT INTO public.recipes VALUES (342, 'Real Aioli', '15 mins', NULL, '15 mins', '6', '2/3 cup', '4 large cloves fresh garlic, peeled and sliced, ½ teaspoon kosher salt, or other course-grain salt, 1 teaspoon lemon juice, or more to taste, ½ cup light, extra-virgin olive oil, 1 teaspoon water to adjust texture, or more as needed', 'Place garlic slices in a mortar with kosher salt. Mash with the pestle into a fine paste, 4 or 5 minutes. Mix in lemon juice.
INSERT INTO public.recipes VALUES (343, 'Amazing Lemon Scones', '25 mins', '15 mins', '55 mins', '10', '10 scones', '3 cups all-purpose flour, ⅓ cup white sugar, 1 ½ teaspoons baking powder, 1 ½ teaspoons baking soda, ⅓ teaspoon salt, ¾ cup cold butter, cut into pieces, 9 tablespoons milk, 3 tablespoons lemon juice, 2 ½ teaspoons lemon zest, 1 ½ teaspoons vinegar', 'Preheat the oven to 350 degrees F (175 degrees C).
INSERT INTO public.recipes VALUES (344, 'Baked Banana Chips', '10 mins', '2 hrs', '2 hrs 15 mins', '2', NULL, '2  just-ripe bananas, sliced in 1/10-inch-thick rounds, or more as needed, 1 teaspoon lemon juice, or to taste', 'Preheat the oven to 225 degrees F (110 degrees C). Line a baking sheet with parchment paper.
INSERT INTO public.recipes VALUES (345, 'Lemon Garlic Chicken', '10 mins', '15 mins', '25 mins', '3', NULL, '2 tablespoons butter, 3  skinless, boneless chicken breast halves, 1 ½ teaspoons salt, 1 ½ teaspoons ground black pepper, 2 tablespoons garlic powder, divided, 1  lemon, juiced', 'Melt butter in a skillet over medium-high heat.
INSERT INTO public.recipes VALUES (346, 'Slow Cooker Lemon Garlic Chicken', '15 mins', '3 hrs 15 mins', '3 hrs 30 mins', '6', NULL, '1 teaspoon dried oregano, ½ teaspoon salt, ¼ teaspoon ground black pepper, 2 tablespoons butter, 2 pounds skinless, boneless chicken breast halves, ¼ cup water, 3 tablespoons fresh lemon juice, 2 cloves garlic, minced, 1 teaspoon chicken bouillon granules, 1 teaspoon chopped fresh parsley', 'Mix together oregano, salt, and pepper in a small bowl. Rub spice mixture all over chicken breasts.
INSERT INTO public.recipes VALUES (347, 'Pear Jam', '20 mins', '20 mins', '40 mins', '64', '8 half-pint jars', '4 ½ cups mashed ripe pears, ¼ cup lemon juice, 3 tablespoons powdered fruit pectin, 1 teaspoon ground cinnamon, ½ teaspoon ground cloves, ½ teaspoon ground allspice, ½ teaspoon ground nutmeg, 7 ½ cups white sugar, 1 teaspoon butter, 8  half-pint canning jars with lids and rings, or as needed', 'Mix pears, lemon juice, fruit pectin, cinnamon, cloves, allspice, and nutmeg in a large heavy pot; bring to a boil, stirring constantly. Add sugar all at once, stirring, and bring back to a full rolling boil. Boil for 1 minute. Mix in butter to settle foam.
INSERT INTO public.recipes VALUES (348, 'Refreshing Cucumber Lemonade', '15 mins', '5 mins', '50 mins', '4', NULL, '1 cup water, ½ cup white sugar, 1  cucumber, sliced, 6  lemons, juiced', 'Make the simple syrup: Combine water and sugar together in a saucepan over medium heat; heat until just about to boil and sugar has dissolved. Place in refrigerator until cool, about 30 minutes.
INSERT INTO public.recipes VALUES (349, 'Air-Fried Crumbed Fish', '10 mins', '15 mins', '25 mins', '4', '4 fillets', '1 cup dry bread crumbs, ¼ cup vegetable oil, 4  flounder fillets, 1  egg, beaten, 1  lemon, sliced', 'Preheat an air fryer to 350 degrees F (180 degrees C).
INSERT INTO public.recipes VALUES (350, 'Mom''s Peach Crisp', '15 mins', '30 mins', '45 mins', '8', '8 servings', '4 cups sliced fresh peaches, ½ cup all-purpose flour, ½ cup brown sugar, ½ cup cold butter, 1 teaspoon ground cinnamon, ¼ teaspoon salt, 1 cup rolled oats', 'Preheat oven to 350 degrees F (175 degrees C).
INSERT INTO public.recipes VALUES (351, 'Peach Pie the Old Fashioned Two Crust Way', '30 mins', '40 mins', '1 hrs 25 mins', '8', '1 9-inch pie', '1 (14.1 ounce) package pastry for a double-crust 9-inch pie, 1  egg, beaten, 5 cups sliced peeled peaches, 2 tablespoons lemon juice, 1 cup white sugar, ½ cup all-purpose flour, ½ teaspoon ground cinnamon, ¼ teaspoon ground nutmeg, ¼ teaspoon salt, 2 tablespoons butter', 'Preheat the oven to 450 degrees F (220 degrees C).
INSERT INTO public.recipes VALUES (352, 'Peach Dump Cake', '10 mins', '45 mins', '55 mins', '24', '1 9x13-inch cake', '2 (16 ounce) cans peaches in heavy syrup, 1 (18.25 ounce) package yellow cake mix, ½ cup butter, ½ teaspoon ground cinnamon, or to taste', 'Preheat the oven to 375 degrees F (190 degrees C).
INSERT INTO public.recipes VALUES (353, 'Quick and Easy Peach Cobbler', '10 mins', '30 mins', '50 mins', '12', '1 cobbler', '½ cup unsalted butter, melted, 1 cup self-rising flour, 1 cup white sugar, 1 cup milk, 2 (16 ounce) cans sliced peaches in heavy syrup', 'Preheat the oven to 350 degrees F (175 degrees C).
INSERT INTO public.recipes VALUES (354, 'Basic Fruit Smoothie', '10 mins', NULL, '10 mins', '4', NULL, '1 quart strawberries, hulled, 2  fresh peaches - peeled, pitted, and sliced, 1  banana, broken into chunks, 2 cups ice, 1 cup orange-peach-mango juice', 'Combine strawberries, peaches, and banana in a blender; blend until smooth. Add ice and pour in juice; blend again to desired consistency.
INSERT INTO public.recipes VALUES (355, 'Old Fashioned Peach Cobbler', '30 mins', '1 hrs 10 mins', '2 hrs 10 mins', '18', '1 9x13-inch dish', '2 ½ cups all-purpose flour, 4 tablespoons white sugar, divided, 1 teaspoon salt, 1 cup shortening, 1 large egg, ¼ cup cold water, 1 tablespoon butter, melted', 'Make crust: Sift together flour, 3 tablespoons sugar, and salt in a medium bowl. Work in shortening with a pastry blender until mixture resembles coarse crumbs. Whisk together egg and cold water in a small bowl. Sprinkle over flour mixture; work with hands to form dough into a ball. Wrap with plastic wrap and chill in the refrigerator for 30 minutes.
INSERT INTO public.recipes VALUES (356, 'Classic Bisquick Peach Cobbler', '10 mins', '50 mins', '1 hrs', '6', '1 8x8-inch dish', '1 cup Original Bisquick® mix, 1 cup milk, ½ teaspoon ground nutmeg, ½ cup butter or margarine, melted, 1 (29 ounce) can sliced peaches, drained, 1 cup sugar', 'Preheat the oven to 350 degrees F (175 degrees C).
INSERT INTO public.recipes VALUES (357, '3-Ingredient Cake Mix Cobbler', '5 mins', '50 mins', '55 mins', '8', NULL, '2 (15.25 ounce) cans peaches in light syrup, 1 (15.25 ounce) package yellow cake mix, ½ cup butter, melted', 'Preheat the oven to 350 degrees F (175 degrees C).
INSERT INTO public.recipes VALUES (358, 'Easy Batter Fruit Cobbler', '15 mins', '55 mins', '1 hrs 10 mins', '4', NULL, '4 tablespoons butter, ¾ cup all-purpose flour, ¾ cup sugar, 1 teaspoon baking powder, ¼ teaspoon salt, ¾ cup milk, 2 cups of sliced fresh peaches or nectarines, or whole blueberries, strawberries, raspberries, blackberries or a combination of fruits (or a 12-ounce package of frozen berries), 1 tablespoon sugar', 'Preheat the oven to 350 degrees F (175 degrees C). Adjust the oven rack to the upper-middle position.
INSERT INTO public.recipes VALUES (359, 'Peach Preserves', '15 mins', '35 mins', '50 mins', '64', '8 cups', '12  fresh peaches, pitted and chopped, 4 ½ cups white sugar, 1 (2 ounce) package dry pectin', 'Crush 1 cup of chopped peaches in the bottom of a large saucepan. Add remaining peaches and set the pan over medium-low heat. Bring to a low boil and cook until peaches become liquid with a few bits of peach left, about 20 minutes.
INSERT INTO public.recipes VALUES (360, 'Georgia Peach Homemade Ice Cream', '15 mins', NULL, '4 hrs 35 mins', '32', '1 gallon', '2 ½ pounds fresh peaches - peeled, pitted and chopped, 1 pint half-and-half cream, ½ cup white sugar, 1 (14 ounce) can sweetened condensed milk, 1 (12 fluid ounce) can evaporated milk, 1 teaspoon vanilla extract, 2 cups whole milk, or as needed', 'Working in batches, purée peaches with half-and-half and sugar in a blender or food processor.
INSERT INTO public.recipes VALUES (361, 'Easy Peach Cobbler', '10 mins', '30 mins', '40 mins', '6', '6 servings', '1 cup white sugar, ½ cup butter, room temperature, 1 cup self-rising flour, 1 cup milk, 1 (15 ounce) can peaches', 'Preheat oven to 350 degrees F (175 degrees C).
INSERT INTO public.recipes VALUES (362, 'Peach Muffins', '25 mins', '25 mins', '50 mins', '16', '16 muffins', '3 cups all-purpose flour, 1 tablespoon ground cinnamon, 1 teaspoon baking soda, 1 teaspoon salt, 1 ¼ cups vegetable oil, 3  eggs, lightly beaten, 2 cups white sugar, 2 cups peeled, pitted, and chopped peaches', 'Preheat oven to 400 degrees F (200 degrees C). Grease the bottoms and sides of 16 muffin cups, or line with paper liners.
INSERT INTO public.recipes VALUES (363, 'Peach Pie with Frozen Peaches', '25 mins', '1 hrs', '2 hrs 10 mins', '8', '1 peach pie', '2 sheets refrigerated pie crust, 2 teaspoons all-purpose flour, or as needed, 2 pounds sliced frozen peaches, ½ cup white sugar, 1 teaspoon lemon juice, ½ teaspoon ground cinnamon, ⅛ teaspoon salt, 3 tablespoons cornstarch, 1 large egg, beaten, 1 tablespoon white sugar, 1 tablespoon coarse sparkling sugar', 'Allow pie crusts to sit at room temperature about 15 minutes if recommended by manufacturer.
INSERT INTO public.recipes VALUES (369, 'Easy Fruit Cobbler', '15 mins', '1 hrs', '1 hrs 15 mins', '8', '1 to 9 - inch cobbler', '1 cup all-purpose flour, 2 teaspoons baking powder, ¾ cup white sugar, ¾ cup milk, ¼ cup butter, 2 cups sliced fresh peaches', 'Preheat oven to 325 degrees F (165 degrees C). Melt butter in a 9 x 9 inch baking dish.
INSERT INTO public.recipes VALUES (364, 'Award Winning Peaches and Cream Pie', '30 mins', '40 mins', '3 hrs 30 mins', '8', '1 to 10 - inch pie', '¾ cup all-purpose flour, ½ teaspoon salt, 1 teaspoon baking powder, 1 (3 ounce) package non-instant vanilla pudding mix, 3 tablespoons butter, softened, 1  egg, ½ cup milk, 1 (29 ounce) can sliced peaches, drained and syrup reserved, 1 (8 ounce) package cream cheese, softened, ½ cup white sugar, 1 tablespoon white sugar, 1 teaspoon ground cinnamon', 'Preheat oven to 350 degrees F (175 degrees C). Grease sides and bottom of a 10 inch deep-dish pie pan.
INSERT INTO public.recipes VALUES (365, 'Peaches and Cream, Literally', '10 mins', '10 mins', '3 hrs 20 mins', '4', '4 servings', '4  fresh peaches, or as needed, ⅓ cup white sugar, or to taste, ¼ cup water, 1 ½ cups heavy cream', 'Cut each peach in half along the crease, twist open, and remove the pit. Peel and slice. Cut slices in half to get roughly 2 cups of sliced peaches.
INSERT INTO public.recipes VALUES (366, 'Nana''s Southern Pickled Peaches', '30 mins', '40 mins', '13 hrs 10 mins', '40', '5 quarts', '4 cups white sugar, 1 cup white vinegar, 1 cup water, 2 tablespoons whole cloves, 4 pounds fresh clingstone peaches, blanched and peeled , 5 (3 inch) cinnamon sticks', 'Inspect 5 quart-sized jars for cracks and rings for rust, discarding any defective ones. Immerse in simmering water until peaches are ready. Wash new, unused lids and rings in warm soapy water.
INSERT INTO public.recipes VALUES (367, 'Blueberry and Peach Crisp', '15 mins', '30 mins', '45 mins', '9', '1 8-inch square dish', '2 (10 ounce) packages frozen sliced peaches(such as Cascadian Farm®), thawed and drained, 1 (10 ounce) package frozen blueberries(such as Cascadian Farm®), thawed and drained, 2 teaspoons lemon juice, 2 tablespoons all-purpose flour, 2 tablespoons white sugar', 'Preheat oven to 350 degrees F (175 degrees C).
INSERT INTO public.recipes VALUES (368, 'Easy Peach Cobbler with Canned Peaches', '10 mins', '45 mins', '55 mins', '16', '1 9x13-inch cobbler', '2 (29 ounce) cans sliced peaches in juice, 2 cups all-purpose flour, 1 cup sugar, ¾ cup unsalted butter, softened, 1 cup chopped pecans', 'Preheat the oven to 350 degrees F (175 degrees C). Pour peaches and juice into a 9x13-inch baking dish.
INSERT INTO public.recipes VALUES (370, 'Butter Biscuit Peach Cobbler', '15 mins', '1 hrs', '1 hrs 35 mins', '10', '10 servings', '2 (29 ounce) cans peaches, ¾ cup white sugar, ½ cup brown sugar, ½ cup unsalted butter, 1 tablespoon cornstarch, 1 teaspoon vanilla extract, 1 teaspoon ground cinnamon, ½ teaspoon nutmeg, 1 pinch salt, 1 (16 ounce) can refrigerated buttermilk biscuit dough (such as Pillsbury Grands!®), 1 pinch ground cinnamon, 1 pinch white sugar, 1 pinch ground nutmeg, 1  pastry for a 9-inch pie crust', 'Preheat oven to 350 degrees F (175 degrees C).
INSERT INTO public.recipes VALUES (371, 'Easy Peach Cobbler with Cake Mix', NULL, NULL, NULL, '12', '12 servings', '12  fresh peaches, pitted and sliced, 1 cup water, 1 cup white sugar, ½ teaspoon ground cinnamon, 1 (18.25 ounce) package white cake mix, 1 (8 ounce) package cream cheese, ½ cup butter', 'Preheat oven to 350 degrees F (175 degrees C).
INSERT INTO public.recipes VALUES (372, 'GA Peach Pound Cake', '20 mins', '1 hrs 10 mins', '1 hrs 30 mins', '16', '1 to 10 - inch tube pan', '1 cup butter or margarine, softened, 2 cups white sugar, 4  eggs, 1 teaspoon vanilla extract, 3 cups all-purpose flour, 1 teaspoon baking powder, ½ teaspoon salt, 2 cups fresh peaches, pitted and chopped', 'Preheat oven to 325 degrees F (165 degrees C). Butter a 10 inch tube pan and coat with white sugar.
INSERT INTO public.recipes VALUES (373, 'White Peachy Sangria', '30 mins', NULL, '8 hrs 30 mins', '20', '20 servings', '4 (750 milliliter) bottles moscato wine, 4 (12 fluid ounce) cans or bottles lemon-lime soda (such as Sprite®), 1 cup brandy, 1 cup peach schnapps, 2  fresh peaches, pitted and sliced, 1 (16 ounce) package fresh strawberries, sliced, 2  mangos - peeled, seeded, and sliced, ½  fresh pineapple - peeled, cored, and cut into chunks, 1 (6 ounce) container fresh raspberries', 'Stir moscato wine, lemon-lime soda, brandy, peach schnapps, peaches, strawberries, mangos, pineapple chunks, and raspberries together in a large container and chill 8 hours or overnight.', '4.9', 'https://www.allrecipes.com/recipe/223329/white-peachy-sangria/', '/Drinks Recipes/Sangria Recipes/', 'Total Fat 0g 0%, Sodium 24mg 1%, Total Carbohydrate 41g 15%, Dietary Fiber 2g 5%, Total Sugars 22g, Protein 1g, Vitamin C 30mg 148%, Calcium 23mg 2%, Iron 1mg 3%, Potassium 228mg 5%', 'Prep Time: 30 mins, Additional Time: 8 hrs, Total Time: 8 hrs 30 mins, Servings: 20, Yield: 20 servings', 'https://www.allrecipes.com/thmb/uz0pOWl7xju8N7kpWz_2HCIbhZE=/1500x0/filters:no_upscale():max_bytes(150000):strip_icc()/223329-White-Peachy-Sangria-Caelynne_5455009_original-4x3-1-8a93bc5db2404e3b84c49b8d671d9cbf.jpg');
INSERT INTO public.recipes VALUES (374, 'Southern Peach Cobbler', '10 mins', '45 mins', '1 hrs', '8', '8 servings', '½ cup butter, 1 cup white sugar, ¾ cup self-rising flour, ¾ cup milk, 1 (29 ounce) can sliced peaches in light syrup', 'Preheat oven to 350 degrees F (175 degrees C). Place butter in a deep 2 quart baking dish and place in oven to melt.
INSERT INTO public.recipes VALUES (375, 'Peach Ice Cream', '20 mins', NULL, '4 hrs 40 mins', '32', '4 quarts', '6 large eggs, beaten, 3 ½ cups white sugar, 10  fresh peaches, pitted and chopped, 4 cups heavy cream, 2 cups half-and-half cream, 2 teaspoons vanilla extract, ¾ teaspoon salt', 'Mix together eggs and sugar in a large bowl until smooth; purée peaches in a blender or food processor and stir 5 cups purée into egg mixture. Stir in cream, half-and-half, vanilla, and salt, and mix well.
INSERT INTO public.recipes VALUES (376, 'Crisp Peach Cobbler', '20 mins', '45 mins', '1 hrs 35 mins', '8', '8 servings', '6 large  fresh peaches, pitted and cut into eighths, 1  lemon, zested and juiced', 'Preheat oven to 375 degrees F (190 degrees C). Place a baking sheet on the rack under the middle rack to catch drips. Generously butter a 2-inch deep (2-quart) baking dish.
INSERT INTO public.recipes VALUES (377, 'Baked Peaches ''n Cream', '10 mins', '15 mins', '25 mins', '4', '4 servings', '8 teaspoons brown sugar, 2 tablespoons butter, cut into 8 pieces, 1 pinch ground cinnamon, or more to taste, 4  ripe peaches, halved and pitted , 4 scoops vanilla ice cream', 'Preheat oven to 400 degrees F (200 degrees C).
INSERT INTO public.recipes VALUES (378, 'Peach and Blackberry Cobbler', '30 mins', '45 mins', '1 hrs 15 mins', '12', '1 9x13-inch dish', '4 cups peeled and sliced fresh peaches, 1 cup fresh blackberries, ¼ cup white sugar, 1 teaspoon ground cinnamon, 1 tablespoon lemon juice, ½ cup butter, melted, 1 ¼ cups all-purpose flour, 1 cup white sugar, 2 teaspoons baking powder, ½ teaspoon salt, 1 cup milk', 'Preheat oven to 350 degrees F (175 degrees C).
INSERT INTO public.recipes VALUES (379, 'Freezer Peach Pie Filling', '15 mins', '55 mins', '3 hrs 10 mins', '8', '8 servings', '2 ½ cups sliced peaches, ¾ cup white sugar, 1 tablespoon cornstarch, 1 tablespoon MINUTE Tapioca, 1 dash Dash of nutmeg', 'Place sliced peaches in a bowl with sugar, cornstarch, tapioca, and nutmeg. Toss until evenly coated and sugar is mostly dissolved.
INSERT INTO public.recipes VALUES (381, 'Peach Cake II', NULL, NULL, NULL, '24', '1 - 9x13 inch pan', '3  egg, beaten, 1 ¾ cups white sugar, 1 cup vegetable oil, 2 cups all-purpose flour, 1 teaspoon salt, 1 teaspoon ground cinnamon, 1 teaspoon baking soda, 2 cups fresh peaches - peeled, pitted, and sliced, ½ cup chopped pecans', 'Preheat oven to 375 degrees F (190 degrees C). Grease and flour a 9x13 inch pan.
INSERT INTO public.recipes VALUES (383, 'Peach Pie', '1 hrs', '45 mins', '1 hrs 45 mins', '8', '1 to 9 - inch pie', '10  fresh peaches, pitted and sliced, ⅓ cup all-purpose flour, 1 cup white sugar, ¼ cup butter, 1 recipe pastry for a 9 inch double crust pie', 'Mix flour, sugar and butter into crumb stage.
INSERT INTO public.recipes VALUES (384, 'Best Peach Cobbler Ever', '30 mins', '1 hrs', '1 hrs 30 mins', '18', '1 9x13-inch cobbler', '1 (29 ounce) can sliced peaches, 2 tablespoons butter, melted, 1 pinch ground cinnamon, 1 pinch ground nutmeg, 1 tablespoon cornstarch, ½ cup water, 1 cup milk, 1 cup white sugar, 1 cup all-purpose flour, 2 teaspoons baking powder, 1 pinch salt, ½ cup butter, 1 teaspoon ground cinnamon, ¼ teaspoon ground nutmeg', 'Preheat oven to 350 degrees F (175 degrees C.) In a large bowl, combine sliced peaches with juice, 2 tablespoons melted butter, a pinch of cinnamon and a pinch of nutmeg. Dissolve cornstarch in water, then stir into peach mixture; set aside.
INSERT INTO public.recipes VALUES (385, 'Peach Cobbler VI', '15 mins', '30 mins', '45 mins', '8', '1 9x9-inch cobbler', '1 cup all-purpose flour, ½ cup brown sugar, ½ cup white sugar, 2 teaspoons baking powder, ½ teaspoon salt, 1 teaspoon vanilla extract, ¾ cup milk, ½ cup margarine, melted, 1 (29 ounce) can sliced canned peaches, drained, 1 teaspoon ground cinnamon', 'Preheat oven to 400 degrees F (200 degrees C). Grease a 9x9-inch baking dish.
INSERT INTO public.recipes VALUES (386, 'Easy Stovetop Peach Cobbler', '5 mins', '15 mins', '35 mins', '6', '6 servings', '1 (29 ounce) can sliced peaches, 2 teaspoons ground cinnamon (Optional), ¼ cup white sugar, 1 (9 ounce) package yellow cake mix, 4 teaspoons margarine', 'Discard 1/2 of the juice from the peaches and pour the rest into a saucepan. Sprinkle the top with cinnamon and sugar. Empty the cake mix on top of the peaches in an even layer. Place the margarine on top of the cake mix in the center.
INSERT INTO public.recipes VALUES (408, 'Hasselback Pear Tart', '20 mins', '35 mins', '1 hrs 15 mins', '8', '1 10-inch square tart pan', '1 sheet frozen puff pastry - thawed, unfolded, and lightly rolled, 2  Bartlett pears, halved and cored, 2  d''Anjou pears, halved and cored, 1  red pear, halved and cored, 2 tablespoons white sugar, ½  lemon, juiced, ½ (8 ounce) package cream cheese, softened, ½ cup confectioners'' sugar, ½ teaspoon vanilla extract, 1 tablespoon turbinado sugar', 'Preheat oven to 400 degrees F (200 degrees C). Fit puff pastry into a 10-inch square tart pan with removable sides.
INSERT INTO public.recipes VALUES (387, 'Single Crust Peach Pie', '30 mins', NULL, '1 hrs 20 mins', '8', '1 pie', '¾ cup white sugar, 2 tablespoons butter, softened, ⅓ cup all-purpose flour, ¼ teaspoon ground nutmeg, 6  fresh peaches - pitted, skinned, and sliced, 1 recipe pastry for a 9 inch single crust pie', 'Cream sugar and butter or margarine together. Add flour and nutmeg; mix until mealy. Spread 1/2 of mixture in pie crust. Arrange peaches on top of crumb mixture. Sprinkle remaining crumb mixture on top of peaches.
INSERT INTO public.recipes VALUES (388, 'Fresh Peach Cobbler I', '30 mins', '25 mins', '55 mins', '6', '6 servings', '½ cup white sugar, 1 tablespoon cornstarch, ¼ teaspoon ground cinnamon, 4 cups sliced fresh peaches, 1 teaspoon lemon juice', 'Preheat oven to 400 degrees F (200 degrees C).
INSERT INTO public.recipes VALUES (389, 'Marie''s Peach Dump Cake', '10 mins', '35 mins', '45 mins', '12', '12 servings', '1 (29 ounce) can sliced peaches in heavy syrup, undrained, 1 (18.25 ounce) box yellow cake mix, ¾ cup butter, sliced into pats, or more if needed', 'Preheat oven to 350 degrees F (175 degrees C). Grease a 9x13-inch baking dish with margarine.
INSERT INTO public.recipes VALUES (390, 'Peachy Bread Pudding with Caramel Sauce', '15 mins', '1 hrs 10 mins', '1 hrs 35 mins', '10', '1 - 9x13 inch baking dish', '2 cups fresh peaches - peeled, pitted and halved, 1 (14 ounce) can sweetened condensed milk, 3  eggs, lightly beaten, 1 ¼ cups hot water, ¼ cup butter, melted, 1 teaspoon ground cinnamon, 1 teaspoon vanilla extract, 4 cups French bread, torn into small pieces', 'Preheat an oven to 325 degrees F (165 degrees C). Grease a 9x13-inch baking dish.
INSERT INTO public.recipes VALUES (391, 'Peach and Tomato Caprese Salad', '15 mins', NULL, '15 mins', '4', '4 servings', '2 tablespoons extra-virgin olive oil, 1 tablespoon balsamic vinegar, 1 teaspoon flaked salt, divided, 2 large heirloom tomatoes, thinly sliced, 2  ripe peaches - halved, pitted, and sliced into half moons, 6 leaves fresh basil, 1 (8 ounce) ball fresh mozzarella, thinly sliced', 'Whisk olive oil, balsamic vinegar, and 1 pinch flaked salt together in a bowl until dressing is smooth.
INSERT INTO public.recipes VALUES (392, 'Baked Peaches', '10 mins', '20 mins', '30 mins', '6', '6 servings', '1 (16 ounce) package frozen peach slices, ⅓ cup brown sugar substitute, ¼ cup pecans, 1 tablespoon all-purpose flour, 1 teaspoon vanilla extract', 'Preheat oven to 350 degrees F (175 degrees C).
INSERT INTO public.recipes VALUES (393, 'Banana Peach Bread', '20 mins', '50 mins', '2 hrs 10 mins', '16', '1 5x9-inch loaf', '¾ cup white sugar, ½ cup butter, softened, 1 tablespoon brown sugar, 1 tablespoon instant hot chocolate mix, 3  bananas, peeled, 1 large fresh peach - peeled, pitted, and diced, ¼ cup milk, 2  eggs, 1 tablespoon vanilla extract, 2 cups all-purpose flour, ½ cup chopped walnuts (Optional), 1 teaspoon baking soda, 1 teaspoon salt', 'Preheat oven to 350 degrees F (175 degrees C). Grease the bottom of a 5x9-inch loaf pan.
INSERT INTO public.recipes VALUES (394, 'Bananerberry Smoothie', '10 mins', NULL, '10 mins', '2', '2 servings', '1 cup fresh strawberries, 1  banana, sliced, 1 cup fresh peaches, 1 cup apples, 1 ½ cups vanilla ice cream, 1 ½ cups ice cubes, ½ cup milk', 'In a blender combine strawberries, banana, peaches, apples, and ice cream. Blend until smooth. Add ice, pour in milk and blend again until smooth. Serve immediately.', '4.4', 'https://www.allrecipes.com/recipe/20126/bananerberry-smoothie/', '/Breakfast and Brunch/Drinks/', 'Total Fat 13g 16%, Saturated Fat 8g 38%, Cholesterol 48mg 16%, Sodium 109mg 5%, Total Carbohydrate 58g 21%, Dietary Fiber 5g 19%, Total Sugars 45g, Protein 7g, Vitamin C 78mg 392%, Calcium 224mg 17%, Iron 1mg 4%, Potassium 698mg 15%', 'Prep Time: 10 mins, Total Time: 10 mins, Servings: 2, Yield: 2 servings', 'https://www.allrecipes.com/thmb/42bkUI8CFjoLdeqporpBD5F7jp0=/1500x0/filters:no_upscale():max_bytes(150000):strip_icc()/433563-bananerberry-smoothie-Pam-Ziegler-Lutz-4x3-1-5ee163f5d3fa4b30ab66f2616f50f9bf.jpg');
INSERT INTO public.recipes VALUES (395, 'Grandma''s Peach French Toast', '9 hrs', '45 mins', '9 hrs 45 mins', '8', '8 servings', '1 cup packed brown sugar, ½ cup butter, 2 tablespoons water, 1 (29 ounce) can sliced peaches, drained, 12 (3/4 inch thick) slices day-old French bread, 5  eggs, 1 tablespoon vanilla extract, 1 pinch ground cinnamon, or to taste', 'In a saucepan, stir together the brown sugar, butter and water. Bring to a boil, then reduce heat to low, and simmer for 10 minutes, stirring frequently.
INSERT INTO public.recipes VALUES (396, 'Fresh Peach Pie I', NULL, NULL, NULL, '8', '1 pie', '1 (9 inch) pie shell, baked, 1 cup white sugar, ½ cup water, 3 tablespoons cornstarch, 1 tablespoon butter, 2 cups fresh peaches, pitted and mashed, ¼ teaspoon ground nutmeg, 1 teaspoon vanilla extract, 4 cups fresh peaches - pitted, skinned, and sliced', 'Combine sugar, water, cornstarch, butter or margarine, mashed peaches, and nutmeg in a saucepan. Cook over medium heat until clear and thick. Stir in vanilla.
INSERT INTO public.recipes VALUES (397, 'Mango, Peach and Pineapple Salsa', '20 mins', NULL, '1 hrs 20 mins', '16', '8 cups', '2  mangos, peeled, seeded and chopped, 2 small peaches, halved, pitted, and cut into 1/2-inch dice, 1 cup diced fresh pineapple, 4  tomatoes, chopped, 1  white onion, diced, 1  red bell pepper, diced, 1  yellow bell pepper, diced, 1 cup chopped fresh cilantro, or to taste, 1 clove garlic, minced, 1 small jalapeno pepper, minced, 2 tablespoons lime juice, 1 teaspoon salt, 2 tablespoons white sugar, or to taste, ¾ cup water', 'Place the mango, peach, pineapple, tomato, onion, red pepper, yellow pepper, and cilantro in a mixing bowl. Stir in the garlic, jalapeno, lime juice, salt, sugar, and water. Cover and refrigerate at least 1 hour before serving.', '4.6', 'https://www.allrecipes.com/recipe/166482/mango-peach-and-pineapple-salsa/', '/Appetizers and Snacks/Dips and Spreads Recipes/Salsa Recipes/Peach Salsa Recipes/', 'Total Fat 0g 0%, Sodium 150mg 7%, Total Carbohydrate 10g 4%, Dietary Fiber 1g 5%, Total Sugars 7g, Protein 1g, Vitamin C 48mg 242%, Calcium 14mg 1%, Iron 0mg 2%, Potassium 199mg 4%', 'Prep Time: 20 mins, Additional Time: 1 hrs, Total Time: 1 hrs 20 mins, Servings: 16, Yield: 8 cups', 'https://www.allrecipes.com/thmb/WI4AYyHsy5Kz-dtE17vXz2h9QWI=/1500x0/filters:no_upscale():max_bytes(150000):strip_icc()/225040-97196159984d4e77b1fdb9e3fec702ca.jpg');
INSERT INTO public.recipes VALUES (732, 'Pineapple and Banana Smoothie', '5 mins', NULL, '5 mins', '1', '1 smoothie', '4  ice cubes, ¼  fresh pineapple - peeled, cored and cubed, 1 large banana, cut into chunks, 1 cup pineapple or apple juice', 'Place ice cubes, pineapple, banana, and pineapple juice into the container of a blender. Puree on high until smooth.
INSERT INTO public.recipes VALUES (398, 'Grandma''s Peach Cobbler', '10 mins', '45 mins', '1 hrs 5 mins', '10', '10 servings', '¾ cup unsalted butter, softened, 1 (15 ounce) can peaches in heavy syrup, 1 ½ cups white sugar, divided, ½ cup brown sugar, 1 teaspoon ground cinnamon, 1 teaspoon ground nutmeg, ¼ teaspoon vanilla extract, 1 cup milk, 1 cup all-purpose flour, 1 tablespoon baking powder, 1 pinch salt', 'Preheat oven to 350 degrees F (175 degrees C). Place 1/2 cup butter in a casserole dish.
INSERT INTO public.recipes VALUES (399, 'Homemade Peach Tea', '5 mins', '10 mins', '50 mins', '6', '6 cups', '1 cup water, 1 cup white sugar, 2 slices fresh peach, or more to taste', 'Mix 1 cup water, sugar, and peach slices together in a saucepan; bring to a boil. Reduce heat to medium and simmer, crushing peach slices as you stir, until sugar is dissolved, about 5 minutes. Remove saucepan from heat, cover, and allow peaches to infuse syrup, about 30 minutes. Strain to remove peach slices.
INSERT INTO public.recipes VALUES (400, 'Spicy Peach Chutney', '8 hrs', '2 hrs', '10 hrs', '96', '6 - 1/2 pints', '4 pounds sliced peeled peaches, 1 cup raisins, 2 cloves garlic, minced, ½ cup chopped onion, 5 ounces chopped preserved ginger, 1 ½ tablespoons chili powder, 1 tablespoon mustard seed, 1 teaspoon curry powder, 4 cups packed brown sugar, 4 cups apple cider vinegar, ¼ cup pickling spice', 'In a large heavy pot, stir together the peaches, raisins, garlic, onion, preserved ginger, chili powder, mustard seed, curry powder, brown sugar and cider vinegar. Wrap the pickling spice in a cheesecloth bag, and place in the pot.
INSERT INTO public.recipes VALUES (401, 'Pear Tarte Tatin', '20 mins', '50 mins', '1 hrs 25 mins', '8', '8 servings', '1 (15 ounce) package ready-to-use refrigerated pie crust, ⅛ teaspoon ground nutmeg, ½ teaspoon ground ginger, 2 tablespoons white sugar, 5  firm pears, 2 tablespoons good quality bourbon whiskey, 4 tablespoons unsalted butter, ⅔ cup white sugar, 1 pinch salt', 'Remove refrigerated pie crust from package, and follow manufacturer''s suggestions for unrolling crust. Set aside.
INSERT INTO public.recipes VALUES (402, 'Pear Sour Cream Pie', '25 mins', '45 mins', '3 hrs 10 mins', '6', '1 to 9 - inch pie', '1 (9 inch) pie crust pastry, ½ cup white sugar, 1 cup sour cream, ¼ cup all-purpose flour, 1  egg, beaten, 1 teaspoon vanilla extract, ¼ teaspoon salt, 4 large pears - peeled, cored and sliced', 'Preheat an oven to 350 degrees F (175 degrees C). Roll out the pastry and transfer it to a 9-inch pie plate. Trim any extra dough and crimp the edge.
INSERT INTO public.recipes VALUES (403, 'Sour Cream Pear Pie', '15 mins', '55 mins', '1 hrs 10 mins', '8', '1 9-inch pie', '¾ cup sugar, 1 tablespoon all-purpose flour, ¼ teaspoon ground cinnamon, 1 pinch salt, 1  egg, beaten, 1 cup sour cream, 2 (15 ounce) cans pears, drained and chopped, 1 (9 inch) graham cracker crust, ½ cup sugar, ⅔ cup butter, ⅔ cup all-purpose flour', 'Preheat the oven to 350 degrees F (175 degrees C).
INSERT INTO public.recipes VALUES (404, 'Pear and Chocolate Tart', NULL, '50 mins', '1 hrs 10 mins', '8', '1 9-inch tart', '1  shortcrust pastry crust, 6 ½ ounces 70% dark chocolate, chopped, 1 ½ cups ground almonds, 2  eggs, ½ cup superfine sugar, 6 ½ tablespoons butter, softened, 3  pears - peeled, cored, and quartered', 'Preheat the oven to 375 degrees F (190 degrees C).
INSERT INTO public.recipes VALUES (405, 'Pear Pie III', '15 mins', '1 hrs', '1 hrs 15 mins', '8', '1 to 9 - inch pie', '1 (9 inch) unbaked pie crust, 2  pears - peeled, cored and cut in half, 1 cup white sugar, ¼ cup butter, ¼ cup all-purpose flour, 1 tablespoon vanilla extract, 2  eggs, beaten', 'Preheat the oven to 350 degrees F (175 degrees C).
INSERT INTO public.recipes VALUES (406, 'Rustic Autumn Fruit Tart', '15 mins', '30 mins', '1 hrs 45 mins', '8', '1 8-inch tart', '½ cup butter, chilled, ½ cup cream cheese, 1 ½ cups all-purpose flour, 2  apples - peeled, cored, and thinly sliced, 1  pear - peeled, cored and sliced, ¼ cup orange juice, ⅓ cup brown sugar, ½ teaspoon ground cinnamon, ¼ teaspoon ground nutmeg, ¼ teaspoon ground cardamom, 1 ½ tablespoons cornstarch, ½ cup apricot jam, warmed', 'Cut the cold butter and cream cheese into the flour with a knife or pastry blender until the mixture resembles coarse crumbs. (This can also be done in a food processor: pulse the cold butter into the flour until the mixture resembles cornmeal; add the cream cheese and pulse until it''s the size of small peas.) When you squeeze a handful of the mixture, it should form a ball. Shape the dough into a round disk, wrap it in plastic, and refrigerate for at least 1 hour.
INSERT INTO public.recipes VALUES (407, 'Cheddar Pear Pie', '20 mins', '45 mins', '1 hrs 5 mins', '6', '1 to 9 - inch pie', '½ cup all-purpose flour, ½ cup brown sugar, ½ cup shredded Cheddar cheese, ¼ cup butter', 'Preheat the oven to 400 degrees F (200 degrees C).
INSERT INTO public.recipes VALUES (409, 'Scandinavian Pear Tart', '25 mins', '25 mins', '3 hrs 50 mins', '8', '1 9-inch tart', '  cooking spray, ½ cup white sugar, 3 tablespoons butter, softened, ¾ cup all-purpose flour, ⅓ cup finely chopped almonds', 'Preheat the oven to 425 degrees F (220 degrees C). Coat a 9-inch fluted tart pan with a removable bottom with cooking spray.
INSERT INTO public.recipes VALUES (410, 'Maple-Pear Tarte Tatin', '15 mins', '30 mins', '50 mins', '8', '1 9-inch tart', '½ (17.3 ounce) package frozen puff pastry, thawed, ¼ cup butter, ⅓ cup brown sugar, ¼ teaspoon ground cinnamon, 1 pinch ground nutmeg, ¼ cup maple syrup, 4  firm pears - peeled, cored, and halved, or more as needed', 'Preheat oven to 375 degrees F (190 degrees C).
INSERT INTO public.recipes VALUES (411, 'Bartlett Pear Pie', '20 mins', '30 mins', '1 hrs 50 mins', '8', '8 servings', '1 (9 inch) pie crust pastry, ½ cup unsalted butter, softened, ½ cup white sugar, ¼ cup brown sugar, 1 ½ tablespoons all-purpose flour, 1 teaspoon ground nutmeg, ½ teaspoon ground allspice, ¼ teaspoon salt, 1 pinch ground cinnamon, 2  eggs, 5  Bartlett pears, peeled and chopped', 'Preheat oven to 375 degrees F (190 degrees C). Press pie crust pastry into a 9-inch pie dish and refrigerate while preparing filling.
INSERT INTO public.recipes VALUES (412, 'French Pear Pie', '45 mins', '45 mins', '1 hrs 30 mins', '8', '1 9-inch pie', '6 large pears, peeled and sliced, 1  lemon, juiced, ⅔ cup white sugar, ½ teaspoon grated nutmeg, 1 (9 inch) unbaked single pie crust, ½ cup butter, ½ cup brown sugar, 1 cup all-purpose flour', 'Preheat oven to 450 degrees F (230 degrees C).
INSERT INTO public.recipes VALUES (413, 'Autumn Spiced Apple and Pear Hand Pies', '1 hrs', '30 mins', '1 hrs 50 mins', '16', '16 3-inch pies', '1 large Pink Lady apple - peeled, cored and diced, 1 large Bartlett pear - peeled, cored and diced, ¼ cup brown sugar, 1 tablespoon vanilla extract, 2 teaspoons cornstarch, 1 teaspoon ground cinnamon, ½ teaspoon ground nutmeg, ¼ teaspoon ground cloves, 1 pinch salt, 1  egg, 1 tablespoon water, 1 recipe pastry for a 9-inch double crust pie, 2 tablespoons coarse granulated sugar, or as needed (Optional), ½ cup dark chocolate chips (Optional)', 'Preheat oven to 400 degrees F (200 degrees C). Line a baking sheet with parchment paper.
INSERT INTO public.recipes VALUES (414, 'Pear Pie', '15 mins', '45 mins', '1 hrs', '8', '1 9-inch pie', '1 (9 inch) unbaked pie crust, 3 cups sliced Bartlett pears, 1 cup sour cream, ½ cup white sugar, 2 tablespoons all-purpose flour, 1  egg, ½ teaspoon vanilla extract, ½ teaspoon salt', 'Preheat oven to 400 degrees F (200 degrees C). Press pie crust into a 9-inch pie dish.
INSERT INTO public.recipes VALUES (415, 'Pear Pie II', '15 mins', '50 mins', '1 hrs 5 mins', '6', '1 to 9 - inch pie', '1 (9 inch) unbaked pie crust, 3  eggs, ⅓ cup all-purpose flour, 1 cup white sugar, 1 teaspoon almond extract, ¼ cup melted butter, 3  pears - peeled, cored and sliced', 'Preheat oven to 375 degrees F (190 degrees C.)
INSERT INTO public.recipes VALUES (416, 'Pear and Hazelnut Frangipane Tart', '15 mins', '50 mins', '2 hrs 15 mins', '8', '1 9-inch tart', '1 ¼ cups all-purpose flour (or gluten-free flour mix), 1 teaspoon sugar, ¼ teaspoon salt, 8 tablespoons cold unsalted butter, cut into 1/2-inch cubes, 3 tablespoons cold water, or more as needed ,   Reynolds® Parchment Paper,   Reynolds Wrap® Aluminum Foil', 'Combine the flour, sugar and salt in a food processor. Add the cold butter and pulse ten times until the butter is the size of large peas. Add 3 tablespoons of cold water and pulse until it comes together. Turn onto a lightly floured work surface and bring the dough together, forming a disk. Wrap in Reynolds® Parchment Paper and refrigerate for at least 45 minutes.
INSERT INTO public.recipes VALUES (417, 'French Puff Pastry Tart with Pears and Chocolate', '20 mins', '30 mins', '50 mins', '8', '8 servings', '½ cup unsalted butter, ½ cup white sugar, 2 tablespoons white sugar, 1 cup blanched almond flour, 2  eggs, 1 sheet frozen puff pastry, thawed, 4 ounces milk chocolate, chopped, 3  pears - peeled, cored and sliced', 'Line a tart pan with parchment paper. Preheat the oven to 400 degrees F (200 degrees C).
INSERT INTO public.recipes VALUES (419, 'd''Anjou Pear and Almond Tarts', '15 mins', '45 mins', '1 hrs', '18', '18 3-inch tarts', '18 (3 inch) unbaked tart shells, 7 tablespoons brown sugar, 2 tablespoons butter, melted, 1 teaspoon pear-flavored white balsamic vinegar, 1 teaspoon ground cinnamon, 3 large ripe d''Anjou pears - peeled, cored, and diced, 3 tablespoons chopped almonds', 'Preheat oven to 350 degrees F (175 degrees C). Place tart shells on a baking sheet.
INSERT INTO public.recipes VALUES (420, 'Creamy Pear Pie', '20 mins', '55 mins', '1 hrs 15 mins', '8', '1 to 9 - inch pie', '⅓ cup white sugar, 2 tablespoons all-purpose flour, 4 cups peeled and sliced pears, 1 cup sour cream, ½ teaspoon vanilla extract, ½ teaspoon lemon extract, ½ teaspoon almond extract, 1 (9 inch) unbaked pie shell', 'Preheat the oven to 400 degrees F (200 degrees C).
INSERT INTO public.recipes VALUES (421, 'Jump Rope Pie', '30 mins', '50 mins', '1 hrs 20 mins', '8', '1 9-inch pie', '1 recipe pastry for a double crust 9-inch pie, 1 cup white sugar, 3 tablespoons all-purpose flour, or more as needed, ½ teaspoon ground cinnamon, 1 pinch freshly grated nutmeg, 2 cups peeled, cored and sliced apples, 1 cup peeled, pitted and sliced peaches, 1 cup peeled, cored and sliced pears, 1 cup pitted and sliced plums, 1 teaspoon grated fresh ginger root, 1 tablespoon lemon juice', 'Preheat oven to 425 degrees F (220 degrees C). Line a 9-inch pie plate with pastry.
INSERT INTO public.recipes VALUES (422, 'Dethbert''s Pear Pie', '30 mins', '25 mins', '55 mins', '16', '2 pies', '1 cup all-purpose flour, ½ cup white sugar, ½ teaspoon salt, 2 cups finely shredded mild Cheddar cheese, 1 cup butter, softened', 'Sift flour, sugar, and salt into a mixing bowl. Stir grated Cheddar cheese into the flour mixture using a fork. Stir in butter using a wide spoon until mixture becomes crumbly. Set topping mixture aside at room temperature.
INSERT INTO public.recipes VALUES (423, 'Coffee-Dusted Pear Galette', '30 mins', '20 mins', '50 mins', '4', '4 servings', '1 ½ cups all-purpose flour, 1 ½ teaspoons white granulated sugar, 1 teaspoon fine sea salt, ½ cup unsalted butter, frozen, 7 tablespoons ice-cold water, or more as needed, divided, 1 large egg, beaten (for egg wash), 1 tablespoon turbinado sugar, 1 sheet Reynolds Wrap® Aluminum Foil, 1 sheet Reynolds® Parchment Paper', 'In a large bowl, mix together the flour, sugar and salt. Using a box grater, grate the cold butter atop the flour mixture. Working quickly and using your hands, break the butter bits into the flour until they''re evenly distributed and resemble the size of small peas.
INSERT INTO public.recipes VALUES (424, 'Grandma''s Pear Preserves', '30 mins', '15 mins', '12 hrs 45 mins', '48', '6 half pints', '6 cups peeled, cored, and sliced pears, 1 cup water, 1 tablespoon lemon juice, 1 (2 ounce) package powdered fruit pectin, 8 cups white sugar, ½ cup brown sugar, 2 teaspoons ground allspice, 2 teaspoons ground nutmeg', 'Inspect six 8-ounce jars for cracks and rings for rust, discarding any defective ones. Immerse in simmering water for 10 minutes. Wash new, unused lids and rings in warm, soapy water.
INSERT INTO public.recipes VALUES (425, 'Pear Jam', '20 mins', '20 mins', '40 mins', '64', '8 half-pint jars', '4 ½ cups mashed ripe pears, ¼ cup lemon juice, 3 tablespoons powdered fruit pectin, 1 teaspoon ground cinnamon, ½ teaspoon ground cloves, ½ teaspoon ground allspice, ½ teaspoon ground nutmeg, 7 ½ cups white sugar, 1 teaspoon butter, 8  half-pint canning jars with lids and rings, or as needed', 'Mix pears, lemon juice, fruit pectin, cinnamon, cloves, allspice, and nutmeg in a large heavy pot; bring to a boil, stirring constantly. Add sugar all at once, stirring, and bring back to a full rolling boil. Boil for 1 minute. Mix in butter to settle foam.
INSERT INTO public.recipes VALUES (426, 'Apple and Pear Crumble', '20 mins', '40 mins', '1 hrs', '8', NULL, '1 ½ cups rolled oats, 1 ½ cups brown sugar, divided, ½ cup all-purpose flour, ½ cup butter, softened, 2 cups peeled and diced apples, 2 cups peeled and diced pears, 1 teaspoon ground cinnamon, ½ cup sliced almonds, or to taste', 'Preheat the oven to 350 degrees F (175 degrees C).
INSERT INTO public.recipes VALUES (427, 'Roquefort Pear Salad', '25 mins', '10 mins', '35 mins', '6', NULL, '½ cup pecans, ¼ cup white sugar', 'Make the pecans: Combine pecans and sugar in a skillet over medium heat. Cook, stirring gently, until sugar has melted and pecans are caramelized, 5 to 7 minutes. Carefully transfer nuts onto a sheet of waxed paper to cool.
INSERT INTO public.recipes VALUES (428, 'Prickly Pear Jelly', '20 mins', '38 mins', '1 day 58 mins', '24', '3 pints', '27  prickly pears (cactus fruit), ¼ cup lemon juice, 1 (1.75 ounce) package fruit pectin (such as Sure-Jell®), 4 ½ cups white sugar', 'Simmer 3 pint-size jars in a large pot of water until ready for use. Wash lids and rings in warm soapy water.
INSERT INTO public.recipes VALUES (429, 'Fresh Pear Cake', NULL, NULL, NULL, '12', '1 to 10 - inch bundt cake', '4 cups peeled, cored and chopped pears, 2 cups white sugar, 3 cups sifted all-purpose flour, 1 teaspoon salt, 1 ½ teaspoons baking soda, 1 teaspoon ground nutmeg, 1 teaspoon ground cinnamon, ½ teaspoon ground cloves, 4  egg whites, ⅔ cup canola oil, 1 cup chopped pecans', 'Combine the pears and the sugar and let stand for one hour.
INSERT INTO public.recipes VALUES (430, 'Classic Pear Crisp', '20 mins', '35 mins', '1 hrs', '6', '6 servings', '1 cup rolled oats, ⅓ cup brown sugar, ½ cup all-purpose flour, 1 teaspoon finely chopped crystallized ginger, 1 teaspoon ground cinnamon, ¼ cup butter, 2 tablespoons white sugar, 2 tablespoons all-purpose flour, 2 teaspoons finely chopped crystallized ginger, 8 cups peeled and sliced pears, 1 pint vanilla ice cream', 'Preheat the oven to 375 degrees F (190 degrees C). Grease a 2 quart casserole dish or 9 inch square baking dish.
INSERT INTO public.recipes VALUES (431, 'Pear or Apple Cobbler', '15 mins', '45 mins', '1 hrs', '9', '9 servings', '4  pears, cored and cut into 1/2-inch slices, 1 teaspoon lemon juice, ⅓ cup maple syrup, 2 tablespoons melted butter', 'Preheat oven to 375 degrees F (190 degrees C).
INSERT INTO public.recipes VALUES (432, 'Pear Vinaigrette', '10 mins', NULL, '10 mins', '12', '1 1/2 cups', '1  ripe pear - peeled, cored, and chopped, ½ cup white wine, 1 clove garlic, chopped, 2 teaspoons Dijon mustard, ¼ cup white balsamic vinegar, 1 teaspoon ground black pepper, ¼ teaspoon sea salt, ½ cup olive oil', 'Blend the pear, white wine, garlic, Dijon mustard, white balsamic vinegar, black pepper, and sea salt in a blender until well combined; drizzle the olive oil into the mixture in a thin, steady stream while continuing to blend. Blend a few seconds longer until the salad dressing is thick and creamy.', '4.7', 'https://www.allrecipes.com/recipe/218334/pear-vinaigrette/', '/Side Dish/Sauces and Condiments/Salad Dressing Recipes/Vinaigrette Dressing Recipes/', 'Total Fat 9g 12%, Saturated Fat 1g 6%, Sodium 60mg 3%, Total Carbohydrate 4g 1%, Dietary Fiber 1g 2%, Total Sugars 2g, Protein 0g, Vitamin C 1mg 4%, Calcium 5mg 0%, Iron 1mg 3%, Potassium 31mg 1%', 'Prep Time: 10 mins, Total Time: 10 mins, Servings: 12, Yield: 1 1/2 cups', 'https://www.allrecipes.com/thmb/l7SzmM8ZfuDg9W2NflJvwxihjek=/1500x0/filters:no_upscale():max_bytes(150000):strip_icc()/2615720_Pear-Vinaigrette-4x3-1-5ac5ff0cea044d4abf83a86fae40aa19.jpg');
INSERT INTO public.recipes VALUES (433, 'Pear Bread I', NULL, NULL, NULL, '20', '2 -8x5 inch loaves', '3 cups all-purpose flour, ¼ teaspoon baking powder, 1 teaspoon baking soda, 1 teaspoon salt, 1 tablespoon ground cinnamon, ¾ cup vegetable oil, 3  eggs, 2 cups white sugar, 2 cups peeled shredded pears, 1 cup chopped pecans, 2 teaspoons vanilla extract', 'In a large mixing bowl combine flour, baking powder, baking soda, salt, and cinnamon. Make a well in the center of the bowl.
INSERT INTO public.recipes VALUES (434, 'Pear Honey', '45 mins', '3 hrs', '3 hrs 45 mins', '64', '4 pints', '8 cups peeled, cored and chopped pears, 1 cup unsweetened pineapple juice, 8 cups white sugar', 'Place chopped pears into a large pot, and pour pineapple juice over them to prevent them from browning. Stir in sugar, and bring to a boil over medium-high heat. Stir frequently to prevent scorching. When the pears are at a full boil, reduce heat to medium, and cook until the mixture is the color and texture of honey. The longer you cook it, the thicker it gets. Cooking time is usually 2 to 3 hours.
INSERT INTO public.recipes VALUES (678, 'Spicy Mango Sauce', '10 mins', NULL, '40 mins', '2', '2 serving', '¾ cup finely minced mango, ¼ cup seasoned rice vinegar,   juice from one lime, ½ small Thai chile pepper, minced, 1 clove garlic, crushed, 1 teaspoon hot chile paste (such as sambal oelek), 1 tablespoon chopped fresh cilantro', 'Stir mango, rice vinegar, lime juice, Thai chile pepper, garlic, and hot chile paste in a bowl until well combined. Cover and let rest 30 minutes. Stir in cilantro.
INSERT INTO public.recipes VALUES (435, 'Curried Butternut Squash and Pear Soup', '15 mins', '1 hrs 30 mins', '1 hrs 45 mins', '8', '8 servings', '1 (2 pound) butternut squash, 3 tablespoons unsalted butter, 1  onion, diced, 2 cloves garlic, minced, 2 teaspoons minced fresh ginger root, 1 tablespoon curry powder, 1 teaspoon salt, 4 cups reduced sodium chicken broth, 2  firm ripe Bartlett pears, peeled, cored, and cut into 1 inch dice, ½ cup half and half', 'Preheat an oven to 375 degrees F (190 degrees C). Line a rimmed baking sheet with parchment paper.
INSERT INTO public.recipes VALUES (436, 'Pear Butter', '30 mins', '1 mins', '31 mins', '32', '2 pints', '4 pounds medium pears, quartered and cored, 2 cups sugar, 1 teaspoon grated orange zest, ¼ teaspoon ground nutmeg, ¼ cup orange juice', 'Place pears into a large pot over medium heat, and add just enough water to cover the bottom of the pot and keep them from sticking, about 1/2 cup. Cook until the pears are soft, about 30 minutes. Press pears through a sieve or food mill, and measure out 2 quarts of the pulp.
INSERT INTO public.recipes VALUES (437, 'Grilled Brie and Pear Sandwich', '10 mins', '5 mins', '15 mins', '1', '1 sandwich', '2 tablespoons butter, softened, 2 thick slices French bread, 6 thin slices  Brie cheese, or more to taste, 12  fresh thyme leaves, or to taste, 1 pinch cracked black pepper, 6 slices pear (such as Bosc),   salt to taste', 'Generously butter one side of each slice of bread.
INSERT INTO public.recipes VALUES (438, 'Pear Relish', '30 mins', '1 hrs 40 mins', '3 hrs 10 mins', '192', '8 pints', '12 large pears, 3 large onions, coarsely chopped, 3 large green bell peppers, seeded and coarsely chopped, 4  jalapeno peppers, coarsely chopped, 2 cups apple cider vinegar, 2 cups white sugar, 9 ounces prepared mustard, 1 tablespoon salt, 10  (1 pint) canning jars with lids and rings, or as needed', 'Place pears into a large stock pot, add water to cover, and boil until tender, about 20 minutes. Drain and cool. When pears are cool, peel, core, and coarsely chop.
INSERT INTO public.recipes VALUES (439, 'Cranberry Sauce Extraordinaire', '10 mins', '35 mins', '45 mins', '12', '12 servings', '1 cup water, 1 cup white sugar, 1 (12 ounce) package fresh cranberries, 1  orange, peeled and pureed, 1  apple - peeled, cored and diced, 1  pear - peeled, cored and diced, 1 cup chopped dried mixed fruit, 1 cup chopped pecans, ½ teaspoon salt, 1 teaspoon ground cinnamon, ½ teaspoon ground nutmeg', 'In a medium saucepan, boil water and sugar until the sugar dissolves. Reduce the heat to simmer, and stir in cranberries, pureed orange, apple, pear, dried fruit, pecans, salt, cinnamon, and nutmeg. Cover, and simmer for 30 minutes, stirring occasionally, until the cranberries burst. Remove from heat, and let cool to room temperature.', '4.8', 'https://www.allrecipes.com/recipe/13643/cranberry-sauce-extraordinaire/', '/Side Dish/Sauces and Condiments/Sauces/Cranberry Sauce Recipes/', 'Total Fat 7g 9%, Saturated Fat 1g 3%, Sodium 100mg 4%, Total Carbohydrate 36g 13%, Dietary Fiber 3g 12%, Total Sugars 22g, Protein 2g, Vitamin C 13mg 65%, Calcium 24mg 2%, Iron 1mg 4%, Potassium 220mg 5%', 'Prep Time: 10 mins, Cook Time: 35 mins, Total Time: 45 mins, Servings: 12, Yield: 12 servings', 'https://www.allrecipes.com/thmb/PqoNDKUqkiywKW-SYZWHbunVYuA=/1500x0/filters:no_upscale():max_bytes(150000):strip_icc()/2907429-cranberry-sauce-extraordinaire-Elizabeth-4x3-1-b324d62d29484113a2ae92ef5dbb0c9f.jpg');
INSERT INTO public.recipes VALUES (440, 'Pear and Blue Cheese Salad', '15 mins', NULL, '15 mins', '6', '6 servings', '1 (10 ounce) bag mixed field greens, ½ cup sliced red onion (Optional), 1  Bosc pear, cored and sliced, ½ cup chopped candied pecans, ½ cup crumbled blue cheese, ¼ cup maple syrup, ⅓ cup apple cider vinegar, ½ cup mayonnaise, 2 tablespoons packed brown sugar, ¾ teaspoon salt, ¼ teaspoon freshly ground black pepper, ¼ cup walnut oil', 'Place the salad greens in a large bowl. Add the red onion, pear, pecans, and blue cheese, and toss to mix evenly.
INSERT INTO public.recipes VALUES (441, 'Lime Pear Gelatin Salad', '10 mins', NULL, '4 hrs 10 mins', '6', '6 servings', '1 (.6 ounce) package sugar-free lime Jell-O®, 1 cup boiling water, 1 (15.25 ounce) can pear halves in juice, 1 (3 ounce) package reduced-fat cream cheese, softened, 1 ½ cups reduced-fat frozen whipped topping, thawed', 'Whisk together the lime gelatin and boiling water in a large bowl until the gelatin dissolves. Pour the mixture into the container of a blender, and add the pear halves and cream cheese. Cover and blend until smooth. Pour back into the bowl, and gently whisk in the whipped topping. Transfer to a mold or serving bowl, cover and refrigerate until firm, at least 4 hours. To unmold, dip the mold briefly into hot tap water to loosen the gelatin, then invert onto a plate.', '4.7', 'https://www.allrecipes.com/recipe/156739/lime-pear-gelatin-salad/', '/Desserts/Specialty Dessert Recipes/Dessert Salad Recipes/Jell-O® Salad/', 'Total Fat 5g 7%, Saturated Fat 4g 20%, Cholesterol 11mg 4%, Sodium 148mg 6%, Total Carbohydrate 15g 6%, Dietary Fiber 1g 4%, Total Sugars 9g, Protein 3g, Vitamin C 1mg 6%, Calcium 18mg 1%, Iron 0mg 1%, Potassium 86mg 2%', 'Prep Time: 10 mins, Additional Time: 4 hrs, Total Time: 4 hrs 10 mins, Servings: 6, Yield: 6 servings', 'https://www.allrecipes.com/thmb/pFuV6qAJWNuYTf6eksHW2WajZ_A=/1500x0/filters:no_upscale():max_bytes(150000):strip_icc()/169919-32e7b9d628ee4f06867cf2e3f7654b49.jpg');
INSERT INTO public.recipes VALUES (442, 'Apple-Cranberry Salad', '25 mins', NULL, '25 mins', '4', '4 servings', '1 teaspoon stone-ground mustard, 2 tablespoons balsamic vinegar, ¼ cup olive oil, 1  apple, diced, 1  pear, diced, ¼ cup dried cranberries, 1 (10 ounce) package mixed baby greens, ¼ cup crumbled blue cheese, 2 tablespoons chopped walnuts', 'Whisk the mustard and vinegar together in a small bowl. Drizzle in the olive oil while whisking to create a dressing; set aside.
INSERT INTO public.recipes VALUES (443, 'Winter Fruit Salad with Lemon Poppyseed Dressing', '25 mins', NULL, '25 mins', '12', '12 servings', '½ cup white sugar, ½ cup lemon juice, 2 teaspoons diced onion, 1 teaspoon Dijon-style prepared mustard, ½ teaspoon salt, ⅔ cup vegetable oil, 1 tablespoon poppy seeds, 1 head romaine lettuce, torn into bite-size pieces, 4 ounces shredded Swiss cheese, 1 cup cashews, ¼ cup dried cranberries, 1  apple - peeled, cored and diced, 1  pear - peeled, cored and sliced', 'In a blender or food processor, combine sugar, lemon juice, onion, mustard, and salt. Process until well blended. With machine still running, add oil in a slow, steady stream until mixture is thick and smooth. Add poppy seeds, and process just a few seconds more to mix.
INSERT INTO public.recipes VALUES (444, 'Pear and Gorgonzola Cheese Pizza', '10 mins', '15 mins', '25 mins', '8', '1 pizza', '1 (16 ounce) package refrigerated pizza crust dough, 4 ounces sliced provolone cheese, 1  Bosc pear, thinly sliced, 2 ounces chopped walnuts, 2 ½ ounces Gorgonzola cheese, crumbled, 2 tablespoons chopped fresh chives', 'Preheat oven to 450 degrees F (230 degrees C).
INSERT INTO public.recipes VALUES (490, 'Plum Chipotle Sauce', '1 hrs', '1 hrs 40 mins', '4 hrs 40 mins', '128', '8 half-pint jars', '5 quarts very ripe plums, pitted, or as needed, 4 cloves garlic, pressed, 1  onion, finely chopped, 6 cups white sugar, ½ cup apple cider vinegar, 2 tablespoons Southwest chipotle seasoning, 1 tablespoon roasted garlic seasoning, 1  jalapeno pepper, finely chopped (remove seeds for milder flavor if desired), 7 teaspoons salt, 1 teaspoon liquid smoke flavoring, 8  half-pint canning jars with lids and rings', 'Place the plums, a few at a time, into a colander set over a large bowl. With gloved hands, squeeze the plums in the colander, forcing the juice through the holes of the colander. Discard spent pulp, and repeat to produce 8 cups of plum juice.
INSERT INTO public.recipes VALUES (445, 'Apple Pear Sauce', '15 mins', '20 mins', '35 mins', '8', '8 servings', '4  pears, cut into chunks, 3  apples, cut into chunks, ½ cup water, 1 teaspoon vanilla extract, ¼ teaspoon ground cinnamon', 'Heat a skillet over medium heat; add pears, apples, water, and vanilla extract to the hot skillet. Cover and simmer fruit mixture for 10 minutes; remove lid and cook until most of liquid is evaporated and fruit is softened, 10 to 15 more minutes.
INSERT INTO public.recipes VALUES (446, 'Blue Cheese, Walnut, and Pear Pizza', '20 mins', '15 mins', '35 mins', '6', '1 pizza', '1  pre-baked pizza crust, 2 cloves garlic, minced, 1 tablespoon Dijon mustard, 2 sprigs fresh rosemary, chopped, ¼ cup white wine vinegar, ½ cup olive oil, ¼ cup crumbled blue cheese,   salt and pepper to taste, ¼ cup crumbled blue cheese, ⅓ cup shredded mozzarella cheese, 2  pears - peeled, cored and sliced, ¼ cup toasted walnut pieces', 'Preheat an oven to 425 degrees F (220 degrees C).
INSERT INTO public.recipes VALUES (447, 'Poached Pears Belle Helene', '20 mins', '20 mins', '3 hrs', '4', '4 pears', '6 cups water, 1  lemon, zested and juiced, 4  Bosc pears - cored, peeled, stems left on, 1  vanilla bean, 3 cups sugar, 1 cup prepared hot fudge topping, or as needed, 1 cup vanilla ice cream, or as needed', 'Place water in a heavy pot. Stir in zest and juice of 1 lemon. Place pears in pot. Split the vanilla bean lengthwise and scrape out the seeds. Add the seeds and split pods to the poaching liquid. Pour in sugar.
INSERT INTO public.recipes VALUES (448, 'Fruit Leather', '20 mins', '5 hrs', '5 hrs 20 mins', '16', '1 sheet', '1 cup sugar, ¼ cup lemon juice, 4 cups peeled, cored and chopped apple, 4 cups peeled, cored and chopped pears', 'Preheat the oven to 150 degrees F (65 degrees C). Cover a baking sheet with a layer of plastic wrap or parchment paper.
INSERT INTO public.recipes VALUES (449, 'Cranberry Pear Salad', '15 mins', NULL, '15 mins', '6', NULL, '¾ cup olive oil, ¼ cup balsamic vinegar, 1 tablespoon dark brown sugar, 2 ½ teaspoons minced garlic, ½ teaspoon salt, ½ teaspoon freshly ground black pepper, 6 cups mixed baby greens, 3  pears, thinly sliced, 1 cup dried cranberries, 1 cup toasted pecans, ¾ cup cubed Havarti cheese, ½ cup toasted sliced almonds', 'Whisk olive oil, balsamic vinegar, brown sugar, garlic, salt, and black pepper in a medium bowl.
INSERT INTO public.recipes VALUES (450, 'Summer Fruit Salad with a Lemon, Honey, and Mint Dressing', '20 mins', NULL, '1 hrs 20 mins', '8', '8 servings', '4 cups cubed seeded watermelon, 2 cups sliced fresh strawberries, 2 large  fresh peaches, cut into cubes, 2 large  nectarines, cut into cubes, 1  red Anjou pear, cut into cubes, 1 cup seedless grapes, halved, 2  lemons, juiced, ¼ cup minced fresh mint (chocolate mint preferred), ½  lemon, zested, 1 tablespoon honey (fireweed honey preferred)', 'Combine watermelon, strawberries, peaches, nectarines, pear, and grapes in a large mixing bowl.
INSERT INTO public.recipes VALUES (451, 'Gorgonzola Pear Pasta', '10 mins', '15 mins', '25 mins', '2', NULL, '9 ounces penne pasta, 2 tablespoons butter, ½ cup grated Parmesan cheese, 3 tablespoons crumbled Gorgonzola cheese, ½ cup heavy whipping cream, 1 large pear, peeled and cubed, ½ cup chopped toasted walnuts,   ground black pepper to taste', 'Bring a large pot of lightly salted water to a rolling boil. Cook penne in the boiling water, stirring occasionally, until tender yet firm to the bite, about 11 minutes; drain.
INSERT INTO public.recipes VALUES (452, 'Duck Sauce', '20 mins', '40 mins', '1 hrs 30 mins', '8', '8 cups', '5 cups coarsely chopped mixed fruit (apples, plums, and pears), 1 cup water, ¾ cup apple juice, 1 teaspoon soy sauce, 1 tablespoon apricot preserves, ½ cup packed light brown sugar, ½ teaspoon garlic powder, ½ teaspoon dry mustard', 'Place fruit in a stock pot over medium high heat. Add water, apple juice, soy sauce, apricot preserves, brown sugar, garlic powder, and dry mustard. Bring to a simmer, stirring frequently to dissolve brown sugar. Reduce heat, and continue simmering for 40 minutes, or until fruit is completely soft. Remove from heat and allow to cool.
INSERT INTO public.recipes VALUES (453, 'Christmas Plum Pudding', '30 mins', '5 hrs', '5 hrs 30 mins', '20', '20 servings', '1 cup whole wheat flour, 2 ½ cups fresh bread crumbs, 4 ounces shredded suet, 3  eggs, beaten, 1 small carrot, grated, 1  apple - peeled, cored and shredded, ½ cup dark brown sugar, ½ cup chopped blanched almonds, 2 ounces preserved stem ginger in syrup, chopped, ⅛ cup ground almonds, ½ cup chopped walnuts, ⅜ cup halved candied cherries, ⅓ cup raisins, ⅜ cup dried currants, ⅜ cup golden raisins, 4 ounces candied mixed fruit peel, chopped, 4  plums, pitted and chopped, 1  lemon, juiced and zested, 1 ½ teaspoons mixed spice, ¾ teaspoon baking powder, ½ cup ale', 'In a large bowl, combine flour, bread crumbs, suet, eggs, carrot, apple, brown sugar, chopped blanched almonds, stem ginger, ground almonds, cherries, raisins, currants, golden raisins, mixed peel, plums, lemon juice and zest, mixed spice, baking powder and ale. Let each family member take a turn stirring and make a wish. If you have used more dry fruit than fresh, add a little extra ale to make the mixture less stiff.
INSERT INTO public.recipes VALUES (454, 'Plum Pudding', '15 mins', '35 mins', '50 mins', '6', '1 2-quart baking dish', '12  plums, pitted and halved, 1 cup white sugar, ½ cup water, 2 tablespoons tapioca, ½ teaspoon ground cinnamon, 2 ¼ cups all-purpose baking mix, 3 tablespoons white sugar, ⅔ cup milk, 3 tablespoons margarine, melted', 'Preheat oven to 350 degrees F (175 degrees C).
INSERT INTO public.recipes VALUES (506, 'Yummy Pomegranate Vinaigrette Dressing', '15 mins', NULL, '15 mins', '24', '3 cups', '1 cup olive oil, 1 cup pomegranate juice, 1 cup rice vinegar, ¼ cup white sugar, 2 tablespoons chopped shallots, 1 ¼ teaspoons chopped garlic, 1 teaspoon ground white pepper,   kosher salt to taste', 'Place olive oil, pomegranate juice, rice vinegar, white sugar, shallots, garlic, white pepper, and salt in a blender. Blend until smooth, about 2 minutes.', '4.7', 'https://www.allrecipes.com/recipe/245346/yummy-pomegranate-vinaigrette-dressing/', '/Side Dish/Sauces and Condiments/Salad Dressing Recipes/Vinaigrette Dressing Recipes/', 'Total Fat 9g 12%, Saturated Fat 1g 6%, Sodium 17mg 1%, Total Carbohydrate 8g 3%, Total Sugars 7g, Vitamin C 0mg 2%, Calcium 1mg 0%, Iron 0mg 1%, Potassium 4mg 0%', 'Prep Time: 15 mins, Total Time: 15 mins, Servings: 24, Yield: 3 cups', 'https://www.allrecipes.com/thmb/4Ln070FGZQiPuxWPYQcZbfeqU9A=/1500x0/filters:no_upscale():max_bytes(150000):strip_icc()/2909912-3d8cd518f4a1404c97d40b8a48b737d6.jpg');
INSERT INTO public.recipes VALUES (455, 'My Mother-in-Law''s Plum Bread', '15 mins', '45 mins', '1 hrs 10 mins', '8', '1 9x5-inch loaf', '1 cup pitted, chopped plums, 1 tablespoon all-purpose flour, ½ cup margarine, 1 cup white sugar, ½ teaspoon vanilla extract, 2  eggs, 1 ½ cups all-purpose flour, ½ teaspoon salt, ¼ teaspoon baking soda, ⅓ cup plain yogurt, ¼ cup brown sugar', 'Preheat oven to 350 degrees F (175 degrees C). Spray a 9x5-inch loaf pan with cooking spray, or line with parchment paper.
INSERT INTO public.recipes VALUES (456, 'Old Fashioned Prune Cake', NULL, NULL, NULL, '12', '1 Bundt or tube pan', '1 cup vegetable oil, 3  eggs, 1 ½ cups white sugar, 2 cups all-purpose flour, 1 teaspoon baking soda, 1 teaspoon salt, 1 teaspoon ground allspice, 1 teaspoon ground cinnamon, 1 teaspoon ground nutmeg, 1 cup buttermilk, 1 ¼ teaspoons vanilla extract, 1 cup prunes, pitted and chopped, 1 ½ cups chopped pecans, ¾ cup butter, ¾ cup buttermilk, 1 ½ teaspoons dark corn syrup, 1 ½ cups white sugar, 2 teaspoons vanilla extract', 'Preheat oven to 350 degrees F (175 degrees C). Grease and flour Bundt or tube pan.
INSERT INTO public.recipes VALUES (457, 'Baby Food: Plum', '10 mins', '10 mins', '20 mins', '6', '1 1/2 cups', '4  plums - peeled, pitted, and cut into small chunks', 'Place a steamer insert into a saucepan and fill with water to just below the bottom of the steamer. Bring water to a boil. Add plums, cover, and steam until tender, about 10 minutes.
INSERT INTO public.recipes VALUES (458, 'Easy Plum Cake', '15 mins', '45 mins', '1 hrs', '8', '1 cake', '¾ cup white sugar, ½ cup unsalted butter, at room temperature , 2 large eggs, 1 cup all-purpose flour, 1 teaspoon baking powder, 1 pinch salt, 12 medium Italian plums, halved and pitted, 1 ½ tablespoons cinnamon sugar, or to taste', 'Preheat the oven to 350 degrees F (175 degrees C). Grease a 10-inch springform pan.
INSERT INTO public.recipes VALUES (463, 'Plum Kuchen', '15 mins', '35 mins', '50 mins', '12', '12 servings', '½ cup white sugar, 2 tablespoons margarine, 2  eggs, beaten, 1 cup all-purpose flour, 1 teaspoon baking powder, ¼ teaspoon salt, 1 teaspoon vanilla extract, 10  Italian plums, halved and pitted', 'Preheat oven to 350 degrees F (175 degrees C). Grease and flour an 7x11-inch baking dish.
INSERT INTO public.recipes VALUES (459, 'Tangy Plum Liqueur', '1 hrs', NULL, '21 days 1 hrs', '80', '10 cups', '16 cups black or red plums, pitted and cut into eighths, 3 ¼ cups white sugar, divided, 3 cups 100 proof vodka, 1 ½ tablespoons vanilla extract, divided, 1  orange peel in pieces, divided', 'Layer half the plums into the bottom of a very large jar with a lid, pressing the plums down as tightly as possible. Pour half the sugar over the plums, then half the vodka over the sugar. Sprinkle on half the vanilla extract, and place about half the orange peel pieces into the jar. Layer the rest of the plums into the jar, pressing them down, and top them with the remaining sugar, vodka, vanilla extract, and orange peel pieces. Screw on the jar lid.
INSERT INTO public.recipes VALUES (460, 'Plum Pie', '30 mins', '1 hrs', '1 hrs 30 mins', '8', '1 pie', '3 cups all-purpose flour, ¾ cup white sugar, 2 ½ teaspoons baking powder, ⅛ teaspoon salt, ⅔ cup butter, 2  eggs, 1 teaspoon vanilla extract, 3 tablespoons milk, ½ teaspoon lemon zest, ½ cup all-purpose flour, ¼ cup packed brown sugar, ½ teaspoon ground cinnamon, ¼ teaspoon salt, ⅓ cup chopped hazelnuts, 1 teaspoon lemon zest, 3 tablespoons butter, 5 cups plums, pitted and sliced, 1 cup white sugar, ¼ cup all-purpose flour, 1 teaspoon ground cinnamon, ½ teaspoon ground nutmeg', 'Preheat oven to 375 degrees F (190 degrees C).
INSERT INTO public.recipes VALUES (461, 'Plum Cake', '20 mins', '40 mins', '1 hrs', '8', '1 9-inch cake', '3  eggs, ½ cup butter, softened, ½ cup white sugar, 1 teaspoon lemon zest, 1 cup all-purpose flour, ½ teaspoon baking powder, 1 ¼ cups plums, pitted and quartered', 'Preheat oven to 375 degrees F (190 degrees C). Grease and flour one 9-inch tube pan.
INSERT INTO public.recipes VALUES (462, 'Roasted Pork Tenderloin with Fresh Plum Sauce', '10 mins', '50 mins', '1 hrs', '2', '2 servings', '1  pork tenderloin,   salt and ground black pepper to taste, 1 tablespoon vegetable oil, 1  red onion, sliced, 2  shallots, sliced, 3  fresh thyme sprigs, or more to taste, 2  firm plums, pitted and each cut into 4 wedges, 1 cup water, 1 tablespoon balsamic vinegar, 1 teaspoon cold butter', 'Preheat oven to 400 degrees F (200 degrees C). Generously season pork tenderloin with salt and black pepper.
INSERT INTO public.recipes VALUES (465, 'Plum Clafouti', '10 mins', '1 hrs', '1 hrs 10 mins', '8', '8 servings', '6 tablespoons white sugar, divided, 14  Italian prune plums, halved and pitted, 3  eggs, 1 ⅓ cups milk, ⅔ cup all-purpose flour, 1 ½ teaspoons grated lemon zest, 2 teaspoons vanilla, 1 pinch salt, ½ teaspoon ground cinnamon, 2 tablespoons confectioners'' sugar', 'Preheat the oven to 375 degrees F (190 degrees C). Butter a 10 inch pie plate, and sprinkle 1 tablespoon of sugar over the bottom.
INSERT INTO public.recipes VALUES (466, 'Plum Butter', '10 mins', '6 hrs 45 mins', '18 hrs 55 mins', '32', '4 cups', '4 ½ pounds plums, pitted and diced, ¼ cup water, or as needed, 1 cup white sugar', 'Place plums in a large stockpot and add enough water to cover the bottom of stockpot; cook over very low heat, stirring occasionally, until plums are broken down, about 2 hours. Remove stockpot from heat and cool for 2 hours.
INSERT INTO public.recipes VALUES (467, 'Plum Blueberry Upside Down Cake', '30 mins', '40 mins', '1 hrs 10 mins', '12', '1 to 9 - inch round cake', '1 ¼ cups all-purpose flour, 1 ½ teaspoons baking powder, ¼ teaspoon salt, 3 tablespoons margarine, ¼ cup brown sugar, ⅓ cup margarine, 1 cup white sugar, 1  egg, 1 teaspoon vanilla extract, ¾ cup milk, 4  black plums, pitted and thinly sliced, ¾ cup blueberries', 'Preheat oven to 350 degrees F (175 degrees C). Grease a 9 inch cake pan. Combine the flour, baking powder and salt. Set aside.
INSERT INTO public.recipes VALUES (468, 'Spicy Oven-Roasted Plums', '15 mins', '20 mins', '35 mins', '4', NULL, '4  plums, halved and pitted, ½ cup orange juice, 2 tablespoons packed brown sugar, ½ teaspoon ground cinnamon, ⅛ teaspoon ground nutmeg, ⅛ teaspoon cumin, ⅛ teaspoon ground cardamom, ¼ cup toasted slivered almonds (Optional)', 'Preheat the oven to 400 degrees F (200 degrees C). Grease a shallow baking dish with cooking spray.
INSERT INTO public.recipes VALUES (514, 'Pavlova with Winter Fruits', '30 mins', '1 hrs', '2 hrs 30 mins', '3', '3 pavlovas', '4  egg whites, at room temperature, ¾ cup white sugar, ¼ cup superfine sugar, 1 ½ teaspoons cornstarch, ½ teaspoon orange blossom water (Optional), ½ teaspoon white vinegar', 'Preheat the oven to 250 degrees F (120 degrees C). Line a large baking sheet with parchment paper. Invert a small bowl onto the parchment paper and trace the rim with a pencil. Repeat twice more. Flip parchment paper over.
INSERT INTO public.recipes VALUES (469, 'Pork with Plum Sauce', '15 mins', '1 hrs', '1 hrs 15 mins', '4', NULL, '2 tablespoons vegetable oil, 4  boneless pork chops,   salt and ground black pepper to taste, 1 large clove garlic, minced, ¼ cup soy sauce, 2 tablespoons red wine vinegar, 2 tablespoons brown sugar, ¼ teaspoon ground ginger, ⅛ teaspoon ground cloves, 5  fresh plums, pitted and coarsely chopped', 'Heat vegetable oil in a skillet over medium-high heat. Season pork chops with salt and pepper; cook in hot oil until browned, about 2 minutes per side. Remove pork chops to a plate.
INSERT INTO public.recipes VALUES (470, 'Prune Whip', '20 mins', '30 mins', '50 mins', '6', '4 cups', '1 ⅓ cups pitted prunes, ⅓ cup water, ⅓ cup white sugar, 1 teaspoon lemon juice, 1 teaspoon vanilla extract, 6  egg whites, ¼ teaspoon cream of tartar', 'In a medium saucepan, simmer the prunes in water until soft, drain and puree. Combine the puree in a saucepan with the sugar and heat until the sugar dissolves. Add the lemon juice and vanilla.
INSERT INTO public.recipes VALUES (471, 'Fresh Fruit Frangipane Tart', '30 mins', '45 mins', '1 hrs 55 mins', '8', NULL, '3  puff pastry rectangles', 'Preheat the oven to 400 degrees F (200 degrees C).
INSERT INTO public.recipes VALUES (472, 'Plum Dumplings', '1 hrs 30 mins', '45 mins', '2 hrs 15 mins', '10', '25 dumplings', '25  Italian prune plums, 3 tablespoons sugar, 2 large potatoes, peeled and quartered', 'To pit the plums, slice them almost in half, open, and remove pit. Place about 1/3 teaspoon of sugar in the hollow of each plum; close the plum, and place in a bowl. Set aside.
INSERT INTO public.recipes VALUES (515, 'Cranberry-Pomegranate Mimosa', '5 mins', NULL, '5 mins', '1', '1 glass', '2 tablespoons white sugar, or as needed, 3  frozen cranberries, 1 fluid ounce cranberry-pomegranate juice (such as Ocean Spray®), 1 fluid ounce orange juice, 2 fluid ounces champagne', 'Fill a small plate with 1/4 inch of water. Pour sugar onto a second small plate, making a depth of 1/8 to 1/4 inch. Gently dip the rim of a champagne glass into the water. Raise the glass to allow excess water to drip off, then dip the rim into the sugar. Twist the glass to ensure the entire rim is coated. Discard remaining sugar.
INSERT INTO public.recipes VALUES (473, 'Damson Plum Cardamom Jam', NULL, '5 hrs 30 mins', '7 hrs 30 mins', '100', '12 pints', '5 pounds fresh Damson or Damask plums, 1 cup water, 12  whole cardamom pods, 4 cups white sugar, ¼ teaspoon butter', 'In a sink full of cool water, rinse and de-stem the plums. Place them in a thick-bottomed pan suitable for slow cooking and deep enough to allow frothing when the plums begin to boil. Add the water and cardamom pods and bring the mixture to a low boil over medium heat. Turn heat to low for a slow simmer and allow the fruit to cook down uncovered for 1 1/2 hours. Allow the plums to cool.
INSERT INTO public.recipes VALUES (474, 'Fresh Fruit Cobbler', '30 mins', '30 mins', '1 hrs', '6', '6 servings', '1 cup sliced fresh peaches, ¾ cup peeled, cored and sliced apple, ¾ cup peeled, cored and sliced pear, ½ cup blueberries, ½ cup pitted and sliced cherries, ½ cup pitted and sliced plums, 1  egg, ¾ cup white sugar, ¼ cup milk, 1 cup all-purpose flour, 1 teaspoon baking powder, ½ teaspoon salt, ½ teaspoon vanilla extract, 2 tablespoons butter, melted', 'Preheat oven to 350 degrees F (175 degrees C). Grease a 2 quart baking dish.
INSERT INTO public.recipes VALUES (475, 'Prune Cake', '30 mins', '45 mins', '1 hrs 25 mins', '12', '1 bundt cake', '1 cup pitted prunes, ½ cup water, 2 cups all-purpose flour, 1 ½ cups white sugar, 1 tablespoon ground allspice, 1 teaspoon baking soda, 1 teaspoon ground nutmeg, 1 teaspoon ground cinnamon, ½ teaspoon salt, 1 cup vegetable oil, 1 cup buttermilk, 2  eggs, lightly beaten, 1 ½ cups chopped pecans', 'Combine prunes and water in a small saucepan over medium-high heat. Bring to a boil, reduce heat to low, and simmer until prunes are tender, about 5 minutes. Drain and set aside.
INSERT INTO public.recipes VALUES (476, 'Delicious Oat Bran Cereal', '5 mins', '5 mins', '10 mins', '1', '1 serving', '1 cup water, ¼ teaspoon ground cinnamon, 5  dried pitted prunes, chopped, 1 teaspoon sugar substitute (such as Splenda), ¼ cup oat bran', 'Combine water, cinnamon, prunes, and sugar substitute in a saucepan over medium heat; bring to a boil; stir in the oat bran and boil for 2 minutes.', '4.2', 'https://www.allrecipes.com/recipe/152260/delicious-oat-bran-cereal/', '/Breakfast and Brunch/Cereals/Oatmeal Recipes/', 'Total Fat 2g 2%, Saturated Fat 0g 2%, Sodium 10mg 0%, Total Carbohydrate 42g 15%, Dietary Fiber 7g 25%, Total Sugars 18g, Protein 5g, Vitamin C 1mg 7%, Calcium 48mg 4%, Iron 2mg 13%, Potassium 451mg 10%', 'Prep Time: 5 mins, Cook Time: 5 mins, Total Time: 10 mins, Servings: 1, Yield: 1 serving', 'https://www.allrecipes.com/thmb/qRbsQx4K5PwYeMBM0ZqRGG8fKyA=/1500x0/filters:no_upscale():max_bytes(150000):strip_icc()/4566099-4fab1b71d86a412885a78c101a795149.jpg');
INSERT INTO public.recipes VALUES (477, 'Banana Plum Bread', '25 mins', '1 hrs', '1 hrs 25 mins', '12', '1 9x13-inch cake', '½ cup white sugar, ½ cup margarine, softened, 2  eggs, 2 ¾ cups all-purpose flour, 1 ½ teaspoons baking powder, ½ teaspoon baking soda, 1 ½ cups mashed ripe bananas, 1 cup plums, pitted and chopped', 'Preheat oven to 350 degrees F (175 degrees C). Grease a 9x13-inch baking dish.
INSERT INTO public.recipes VALUES (478, 'Rachel''s Sugar Plum Spice Jam', '30 mins', '45 mins', '2 hrs 15 mins', '120', '10 12-ounce jars', '10  red plums, pitted and chopped, 2 cups chopped fresh pineapple, ½ cup apple juice, ½ (12 fluid ounce) can frozen orange juice concentrate, 1  lemon, juiced, 1 ½ teaspoons ground cloves, 1 teaspoon ground allspice, 1 (1.75 ounce) package powdered fruit pectin, 1 tablespoon butter, 8 cups white sugar, 4 drops red food coloring', 'Place the plums, pineapple, apple juice, orange juice concentrate, and lemon juice into a large pot over medium-low heat, cover, and cook until the plums are soft, 15 to 20 minutes. Mash the plums and pineapple with a potato masher until thoroughly broken up, but leave small chunks of fruit in the mixture. With the fruit mixture at a slow simmer, stir in the cloves, allspice, pectin, and butter (to reduce foaming). Raise heat to high and bring the mixture to a full, rolling boil for 1 minute, stirring constantly. Mix in the sugar, stirring constantly, and cook for 1 more minute at a full, rolling boil. Remove from heat, stir in red food coloring until even in color, and skim off any foam.
INSERT INTO public.recipes VALUES (479, 'Grandma Skeet''s Prune Kolaches', '55 mins', '15 mins', '2 hrs 50 mins', '20', '20 kolaches', '1 cup warm water, 1 teaspoon salt, 1  egg, 2 tablespoons butter, room temperature, 3 cups bread flour, ¼ cup white sugar, 3 teaspoons bread machine yeast', 'Place the warm water, salt, egg and 2 tablespoons butter in the pan of a bread machine. Add bread flour, and pour 1/4 cup sugar on the edge of the pan. Make a shallow hole in the flour and add the yeast. Close the lid, and set machine for the DOUGH cycle.
INSERT INTO public.recipes VALUES (480, 'Potato Plum Dumplings', '35 mins', '20 mins', '2 hrs 55 mins', '12', '12 dumplings', '4 large russet potatoes, ½ teaspoon salt, 1 tablespoon butter, softened, 2  eggs, beaten, ¼ cup farina, 1 cup all-purpose flour, or as needed, 12  Italian prune plums, 12 cubes  white sugar, ½ cup butter, melted, ¼ cup white sugar, 1 cup dry bread crumbs,   additional melted butter and sugar for garnish (optional)', 'Scrub potatoes, and place them into a large pot with enough water to cover. bring to a boil, and cook until tender, about 40 minutes. Drain, and cool. When potatoes are cool enough to handle, peel, and press through a ricer into a large bowl. Set aside to cool. This part of the process can be done as much as one day in advance.
INSERT INTO public.recipes VALUES (481, 'Zwetschgendatschi (German Plum Sheet Cake)', '30 mins', '30 mins', '2 hrs', '16', '16 servings', '4 ¾ cups all-purpose flour, 4 teaspoons baking powder, 1 cup white sugar, 2 teaspoons vanilla sugar, 2 pinches salt, 1 ⅓ cups unsalted butter, room temperature and cut into chunks, 2 large eggs, 2 ¼ pounds Italian prune plums, halved and pitted, 2 tablespoons white sugar, 1 teaspoon ground cinnamon, 2 tablespoons unsalted butter, room temperature and cut into chunks, 1 tablespoon sliced almonds (Optional)', 'Combine flour and baking powder in a large bowl. Mix in 1 cup sugar, vanilla sugar, and salt. Add 1 1/3 cups butter and eggs. Knead everything into a smooth dough. Shape dough into a ball, press flat, cover, and chill in the refrigerator 1 hour to overnight.
INSERT INTO public.recipes VALUES (482, 'Far Breton', '15 mins', '40 mins', '55 mins', '8', '8 servings', '9 ounces pitted prunes, 1 cup all-purpose flour, ⅝ cup white sugar, 1 tablespoon vanilla sugar, 1 teaspoon baking powder, 1 pinch salt, 4  eggs, 3 cups whole milk, 2 tablespoons rum', 'Preheat the oven to 450 degrees F (230 degrees C). Grease a shallow 2 quart baking dish.
INSERT INTO public.recipes VALUES (483, 'Drozdzowka (Polish Yeast Plum Cake)', '1 hrs', '1 hrs', '2 hrs 20 mins', '24', '1 9x13-inch cake', '½ cup whole milk, 1 tablespoon all-purpose flour, 1 tablespoon white sugar, 2 (0.6 ounce) cakes cake yeast, 1 ⅓ cups margarine, ½ cup dry bread crumbs, 4  eggs, 1 ⅛ cups white sugar, 8 cups all-purpose flour, 4 teaspoons vanilla sugar, 1 cup whole milk, or as needed, 6 cups fresh plums, pitted and quartered, 1 ½ cups all-purpose flour, ½ cup butter, ½ cup white sugar, ½ teaspoon ground cinnamon (Optional)', 'In a saucepan over very low heat, warm up 1/2 cup of milk to no more than 100 degrees F (38 degrees C); stir in 1 tablespoon of flour and 1 tablespoon of sugar. Remove from heat and transfer to a bowl. Crumble the cake yeast into the milk mixture, and gently stir until the mixture becomes creamy. Cover the pan with a cloth, and set aside in a warm place until the yeast forms a spongy texture, 20 to 30 minutes.
INSERT INTO public.recipes VALUES (485, 'Plum Custard Kuchen', '30 mins', '1 hrs', '1 hrs 30 mins', '9', '1 to 9 - inch square pan', '1 cup all-purpose flour, 1 tablespoon white sugar, 1 teaspoon baking powder, ½ cup butter, 2 tablespoons heavy cream, 1  egg, 2 ½ cups pitted and sliced plums, ½ cup heavy cream, ½ cup white sugar, 1  egg, 1 teaspoon vanilla extract', 'Preheat oven to 350 degrees F (175 degrees C). In a large bowl, mix flour, 1 tablespoon sugar and baking powder in a bowl. Cut in butter until mixture looks like coarse crumbs. Stir in 2 tablespoons whipping cream and 1 egg. Press in bottom of ungreased 9-inch square pan and arrange plums over the top.
INSERT INTO public.recipes VALUES (486, 'Pork Tenderloin with Balsamic Plum Reduction', '15 mins', '30 mins', '45 mins', '4', '4 servings', '1  pork tenderloin,   salt and ground black pepper to taste, 1 tablespoon olive oil, 1 ½  plums, pitted and chopped, 2 tablespoons balsamic vinegar, 1 tablespoon brown sugar, 1 tablespoon honey, 2 tablespoons blueberry juice (Optional)', 'Preheat oven to 400 degrees F (200 degrees C). Line a baking sheet with foil.
INSERT INTO public.recipes VALUES (487, 'Plum Pudding II', '20 mins', '2 hrs', '2 hrs 20 mins', '6', '6 servings', '¼ cup butter, ⅓ cup brown sugar, 1 cup milk, 12  dates, pitted and chopped, ½ cup raisins, ¼ cup dried currants, ¼ cup candied mixed fruit peel, chopped, 1  orange, zested, 1 teaspoon baking soda, 1 cup self-rising flour, 2 teaspoons ground cinnamon, 1 pinch salt', 'Well grease a pudding mold.
INSERT INTO public.recipes VALUES (488, 'Peach and Plum Cake', '30 mins', '45 mins', '1 hrs 15 mins', '12', '1 9-inch square cake', '1 teaspoon unsalted butter, or as needed, 1 ½ cups white sugar, divided, 1 stick unsalted butter, room temperature, 2 extra large eggs, 1 cup plain yogurt, 1 teaspoon vanilla extract, 2 cups all-purpose flour, 1 teaspoon baking soda, 1 teaspoon baking powder, ½ teaspoon salt, 1 teaspoon ground cinnamon, 5 medium ripe plums, pitted and sliced, 3 large  ripe peaches - peeled, pitted, and sliced', 'Preheat the oven to 350 degrees F (175 degrees C). Butter a 9-inch square baking pan.
INSERT INTO public.recipes VALUES (489, 'Prune Filling', '10 mins', NULL, '10 mins', '24', '3 cups', '1 cup chopped pecans, 1 (16 ounce) can stewed prunes, 2 tablespoons white sugar, ½ teaspoon ground cinnamon, ¼ teaspoon ground cloves, 1 tablespoon lime juice', 'Chop pecans and prunes together in a blender or food processor, stir in the sugar, cinnamon, cloves and lime juice. Use as a filling for cookies or pastries.', '5.0', 'https://www.allrecipes.com/recipe/26216/prune-filling/', '/Desserts/Fillings/Fruit Fillings/', 'Total Fat 3g 4%, Saturated Fat 0g 2%, Sodium 1mg 0%, Total Carbohydrate 7g 3%, Dietary Fiber 1g 4%, Total Sugars 6g, Protein 1g, Vitamin C 1mg 4%, Calcium 7mg 1%, Iron 0mg 1%, Potassium 62mg 1%', 'Prep Time: 10 mins, Total Time: 10 mins, Servings: 24, Yield: 3 cups', 'https://www.allrecipes.com/thmb/rLCRIG0I7zNR32oUvZZEM-k8IaY=/1500x0/filters:no_upscale():max_bytes(150000):strip_icc()/5057331-66818de25d3c45749dca1964b39a5386.jpg');
INSERT INTO public.recipes VALUES (491, 'Fruit-Stuffed Pork Loin', '20 mins', '1 hrs 40 mins', '2 hrs', '8', '1 stuffed pork loin roast', '¾ cup chopped pitted prunes, ¾ cup chopped dried apricots, 1 tablespoon grated fresh ginger , 1 teaspoon grated orange zest, ½ teaspoon ground cumin, ½ teaspoon ground cinnamon,   salt and ground black pepper to taste, 1 (4 pound) boneless pork loin roast, butterflied , ¼ cup packed brown sugar, 2 teaspoons all-purpose flour, 2 teaspoons cider vinegar, 1 teaspoon ground cumin, 1 teaspoon mustard powder, ½ cup water, 1 teaspoon cornstarch, 1 tablespoon water', 'Preheat oven to 325 degrees F (165 degrees C).
INSERT INTO public.recipes VALUES (492, 'Plum Flummery', '15 mins', '5 mins', '3 hrs 50 mins', '5', '5 servings', '2 cups plums, pitted and sliced, 1 tablespoon water (Optional), 1 (.25 ounce) package unflavored gelatin, ½ cup hot water (Optional), ½ cup white sugar, 2 tablespoons lemon juice, ½ cup evaporated milk', 'Place the plums into a saucepan over medium-low heat, cover, and simmer, stirring occasionally, until the plums are soft, 5 to 10 minutes. If the mixture becomes too thick or starts to burn, add a tablespoon of water. Remove from heat, and allow to cool.
INSERT INTO public.recipes VALUES (493, 'Ponche de Frutas (Fruit Punch)', '20 mins', NULL, '20 mins', '20', '20 servings', '3  oranges, juiced, 3  lemons, juiced, ½ pound seedless green grapes, halved, ½ pound plums, pitted and chopped into small bite-size pieces, 1  fresh pineapple - peeled, cored and chopped into small bite-size pieces, 1 cup white sugar, 4 cups strong brewed black tea, chilled, 4 cups crushed ice', 'In a large punch bowl, combine orange juice, lemon juice, grapes, plums and pineapple. Stir in sugar. Pour in tea and crushed ice.
INSERT INTO public.recipes VALUES (494, 'Rogaliki (Polish Jam-Filled Crescents)', '1 hrs', '20 mins', '2 hrs', '40', '40 rogaliki', '3 ½ ounces compressed fresh yeast, 7 tablespoons milk, 5 ½ cups all-purpose flour, or more as needed, 2 ¼ cups unsalted butter, at room temperature, 4 tablespoons sour cream, 4 tablespoons white sugar, 2  eggs, 3  egg yolks, 1 ½ cups plum jam, 2 ½ cups confectioners'' sugar, 2 tablespoons water, or as needed', 'Stir milk and yeast together in a bowl until smooth. Set aside until foamy, about 10 minutes.
INSERT INTO public.recipes VALUES (495, 'Zwetschekuchen (German Plum Tart)', '30 mins', '45 mins', '5 hrs 15 mins', '12', '1 9-inch tart', '4 cups all-purpose flour, 1 ⅓ cups white sugar, 1 teaspoon grated fresh lemon peel, 1 pinch ground cinnamon, 1 cup butter, cut into chunks, 2  eggs, 2  egg yolks, 1 teaspoon water, if needed, 3 pounds Italian prune plums, 1 tablespoon white sugar, or to taste', 'Place the flour, 1 1/3 cup of sugar, lemon peel, cinnamon, and butter into the work bowl of a food processor, and process until the mixture turns grainy. Stop the machine, add eggs and egg yolks, and process in the machine until the mixture gathers itself up into one dough ball. If the dough doesn''t ball up, stop the machine, sprinkle several drops of water onto the dough, and process again. Place the dough into a covered container and refrigerate at least 3 hours or preferably overnight.
INSERT INTO public.recipes VALUES (516, 'Holiday Cranberry-Pomegranate Sauce', '15 mins', '20 mins', '8 hrs 35 mins', '24', '3 cups', '1 (12 ounce) bag fresh cranberries, rinsed and sorted, 1 cup white sugar, 1 cup orange juice, 1 teaspoon orange zest, ¼ teaspoon ground cloves, 2  cinnamon sticks, 1  pomegranate, peeled and seeds separated', 'Mix the cranberries, sugar, orange juice, orange zest, ground cloves, and cinnamon sticks together in a saucepan. Bring to a boil. Lower heat to medium, and simmer for 10 minutes, stirring constantly. Remove from the heat and cool.
INSERT INTO public.recipes VALUES (496, 'Plum Buckle', '30 mins', '45 mins', '1 hrs 15 mins', '12', '1 9x13-inch cake', '7 cups pitted and quartered plums, ⅔ cup butter, softened, 1 ½ cups white sugar, 2  eggs, 3 cups sifted all-purpose flour, 1 tablespoon baking powder, ½ teaspoon salt, 2 cups milk, 2 teaspoons vanilla extract, 1 cup white sugar, ½ cup butter, softened, ¼ cup all-purpose flour, 1 teaspoon cinnamon', 'Preheat oven to 350 degrees F (175 degrees C). Grease a 9x13-inch baking dish.
INSERT INTO public.recipes VALUES (497, 'Zucchini Plum Bread', '15 mins', '1 hrs', '1 hrs 25 mins', '24', '2 loaves', '2 cups shredded zucchini, 1 cup vegetable oil, 1 cup white sugar, 1 cup packed brown sugar, 3  eggs, 2 teaspoons vanilla extract, 2 cups all-purpose flour, 1 cup whole wheat flour, 1 teaspoon baking soda, 1 teaspoon salt, 1 teaspoon ground cinnamon, ½ teaspoon baking powder, 3 cups chopped plums, 1 tablespoon white sugar, 1 teaspoon ground cinnamon', 'Preheat oven to 350 degrees F (175 degrees C). Line 2 bread pans with parchment paper or spray with cooking spray.
INSERT INTO public.recipes VALUES (498, 'Spinach Pomegranate Salad', '10 mins', NULL, '10 mins', '4', NULL, '1 (10 ounce) bag baby spinach leaves, rinsed and drained, ½ cup walnut pieces, ½ cup crumbled feta, ¼ medium red onion, sliced very thin, ¼ cup alfalfa sprouts (Optional), ½ cup pomegranate seeds, or to taste, 4 tablespoons balsamic vinaigrette', 'Place spinach into a salad bowl. Top with walnuts, feta, red onion, alfalfa sprouts, and pomegranate seeds. Drizzle with vinaigrette.
INSERT INTO public.recipes VALUES (499, 'Chiles en Nogada (Mexican Stuffed Poblano Peppers in Walnut Sauce)', '1 hrs', '30 mins', '1 hrs 35 mins', '8', '8 servings', '8  poblano peppers', 'Roast poblano chiles over an open flame on a gas stove or grill until the skin is black and charred on all sides, turning often, 10 to 15 minutes.
INSERT INTO public.recipes VALUES (500, 'Christmas Pomegranate Salad', '10 mins', NULL, '10 mins', '2', NULL, '3 cups leafy salad green mix, ½ cup pomegranate seeds, ⅓ cup crumbled blue cheese, ¼ cup crushed walnuts, ¼ cup cranberry vinaigrette', 'Toss leafy greens, pomegranate seeds, blue cheese, and walnuts together in a medium-sized salad bowl. Add cranberry vinaigrette just before serving.', '4.8', 'https://www.allrecipes.com/recipe/268727/christmas-pomegranate-salad/', '/Salad/Green Salad Recipes/', 'Total Fat 17g 21%, Saturated Fat 5g 26%, Cholesterol 17mg 6%, Sodium 447mg 19%, Total Carbohydrate 22g 8%, Dietary Fiber 3g 11%, Total Sugars 11g, Protein 9g, Vitamin C 17mg 87%, Calcium 181mg 14%, Iron 2mg 10%, Potassium 547mg 12%', 'Prep Time: 10 mins, Total Time: 10 mins, Servings: 2', 'https://www.allrecipes.com/thmb/6Mo9DEcorHiAqGhtOKOJdohanxE=/1500x0/filters:no_upscale():max_bytes(150000):strip_icc()/JD_25825-4x3-1-a40f6990d57b468187c162e4dcfd15a4.jpg');
INSERT INTO public.recipes VALUES (501, 'Brenda''s Apple and Pomegranate Crisp', '15 mins', '45 mins', '1 hrs 10 mins', '8', NULL, '4 medium apples - peeled, cored and sliced, ½  pomegranate, skin and light-colored membrane removed, ½ cup brown sugar, 1 tablespoon ground cinnamon, ½ teaspoon ground nutmeg, ½ cup rolled oats, ½ cup all-purpose flour, ½ cup white sugar, ½ cup unsalted butter, melted', 'Preheat the oven to 375 degrees F (190 degrees C). Butter a 9x13-inch baking dish.
INSERT INTO public.recipes VALUES (502, 'Pomegranate Holiday Cocktail', '5 mins', NULL, '5 mins', '2', '2 cocktails', '3 cups ice, or as needed, 2 fluid ounces vodka, 2 fluid ounces pomegranate juice, 1  lime, juiced, ½ fluid ounce orange-flavored liqueur, 2 ½ fluid ounces club soda, or as needed, 1 teaspoon pomegranate seeds, or to taste', 'Fill 2 highball glasses and a cocktail shaker with ice.
INSERT INTO public.recipes VALUES (503, 'Pomegranate Jelly', '5 mins', '10 mins', '15 mins', '176', '11 8-ounce glasses', '7 ½ cups white sugar, 4 cups pomegranate juice, 2  lemons, juiced, 1 (6 fluid ounce) container liquid pectin', 'Combine sugar and pomegranate and lemon juices in a large stainless steel saucepan. Bring to boil over high heat; at once, stir in liquid pectin. Bring to a full rolling boil and boil for exactly 30 seconds. Remove from heat and skim off foam.
INSERT INTO public.recipes VALUES (504, 'Lamb Braised in Pomegranate', '15 mins', '2 hrs 30 mins', '2 hrs 45 mins', '6', NULL, '3 pounds lamb shoulder blade chops,   salt and freshly ground pepper to taste, 1 tablespoon vegetable oil, 1  onion, sliced, 1 pinch salt, 4 cloves garlic, sliced, 2 cups pomegranate juice, ⅓ cup aged balsamic vinegar, 8  fresh mint leaves, ¼ teaspoon dried rosemary, ¼ teaspoon red pepper flakes, 1 tablespoon honey, or more to taste, 2 tablespoons pomegranate seeds, 1 tablespoon sliced fresh mint leaves, 1 tablespoon pumpkin seeds', 'Preheat the oven to 300 degrees F (150 degrees C).
INSERT INTO public.recipes VALUES (505, 'Pomegranate Molasses Barbecue Sauce', '15 mins', NULL, '15 mins', '8', '1 cup', '1 ½ tablespoons dark soy sauce, 2 tablespoons ketchup, 2 tablespoons pomegranate molasses, 2 tablespoons honey, 1 tablespoon sunflower seed oil, 1 teaspoon smooth mustard, 1 clove garlic, minced, ¼ teaspoon sea salt, ¼ teaspoon coarsely ground black pepper, ¼ teaspoon ground paprika', 'In a bowl, stir together the soy sauce, ketchup, pomegranate molasses, honey, sunflower seed oil, mustard, garlic, sea salt, black pepper, and paprika to make a smooth paste.', '4.8', 'https://www.allrecipes.com/recipe/214977/pomegranate-molasses-barbecue-sauce/', '/Side Dish/Sauces and Condiments/Sauces/BBQ Sauce Recipes/', 'Total Fat 2g 2%, Saturated Fat 0g 1%, Sodium 266mg 12%, Total Carbohydrate 6g 2%, Dietary Fiber 0g 0%, Total Sugars 5g, Protein 0g, Vitamin C 1mg 4%, Calcium 3mg 0%, Iron 1mg 4%, Potassium 28mg 1%', 'Prep Time: 15 mins, Total Time: 15 mins, Servings: 8, Yield: 1 cup', 'https://www.allrecipes.com/thmb/q4lUyUiZURYCZ4Av6Imx8kfSvHk=/1500x0/filters:no_upscale():max_bytes(150000):strip_icc()/6372736-ef5b46b37de4413b9a4081c26ceec06d.jpg');
INSERT INTO public.recipes VALUES (507, 'Middle Eastern Rice Pilaf with Pomegranate', '10 mins', '25 mins', '35 mins', '4', '4 servings', '2 tablespoons olive oil, 1  onion, finely chopped, 1 cup long-grain rice, 2 ¼ cups hot vegetable broth, 4  saffron threads, 1 pinch ground allspice, 3 tablespoons unsalted shelled pistachios, 1 tablespoon butter, 1 large pomegranate, peeled and seeds separated,   salt and freshly ground black pepper', 'Heat oil in a saucepan over medium heat and cook onion until soft and translucent. Add rice and toast until fragrant, 2 to 3 minutes. Pour in hot vegetable broth and bring to a boil. Add saffron and allspice, reduce heat to medium-low, cover, and simmer until rice is tender and liquid has been absorbed, about 20 minutes.
INSERT INTO public.recipes VALUES (508, 'Pear and Pomegranate Salad', '10 mins', '2 mins', '12 mins', '2', '2 salads', '3 cups green leaf lettuce, rinsed and torn, 1  Bartlett or Anjou pear, ⅓ cup pomegranate seeds, 1 tablespoon vegetable oil, 2 tablespoons pomegranate juice, 1 tablespoon lemon juice, 1 teaspoon prepared Dijon-style mustard, ½ tablespoon honey,   ground black pepper to taste', 'Divide the lettuce between two bowls. Halve and core the pear, then cut each half in slices. Divide the pear slices and pomegranate seeds among the two bowls and mix gently.
INSERT INTO public.recipes VALUES (509, 'Heart Healthy Blueberry Smoothie', '10 mins', NULL, '10 mins', '2', '2 servings', '1 cup blueberries, ¾ cup pomegranate juice, ½ cup low-fat plain Greek-style yogurt, ½ cup skim milk, ½ cup rolled oats, ¼ cup granular sucralose sweetener (such as Splenda®), 1 teaspoon ground cinnamon', 'Blend blueberries, pomegranate juice, yogurt, milk, oats, sweetener, and cinnamon together in a blender until smooth, about 2 minutes.', '4.0', 'https://www.allrecipes.com/recipe/235261/heart-healthy-blueberry-smoothie/', '/Drinks Recipes/Smoothie Recipes/Blueberry/', 'Total Fat 3g 4%, Saturated Fat 1g 6%, Cholesterol 4mg 1%, Sodium 50mg 2%, Total Carbohydrate 45g 16%, Dietary Fiber 4g 16%, Total Sugars 25g, Protein 10g, Vitamin C 7mg 36%, Calcium 103mg 8%, Iron 1mg 7%, Potassium 230mg 5%', 'Prep Time: 10 mins, Total Time: 10 mins, Servings: 2, Yield: 2 servings', 'https://www.allrecipes.com/thmb/8THqMejnVd39ggiPUc3t-Z0P36s=/1500x0/filters:no_upscale():max_bytes(150000):strip_icc()/1129213-f0ce7480966b467bb126c71199a11f94.jpg');
INSERT INTO public.recipes VALUES (511, 'Spiced Pears and Pomegranate', '10 mins', NULL, '10 mins', '4', '4 servings', '3  pears - peeled, cored and cut into wedges, 1  pomegranate, skin and light-colored membrane removed, 1 tablespoon fresh lemon juice, 2 tablespoons light brown sugar, ¼ teaspoon ground nutmeg, ½ teaspoon ground cinnamon, 2 tablespoons finely chopped almonds (Optional), 4 sprigs fresh mint leaves for garnish (Optional)', 'Place the sliced pears and pomegranate seeds into a bowl. Toss with lemon juice to coat. Combine the brown sugar, nutmeg, and cinnamon in a small cup or bowl, then mix into the fruit. Cover and refrigerate for at least 1 hour before serving to blend the flavors. Serve in individual dishes, and garnish with a sprinkling of chopped almonds and a sprig of mint.', '4.4', 'https://www.allrecipes.com/recipe/56148/spiced-pears-and-pomegranate/', '/Desserts/', 'Total Fat 2g 2%, Saturated Fat 0g 1%, Sodium 5mg 0%, Total Carbohydrate 39g 14%, Dietary Fiber 6g 20%, Total Sugars 29g, Protein 2g, Vitamin C 13mg 63%, Calcium 38mg 3%, Iron 1mg 4%, Potassium 329mg 7%', 'Prep Time: 10 mins, Total Time: 10 mins, Servings: 4, Yield: 4 servings', 'https://www.allrecipes.com/thmb/C9SUglRUXZ-NNT7M_-F8tZBUW-c=/1500x0/filters:no_upscale():max_bytes(150000):strip_icc()/5210-7c1b62609ae34163abd4a8d55d59f0e4.jpg');
INSERT INTO public.recipes VALUES (512, 'Chef John''s Sweet Potato Biscuits', '20 mins', '20 mins', '40 mins', '8', '8 large or 12 regular biscuits', '1 large orange-fleshed sweet potato, peeled, 1 teaspoon salt, 1 tablespoon brown sugar, ½ cup buttermilk, 3 ¼ cups self-rising flour, 1 ½ sticks unsalted butter, frozen, 1 tablespoon melted butter', 'Cut sweet potato in half lengthwise. Cut each in half again lengthwise, then in half cross-wise. Cut each piece in half to make about 16 evenly sized chunks. Transfer into pot; cover with water and add salt. Bring to a simmer on high heat; reduce heat to medium-low and cook until potatoes are tender, about 17 minutes. Drain thoroughly; return to pot and mash potatoes. You will need 1 1/2 cups mashed sweet potatoes. Cool thoroughly.
INSERT INTO public.recipes VALUES (513, 'Spinach and Persimmon Salad with Goat Cheese and Pomegranate', '20 mins', NULL, '20 mins', '2', '2 servings', '1  Fuyu persimmon, peeled and cored, 2 cups roughly chopped spinach, 3 tablespoons pomegranate seeds, 2 ounces goat cheese, crumbled, 1 tablespoon sliced almonds', 'Slice persimmon into 1/4-inch rounds, then slice each round into quarters.
INSERT INTO public.recipes VALUES (517, 'Pomegranate Stew with Chicken (Khoresh Fesenjan)', '15 mins', '2 hrs 30 mins', '2 hrs 45 mins', '6', '6 servings', '2 tablespoons olive oil, 1 ½ pounds chicken legs, cut up, 1  white onion, thinly sliced, ½ pound walnuts, toasted and finely ground in a food processor, 1 teaspoon salt, 4 cups pomegranate juice, ½ teaspoon cardamom (Optional), 2 tablespoons sugar (Optional)', 'Heat olive oil in a large skillet over medium heat. Place chicken and onions in skillet, and cook 20 minutes, stirring occasionally. Mix in pureed walnuts, salt, pomegranate juice, and cardamom. Bring to a boil. Reduce heat to low, cover, and simmer for 1 1/2 hours, stirring occasionally. (If the sauce becomes too thick, stir in 1/4 cup warm water.) Mix in sugar, adjust seasoning, and simmer 30 minutes more.', '4.2', 'https://www.allrecipes.com/recipe/85118/pomegranate-stew-with-chicken-khoresh-fesenjan/', '/Soups, Stews and Chili Recipes/Stews/Chicken/', 'Total Fat 39g 50%, Saturated Fat 6g 29%, Cholesterol 64mg 21%, Sodium 445mg 19%, Total Carbohydrate 95g 35%, Dietary Fiber 3g 10%, Total Sugars 83g, Protein 24g, Vitamin C 7mg 33%, Calcium 51mg 4%, Iron 4mg 20%, Potassium 329mg 7%', 'Prep Time: 15 mins, Cook Time: 2 hrs 30 mins, Total Time: 2 hrs 45 mins, Servings: 6, Yield: 6 servings', 'https://www.allrecipes.com/thmb/i4zJSe3VyGcvvHCpmiGaz9tJl0g=/1500x0/filters:no_upscale():max_bytes(150000):strip_icc()/8815-856fad791c744317aaecd2701c66d0ef.jpg');
INSERT INTO public.recipes VALUES (518, 'Cranberry Pomegranate Sauce', '30 mins', '45 mins', '1 hrs 15 mins', '24', '5 cups', '2 large tart apples, 2  pomegranates, peeled and seeds separated, 1 (16 fl oz) bottle pomegranate juice, 2 cups white sugar, 2 large  oranges, 2 (12 ounce) bags fresh cranberries, rinsed and sorted, 1 cup pecans, chopped', 'Peel and core apples, and put peelings and cores in a small saucepan with pomegranate seeds, 1/2 cup juice, and 1/2 cup sugar. Bring to a boil, and then reduce heat to simmer. Cook for 30 minutes.
INSERT INTO public.recipes VALUES (519, 'Smokey Butternut Squash Soup', '15 mins', '45 mins', '1 hrs', '6', '6 servings', '1  butternut squash - peeled and cut into cubes, seeds removed and reserved, ½  shallot, diced, 3 tablespoons canola oil, divided , 2 teaspoons smoked paprika, 1 ½ teaspoons chili powder, 1 ½ teaspoons chipotle chile powder, 1 teaspoon minced fresh ginger,   salt and ground black pepper to taste, 6  fresh Brussels sprouts, cored and separated into leaves, 2 tablespoons maple syrup, 1 ½ cups almond milk, ¼ cup crumbled goat cheese, or to taste,   seeds of 1 pomegranate', 'Preheat oven to 375 degrees F (190 degrees C). Line a roasting pan with a large sheet of aluminum foil.
INSERT INTO public.recipes VALUES (520, 'Pomegranate Grenadine', '5 mins', '20 mins', '55 mins', '32', '32 servings', '4 cups pomegranate juice, divided, 1 cup white sugar', 'Combine 3 cups pomegranate juice and sugar together in a saucepan; heat to 244 degrees F (118 degrees C) or until a small amount of mixture dropped into cold water forms a firm ball. Remove saucepan from heat and cover with a lid; let cool until pan is cool enough to touch. Stir remaining 1 cup pomegranate juice into mixture. Refrigerate.', '5.0', 'https://www.allrecipes.com/recipe/237763/pomegranate-grenadine/', '/Side Dish/Sauces and Condiments/Syrup Recipes/', 'Sodium 1mg 0%, Total Carbohydrate 11g 4%, Total Sugars 11g, Calcium 0mg 0%, Potassium 0mg 0%', 'Prep Time: 5 mins, Cook Time: 20 mins, Additional Time: 30 mins, Total Time: 55 mins, Servings: 32, Yield: 32 servings', 'https://www.allrecipes.com/thmb/n4zz7VM_jeYXB5-oRLMSRtUGdoo=/1500x0/filters:no_upscale():max_bytes(150000):strip_icc()/1172032-ef4749c216f744e6a644f3aef3597a1e.jpg');
INSERT INTO public.recipes VALUES (521, 'Halloumi Three-Bean Salad with Pomegranate-Harissa Vinaigrette', '10 mins', '15 mins', '40 mins', '8', '8 servings', '7 ounces halloumi cheese, cut into 1-inch slabs, 2 tablespoons pomegranate vinegar, 1 tablespoon honey, 1 ½ teaspoons harissa, or more to taste, 3 tablespoons olive oil, 1 pinch freshly ground black pepper, 1 cup black beans, drained and rinsed, 1 cup kidney beans, drained and rinsed, 1 cup white beans, drained and rinsed, ⅓ cup chopped red onion, 2 tablespoons chopped fresh mint, 2 tablespoons chopped fresh cilantro', 'Heat a large nonstick pan over medium-high heat. Cook each halloumi slab on all 4 sides, about 5 minutes. Set aside and allow to cool slightly; cut into 1/4-inch cubes.
INSERT INTO public.recipes VALUES (522, 'Salmon with Pomegranate Glaze', '10 mins', '11 mins', '36 mins', '4', '4 fillets', '⅓ cup pomegranate juice, 1 tablespoon soy sauce, or to taste, 1 clove garlic, sliced, 4 (6 ounce) fillets salmon, 2 tablespoons olive oil, ½  pomegranate, peeled and seeds separated', 'Whisk pomegranate juice, soy sauce, and garlic together in a shallow non-reactive bowl until marinade is well mixed. Add salmon and turn to coat. Cover and marinate for 15 minutes.
INSERT INTO public.recipes VALUES (523, 'Apple, Pomegranate, and Pecan Salad', '20 mins', NULL, '20 mins', '8', '8 servings', '½ cup pomegranate juice, 1 tablespoon balsamic vinegar, 1 teaspoon Dijon mustard, 1 teaspoon honey, ¼ cup canola oil, ⅛ teaspoon salt, ⅛ teaspoon ground black pepper, 2 medium Granny Smith apples, cored and chopped, 1 (5 ounce) package baby spinach, ⅔ cup pomegranate seeds, ⅓ cup candied pecans, ¼ cup crumbled feta cheese', 'Combine pomegranate juice, balsamic vinegar, Dijon, and honey in the bowl of a food processor; pulse until combined. Keep the blade running and slowly pour canola oil in through the food chute until smooth. Add salt and pepper and set dressing aside.
INSERT INTO public.recipes VALUES (524, 'Creamy Pomegranate Ice Cream', '5 mins', NULL, '35 mins', '6', '3 cups', '1 cup heavy cream, 1 cup white sugar, 1 cup pomegranate juice, 1 teaspoon vanilla extract, 1 pinch salt', 'Stir together the heavy cream and sugar. Stir in the pomegranate juice, vanilla extract, and salt. Add the mixture to an ice cream maker and freeze according to the manufacturer''s directions.', '4.0', 'https://www.allrecipes.com/recipe/200443/creamy-pomegranate-ice-cream/', '/Desserts/Frozen Dessert Recipes/Ice Cream/', 'Total Fat 15g 19%, Saturated Fat 9g 46%, Cholesterol 54mg 18%, Sodium 17mg 1%, Total Carbohydrate 41g 15%, Total Sugars 39g, Protein 1g, Vitamin C 0mg 1%, Calcium 26mg 2%, Potassium 32mg 1%', 'Prep Time: 5 mins, Additional Time: 30 mins, Total Time: 35 mins, Servings: 6, Yield: 3 cups', 'https://www.allrecipes.com/thmb/-8LvSaNIhaOg2I0WqalIkd-FcDs=/1500x0/filters:no_upscale():max_bytes(150000):strip_icc()/672087-942d677c8f2f46b6a4f7a4d382ab50aa.jpg');
INSERT INTO public.recipes VALUES (525, 'Spiced Pomegranate Syrup', '5 mins', '5 mins', '20 mins', '6', '1 cup syrup', '¾ cup pomegranate juice, ¾ cup Shiraz or other dry red wine, 2 tablespoons fresh lemon juice, 1 ½ teaspoons ground cinnamon, ¼ teaspoon ground nutmeg, ⅛ teaspoon ground cloves, ⅛ teaspoon ground ginger, 1 tablespoon butter, ½ cup packed brown sugar, divided', 'Combine the pomegranate juice, wine, and lemon juice in a bowl. Whisk in the cinnamon, nutmeg, cloves and ginger. Crumble in half of the brown sugar and whisk mixture until sugar dissolves.
INSERT INTO public.recipes VALUES (526, 'Roasted Pork Shoulder with Pomegranate Sauce', '20 mins', '1 hrs 15 mins', '1 hrs 55 mins', '4', NULL, '1 (3 pound) bone-in pork shoulder roast, 2 teaspoons minced garlic,   kosher salt and ground black pepper to taste, 2  pomegranates with the seeds removed, ½ cup water, 2 tablespoons balsamic vinegar, 2 tablespoons turbinado sugar, ¼ teaspoon ground cinnamon', 'Preheat the oven to 325 degrees F (165 degrees C). Season the pork roast with garlic, kosher salt, and pepper. Place in a roasting pan.
INSERT INTO public.recipes VALUES (528, 'Freekeh Salad with Tahini Dressing', '10 mins', '30 mins', '1 hrs 10 mins', '6', '6 servings', '1 cup freekeh, 2 cups chicken broth, 3 tablespoons apple cider vinegar, 1 tablespoon tahini, 1 teaspoon honey, 2 tablespoons olive oil,   salt and ground black pepper to taste, ½ cup pomegranate seeds, ¼ cup red onion, minced, 2 tablespoons minced fresh mint, 2 tablespoons minced fresh parsley, ½ cup crushed pistachios', 'Stir freekeh in a medium-sized saucepan over medium-high heat until lightly toasted and fragrant, about 3 minutes. Add broth and bring to a simmer. Cover pan and cook until water is absorbed, about 20 minutes. Remove from heat and let stand 5 minutes. Transfer freekeh to a bowl to cool.
INSERT INTO public.recipes VALUES (529, 'Pretty Pomegranate Salad', '15 mins', NULL, '15 mins', '4', '1 salad', '10 ounces fresh baby spinach leaves, 10 ounces arugula leaves, ½  red onion, thinly sliced, 1 (10 ounce) can mandarin oranges, drained, 1  pomegranate, peeled and seeds separated', 'Place the spinach and arugula leaves into a mixing bowl. Add the onion, mandarin oranges, and pomegranate seeds. Toss gently by hand to mix.', '4.5', 'https://www.allrecipes.com/recipe/214633/pretty-pomegranate-salad/', '/Salad/Green Salad Recipes/Spinach Salad Recipes/', 'Total Fat 1g 1%, Saturated Fat 0g 1%, Sodium 80mg 3%, Total Carbohydrate 20g 7%, Dietary Fiber 4g 13%, Total Sugars 15g, Protein 5g, Vitamin C 58mg 289%, Calcium 193mg 15%, Iron 3mg 18%, Potassium 863mg 18%', 'Prep Time: 15 mins, Total Time: 15 mins, Servings: 4, Yield: 1 salad', 'https://www.allrecipes.com/thmb/ppyYOGpBqBiQk5fmGIE00TD7UK8=/1500x0/filters:no_upscale():max_bytes(150000):strip_icc()/1067083-d53eb576d9fc451ab7a480b5fbe3989f.jpg');
INSERT INTO public.recipes VALUES (530, 'Pomegranate Relish', '5 mins', '5 mins', '10 mins', '5', '4 to 6 servings', '2  pomegranates, 3 tablespoons olive oil, 1  shallot, minced, 1 tablespoon lime juice,   salt and pepper to taste, ½ cup fresh cilantro, chopped', 'Juice the pomegranates retaining the seeds and juice.
INSERT INTO public.recipes VALUES (531, 'Khoresht Fesenjaan (Chicken with Pomegranate Sauce)', '20 mins', '3 hrs 30 mins', '3 hrs 50 mins', '12', '12 servings', '½ cup vegetable oil, 4 medium red onions, thinly sliced, 3 pounds bone-in chicken pieces, 2 cups hot water or as needed, 2 ½ cups pomegranate juice, 4 cups chopped walnuts, 2 tablespoons freshly ground cardamom, 2 tablespoons ground cinnamon, 1 medium butternut squash, seeded and cubed, ¼ teaspoon saffron powder, 1 teaspoon salt, or to taste', 'Heat the oil in a large heavy skillet over medium heat. Stir in sliced onions; cook and stir until the onion has softened and turned translucent, about 5 minutes. Reduce heat to medium-low, and continue cooking and stirring until the onion is very tender and dark brown, 15 to 20 minutes more.
INSERT INTO public.recipes VALUES (532, 'Persimmon, Pomegranate, and Massaged Kale Salad', '25 mins', '5 mins', '30 mins', '4', '4 servings', '½ cup raw macadamia nuts, 2 tablespoons maple syrup, divided, 1 pinch salt', 'Preheat oven to 375 degrees F (190 degrees C). Line a baking sheet with parchment paper.
INSERT INTO public.recipes VALUES (533, 'Zesty Salad', '20 mins', '10 mins', '40 mins', '2', '2 servings', '1 small potato, cut into cubes, ½ cup finely chopped cabbage, ¼ cup fresh pomegranate seeds , ½  carrot, cut into matchsticks, 1 tablespoon extra-virgin olive oil, 1 teaspoon lemon juice, 1 clove garlic, minced, ½ teaspoon salt, ¼ teaspoon brown sugar, ¼ teaspoon red pepper flakes', 'Place potato cubes into a small pot and cover with salted water; bring to a boil. Reduce heat to medium-low and simmer until tender, 5 to 10 minutes. Drain and let cool, about 10 minutes.
INSERT INTO public.recipes VALUES (534, 'Quinoa Salad with Broccoli, Nuts, and Pomegranate', '15 mins', '30 mins', '45 mins', '4', '4 servings', '2 cups water, 1 cup quinoa, 1 cube vegetable bouillon, 2 cups broccoli florets, ½ cup finely diced red onion, ½ cup finely chopped Brazil nuts, 1 large pomegranate, seeded, 2 tablespoons olive oil, or to taste, 1 tablespoon balsamic vinegar, or to taste, 1 teaspoon honey, or to taste,   salt and ground black pepper to taste', 'Combine water, quinoa, and vegetable bouillon in a saucepan. Bring to a boil over medium-high heat. Reduce heat, cover, and simmer until quinoa has doubled in size and looks like transparent little pearls, 25 to 30 minutes.
INSERT INTO public.recipes VALUES (535, 'Healthy Apple and Kale Salad', '15 mins', NULL, '15 mins', '3', '3 servings', '10 ounces kale, shredded, 2  Honeycrisp apples, thinly sliced, 1  pomegranate, seeds only, ½ teaspoon ground cinnamon,   Dressing:, 2 tablespoons extra-virgin olive oil, 2 tablespoons lemon juice, 1  shallot, thinly sliced, 1 tablespoon chopped fresh thyme,   ground black pepper to taste, 1 pinch crushed red pepper flakes', 'Massage kale with your hands until leaves have softened, about 2 minutes. Place in a large bowl. Add apples, pomegranate seeds, and cinnamon.
INSERT INTO public.recipes VALUES (536, 'Pomegranate Glazed Carrots', '10 mins', '15 mins', '25 mins', '4', '4 servings', '1 tablespoon butter, 3 cups peeled, sliced carrots,   salt and ground black pepper to taste, ¼ cup orange juice, ¼ cup pomegranate juice', 'Melt butter in a skillet over medium heat. Cook and stir carrots in the hot butter until they begin to soften, about 5 minutes; season with salt and black pepper.
INSERT INTO public.recipes VALUES (537, 'World''s Best Guacamole', '25 mins', NULL, '2 hrs 25 mins', '6', '6 servings', '¼ cup minced onion, 2  limes, juiced, 2  serrano chile peppers, or to taste, 2  limes, juiced,   salt to taste, 4  ripe avocados, peeled and pitted, ¼ cup chopped fresh cilantro, ¼ cup pomegranate seeds, divided, 1 sprig cilantro for garnish', 'Combine the onion with the juice of 2 limes in a small bowl; allow the onion to soak in the lime juice for 2 hours. Strain through a fine-mesh sieve and discard the lime juice. Set the onions aside.
INSERT INTO public.recipes VALUES (538, 'Persimmon Bread I', NULL, NULL, NULL, '6', '1 loaf', '2  eggs, 1 ½ cups all-purpose flour, ¾ cup white sugar, ½ teaspoon salt, ½ cup vegetable oil, 1 teaspoon ground cinnamon, 1 cup persimmon pulp, ½ cup chopped walnuts, 1 teaspoon baking soda, ½ cup raisins', 'Preheat oven to 325 degrees F (165 degrees C). Oil a 9 x 4 inch pan.
INSERT INTO public.recipes VALUES (561, 'Fuyu Persimmon and Burrata Caprese Salad', '10 mins', NULL, '10 mins', '2', '2 servings', '1  Fuyu persimmon, stem removed and sliced into rounds, 1 (4 ounce) ball burrata cheese, 1 ½ teaspoons balsamic glaze, 1 ½ teaspoons extra-virgin olive oil, 5 leaves fresh basil, or more to taste, 1 pinch freshly ground black pepper', 'Place persimmon rounds on a platter. Cut burrata ball into 5 or 6 pieces, ensuring that each piece has some of the firm outer shell (mozzarella) as well as some of the creamy inside (stracciatella and cream). Distribute burrata pieces around persimmon rounds. Drizzle with balsamic glaze and olive oil. Scatter basil leaves on top and sprinkle with pepper.', '5.0', 'https://www.allrecipes.com/recipe/277069/fuyu-persimmon-and-burrata-caprese-salad/', '/Salad/', 'Total Fat 16g 20%, Saturated Fat 9g 43%, Cholesterol 40mg 13%, Sodium 140mg 6%, Total Carbohydrate 6g 2%, Dietary Fiber 0g 1%, Protein 8g, Vitamin C 9mg 43%, Calcium 8mg 1%, Iron 1mg 3%, Potassium 49mg 1%', 'Prep Time: 10 mins, Total Time: 10 mins, Servings: 2, Yield: 2 servings', 'https://www.allrecipes.com/thmb/Ls5QKwTwj80p5ag9J5eEOKy5l4k=/1500x0/filters:no_upscale():max_bytes(150000):strip_icc()/7239203-aeddaeda9ff14cc5a27782dc6db0b34d.jpg');
INSERT INTO public.recipes VALUES (539, 'Persimmon Bread II', '10 mins', '1 hrs', '1 hrs 10 mins', '24', '3 - 6x3 inch loaves', '1 cup persimmon pulp, 2 teaspoons baking soda, 3 cups white sugar, 1 cup vegetable oil, 4  eggs, 1 ½ teaspoons ground cinnamon, ½ teaspoon ground nutmeg, 1 ½ teaspoons salt, ⅔ cup water, 3 cups all-purpose flour, 1 cup chopped walnuts', 'Preheat the oven to 350 degrees F (175 degrees C). Grease three 6x3 inch loaf pans.
INSERT INTO public.recipes VALUES (540, 'Fuyu Persimmon Pie', '20 mins', '1 hrs 10 mins', '3 hrs 30 mins', '10', '1 9-inch pie', '½ cup unsalted butter, 3 tablespoons all-purpose flour, ½ cup white sugar, ½ cup packed brown sugar, ¼ cup lemon juice, 1 teaspoon ground cinnamon, 1 (14.1 ounce) package 9-inch pie crusts, 3 pounds Fuyu persimmons - peeled, cored, and sliced, 1 tablespoon cinnamon sugar, or to taste', 'Preheat the oven to 425 degrees F (220 degrees C).
INSERT INTO public.recipes VALUES (541, 'Easy Persimmon Jam', '15 mins', '15 mins', '1 hrs', '16', '16 servings', '12 ounces persimmon flesh, cut into small chunks, 5 ounces white sugar, 3 ounces persimmon skin, finely sliced, 2 tablespoons lemon juice, ¾ ounce lemon zest, finely sliced', 'Combine persimmon flesh, sugar, persimmon skin, lemon juice, and lemon zest in a small pot over medium heat; bring to a boil. Reduce heat to low and simmer until persimmon flesh softens and jam thickens, about 10 minutes.
INSERT INTO public.recipes VALUES (542, 'Persimmon Pie', '15 mins', '40 mins', '2 hrs 25 mins', '8', '1 to 9 - inch pie', '1 recipe pastry for a 9 inch single crust pie, 2  eggs, ½ teaspoon ground cinnamon, ½ cup white sugar, ¼ teaspoon salt, 2 cups half-and-half cream, 1 cup persimmon pulp, 2 tablespoons butter, melted, 1 teaspoon lemon juice', 'Preheat oven to 450 degrees F (230 degrees C). Place a sheet pan on the lowest oven rack to preheat.
INSERT INTO public.recipes VALUES (543, 'Old-Fashioned Persimmon Pudding', '25 mins', '1 hrs', '1 hrs 55 mins', '12', '1 9x13-inch dish', '  cooking spray, 4 cups all-purpose flour, 1 teaspoon baking soda, 1 teaspoon baking powder, ½ teaspoon salt, 1 teaspoon cinnamon, 1 cup white sugar, 1 cup brown sugar, 3  eggs, beaten, 2 cups milk, 2 ½ cups persimmon pulp, 6 tablespoons butter, melted', 'Preheat oven to 300 degrees F (150 degrees C). Spray a 9x13-inch baking dish with cooking spray.
INSERT INTO public.recipes VALUES (544, 'Persimmon Cake', '20 mins', '1 hrs 5 mins', '1 hrs 35 mins', '16', '1 9x13-inch cake', '  nonstick cooking spray, 2 ½ cups all-purpose flour, 2 cups sugar, 2 teaspoons baking soda, ½ teaspoon baking powder, ½ teaspoon salt, 2 cups persimmon pulp, 1 cup milk, 2 large eggs, 2 teaspoons vanilla extract', 'Preheat the oven to 300 degrees F (150 degrees C). Spray a 9x13-inch baking pan with nonstick spray and dust with flour.
INSERT INTO public.recipes VALUES (545, 'Soft Persimmon Cookies', '15 mins', '15 mins', '30 mins', '36', '3 dozen', '2 cups all-purpose flour, 1 teaspoon baking soda, 1 teaspoon ground cinnamon, ½ teaspoon ground cloves, ½ teaspoon ground nutmeg, ½ teaspoon salt, 1 cup white sugar, ½ cup butter, 2  ripe persimmons, pureed, 1 large egg, 1 cup chopped walnuts', 'Preheat the oven to 375 degrees F (190 degrees C). Lightly grease or line a baking sheet with parchment paper.
INSERT INTO public.recipes VALUES (546, 'Spiced Persimmon Butter', '40 mins', '10 hrs', '10 hrs 40 mins', '64', '4 half-pint jars', '20  ripe Fuyu persimmons, peeled and coarsely chopped, 1 medium lemon, juiced, ¼ cup agave syrup, 1 teaspoon ground cinnamon, ¼ teaspoon ground cloves', 'Place persimmons into a slow cooker and drizzle lemon juice over top. Cover and cook on High for about 2 hours.
INSERT INTO public.recipes VALUES (547, 'Old-Fashioned Persimmon Cookies', NULL, NULL, NULL, '48', '4 to 5 dozen', '½ cup shortening, 1 cup white sugar, 1  egg, ½ teaspoon vanilla extract, 2 cups all-purpose flour, ½ teaspoon baking soda, ½ teaspoon baking powder, ¼ teaspoon salt, ½ teaspoon ground cloves, ½ teaspoon ground cinnamon, ½ teaspoon ground nutmeg, 1 cup raisins, 1 cup chopped walnuts, ¼ teaspoon salt, 1 cup persimmon pulp', 'Preheat oven to 350 degrees F (175 degrees C).
INSERT INTO public.recipes VALUES (548, 'Persimmon Muffins', '15 mins', '19 mins', '34 mins', '12', '12 muffins', '1  egg, 1 cup persimmon pulp, ½ cup canola oil, ⅓ cup milk, 2 cups all-purpose flour, ½ cup walnuts, ⅓ cup white sugar, 1 teaspoon salt, 1 teaspoon baking powder, 1 teaspoon ground cinnamon', 'Preheat oven to 400 degrees F (200 degrees C). Grease a 12-cup muffin tin.
INSERT INTO public.recipes VALUES (549, 'Persimmon Bars', '10 mins', '20 mins', '30 mins', '12', '12 servings', '1 cup persimmon pulp, 1 teaspoon baking soda, 1  egg, beaten, 1 cup white sugar, ½ cup vegetable oil, 1 cup raisins, 1 ½ cups all-purpose flour, 1 teaspoon ground cinnamon, 1 teaspoon ground nutmeg, 1 teaspoon salt, ¼ teaspoon ground cloves, 1 cup chopped walnuts, 1 cup confectioners'' sugar, 2 tablespoons lemon juice', 'Preheat oven to 350 degrees F (175 degrees C). Lightly grease a 10x15 inch jelly roll pan.
INSERT INTO public.recipes VALUES (550, 'Persimmon Oatmeal Cookies', '15 mins', '10 mins', '25 mins', '24', '2 dozen cookies', '1 ¾ cups rolled oats, 1 ½ cups sifted all-purpose flour, ½ cup English toffee-flavored baking bits (such as Heath®), 1 teaspoon baking soda, 1 teaspoon salt, ¼ teaspoon ground nutmeg, ½ teaspoon ground cinnamon, ¼ teaspoon ground cloves, 1 cup brown sugar, ¾ cup butter, 1  egg, 1 cup persimmon puree, 1 teaspoon vanilla', 'Preheat oven to 350 degrees F (175 degrees C). Line baking sheets with parchment paper.
INSERT INTO public.recipes VALUES (551, 'Banana and Persimmon Cinnamon Muffins', '20 mins', '20 mins', '40 mins', '6', '6 muffins', '2  ripe bananas, peeled, 1  Hachiya persimmon, peeled, ¾ cup white sugar, ⅓ cup coconut oil, melted, 1  egg, 2 teaspoons vanilla extract, 1 ½ cups all-purpose flour, 1 ½ teaspoons baking powder, ½ teaspoon salt, 1 tablespoon white sugar, 1 ½ teaspoons ground cinnamon', 'Preheat oven to 375 degrees F (190 degrees C). Line 6 muffin cups with paper liners.
INSERT INTO public.recipes VALUES (552, 'Persimmon Cheesecake', '25 mins', '1 hrs 22 mins', '5 hrs 47 mins', '12', '1 cheesecake', '2 cups chopped walnuts, ⅓ cup brown sugar, 3 tablespoons melted butter, 2 cups pureed persimmons, 3 (8 ounce) packages cream cheese, softened, 1 ¼ cups white sugar, ¾ cup sour cream, ¼ teaspoon ground cinnamon, ½ teaspoon ground ginger, 6  eggs, 1 ¼ cups sour cream, 3 tablespoons white sugar, 1 teaspoon vanilla extract', 'Preheat oven to 325 degrees F (165 degrees C).
INSERT INTO public.recipes VALUES (553, 'Spinach and Persimmon Salad with Goat Cheese and Pomegranate', '20 mins', NULL, '20 mins', '2', '2 servings', '1  Fuyu persimmon, peeled and cored, 2 cups roughly chopped spinach, 3 tablespoons pomegranate seeds, 2 ounces goat cheese, crumbled, 1 tablespoon sliced almonds', 'Slice persimmon into 1/4-inch rounds, then slice each round into quarters.
INSERT INTO public.recipes VALUES (554, 'Butternut Squash Soup with Persimmon', '15 mins', '40 mins', '55 mins', '6', '6 servings', '2 tablespoons olive oil, 1  onion, finely chopped, 2  carrots, peeled and cubed, 1  bay leaf, 2 pounds butternut squash- peeled, seeded and cubed, ½ cup dry white wine, 4 cups chicken broth, 2  persimmons, diced, 1 tablespoon white wine vinegar, 1 pinch salt and freshly ground black pepper to taste', 'Heat olive oil in a large pot over medium heat and cook onion until soft and translucent, about 5 minutes. Add carrots and bay leaf and cook an additional 5 minutes. Add butternut squash and keep cooking, 5 more minutes.
INSERT INTO public.recipes VALUES (555, 'Persimmon Chocolate Chip Cookies', '20 mins', '10 mins', '45 mins', '33', '33 cookies', '1 cup butter, softened, 1 cup white sugar, 3  Hachiya persimmons, pulp extracted, 1  egg, 1 ½ teaspoons vanilla extract, 3 cups all-purpose flour, 1 teaspoon baking soda, 1 teaspoon salt, 2 ½ cups chocolate chips', 'Preheat oven to 375 degrees F (190 degrees C). Line a baking sheet with parchment paper.
INSERT INTO public.recipes VALUES (556, 'Pavlova with Winter Fruits', '30 mins', '1 hrs', '2 hrs 30 mins', '3', '3 pavlovas', '4  egg whites, at room temperature, ¾ cup white sugar, ¼ cup superfine sugar, 1 ½ teaspoons cornstarch, ½ teaspoon orange blossom water (Optional), ½ teaspoon white vinegar', 'Preheat the oven to 250 degrees F (120 degrees C). Line a large baking sheet with parchment paper. Invert a small bowl onto the parchment paper and trace the rim with a pencil. Repeat twice more. Flip parchment paper over.
INSERT INTO public.recipes VALUES (557, 'Gingered Apple-Persimmon Compote', '10 mins', '10 mins', '20 mins', '4', '4 servings', '5  overripe Fuyu persimmons, mashed, 1 small Granny Smith apple, peeled and diced, 1 tablespoon brown sugar, 2 teaspoons ground cinnamon, 1 teaspoon freshly grated ginger, ½  lemon, juiced, ½ teaspoon lemon zest', 'Heat mashed persimmons in a saucepan over medium heat. Stir apple, brown sugar, cinnamon, ginger, lemon juice, and lemon zest into persimmons. Bring mixture to a boil, reduce heat to medium-low, and simmer until sauce is desired consistency and flavors blend, 10 to 15 minutes.', '5.0', 'https://www.allrecipes.com/recipe/235253/gingered-apple-persimmon-compote/', '/Side Dish/', 'Total Fat 0g 0%, Sodium 2mg 0%, Total Carbohydrate 18g 7%, Dietary Fiber 2g 6%, Total Sugars 6g, Protein 0g, Vitamin C 22mg 112%, Calcium 25mg 2%, Iron 1mg 6%, Potassium 138mg 3%', 'Prep Time: 10 mins, Cook Time: 10 mins, Total Time: 20 mins, Servings: 4, Yield: 4 servings', 'https://www.allrecipes.com/thmb/Dh5_8nav65wHup2MjJdWfxlx6QQ=/1500x0/filters:no_upscale():max_bytes(150000):strip_icc()/2787357-876ea0dfe0b142fcb1210204d7089006.jpg');
INSERT INTO public.recipes VALUES (558, 'Persimmon Upside Down Cake', '25 mins', '35 mins', '1 hrs 10 mins', '8', '1 9-inch cake', '3 tablespoons margarine, ¼ cup brown sugar, 4  large ripe persimmons, peeled and sliced', 'Preheat an oven to 350 degrees F (175 degrees C). Grease a 9-inch round cake pan.
INSERT INTO public.recipes VALUES (559, 'Nonnie''s Persimmon Pudding', '30 mins', '1 hrs', '2 hrs', '12', '12 servings', '2 cups persimmon pulp, 2 cups white sugar, 2  eggs, beaten, 1 teaspoon baking soda, 1 cup all-purpose flour, 1 pinch salt, 1 teaspoon baking powder, 1 teaspoon ground cinnamon, 1 ½ cups buttermilk, ¼ cup heavy cream, 1 tablespoon honey, 4 tablespoons butter, melted', 'Preheat an oven to 350 degrees F (175 degrees C). Spray a 9x13 inch baking pan lightly with nonstick spray; set aside.
INSERT INTO public.recipes VALUES (562, 'Cranberry Persimmon Bread', '10 mins', '1 hrs', '1 hrs 20 mins', '20', '2 loaves', '1 ½ cups ripe Hachiya persimmon pulp, 2 teaspoons baking soda, 2 cups brown sugar, 4  eggs, ⅔ cup vegetable oil, 1 ½ teaspoons ground cinnamon, ½ teaspoon ground nutmeg, 1 teaspoon salt, 3 cups all-purpose flour, 2 cups fresh cranberries', 'Preheat oven to 350 degrees F (175 degrees C). Grease 2 loaf pans.
INSERT INTO public.recipes VALUES (563, 'Gram''s Persimmon Pudding', '10 mins', '1 hrs', '1 hrs 10 mins', '4', '4 servings', '1  egg, 1 cup persimmon pulp, ½ cup canned sweetened condensed milk, 1 teaspoon vanilla extract, 1 tablespoon melted butter, 1 cup white sugar, 1 cup all-purpose flour, 2 teaspoons baking soda, ½ teaspoon salt, ¼ teaspoon ground cinnamon', 'Preheat the oven to 300 degrees F (150 degrees C). Butter a 1 1/2 quart casserole dish.
INSERT INTO public.recipes VALUES (564, 'Granny Franny''s Persimmon Curry Chili', '10 mins', '55 mins', '1 hrs 5 mins', '10', '10 servings', '1 pound ground beef, or more to taste, 1  yellow onion, chopped, 1 (15 ounce) can seasoned diced tomatoes, 1 (15 ounce) can diced tomatoes with jalapeno peppers, 1 (15 ounce) can pinto beans, 1 (15 ounce) can kidney beans, 1 (15 ounce) can black beans, 1 (15 ounce) can chicken broth, 1 (15 ounce) can chili with beans (Optional), ⅔ cup tangy coconut and chili vindaloo sauce (such as Maya Kaimal®), ⅓ cup ketchup, 2 tablespoons tomato paste, 1  ripe persimmon, chopped, ½ teaspoon salt, ½ teaspoon red pepper flakes, ½ teaspoon ground cumin, ½ teaspoon chili powder', 'Place ground beef and onion in a skillet over medium heat; cook and stir until brown and crumbled, 5 to 10 minutes. Drain; place into a large pot.
INSERT INTO public.recipes VALUES (565, 'Roasted Persimmon-Burrata Focaccia', '10 mins', '40 mins', '50 mins', '2', '2 servings', '1  precooked 9-inch focaccia flatbread, 1  Fuyu persimmon, peeled and sliced into 1/4-inch rounds, 4 teaspoons olive oil, divided, ½ teaspoon salt, 2 sprigs fresh rosemary, leaves stripped, ½ cup burrata cheese', 'Preheat the oven to 350 degrees F (175 degrees C). Line a baking sheet with parchment paper.
INSERT INTO public.recipes VALUES (576, 'Auntie''s Persimmon Cookies', '30 mins', '14 mins', '2 hrs 14 mins', '36', '36 cookies', '1 ½ cups persimmon pulp, 1 teaspoon baking soda, ½ cup butter, softened, 1 cup white sugar, 2 cups all-purpose flour, 1 teaspoon ground cinnamon, 1 teaspoon ground cloves, 1 teaspoon ground nutmeg, ½ teaspoon salt, 1  egg, 1 cup chopped pecans, 1 cup golden raisins', 'Preheat oven to 350 degrees F (175 degrees C). Line a baking sheet with parchment paper or a Silpat® nonstick baking mat.
INSERT INTO public.recipes VALUES (566, 'Persimmon Cookies IV', '15 mins', '15 mins', '1 hrs 30 mins', '36', '3 dozen', '4 cups all-purpose flour, 2 teaspoons baking soda, 1 teaspoon ground cinnamon, 1 teaspoon ground ginger, 1 cup butter, 2 cups white sugar, 2  eggs, 2 cups persimmon pulp', 'Preheat an oven to 375 degrees F (190 degrees C).
INSERT INTO public.recipes VALUES (567, 'Persimmon Bread III', '20 mins', '50 mins', '1 hrs 10 mins', '24', '2 loaves', '2 cups white sugar, 1 ½ cups wheat flour, 1 ½ cups all-purpose flour, ½ cup oatmeal, ½ teaspoon salt, 1 teaspoon ground cinnamon, ½ teaspoon ground nutmeg, 1 teaspoon ground allspice, ½ teaspoon ground cloves, 2 teaspoons baking soda, 2 cups ripe Hachiya persimmon pulp, ½ cup applesauce, ½ cup vegetable oil, 3  eggs', 'Preheat oven to 350 degrees F (175 degrees C).
INSERT INTO public.recipes VALUES (568, 'Persimmon Raisin Yeast Bread', '5 mins', '3 mins', '8 mins', '12', '1 to 1 1/2 - pound loaf', '½ cup very ripe persimmon pulp, 9 tablespoons water, 2 tablespoons butter, 1 ½ teaspoons white sugar, 1 ½ teaspoons salt, 2 cups bread flour, 1 cup whole wheat flour, 2 tablespoons wheat germ, 1 teaspoon ground cinnamon, 2 ½ teaspoons active dry yeast, ⅓ cup raisins', 'Place all ingredients except raisins in your bread machine''s baking pan in the order recommended by the manufacturer. Use the basic or white cycle. You may need to add an extra tablespoon of water during kneading
INSERT INTO public.recipes VALUES (569, 'Deep Dish Persimmon Pie', '20 mins', '45 mins', '2 hrs 5 mins', '8', '1 8-inch deep dish pie', '¼ cup light brown sugar, packed, 1 tablespoon ground cinnamon, 1 tablespoon cornstarch, ⅛ teaspoon sea salt, 6 cups Fuyu persimmons, peeled and thinly sliced, 10  graham crackers, crushed, ¼ cup butter, melted', 'Preheat an oven to 375 degrees F (190 degrees C).
INSERT INTO public.recipes VALUES (570, 'Persimmon Raisin Cookies', '20 mins', '12 mins', '32 mins', '60', '60 cookies', '2 cups white sugar, 1 cup shortening, 2  eggs, 4 cups all-purpose flour, 1 teaspoon salt, 2 teaspoons baking soda, 2 teaspoons ground cinnamon, 2 teaspoons ground nutmeg, 2 cups persimmon pulp, 2 cups raisin paste, 2 cups chopped walnuts', 'Preheat oven to 350 degrees F (175 degrees C). Lightly grease two baking sheets.
INSERT INTO public.recipes VALUES (571, 'Harriet Davis''s Indiana Persimmon Pudding', '15 mins', '25 mins', '40 mins', '12', '1 9x13-inch baking pan', '1 ½ cups buttermilk, 1 teaspoon baking soda, 1 ½ cups all-purpose flour, 1 teaspoon baking powder, ½ teaspoon ground cinnamon, ⅛ teaspoon salt, 2 cups persimmon pulp, 2 cups white sugar, 2  eggs, well beaten, ¼ cup heavy whipping cream, ¼ cup butter, melted', 'Preheat oven to 325 degrees F (165 degrees C).
INSERT INTO public.recipes VALUES (572, 'Persimmon Pudding Pie', '15 mins', '1 hrs', '1 hrs 15 mins', '8', '8 servings', '2 tablespoons butter, melted, 2 cups persimmon pulp, 2 cups white sugar, 3  eggs, lightly beaten, 1 ¼ cups buttermilk, 1 teaspoon baking soda, 2 cups all-purpose flour, 1 teaspoon baking powder, ½ teaspoon ground cinnamon, ½ teaspoon salt, ½ teaspoon vanilla extract', 'Preheat oven to 325 degrees F (165 degrees C). Spread melted butter evenly over the bottom of a baking dish.
INSERT INTO public.recipes VALUES (573, 'Christmas Cranberry-Persimmon Loaf', '20 mins', '1 hrs 15 mins', '2 hrs 5 mins', '12', '1 9x5-inch loaf', '1 ½ cups all-purpose flour, 1 tablespoon ground cinnamon, 1 teaspoon baking soda, ½ teaspoon salt, ¼ teaspoon ground ginger, or more to taste, ¼ teaspoon ground nutmeg, or more to taste, ½ cup chopped toasted walnuts, ½ cup dried cranberries, 2 large eggs, ¾ cup light brown sugar, ½ cup vegetable oil, 4  ripe Fuyu persimmons, chopped into small pieces', 'Preheat the oven to 325 degrees F (165 degrees C). Grease a 9x5-inch loaf pan and dust the bottom with flour.
INSERT INTO public.recipes VALUES (574, 'Paleo Persimmon Pie', '30 mins', NULL, '30 mins', '8', '8 slices', '½ teaspoon olive oil, 3 cups pecans, 20  pitted dates, ¼ cup agave nectar, 6  ripe persimmons, 2 tablespoons chopped pecans, 1 teaspoon ground cinnamon, for garnish', 'Lightly grease an 8-inch pie pan with olive oil.
INSERT INTO public.recipes VALUES (575, 'Persimmon, Pomegranate, and Massaged Kale Salad', '25 mins', '5 mins', '30 mins', '4', '4 servings', '½ cup raw macadamia nuts, 2 tablespoons maple syrup, divided, 1 pinch salt', 'Preheat oven to 375 degrees F (190 degrees C). Line a baking sheet with parchment paper.
INSERT INTO public.recipes VALUES (577, 'Persimmon Cookies III', '20 mins', '12 mins', '32 mins', '72', '6 dozen', '½ cup shortening, 1 cup white sugar, 1  egg, 1 cup persimmon pulp, 1 cup all-purpose flour, ½ teaspoon baking powder, ½ teaspoon baking soda, ½ teaspoon ground cinnamon, ¼ teaspoon ground cloves, ½ teaspoon salt, ½ cup raisins, ½ cup chopped walnuts', 'Preheat oven to 350 degrees F (175 degrees C). Grease cookie sheets.
INSERT INTO public.recipes VALUES (578, 'Sandra''s Persimmon Pudding', NULL, NULL, NULL, '4', '4 servings', '1 cup persimmon pulp, 1  egg, beaten, 1 ¼ cups white sugar, 1 cup all-purpose flour, 1 ¼ cups milk, ¼ teaspoon baking soda, 1 teaspoon baking powder, ½ teaspoon ground cinnamon, ¼ teaspoon salt, ¼ cup butter, melted', 'Butter one 9x13 inch baking pan. Preheat oven to 350 degrees F (175 degrees C).
INSERT INTO public.recipes VALUES (579, 'Spicy Persimmon Chutney', '15 mins', '35 mins', '50 mins', '32', '4 cups', '1 ½ cups cider vinegar, 1 cup chopped onion, 1 large Granny Smith apple - peeled, cored and chopped, 1 cup golden raisins, ¾ cup white sugar, ¼ cup lemon juice, 1  green chile pepper, seeded and minced, 1 tablespoon minced fresh ginger root, 1 tablespoon lemon zest, 1 teaspoon ground coriander seed, ⅛ teaspoon ground cloves, 4  Fuyu persimmons, peeled and chopped', 'Combine cider vinegar, onion, apple, raisins, sugar, lemon juice, green chile, ginger, lemon zest, coriander, and cloves in a large saucepan. Bring to a boil over medium heat, stirring occasionally. Reduce heat to medium-low and simmer until mixture thickens, stirring frequently, about 25 minutes. Add persimmons and simmer until the persimmons are tender, about 5 to 10 minutes.
INSERT INTO public.recipes VALUES (580, 'Sweet Persimmon Fireside Cookies', NULL, NULL, NULL, '16', '16 bars', '2 cups all-purpose flour, ½ cup cake flour, 1 teaspoon ground cinnamon, 1 teaspoon ground ginger, ½ teaspoon baking soda, ¼ teaspoon salt, ½ cup unsalted butter, 1 cup white sugar, 1 tablespoon lemon zest, 2  ripe persimmons, pureed, 1  egg, ¼ cup confectioners'' sugar', 'Preheat oven to 375 degrees F (190 degrees C). Grease one 9x13 inch baking pan.
INSERT INTO public.recipes VALUES (581, 'Banana Chocolate Chip Bread', '15 mins', '1 hrs 10 mins', '1 hrs 35 mins', '10', '1 9x5-inch loaf', '2 cups all-purpose flour, 1 teaspoon baking powder, 1 teaspoon baking soda, 1 teaspoon salt, 3  ripe bananas, mashed, 1 tablespoon milk, 1 teaspoon ground cinnamon, or to taste, 1 cup white sugar, ½ cup butter, softened, 2 large eggs, 1 cup semisweet chocolate chips', 'Preheat the oven to 325 degrees F (165 degrees C). Grease a 9x5-inch loaf pan, preferably glass.
INSERT INTO public.recipes VALUES (582, 'Joy''s Easy Banana Bread', '15 mins', '1 hrs', '1 hrs 15 mins', '10', '1 9x5-inch loaf', '3  ripe bananas, mashed, 1 cup white sugar, 1  egg, ¼ cup melted butter, 1 ½ cups all-purpose flour, 1 teaspoon baking soda, 1 teaspoon salt', 'Preheat the oven to 325 degrees F (165 degrees C). Grease a 9x5-inch loaf pan.
INSERT INTO public.recipes VALUES (583, 'Banana Muffins', '10 mins', '25 mins', '35 mins', '12', '12 muffins', '1 ½ cups all-purpose flour, 1 teaspoon baking powder, 1 teaspoon baking soda, ½ teaspoon salt, 3 large bananas, mashed, ¾ cup white sugar, 1  egg, ⅓ cup butter, melted', 'Preheat the oven to 350 degrees F (175 degrees C). Grease a 12-cup muffin tin or line cups with paper liners. Sift flour, baking powder, baking soda, and salt together in a bowl; set aside.
INSERT INTO public.recipes VALUES (584, 'Peanut Butter Banana Smoothie', '5 mins', NULL, '5 mins', '4', '4 servings', '2  bananas, broken into chunks, 2 cups milk, ½ cup peanut butter, 2 tablespoons honey, or to taste, 2 cups ice cubes', 'Place bananas, milk, peanut butter, honey, and ice cubes in a blender; blend until smooth, about 30 seconds.
INSERT INTO public.recipes VALUES (585, 'Janet''s Rich Banana Bread', '10 mins', '1 hrs', '1 hrs 20 mins', '10', '1 9x5-inch loaf', '1 cup white sugar, ½ cup butter, melted, 2  eggs, 1 teaspoon vanilla extract, 1 ½ cups all-purpose flour, 1 teaspoon baking soda, ½ teaspoon salt, ½ cup sour cream, ½ cup chopped walnuts, 2  medium bananas, sliced', 'Preheat the oven to 350 degrees F (175 degrees C). Grease a 9x5-inch loaf pan.
INSERT INTO public.recipes VALUES (586, 'Bananas Foster', '5 mins', '15 mins', '20 mins', '4', NULL, '¼ cup butter, ⅔ cup dark brown sugar, 3 ½ tablespoons rum, 1 ½ teaspoons vanilla extract, ½ teaspoon ground cinnamon, 3  bananas, peeled and sliced lengthwise and crosswise, ¼ cup coarsely chopped walnuts, 1 pint vanilla ice cream', 'Melt butter in a large, deep skillet over medium heat. Stir in brown sugar, rum, vanilla, and cinnamon; bring to a low boil.
INSERT INTO public.recipes VALUES (613, 'Banana Fritters', '10 mins', '5 mins', '15 mins', '6', '24 fritters', '2  bananas, mashed, ½ cup milk, 2 cups all-purpose flour, 3 teaspoons baking powder, ½ teaspoon salt, 2  eggs, beaten, 1 tablespoon margarine, melted, 1 quart vegetable oil for frying, ½ cup confectioners'' sugar, or as needed', 'Combine bananas and milk in a large mixing bowl; sift in flour, baking powder, and salt. Add eggs and margarine; mix well to combine.
INSERT INTO public.recipes VALUES (587, 'Banana Cream Pie', '15 mins', '25 mins', '1 hrs 40 mins', '8', '1 9-inch pie', '¾ cup white sugar, ⅓ cup all-purpose flour, ¼ teaspoon salt, 2 cups milk, 3  egg yolks, beaten, 2 tablespoons butter, 1 ¼ teaspoons vanilla extract, 1 (9 inch) baked pastry shell, cooled, 4  bananas, sliced', 'Preheat the oven to 350 degrees F (175 degrees C).
INSERT INTO public.recipes VALUES (588, 'Banana Oat Muffins', '15 mins', '20 mins', '35 mins', '12', '12 muffins', '1 ½ cups unbleached all-purpose flour, 1 cup rolled oats, ½ cup white sugar, 2 teaspoons baking powder, 1 teaspoon baking soda, ½ teaspoon salt, 1  egg, ¾ cup milk, ⅓ cup vegetable oil, ½ teaspoon vanilla extract, 1 cup mashed bananas', 'Preheat the oven to 400 degrees F (205 degrees C). Line a 12-cup muffin tin with paper liners.
INSERT INTO public.recipes VALUES (589, 'Extreme Banana Nut Bread ''EBNB''', '15 mins', '1 hrs', '1 hrs 50 mins', '24', '2 9x5-inch loaves', '2 cups all-purpose flour, 2 teaspoons baking soda, 1 teaspoon salt, 2 cups white sugar, 1 cup butter, softened, 2 cups mashed overripe bananas, 4 large eggs, beaten, 1 cup chopped walnuts', 'Preheat the oven to 350 degrees F (175 degrees C). Grease and flour two 9x5-inch loaf pans.
INSERT INTO public.recipes VALUES (590, 'Ultimate Banana Muffins', '15 mins', '20 mins', '35 mins', '12', '12 muffins', '1 ½ cups all-purpose flour, 1 teaspoon baking powder, 1 teaspoon baking soda, 1 teaspoon ground cinnamon, ½ teaspoon salt, 1 pinch ground nutmeg, 3  bananas (ripe or very ripe work best), ½ cup white sugar, ⅓ cup butter, melted, ¼ cup lightly packed brown sugar, 1 large egg, 1 teaspoon vanilla extract, ¼ cup chopped walnuts (Optional)', 'Preheat the oven to 350 degrees F (175 degrees C). Grease a muffin tin.
INSERT INTO public.recipes VALUES (629, 'Strawberry Orange Banana Smoothie', '5 mins', NULL, '5 mins', '1', NULL, '1 cup fresh strawberries, ¾ cup orange juice, 1  ripe banana, 1 cup ice cubes, or as needed', 'Blend strawberries, orange juice, banana, and ice in a blender until smooth and frothy.', '4.5', 'https://www.allrecipes.com/recipe/215163/strawberry-orange-banana-smoothie/', '/Drinks Recipes/Smoothie Recipes/Strawberry/', 'Total Fat 1g 2%, Saturated Fat 0g 1%, Sodium 8mg 0%, Total Carbohydrate 58g 21%, Dietary Fiber 7g 23%, Total Sugars 38g, Protein 4g, Vitamin C 194mg 971%, Calcium 55mg 4%, Iron 1mg 7%, Potassium 1032mg 22%', 'Prep Time: 5 mins, Total Time: 5 mins, Servings: 1', 'https://www.allrecipes.com/thmb/Hu0ENnOtLbhzskFxtlsEkkPoDNg=/1500x0/filters:no_upscale():max_bytes(150000):strip_icc()/3926318-ee7aaacd2b3244b1a1efcc57361b32b7.jpg');
INSERT INTO public.recipes VALUES (591, 'Banana Crumb Muffins', '15 mins', '20 mins', '35 mins', '10', '10 muffins', '1 ½ cups all-purpose flour, 1 teaspoon baking soda, 1 teaspoon baking powder, ½ teaspoon salt, 3  bananas, mashed, ¾ cup white sugar, ⅓ cup butter, melted, 1  egg, lightly beaten', 'Preheat the oven to 375 degrees F (190 degrees C). Lightly grease or line 10 muffin cups with paper liners.
INSERT INTO public.recipes VALUES (592, 'Banana Cake', '30 mins', '1 hrs', '2 hrs 15 mins', '18', '1 9x13-inch cake', '1 ½ cups mashed bananas, 2 teaspoons lemon juice, 3 cups all-purpose flour, 1 ½ teaspoons baking soda, ¼ teaspoon salt, 2 ⅛ cups white sugar, ¾ cup butter, 3  eggs, 2 teaspoons vanilla extract, 1 ½ cups buttermilk', 'Preheat the oven to 275 degrees F (135 degrees C). Grease and flour a 9x13-inch pan.
INSERT INTO public.recipes VALUES (593, 'Chocolate Banana Peanut Butter Protein Shake', '10 mins', NULL, '10 mins', '1', NULL, '6  ice cubes, 1 cup milk, 1  banana, 1 scoop chocolate-flavored protein powder, 2 tablespoons peanut butter, 1 tablespoon honey, 1 teaspoon unsweetened cocoa powder, or more to taste', 'Blend ice cubes, milk, banana, protein powder, peanut butter, honey, and cocoa powder together in a blender until smooth.', '4.8', 'https://www.allrecipes.com/recipe/244959/chocolate-banana-peanut-butter-protein-shake/', '/Drinks Recipes/Shakes and Floats Recipes/Chocolate/', 'Total Fat 23g 29%, Saturated Fat 7g 37%, Cholesterol 60mg 20%, Sodium 341mg 15%, Total Carbohydrate 67g 24%, Dietary Fiber 6g 22%, Total Sugars 46g, Protein 31g, Vitamin C 11mg 55%, Calcium 313mg 24%, Iron 1mg 7%, Potassium 1041mg 22%', 'Prep Time: 10 mins, Total Time: 10 mins, Servings: 1', 'https://www.allrecipes.com/thmb/o_l87oGIqY71mamvxApxRV8-47I=/1500x0/filters:no_upscale():max_bytes(150000):strip_icc()/3618581-b0054e8d05ca4231a3e11626e381d82c.jpg');
INSERT INTO public.recipes VALUES (594, 'Fruit and Yogurt Smoothie', '5 mins', NULL, '5 mins', '2', NULL, '1 cup strawberries, 1  banana, ½ cup yogurt, ¼ cup pineapple juice, 1 ½ teaspoons white sugar, 1 teaspoon orange juice, 1 teaspoon milk', 'Combine strawberries, banana, yogurt, pineapple juice, sugar, orange juice, and milk in a blender; blend until smooth.', '4.7', 'https://www.allrecipes.com/recipe/215189/fruit-and-yogurt-smoothie/', '/Drinks Recipes/Smoothie Recipes/Strawberry/', 'Total Fat 1g 2%, Saturated Fat 1g 4%, Cholesterol 4mg 1%, Sodium 45mg 2%, Total Carbohydrate 31g 11%, Dietary Fiber 3g 11%, Total Sugars 22g, Protein 5g, Vitamin C 56mg 278%, Calcium 132mg 10%, Iron 1mg 3%, Potassium 519mg 11%', 'Prep Time: 5 mins, Total Time: 5 mins, Servings: 2', 'https://www.allrecipes.com/thmb/nXTnAdimMBtkQieZhloU45cM1V0=/1500x0/filters:no_upscale():max_bytes(150000):strip_icc()/441727-fruit-and-yogurt-smoothie-Alberta-Rose-4x3-1-aa04390dac11483aaeeec142dff1f6c7.jpg');
INSERT INTO public.recipes VALUES (595, 'Banana Pudding', '30 mins', NULL, '3 hrs 30 mins', '12', '1 (9x13-inch) dish', '1 (8 ounce) package cream cheese, at room temperature , 1 (14 ounce) can sweetened condensed milk, 1 (5 ounce) package instant vanilla pudding mix, 3 cups cold skim milk, 1 teaspoon vanilla extract, 1 (8 ounce) container frozen whipped topping, thawed, ½ (12 ounce) package vanilla wafers, 4  bananas, sliced', 'Beat cream cheese in a large bowl until fluffy. Beat in condensed milk, then pudding mix. Gradually mix in cold milk until smooth, followed by vanilla. Fold in 1/2 of the whipped topping.
