INSERT INTO public.recipes VALUES (600, 'Spinach and Banana Power Smoothie', '10 mins', NULL, '10 mins', '1', NULL, '1 cup plain soy milk, ¾ cup packed fresh spinach leaves, 1 large banana, sliced', 'Blend soy milk and spinach together in a blender until smooth. Add banana and pulse until thoroughly blended.', '4.8', 'https://www.allrecipes.com/recipe/241019/spinach-and-banana-power-smoothie/', '/Drinks Recipes/Smoothie Recipes/Veggie/', 'Total Fat 5g 6%, Saturated Fat 1g 4%, Sodium 143mg 6%, Total Carbohydrate 47g 17%, Dietary Fiber 6g 20%, Total Sugars 26g, Protein 10g, Vitamin C 18mg 91%, Calcium 90mg 7%, Iron 3mg 14%, Potassium 899mg 19%', 'Prep Time: 10 mins, Total Time: 10 mins, Servings: 1', 'https://www.allrecipes.com/thmb/7fxIkXzDquL8VytxAU0wlEf-OuM=/1500x0/filters:no_upscale():max_bytes(150000):strip_icc()/4548861-9766946c2ba1471ca2c8cc51afe1c18b.jpg');
INSERT INTO public.recipes VALUES (601, 'Basic Fruit Smoothie', '10 mins', NULL, '10 mins', '4', NULL, '1 quart strawberries, hulled, 2  fresh peaches - peeled, pitted, and sliced, 1  banana, broken into chunks, 2 cups ice, 1 cup orange-peach-mango juice', 'Combine strawberries, peaches, and banana in a blender; blend until smooth. Add ice and pour in juice; blend again to desired consistency.
INSERT INTO public.recipes VALUES (602, 'Southern Style Banana Split Cake', '30 mins', NULL, '2 hrs', '12', '1 9x13-inch pan', '2 cups graham cracker crumbs, ¾ cup white sugar, ¼ pound butter, melted, 2 (8 ounce) packages cream cheese, 1 ½ cups confectioners'' sugar, 4  bananas, sliced, 1 (15 ounce) can crushed pineapple, drained, 1 (16 ounce) container frozen whipped topping, thawed, 1 (16 ounce) jar maraschino cherries, drained, 12 ounces crushed peanuts', 'Combine graham cracker crumbs, white sugar, and melted butter in a large bowl; mix well. Press into a 9x13-inch cake pan; refrigerate until chilled, about 30 minutes.
