INSERT INTO public.recipes VALUES (618, 'Bob''s Stuffed Banana Peppers', '30 mins', '1 hrs 30 mins', '2 hrs', '8', '8 stuffed peppers', '8  banana peppers, 2 tablespoons butter, ½ cup chopped onion, ½ cup chopped celery, 1 (28 ounce) can crushed tomatoes, 1 (8 ounce) can tomato sauce, 2 cloves garlic, minced, 2 ½ teaspoons salt, divided, 1 teaspoon dried basil, 1 teaspoon dried oregano, ½ teaspoon ground black pepper, divided, ½ cup grated Parmesan cheese, 1 large egg, 1 teaspoon Worcestershire sauce, 1 pound hot Italian sausage, 1 pound mild Italian sausage, 1 ½ cups bread crumbs', 'Cut off the tops of peppers. Remove ribs and seeds; rinse peppers. Chop edible portion of the tops; set aside.
