INSERT INTO public.recipes VALUES (643, 'Poblano and Ground Pork Tacos', '30 mins', '10 mins', '40 mins', '6', '6 tacos', '1  red onion, halved and thinly sliced, 1  Roma tomato, seeded and finely chopped, 1  ripe kiwi, diced, 1  lime, quartered, divided, 2 tablespoons chopped cilantro, divided,   salt and ground black pepper to taste, 4 tablespoons sour cream,   olive oil, 1  poblano pepper - cored, seeded, and finely chopped, 10 ounces ground pork, 1 tablespoon Mexican seasoning, 2 tablespoons chicken stock, 1 tablespoon tomato paste, 6  flour tortillas', 'Mince a few slices of onion to get 1 tablespoon. Add minced onion, tomato, kiwi, juice from 2 lime wedges, 3/4 of the cilantro, salt, and pepper to a small bowl. Mix into a salsa.
INSERT INTO public.recipes VALUES (644, 'Strawberry, Kiwi, and Spinach Salad', '15 mins', NULL, '15 mins', '8', '8 servings', '2 tablespoons raspberry vinegar, 2 ½ tablespoons raspberry jam, ⅓ cup vegetable oil, 8 cups spinach, rinsed and torn into bite-size pieces, ½ cup chopped walnuts, 8  strawberries, quartered, 2  kiwis, peeled and sliced', 'Mix together raspberry vinegar, raspberry jam, and vegetable oil in a small container.
INSERT INTO public.recipes VALUES (645, 'Supreme Green Smoothie', '5 mins', NULL, '5 mins', '3', '3 servings', '2 cups Almond Breeze Hint of Honey almondmilk, 1 cup green grapes, 2 cups packed baby kale, 1 large kiwi fruit, peeled and chopped, 1 (10 ounce) package frozen pineapple chunks', 'Place all ingredients in large blender container in order given. Cover; blend on high 15 to 20 seconds or until completely smooth. Pour into glasses.', '4.3', 'https://www.allrecipes.com/recipe/269576/supreme-green-smoothie/', '/Trusted Brands: Recipes and Tips/Almond Breeze/', 'Total Fat 3g 3%, Saturated Fat 0g 1%, Sodium 123mg 5%, Total Carbohydrate 45g 17%, Dietary Fiber 3g 12%, Protein 3g, Potassium 488mg 10%', 'Prep Time: 5 mins, Total Time: 5 mins, Servings: 3, Yield: 3 servings', 'https://www.allrecipes.com/thmb/USNp5SAYHIBq89xMPAWDhr49Khw=/1500x0/filters:no_upscale():max_bytes(150000):strip_icc()/6106325-449c495a815247baa7652f3f118b6867.jpg');
INSERT INTO public.recipes VALUES (646, 'Furutsu Sando (Fruit Sandwiches)', '15 mins', NULL, '1 hrs 15 mins', '2', '2 sandwiches', '½ cup heavy whipping cream, 1 tablespoon powdered sugar, ½ teaspoon vanilla extract, 4 slices Japanese milk bread, crusts removed, ½ cup sliced strawberries, ½ cup peeled sliced kiwi , ½ cup mandarin orange segments, ½ cup halved seedless grapes', 'Beat cream, powdered sugar, and vanilla together in a bowl with an electric mixer on medium speed until stiff peaks form, 3 to 5 minutes.
INSERT INTO public.recipes VALUES (650, 'Spicy Fruit Salsa', '15 mins', NULL, '15 mins', '12', '12 servings', '5  kiwis, peeled and diced, 1 quart strawberries, finely chopped, 1 pint fresh blackberries, chopped, 4  Granny Smith apples - peeled, cored and coarsely shredded, 2 tablespoons any flavor fruit jelly, ¾ cup brown sugar, 1 tablespoon cayenne pepper, 3 tablespoons habanero hot sauce, 1 (7 ounce) can green salsa, ⅓ cup lime juice', 'Place kiwis, strawberries, blackberries, and apples in a bowl. Stir in jelly, brown sugar, cayenne pepper, hot sauce, green salsa, and lime juice. Stir together.', '4.4', 'https://www.allrecipes.com/recipe/88461/spicy-fruit-salsa/', '/Appetizers and Snacks/Dips and Spreads Recipes/Salsa Recipes/', 'Total Fat 1g 1%, Sodium 149mg 6%, Total Carbohydrate 34g 12%, Dietary Fiber 4g 15%, Total Sugars 27g, Protein 1g, Vitamin C 71mg 356%, Calcium 42mg 3%, Iron 1mg 4%, Potassium 307mg 7%', 'Prep Time: 15 mins, Total Time: 15 mins, Servings: 12, Yield: 12 servings', 'https://www.allrecipes.com/thmb/DFeNvJcLF50TxcO50vL0OEZZv9U=/1500x0/filters:no_upscale():max_bytes(150000):strip_icc()/411534-b8706fbd8871456888e109ac136fde6c.jpg');
INSERT INTO public.recipes VALUES (651, 'Pavlova Deluxe', NULL, NULL, NULL, '8', '1 8-inch pavlova', '6  egg whites, ⅛ teaspoon cream of tartar, 1 cup white sugar, 1 tablespoon cornstarch, 2 teaspoons distilled white vinegar, 1 ¼ cups heavy cream, chilled, 1 teaspoon vanilla extract, 2 teaspoons confectioners'' sugar, 4  passion fruits', 'Preheat oven to 400 degrees F (205 degrees C). Grease interior of 8 inch springform pan and dust lightly with cornstarch.
INSERT INTO public.recipes VALUES (652, 'White Sangria with Kiwi', '20 mins', NULL, '20 mins', '8', '8 servings', '1 (750 milliliter) bottle Chardonnay wine, 1 liter club soda, 3 tablespoons orange-flavored liqueur (such as Cointreau®), 2 tablespoons white sugar, 1 cup seedless green grapes, 2  kiwis, peeled and sliced, 1 large pear, thinly sliced,   ice cubes, 8 sprigs mint', 'Mix Chardonnay wine, club soda, orange-flavored liqueur, sugar, grapes, kiwis, and pear in a large pitcher. Stir until sugar is dissolved. Pour wine mixture into wine glasses filled with ice, making sure each glass has some fruit. Garnish with mint sprigs.', '4.3', 'https://www.allrecipes.com/recipe/222834/white-sangria-with-kiwi/', '/Drinks Recipes/Sangria Recipes/', 'Total Fat 0g 0%, Sodium 10mg 0%, Total Carbohydrate 19g 7%, Dietary Fiber 2g 6%, Total Sugars 14g, Protein 1g, Vitamin C 22mg 112%, Calcium 29mg 2%, Iron 1mg 3%, Potassium 200mg 4%', 'Prep Time: 20 mins, Total Time: 20 mins, Servings: 8, Yield: 8 servings', 'https://www.allrecipes.com/thmb/vRE3Pm6VOoNImHPSMagXe5NjbFo=/1500x0/filters:no_upscale():max_bytes(150000):strip_icc()/844865-a9bf1f673ff94230840086059961e1ad.jpg');
INSERT INTO public.recipes VALUES (653, 'Strawberry Kiwi Tartlets', '25 mins', '30 mins', '55 mins', '12', '12 servings', '1  egg, 2 teaspoons water, 12  frozen puff pastry shells, thawed, ⅓ cup strawberry preserves, 2 pints fresh strawberries, sliced, 4  kiwis, peeled and seeded, 2 tablespoons honey, ½ cup heavy cream, 2 teaspoons confectioners'' sugar', 'Beat together the egg and water in a bowl. Brush the puff pastry shells with the egg mixture, and bake shells according to package directions.
INSERT INTO public.recipes VALUES (654, 'LaWanna''s Mango Salsa on Tilapia Fillets', '30 mins', '10 mins', '40 mins', '4', '4 servings', '½  fresh pineapple - peeled, cored, and chopped, ½ pound strawberries, quartered, 3  kiwifruit, peeled and diced, 1 large mango - peeled, seeded and diced, ½ cup grape tomatoes, 2 tablespoons finely chopped fresh cilantro, 1 tablespoon balsamic vinegar, 1 ½ pounds tilapia fillets, ½ teaspoon seasoned pepper blend', 'In a bowl, toss together the pineapple, strawberries, kiwifruit, mango, tomatoes, cilantro, and balsamic vinegar.
INSERT INTO public.recipes VALUES (655, 'A Drama Queen''s Pavlova', '30 mins', '50 mins', '1 hrs 20 mins', '12', '12 servings', '6  egg whites, 1 pinch salt, 1 ½ teaspoons vinegar, 2 cups castor sugar or superfine sugar, 1 ½ teaspoons vanilla extract, ½ cup unsweetened flaked coconut (Optional), 2 cups sweetened whipped cream, 1 cup fresh strawberries, sliced, 2  kiwifruit, peeled, halved lengthwise, and sliced, 1  fresh peach - peeled, pitted and sliced, ½ cup fresh blueberries', 'Preheat the oven to 450 degrees F (220 degrees C). You will be turning the temperature down to 300 degrees F (150 degrees C) when you put this in to bake. Line a 9 or 10 inch round glass dish with parchment paper.
INSERT INTO public.recipes VALUES (656, 'Creamy Kiwi Sandwich', '20 mins', NULL, '20 mins', '8', '8 sandwiches', '1 (8 ounce) package Neufchatel cheese, 2 teaspoons lemon zest, finely chopped, 2 tablespoons honey, or to taste, 1 cup chopped kiwi fruit, 16 slices whole wheat bread', 'In a small bowl, mix together Neufchatel cheese, lemon zest, and honey. Refrigerate for 1 day to allow the flavors to develop.
INSERT INTO public.recipes VALUES (657, 'Char Siu (Chinese Barbeque Pork)', '15 mins', '1 hrs 10 mins', '2 days 1 hrs 25 mins', '4', '4 servings', '2 tablespoons honey, 2 tablespoons Shaoxing cooking wine, 1 tablespoon hoisin sauce, 1 tablespoon pureed kiwi, 1 tablespoon Chinese dark soy sauce, 1 tablespoon Thai chile sauce, 2 cloves garlic, grated, 2 teaspoons oyster sauce, ½ teaspoon Chinese five-spice powder, 1 ½ pounds pork belly, skin removed', 'Mix honey, cooking wine, hoisin sauce, kiwi, dark soy sauce, chile sauce, garlic, oyster sauce, and five-spice powder together in a large resealable plastic bag. Add pork belly. Seal bag, pressing out as much air as possible.
INSERT INTO public.recipes VALUES (658, 'Strawberry-Kiwi Slush', '5 mins', NULL, '5 mins', '3', '24 ounces', '2 cups crushed ice, ¾ pint fresh strawberries, hulled, ¾ cup grape juice (such as Welch''s®), 1 large kiwi fruit, peeled, ¼ cup water, ¼ cup lemon juice', 'Blend ice, strawberries, grape juice, kiwi fruit, water, and lemon juice in a blender until it reaches an even slush consistency, 25 to 35 seconds.', '4.0', 'https://www.allrecipes.com/recipe/242220/strawberry-kiwi-slush/', '/Drinks Recipes/Slushie Recipes/', 'Total Fat 1g 1%, Sodium 5mg 0%, Total Carbohydrate 23g 8%, Dietary Fiber 3g 10%, Total Sugars 17g, Protein 1g, Vitamin C 90mg 450%, Calcium 32mg 2%, Iron 1mg 3%, Potassium 340mg 7%', 'Prep Time: 5 mins, Total Time: 5 mins, Servings: 3, Yield: 24 ounces', 'https://www.allrecipes.com/thmb/SFfoRk80b4GJhQwMSSovnmbaC6Q=/1500x0/filters:no_upscale():max_bytes(150000):strip_icc()/2266989-fa173eb6084e454d8dfc157fe55a4a72.jpg');
INSERT INTO public.recipes VALUES (659, 'Lemon Pretzel Salad with Mango and Kiwi', '20 mins', '10 mins', '4 hrs', '12', '1 9x13-inch baking dish', '2 cups crushed pretzels, ¾ cup butter, melted, 3 tablespoons brown sugar', 'Preheat oven to 350 degrees F (175 degrees C).
INSERT INTO public.recipes VALUES (660, 'Simple Strawberry Salsa', '15 mins', NULL, '45 mins', '10', '10 servings', '1 tablespoon lemon juice, 1 ½ teaspoons white sugar, 1 cup finely chopped strawberries, 1 (8 ounce) can unsweetened crushed pineapple, drained, 3  kiwis, peeled and finely chopped, 1  naval orange, peeled and cut into small pieces', 'Stir lemon juice and sugar together in a bowl to dissolve the sugar; add strawberries, pineapple, kiwis, and orange pieces and stir to coat in the lemon juice mixture.
INSERT INTO public.recipes VALUES (707, 'Jerk Chicken Egg Rolls with Mango-Habanero Sauce', '45 mins', '40 mins', '1 hrs 25 mins', '18', NULL, '1  mango, peeled and diced, ¾ cup water, 1 tablespoon seasoned rice vinegar, 1 clove garlic, minced, 1 pinch salt, ½ cup brown sugar, divided, 2  habanero peppers, seeded and minced, 2 tablespoons water, 1 teaspoon cornstarch', 'For the habanero sauce: Combine mango with 3/4 cup water, rice vinegar, garlic, and salt in a small saucepan. Add most of the brown sugar, reserving 1 teaspoon. Bring to a boil, then reduce heat to medium-low; cook for 5 minutes. Add habanero peppers and simmer for 2 minutes. Mix 2 tablespoon water with cornstarch; stir slurry into the saucepan. Cook over medium-high until thick, 3 to 5 minutes. Leave mixture chunky or blend for a smoother texture.
INSERT INTO public.recipes VALUES (661, 'Kale with Kiwi', '20 mins', '10 mins', '30 mins', '2', '2 servings', '2 teaspoons coconut oil, 2 cloves garlic, chopped, 1 teaspoon minced fresh ginger, ¼ teaspoon sea salt, ½ teaspoon freshly ground black pepper, 2  kiwis, peeled and coarsely chopped, 1 tablespoon fresh oregano leaves, 1 bunch lacinato (dinosaur) kale, washed and sliced thin, 2 tablespoons blanched slivered almonds', 'Heat coconut oil in a skillet over medium-high heat. Add garlic, ginger, sea salt and freshly ground black pepper; cook and stir until garlic begins to turn color, about 3 minutes. Stir in chopped kiwi and oregano leaves and cook for another 2 minutes. Add kale; lower heat to medium and cook until kale is dark green and tender, about 5 minutes. Stir in slivered almonds and adjust seasonings to taste.', '4.1', 'https://www.allrecipes.com/recipe/230406/kale-with-kiwi/', '/Side Dish/Vegetables/Greens/', 'Total Fat 10g 13%, Saturated Fat 5g 23%, Sodium 381mg 17%, Total Carbohydrate 33g 12%, Dietary Fiber 7g 25%, Total Sugars 7g, Protein 9g, Vitamin C 364mg 1,821%, Calcium 519mg 40%, Iron 10mg 56%, Potassium 1322mg 28%', 'Prep Time: 20 mins, Cook Time: 10 mins, Total Time: 30 mins, Servings: 2, Yield: 2 servings', 'https://www.allrecipes.com/thmb/BRh163goV0DrX8Pd9cVQDldlvck=/1500x0/filters:no_upscale():max_bytes(150000):strip_icc()/997494-4c899e84249742adb2a8b5d86e816b21.jpg');
INSERT INTO public.recipes VALUES (662, 'Crazy Fruit Smoothie', '10 mins', NULL, '10 mins', '1', '1 servings', '1 ½ cups crushed ice, 1  banana, chopped, 1  kiwi, peeled and chopped, ½ cup chopped strawberries, ½ cup chopped pineapple, ¼ cup cream of coconut, 1 tablespoon coconut flakes for garnish', 'Blend the ice, banana, kiwi, strawberries, pineapple, and cream of coconut in a blender until smooth; pour into a glass and garnish with the coconut flakes to serve.', '4.7', 'https://www.allrecipes.com/recipe/215196/crazy-fruit-smoothie/', '/Drinks Recipes/Smoothie Recipes/Strawberry/', 'Total Fat 2g 3%, Saturated Fat 1g 7%, Sodium 18mg 1%, Total Carbohydrate 57g 21%, Dietary Fiber 8g 30%, Total Sugars 35g, Protein 3g, Vitamin C 164mg 819%, Calcium 55mg 4%, Iron 1mg 7%, Potassium 878mg 19%', 'Prep Time: 10 mins, Total Time: 10 mins, Servings: 1, Yield: 1 servings', 'https://www.allrecipes.com/thmb/FYy2Hu9EQxLBrRKvW2ZweKz1Zlk=/1500x0/filters:no_upscale():max_bytes(150000):strip_icc()/2328924-804d3d0957d348f5b87d2cc1c5e54bb5.jpg');
INSERT INTO public.recipes VALUES (663, 'Healthier Absolutely the Best Chocolate Chip Cookies', '20 mins', '10 mins', '30 mins', '24', '2 dozen cookies', '½ cup butter, 1  kiwi, pureed, ½ cup brown sugar, ½ cup white sugar, 2  eggs, 2 teaspoons Mexican vanilla extract, 2 ¼ cups all-purpose flour, 1 teaspoon baking soda, 1 cup toasted oat cereal (such as Cheerios ®), smashed, 2 cups milk chocolate chips', 'Preheat oven to 350 degrees F (175 degrees C). Grease two baking sheets.
INSERT INTO public.recipes VALUES (664, 'Fruit Pizza Trifles To Go', '30 mins', NULL, '1 hrs', '25', '25 trifles', '4 (8 ounce) packages reduced-fat cream cheese, softened, 2 cups brown sugar, 4 teaspoons vanilla extract, 1 pound fresh strawberries, coarsely chopped , 1  fresh pineapple - peeled, cored and chopped, 1 pound seedless grapes, halved, 1 pint blueberries, 25  clear, plastic (10 ounce) cups, 12  sugar cookies, crushed, 2  kiwis, peeled and sliced', 'Mix cream cheese, brown sugar, and vanilla extract in a bowl until smooth. Refrigerate until cold, about 30 minutes.
INSERT INTO public.recipes VALUES (665, 'Sweet Salsa and Cinnamon Chips', '20 mins', '10 mins', '30 mins', '5', '5 servings', '10  frozen strawberries, 2  kiwi, peeled and chopped, ½ medium mango - peeled and diced, 1 ½  bananas, peeled and diced, 3 (12 inch) flour tortillas,   canola cooking spray, 1 cup cinnamon sugar', 'Preheat oven to 400 degrees F (200 degrees C).
INSERT INTO public.recipes VALUES (880, 'Apricot Pork Chops', '5 mins', '1 hrs', '1 hrs 5 mins', '6', '6 servings', '6  pork chops, 1 (1 ounce) package dry onion soup mix, 10 ounces Russian-style salad dressing, 1 cup apricot preserves', 'Preheat oven to 350 degrees F (175 degrees C).
INSERT INTO public.recipes VALUES (667, 'Grilled Tilapia with Mango Salsa', '45 mins', '10 mins', '1 hrs 55 mins', '2', NULL, '⅓ cup extra-virgin olive oil, 1 tablespoon lemon juice, 1 tablespoon minced fresh parsley, 1 clove garlic, minced, 1 teaspoon dried basil, 1 teaspoon ground black pepper, ½ teaspoon salt, 2 (6 ounce) tilapia fillets', 'Prepare the fish: Whisk together olive oil, lemon juice, parsley, garlic, basil, black pepper, and salt in a bowl and pour into a resealable plastic bag. Add tilapia fillets, coat with the marinade, squeeze out excess air, and seal the bag. Marinate in the refrigerator for 1 hour.
INSERT INTO public.recipes VALUES (668, 'Jicama Mango Salad with Cilantro and Lime', '30 mins', NULL, '45 mins', '8', '8 servings', '1 large jicama, peeled and cut into matchsticks, 1 small red bell pepper, cut into matchsticks, 1 large firm mango, peeled and cut into matchsticks, ½  red onion, cut into matchsticks', 'Toss jicama, red pepper, mango, and red onion together in a large bowl. Set aside.
INSERT INTO public.recipes VALUES (669, 'Mango Jam', '15 mins', '30 mins', '45 mins', '24', '3 cups', '2 pounds ripe mangoes , 1 ½ cups white sugar, ¾ cup water, 3  saffron threads (Optional)', 'Make 4 to 5 slits in mangoes and microwave on High until soft, 1 to 2 minutes. Cool, then remove the peel and inner seed; place mango pulp in a large bowl. Use a fork or potato masher to mash the pulp well.
INSERT INTO public.recipes VALUES (670, 'Mango-Habanero Chicken Wings', '20 mins', '1 hrs 33 mins', '1 hrs 53 mins', '10', '30 wings', '30  chicken wing sections, 1 (12 ounce) can mango nectar, ¼ cup brown sugar, 6  habanero peppers, stemmed, 2 tablespoons soy sauce, 1 tablespoon sriracha hot chili sauce, 1 tablespoon rice vinegar, 1 stick butter, 3 cloves garlic, minced, 2 tablespoons honey, 1 cup cornstarch, 2 cups vegetable oil for frying', 'Rinse chicken wings and pat dry with paper towels. Place wings on a baking sheet and refrigerate to dry a bit more.
INSERT INTO public.recipes VALUES (671, 'Mahi Mahi with Coconut Rice and Mango Salsa', '30 mins', '30 mins', '2 hrs', '4', '4 servings', '2 tablespoons olive oil, 1 ½ teaspoons soy sauce, 2 teaspoons lemon juice, 1 clove garlic, crushed, 2 teaspoons red pepper flakes, 1 teaspoon fresh ground black pepper , ½ teaspoon minced fresh ginger root, 2 tablespoons chopped green onion (Optional),   salt to taste, 4 (4 ounce) mahi mahi fillets, 2 cups uncooked jasmine rice, 2 cups water, 1 cube chicken bouillon, 1 tablespoon butter (Optional), ¾ (14 ounce) can coconut milk, 2 tablespoons white sugar, 1 ½ teaspoons butter (Optional), 1 ½ tablespoons white sugar, 1 ½ cups fresh mango, cubed', 'Whisk together the olive oil, soy sauce, lemon juice, garlic, red pepper flakes, black pepper, ginger, green onion, and salt in a bowl. Add the mahi mahi and toss to evenly coat. Cover the bowl with plastic wrap, and marinate in the refrigerator for 1 hour.
INSERT INTO public.recipes VALUES (672, 'Mango Bread', '20 mins', '1 hrs', '1 hrs 30 mins', '16', '2 8x4x2-inch loaves', '2 cups all-purpose flour, 2 teaspoons baking soda, 2 teaspoons ground cinnamon, ½ teaspoon salt, 3  eggs, ¾ cup softened butter, 1 ¼ cups white sugar, 1 teaspoon vanilla extract, 2 cups chopped mango, ½ cup shredded coconut, ¼ cup chopped walnuts', 'Preheat oven to 350 degrees F (175 degrees C). Grease and flour 2 loaf pans.
INSERT INTO public.recipes VALUES (673, 'White Peachy Sangria', '30 mins', NULL, '8 hrs 30 mins', '20', '20 servings', '4 (750 milliliter) bottles moscato wine, 4 (12 fluid ounce) cans or bottles lemon-lime soda (such as Sprite®), 1 cup brandy, 1 cup peach schnapps, 2  fresh peaches, pitted and sliced, 1 (16 ounce) package fresh strawberries, sliced, 2  mangos - peeled, seeded, and sliced, ½  fresh pineapple - peeled, cored, and cut into chunks, 1 (6 ounce) container fresh raspberries', 'Stir moscato wine, lemon-lime soda, brandy, peach schnapps, peaches, strawberries, mangos, pineapple chunks, and raspberries together in a large container and chill 8 hours or overnight.', '4.9', 'https://www.allrecipes.com/recipe/223329/white-peachy-sangria/', '/Drinks Recipes/Sangria Recipes/', 'Total Fat 0g 0%, Sodium 24mg 1%, Total Carbohydrate 41g 15%, Dietary Fiber 2g 5%, Total Sugars 22g, Protein 1g, Vitamin C 30mg 148%, Calcium 23mg 2%, Iron 1mg 3%, Potassium 228mg 5%', 'Prep Time: 30 mins, Additional Time: 8 hrs, Total Time: 8 hrs 30 mins, Servings: 20, Yield: 20 servings', 'https://www.allrecipes.com/thmb/uz0pOWl7xju8N7kpWz_2HCIbhZE=/1500x0/filters:no_upscale():max_bytes(150000):strip_icc()/223329-White-Peachy-Sangria-Caelynne_5455009_original-4x3-1-8a93bc5db2404e3b84c49b8d671d9cbf.jpg');
INSERT INTO public.recipes VALUES (674, 'Maui Girl''s Mango Pie', '25 mins', '45 mins', '1 hrs 10 mins', '8', '8 servings', '  pastry for a double-crust 9-inch pie, 4 cups peeled and sliced mango, ½ cup white sugar, 3 tablespoons cornstarch, 2 teaspoons lemon juice, 1 teaspoon ground cinnamon, 1 tablespoon butter, cut into small chunks', 'Preheat oven to 400 degrees F (200 degrees C). Line a 9-inch pie pan with half of the pie pastry. Set aside.
INSERT INTO public.recipes VALUES (675, 'Healthy Fish Tacos with Mango Salsa', '20 mins', '15 mins', '1 hrs 35 mins', '8', '8 tacos', '1  mango - peeled, seeded, and chopped, 2  avocados - peeled, pitted, and chopped, 1 cup chopped tomato, ½ cup diced red onion, ½ cup diced red pepper, 2 tablespoons chopped fresh flat-leaf parsley, 2 tablespoons canola oil, 2 tablespoons brown sugar, 1  lime, juiced, 1 teaspoon cider vinegar, 1 dash hot pepper sauce, or to taste,   salt and ground black pepper to taste, 8  taco shells, 4 (6 ounce) mahi mahi fillets, cut into 1-inch slices, 1 teaspoon ground black pepper, 1 teaspoon paprika, ½ teaspoon salt, 2 tablespoons olive oil', 'Stir mango, avocado, tomato, red onion, red pepper, parsley, canola oil, brown sugar, lime juice, cider vinegar, hot pepper sauce, salt, and ground black pepper together in a bowl. Refrigerate salsa for at least 1 hour.
INSERT INTO public.recipes VALUES (676, 'Sweet and Kickin'' Mango-Habanero Hot Sauce', '25 mins', '20 mins', '45 mins', '128', '1 gallon or more', '2 tablespoons extra virgin olive oil, 1 large sweet onion, chopped, 7  ripe mangoes, cored and chopped, 1  fresh peach, chopped (Optional), ⅓ cup honey, 15  habanero peppers, stemmed, or more to taste, ¼ cup yellow mustard, 2 ½ tablespoons salt, 2 ½ tablespoons paprika, 1 ½ tablespoons ground white pepper, 1 tablespoon ground cumin, ⅓ teaspoon ground allspice, ¼ cup light brown sugar, 1 ½ cups white vinegar, ½ cup apple cider vinegar', 'Heat olive oil in a skillet over medium heat. Add onion; cook and stir until translucent, about 5 minutes.
INSERT INTO public.recipes VALUES (679, 'Fresh Mango Salsa', '20 mins', NULL, '1 hrs 20 mins', '40', '5 cups', '2 cups diced Roma tomatoes , 1 ½ cups diced mango, ½ cup diced onion, 1 teaspoon white sugar, ½ cup chopped fresh cilantro, 2 tablespoons fresh lime juice, 1 tablespoon cider vinegar, ½ teaspoon salt, ½ teaspoon black pepper, 2 cloves garlic, minced', 'Stir the tomatoes, mango, onion, sugar, cilantro, lime juice, cider vinegar, salt, pepper, and garlic together in a bowl; refrigerate 1 hour before serving.', '4.7', 'https://www.allrecipes.com/recipe/215631/fresh-mango-salsa/', '/Appetizers and Snacks/Dips and Spreads Recipes/Salsa Recipes/Mango Salsa Recipes/', 'Sodium 30mg 1%, Total Carbohydrate 2g 1%, Dietary Fiber 0g 1%, Total Sugars 1g, Protein 0g, Vitamin C 3mg 17%, Calcium 3mg 0%, Iron 0mg 1%, Potassium 39mg 1%', 'Prep Time: 20 mins, Additional Time: 1 hrs, Total Time: 1 hrs 20 mins, Servings: 40, Yield: 5 cups', 'https://www.allrecipes.com/thmb/b3FUpYiIyaleO57XPwTjVZcW_SE=/1500x0/filters:no_upscale():max_bytes(150000):strip_icc()/3783957-be220865b9f444279b1d1c55a7879ec7.jpg');
INSERT INTO public.recipes VALUES (680, 'Creamy Mango Smoothie', '5 mins', NULL, '5 mins', '2', '2 servings', '¾ cup cold milk, ¼ cup vanilla yogurt, ¾ teaspoon vanilla extract, 1 ½ cups chopped fresh mango, 3  ice cubes', 'Blend the milk, yogurt, vanilla extract, mango, and ice cubes in a blender until smooth and creamy.', '4.4', 'https://www.allrecipes.com/recipe/215171/creamy-mango-smoothie/', '/Drinks Recipes/Smoothie Recipes/Mango/', 'Total Fat 3g 3%, Saturated Fat 2g 8%, Cholesterol 9mg 3%, Sodium 61mg 3%, Total Carbohydrate 30g 11%, Dietary Fiber 2g 8%, Total Sugars 27g, Protein 5g, Vitamin C 35mg 174%, Calcium 173mg 13%, Iron 0mg 1%, Potassium 400mg 9%', 'Prep Time: 5 mins, Total Time: 5 mins, Servings: 2, Yield: 2 servings', 'https://www.allrecipes.com/thmb/-EY929TdKF1ZQZy7E7YKnJvrj8c=/1500x0/filters:no_upscale():max_bytes(150000):strip_icc()/964770-5711c7351e7c4c0aba32942af7069989.jpg');
INSERT INTO public.recipes VALUES (681, 'Easy Mango Cake', '15 mins', '40 mins', '1 hrs 25 mins', '12', '1 fluted tube pan', '1  ripe mango, 1 (18.25 ounce) box yellow cake mix, 3  eggs, ½ cup water, ¼ cup vegetable oil, 2 tablespoons lime zest', 'Preheat oven to 350 degrees F (175 degrees C). Grease a fluted tube pan (such as Bundt®).
INSERT INTO public.recipes VALUES (682, 'Easy Mango Salad', '20 mins', NULL, '20 mins', '4', '4 servings', '2  firm green mangoes - peeled, pitted, and cut into matchsticks, ¼  purple onion, thinly sliced, ¼  red bell pepper, thinly sliced, 3 sprigs cilantro, or more to taste, leaves removed and stems discarded, 2 tablespoons lime juice, 2 tablespoons fish sauce, 1 tablespoon brown sugar, 1 tablespoon crushed peanuts', 'Mix mangoes, onion, red bell pepper, and cilantro leaves together in a bowl.
INSERT INTO public.recipes VALUES (683, 'Mango Sorbet', '15 mins', NULL, '15 mins', '12', '6 cups', '4  mangos - peeled, seeded, and cubed, 1 cup simple syrup, 3 tablespoons fresh lime juice', 'Place cubed mango in a food processor, and puree. Pour in simple syrup and lime juice, and puree until smooth.
INSERT INTO public.recipes VALUES (684, 'Delightfully Exotic Mango Cake', '15 mins', '35 mins', '50 mins', '10', '1 9x13-inch pan', '1 ½ cups canned sweetened mango pulp, 1 cup white sugar, ½ cup margarine, 2 medium eggs, 2 cups all-purpose flour, 1 teaspoon baking powder, 1 teaspoon baking soda, 2 tablespoons whole almonds, or as desired (Optional)', 'Preheat oven to 375 degrees F (190 degrees C). Grease a 9x13-inch baking dish.
INSERT INTO public.recipes VALUES (685, 'Blackened Tuna Steaks with Mango Salsa', '45 mins', '10 mins', '3 hrs 55 mins', '4', '4 steaks', '2 tablespoons olive oil, 2 tablespoons lime juice, 2 cloves garlic, minced, 4  tuna steaks, 1  fresh mango - peeled, pitted, and chopped, ¼ cup finely chopped red bell pepper, ½  Spanish onion, finely chopped, 1  green onion, chopped, 2 tablespoons chopped fresh cilantro, 1  jalapeno pepper, seeded and minced, 2 tablespoons lime juice, 1 ½ teaspoons olive oil, 2 tablespoons paprika, 1 tablespoon cayenne pepper, 1 tablespoon onion powder, 2 teaspoons salt, 1 teaspoon ground black pepper, 1 teaspoon dried thyme, 1 teaspoon dried basil, 1 teaspoon dried oregano, 1 tablespoon garlic powder, 4 tablespoons olive oil', 'Whisk together the olive oil, lime juice, and garlic in a bowl. Rub the tuna steaks with the mixture. Place the steaks in a sealable container and chill in refrigerator 3 hours.
INSERT INTO public.recipes VALUES (686, 'Peanut Butter Mango Smoothie', '5 mins', NULL, '5 mins', '2', '2 smoothies', '1 cup vanilla yogurt, 1  banana, broken into chunks, ½ cup frozen mango chunks, 2 tablespoons peanut butter, or to taste', 'Blend yogurt, banana, mango, and peanut butter together in a blender until smooth.', '4.4', 'https://www.allrecipes.com/recipe/238642/peanut-butter-mango-smoothie/', '/Drinks Recipes/Smoothie Recipes/Mango/', 'Total Fat 10g 13%, Saturated Fat 3g 14%, Cholesterol 6mg 2%, Sodium 157mg 7%, Total Carbohydrate 41g 15%, Dietary Fiber 3g 12%, Total Sugars 32g, Protein 11g, Vitamin C 18mg 88%, Calcium 224mg 17%, Iron 1mg 3%, Potassium 649mg 14%', 'Prep Time: 5 mins, Total Time: 5 mins, Servings: 2, Yield: 2 smoothies', 'https://www.allrecipes.com/thmb/1lYMFZXgJySgs6CXn_C-osY62lo=/1500x0/filters:no_upscale():max_bytes(150000):strip_icc()/1351359-8888229b6133489ba0eeaf6e6cbe8ec8.jpg');
INSERT INTO public.recipes VALUES (687, 'Mango Watermelon Smoothie', '10 mins', NULL, '10 mins', '4', '4 servings', '5 cups cubed seeded watermelon, 1  mango - peeled, seeded, and diced, ½ cup water, 1 tablespoon white sugar, 4 cubes  ice cubes', 'Blend watermelon, mango, water, and sugar together in a blender until smooth.
INSERT INTO public.recipes VALUES (688, 'Fresh Mango Muffins', '20 mins', '25 mins', '45 mins', '12', '1 dozen muffins', '1 ½ cups all-purpose flour, ¼ cup white sugar, 2 teaspoons baking powder, 1 pinch salt, 3  eggs, ¼ cup heavy whipping cream, ¼ cup unsalted butter, melted, 3 cups mango - peeled, seeded, and cubed', 'Preheat oven to 350 degrees F (175 degrees C). Grease 12 muffin cups or line with paper muffin liners.
INSERT INTO public.recipes VALUES (689, 'Mango Cilantro Slaw', '15 mins', NULL, '1 hrs 15 mins', '4', '4 servings', '3 tablespoons white wine vinegar, 2 tablespoons canola oil, 2 tablespoons honey, 2 tablespoons mayonnaise, ½ teaspoon celery seed (Optional), ½ teaspoon poppy seeds (Optional), ½ teaspoon salt, ¼ teaspoon ground black pepper, 1 (10 ounce) package finely shredded cabbage, 1  firm, ripe mango - peeled, seeded, and cut into 1/2-inch pieces, ⅓ cup chopped cilantro, 3  green onions, chopped', 'Whisk vinegar, oil, honey, mayonnaise, celery seed, poppy seeds, salt, and black pepper together in a bowl until smooth and creamy. Add cabbage, mango, cilantro, and green onions; toss until well-combined. Cover the bowl with plastic wrap and refrigerate until flavors blend, about 1 hour.', '4.8', 'https://www.allrecipes.com/recipe/238205/mango-cilantro-slaw/', '/Salad/Coleslaw Recipes/With Mayo/', 'Total Fat 13g 17%, Saturated Fat 1g 7%, Cholesterol 3mg 1%, Sodium 338mg 15%, Total Carbohydrate 17g 6%, Dietary Fiber 1g 5%, Total Sugars 15g, Protein 1g, Vitamin C 17mg 83%, Calcium 30mg 2%, Iron 1mg 4%, Potassium 136mg 3%', 'Prep Time: 15 mins, Additional Time: 1 hrs, Total Time: 1 hrs 15 mins, Servings: 4, Yield: 4 servings', 'https://www.allrecipes.com/thmb/R7X9Rn2s6O8ukVRgNAjSGoj3G9c=/1500x0/filters:no_upscale():max_bytes(150000):strip_icc()/1216117-101849fa88bc4dc3b86cc981080e0f64.jpg');
INSERT INTO public.recipes VALUES (690, 'Mango Oatmeal Breakfast Smoothie', '10 mins', NULL, '10 mins', '1', '1 smoothie', '½ cup orange juice, ½ cup frozen mango chunks, ½  banana, cut into chunks, ⅓ cup plain yogurt, ¼ cup oats', 'Blend orange juice, mango, banana, yogurt, and oats together in a blender until smooth.', '4.6', 'https://www.allrecipes.com/recipe/241023/mango-oatmeal-breakfast-smoothie/', '/Breakfast and Brunch/Drinks/', 'Total Fat 3g 4%, Saturated Fat 1g 6%, Cholesterol 5mg 2%, Sodium 62mg 3%, Total Carbohydrate 60g 22%, Dietary Fiber 5g 19%, Total Sugars 36g, Protein 9g, Vitamin C 91mg 453%, Calcium 185mg 14%, Iron 1mg 8%, Potassium 852mg 18%', 'Prep Time: 10 mins, Total Time: 10 mins, Servings: 1, Yield: 1 smoothie', 'https://www.allrecipes.com/thmb/e44FJH-cO01seBS6Mqrc60dLxI8=/1500x0/filters:no_upscale():max_bytes(150000):strip_icc()/2253824-f4428a7d341d468892c8af986f8dfaf7.jpg');
INSERT INTO public.recipes VALUES (691, 'Mango, Peach and Pineapple Salsa', '20 mins', NULL, '1 hrs 20 mins', '16', '8 cups', '2  mangos, peeled, seeded and chopped, 2 small peaches, halved, pitted, and cut into 1/2-inch dice, 1 cup diced fresh pineapple, 4  tomatoes, chopped, 1  white onion, diced, 1  red bell pepper, diced, 1  yellow bell pepper, diced, 1 cup chopped fresh cilantro, or to taste, 1 clove garlic, minced, 1 small jalapeno pepper, minced, 2 tablespoons lime juice, 1 teaspoon salt, 2 tablespoons white sugar, or to taste, ¾ cup water', 'Place the mango, peach, pineapple, tomato, onion, red pepper, yellow pepper, and cilantro in a mixing bowl. Stir in the garlic, jalapeno, lime juice, salt, sugar, and water. Cover and refrigerate at least 1 hour before serving.', '4.6', 'https://www.allrecipes.com/recipe/166482/mango-peach-and-pineapple-salsa/', '/Appetizers and Snacks/Dips and Spreads Recipes/Salsa Recipes/Peach Salsa Recipes/', 'Total Fat 0g 0%, Sodium 150mg 7%, Total Carbohydrate 10g 4%, Dietary Fiber 1g 5%, Total Sugars 7g, Protein 1g, Vitamin C 48mg 242%, Calcium 14mg 1%, Iron 0mg 2%, Potassium 199mg 4%', 'Prep Time: 20 mins, Additional Time: 1 hrs, Total Time: 1 hrs 20 mins, Servings: 16, Yield: 8 cups', 'https://www.allrecipes.com/thmb/WI4AYyHsy5Kz-dtE17vXz2h9QWI=/1500x0/filters:no_upscale():max_bytes(150000):strip_icc()/225040-97196159984d4e77b1fdb9e3fec702ca.jpg');
INSERT INTO public.recipes VALUES (692, 'Real Indian Mango Chutney', '30 mins', '1 hrs 10 mins', '3 hrs 10 mins', '24', '24 servings', '2 ¼ cups diced fresh mango, ¼ cup salt, 2 ½ cups water, 2 ⅓ cups white sugar, 2 cups vinegar, ½ cup raisins, ½ cup chopped pitted dates, 2  cinnamon sticks, 2 teaspoons minced fresh ginger root, 2 teaspoons crushed garlic, 2 teaspoons ground dried chile pepper, 10  half-pint canning jars with lids and rings', 'Put mango into a large bowl. Sprinkle salt over the mango. Pour water over the mango. Let mango soak for 1 hour to overnight.
INSERT INTO public.recipes VALUES (693, 'Mango Chutney', '10 mins', '1 hrs 30 mins', '1 hrs 40 mins', '240', '4 quarts', '3 cups distilled white vinegar, 6 cups white sugar, 6 cups brown sugar, 1 teaspoon ground cinnamon, 2 teaspoons ground ginger, 4 teaspoons ground allspice, 1 teaspoon ground cloves, 2 teaspoons ground nutmeg, 5  small red hot chile peppers, seeded and chopped, 1 teaspoon kosher salt, 2 large onions, chopped, 3 cloves garlic, chopped, 1 cup golden raisins, 1 cup raisins, ½ cup fresh ginger root, chopped, 16 cups sliced, semi-ripe mangos, ½ cup sliced almonds', 'In a large saucepan combine vinegar, white sugar, brown sugar, cinnamon, ground ginger, allspice, cloves, nutmeg, chile peppers and salt. Bring to a boil; boil for 1/2 hour.
INSERT INTO public.recipes VALUES (694, 'Smoked Salmon Poke Bowl', '15 mins', NULL, '45 mins', '4', '4 servings', '¼ cup soy sauce, 3  green onions, thinly sliced, 1 tablespoon black sesame oil, 1 tablespoon rice vinegar, 1 teaspoon grated ginger, ½ teaspoon garlic, minced, 12 ounces smoked salmon, chopped, 2 cups cooked brown rice, ¼ cup diced mango, ¼ cup diced cucumber, ¼ cup diced avocado, ¼ cup sliced fresh strawberries, 1 teaspoon black sesame seeds, or to taste', 'Combine soy sauce, green onions, sesame oil, rice vinegar, ginger, and garlic in a bowl. Mix until thoroughly combined. Add salmon and marinate in the refrigerator for 30 minutes to 1 hour.
INSERT INTO public.recipes VALUES (695, 'Summertime Mango Drink', '5 mins', NULL, '5 mins', '4', '4 servings', '2  mangoes, cut into cubes, 1 cup ice cubes, 1 teaspoon vanilla extract, 1 tablespoon white sugar, 1 ⅔ cups milk', 'Combine mangoes, ice cubes, vanilla extract, and sugar in a blender; pour in milk. Blend until liquefied.', '4.3', 'https://www.allrecipes.com/recipe/259088/summertime-mango-drink/', '/Breakfast and Brunch/Drinks/', 'Total Fat 2g 3%, Saturated Fat 1g 7%, Cholesterol 8mg 3%, Sodium 43mg 2%, Total Carbohydrate 21g 8%, Dietary Fiber 1g 5%, Total Sugars 19g, Protein 4g, Vitamin C 21mg 105%, Calcium 127mg 10%, Iron 0mg 1%, Potassium 271mg 6%', 'Prep Time: 5 mins, Total Time: 5 mins, Servings: 4, Yield: 4 servings', 'https://www.allrecipes.com/thmb/vgyt7I2dEYK9V5SEN2K_hABh7uM=/1500x0/filters:no_upscale():max_bytes(150000):strip_icc()/4539415-106f0fbc6e2640c4b3a52a975710091f.jpg');
INSERT INTO public.recipes VALUES (696, 'Mango Salsa Salmon', '15 mins', '15 mins', '30 mins', '4', '4 servings', '4 (6 ounce) salmon steaks, 3 tablespoons olive oil, 1 large red onion, diced, 2 cloves garlic, peeled and minced, 2  tomatoes, diced, 1 sprig fresh cilantro, chopped, 2  mangos - peeled, seeded, and diced', 'Preheat the oven broiler. Line a broiler pan with foil.
INSERT INTO public.recipes VALUES (697, 'Spicy Mango Salad', '15 mins', NULL, '45 mins', '6', '6 servings', '4 medium mangos - peeled, seeded, and cubed, ¼ cup fresh lime juice, 2 tablespoons extra-virgin olive oil, 1 tablespoon red pepper flakes, 2 tablespoons chopped fresh cilantro, 2 tablespoons chopped shallots,   salt and freshly ground black pepper to taste', 'Place the mango cubes into a serving bowl. In a separate bowl, whisk together the lime juice and olive oil. Season with red pepper flakes, cilantro, shallots, salt and pepper. Whisk briefly, then pour over the mangos. Stir to coat, then cover and refrigerate for about 30 minutes to blend the flavors before serving.', '4.5', 'https://www.allrecipes.com/recipe/85165/spicy-mango-salad/', '/Salad/Fruit Salad Recipes/', 'Total Fat 5g 7%, Saturated Fat 1g 4%, Sodium 4mg 0%, Total Carbohydrate 26g 9%, Dietary Fiber 3g 11%, Total Sugars 21g, Protein 1g, Vitamin C 43mg 215%, Calcium 19mg 1%, Iron 0mg 2%, Potassium 274mg 6%', 'Prep Time: 15 mins, Additional Time: 30 mins, Total Time: 45 mins, Servings: 6, Yield: 6 servings', 'https://www.allrecipes.com/thmb/TRkjMLp_tdaCRNyTCrMk95wTX2U=/1500x0/filters:no_upscale():max_bytes(150000):strip_icc()/22476-c7fabc2f40f3431eb86da7c497bd645b.jpg');
INSERT INTO public.recipes VALUES (698, 'Mango-Pineapple Chutney', '35 mins', '1 hrs 10 mins', '3 hrs 45 mins', '24', '24 servings', '2 tablespoons vegetable oil, 1 teaspoon crushed red pepper flakes, 1 large sweet onion, minced, 4 inch piece fresh ginger root, peeled and minced, 1 large yellow bell pepper, diced, 3 large ripe mangoes, peeled, pitted, and diced, 1 small pineapple, peeled and diced, ½ cup brown sugar, 1 ½ tablespoons curry powder, ½ cup apple cider vinegar', 'Heat the vegetable oil in a large saucepan over medium heat. Stir in the red pepper flakes and cook until they begin to sizzle, then stir in the minced onion. Reduce the heat to low, cover, and cook, stirring occasionally until the onions have softened, about 20 minutes.
INSERT INTO public.recipes VALUES (699, 'Mexican Mango and White Fish Ceviche', '15 mins', NULL, '1 hrs 55 mins', '12', '12 servings', '2 pounds white fish, cut into small cubes, 4  limes, juiced, ½  orange, juiced, 1 tablespoon olive oil, 1  green chile pepper, chopped, 2  mangoes, cut into cubes, 5  green onions, chopped, 3  tomatoes, seeded and chopped, ½ cup chopped fresh cilantro,   salt and ground black pepper to taste', 'Combine white fish, lime juice, orange juice, oil, and chile pepper in a glass or ceramic bowl. Cover with plastic wrap and refrigerate for 90 minutes.
INSERT INTO public.recipes VALUES (700, 'Simple Mango Pudding', '10 mins', NULL, '4 hrs 10 mins', '6', NULL, '1 cup hot water, 1 cup white sugar, 2 (.25 ounce) packages powdered gelatin (such as Knox®), 26 ounces canned mango pulp, 1 ½ cups evaporated milk, 1 cup cold water', 'Combine hot water, sugar, and powdered gelatin in a small bowl; stir until sugar and gelatin are dissolved.
INSERT INTO public.recipes VALUES (701, 'Mommy''s Mango Cobbler', '15 mins', '45 mins', '1 hrs', '12', '12 servings', '8  mangoes - peeled, seeded, and sliced, 2 cups water, ½ cup white sugar', 'Preheat oven to 375 degrees F (190 degrees C).
INSERT INTO public.recipes VALUES (708, 'Coconut-Lime Cheesecake with Mango Coulis', '35 mins', '55 mins', '9 hrs 30 mins', '8', '1 9-inch cheesecake', '¾ cup sweetened flaked coconut, ¾ cup crushed gingersnap cookies, 3 tablespoons melted butter, 2 (8 ounce) packages cream cheese, softened, 1 (10 ounce) can sweetened condensed milk, 2  eggs, 1 tablespoon lime zest, 2 tablespoons lime juice, 1 tablespoon coconut extract, 2 cups cubed fresh mango, 1 teaspoon white sugar, or more to taste', 'Preheat the oven to 325 degrees F (165 degrees C). Lightly grease a 9-inch springform pan.
INSERT INTO public.recipes VALUES (702, 'Mangonada Jell-O Shots', '10 mins', '10 mins', '4 hrs 25 mins', '20', '20 shots', '¼ cup water, 2 (.25 ounce) packages unflavored gelatin, 2 cups mango puree, ½ cup white sugar, 1 tablespoon lemon juice, 1 cup vodka, 1 teaspoon chamoy sauce, or to taste, 1 teaspoon chile-lime seasoning (such as Tajin®), or as needed', 'Heat water and gelatin in a small saucepan over medium-high heat; whisk until dissolved, about 5 minutes. Add mango purée, sugar, and lemon juice; whisk until dissolved, about 5 minutes. Remove from heat to cool slightly, about 5 minutes.
INSERT INTO public.recipes VALUES (703, 'Mango-Peach Smoothie', '10 mins', NULL, '10 mins', '2', NULL, '1  peach, sliced, 1  mango, peeled and diced, ½ cup vanilla soy milk, ½ cup orange juice, or as needed', 'Place peach, mango, soy milk, and orange juice into a blender. Cover, and puree until smooth. Pour into glasses to serve.', '4.7', 'https://www.allrecipes.com/recipe/66224/mango-peach-smoothie/', '/Breakfast and Brunch/Drinks/', 'Total Fat 1g 2%, Saturated Fat 0g 1%, Sodium 29mg 1%, Total Carbohydrate 22g 8%, Dietary Fiber 2g 6%, Total Sugars 18g, Protein 3g, Vitamin C 52mg 260%, Calcium 24mg 2%, Iron 0mg 2%, Potassium 316mg 7%', 'Prep Time: 10 mins, Total Time: 10 mins, Servings: 2', 'https://www.allrecipes.com/thmb/Y9Nbxm67CkvEOFJcMo3YW0Uy0v0=/1500x0/filters:no_upscale():max_bytes(150000):strip_icc()/414770-bfa2d3557f264bc58a0d84f96d0fd3f9.jpg');
INSERT INTO public.recipes VALUES (704, 'Blackened Salmon Tacos with Chunky Mango Avocado Salsa', '40 mins', '9 mins', '49 mins', '6', '6 tacos', '3  ripe mangoes - peeled, pitted, and diced, 1  avocado - peeled, pitted, and diced, 1  orange bell pepper, diced, 1  jalapeno pepper, seeded and diced, 1  lime, juiced, 2 tablespoons chopped fresh cilantro, 1 pinch salt, 1 tablespoon sweet and spicy seafood rub, or to taste, ½ teaspoon chili powder, or to taste,   salt and ground black pepper to taste, 2  skin-on salmon fillets, 2 tablespoons olive oil, or as needed, divided, 6  corn tortillas, 3 large limes, cut into wedges', 'Combine mangoes, avocado, orange bell pepper, and jalapeno in a large bowl to make salsa. Add lime juice, cilantro, and salt; mix to combine. Cover with plastic wrap and refrigerate.
INSERT INTO public.recipes VALUES (705, 'Pineapple Mango Habanero Jam', '20 mins', '40 mins', '9 hrs', '64', '8 half-pint jars', '1 ½ pounds fresh mangos, cut into chunks, 1 pound fresh pineapple, cut into chunks, ½ cup cider vinegar, 4 cups white sugar, 1 (3 ounce) pouch liquid pectin, 4  habanero chiles - stemmed, halved, and seeded', 'Combine mangos, pineapple, and cider vinegar in a stockpot over medium-high heat. Bring to a simmer; mash mangos and pineapple to a chunky consistency with a potato masher. Stir in sugar until dissolved.
INSERT INTO public.recipes VALUES (706, 'Easy Fish Tacos with Mango-Pineapple Slaw', '30 mins', '20 mins', '50 mins', '8', '8 tacos', '1 pound cod fillets, 1 tablespoon lemon juice,   salt and ground black pepper to taste, ½ cup red wine vinegar, ¼ cup reduced-fat mayonnaise, 1 tablespoon white sugar, 1 tablespoon salt, 1 tablespoon ground black pepper, 1 teaspoon garlic powder, 3 cups shredded cabbage, ½ cup chopped fresh mango, ½ cup chopped fresh pineapple, ½ cup chopped red onion, ¼ cup chopped fresh cilantro, 1  fresh jalapeno pepper, chopped, 8 (8 inch) flour tortillas', 'Preheat the oven to 375 degrees F (190 degrees C).
INSERT INTO public.recipes VALUES (881, 'Apricot and Honey Ham Glaze', '5 mins', NULL, '5 mins', '12', '3 /4 cup', '½ cup apricot jam, 3 tablespoons honey, 1 tablespoon hot English mustard, 2 tablespoons orange marmalade', 'Stir together the apricot jam, honey, hot English mustard, and orange marmalade in a bowl until the mixture is well combined.
INSERT INTO public.recipes VALUES (711, 'Macadamia-Crusted Sea Bass with Mango Cream Sauce', '20 mins', '20 mins', '40 mins', '4', '4 servings', '½  mango - peeled, seeded and diced, ½ cup heavy cream, 1 teaspoon lemon juice, ½ cup chopped macadamia nuts, ¼ cup seasoned bread crumbs, 1 teaspoon olive oil, ½ teaspoon black pepper, 1 pinch red pepper flakes, 1 pound fresh sea bass,   salt and ground black pepper to taste, 2 cloves minced garlic, 1 tablespoon extra virgin olive oil', 'In a food processor, combine macadamia nuts, bread crumbs, 1 teaspoon olive oil, black pepper, and red pepper flakes. Process until smooth. Preheat oven to 350 degrees F (175 degrees C).
INSERT INTO public.recipes VALUES (712, 'Caribbean Fish With Mango Salsa', '45 mins', '10 mins', '1 hrs 25 mins', '5', NULL, '1 tablespoon paprika, 2 teaspoons curry powder, 2 teaspoons ground cumin, 1 ½ teaspoons ground allspice, 1 teaspoon ground ginger, 1 teaspoon ground coriander, ¾ teaspoon salt, ½ teaspoon freshly ground black pepper, ¼ teaspoon ground fennel seed (Optional), ⅛ teaspoon cayenne pepper (Optional)', 'Mix together paprika, curry powder, cumin, allspice, ginger, coriander, salt, black pepper, fennel, and cayenne pepper in a bowl; set aside.
INSERT INTO public.recipes VALUES (713, 'Chamoyada', '10 mins', NULL, '10 mins', '1', NULL, '1 cup fresh or frozen mango cubes, 1 (6 ounce) can pineapple juice, ½  lime, 2 teaspoons chili-lime seasoning (such as Tajin®), 2 tablespoons chamoy (Mexican chili fruit condiment)', 'Combine mango and pineapple juice in a blender; blend until smooth. Set aside.
INSERT INTO public.recipes VALUES (714, 'Peach-Mango-Habanero Wing Sauce', '10 mins', '10 mins', '20 mins', '16', NULL, '1 large mango, peeled and pitted, 1 small fresh peach, halved and pitted, 2  habanero peppers, stemmed, ¼ cup unsalted butter, 4 cloves garlic, minced, ½ cup brown sugar, 2 teaspoons Worcestershire sauce, 1 teaspoon minced fresh ginger root,   salt and ground black pepper to taste', 'Blend mango, peach, and habanero peppers in a food processor or blender until smooth.
INSERT INTO public.recipes VALUES (715, 'Savory Mango Guacamole', '15 mins', NULL, '15 mins', '6', '6 servings', '3 large avocados, peeled and pitted, 1 small red onion, chopped, 1  mango - peeled, pitted, and chopped, 1  lime, juiced, 1 tablespoon minced garlic, 1 tablespoon salt, 3 tablespoons chopped fresh cilantro', 'Mash avocados in a medium bowl to a lumpy consistency. Mix onion, mango, lime juice, garlic, salt, and cilantro into avocado.', '4.7', 'https://www.allrecipes.com/recipe/221288/savory-mango-guacamole/', '/Appetizers and Snacks/Dips and Spreads Recipes/Guacamole Recipes/', 'Total Fat 21g 27%, Saturated Fat 3g 15%, Sodium 1175mg 51%, Total Carbohydrate 19g 7%, Dietary Fiber 11g 38%, Total Sugars 5g, Protein 3g, Vitamin C 26mg 131%, Calcium 30mg 2%, Iron 1mg 6%, Potassium 770mg 16%', 'Prep Time: 15 mins, Total Time: 15 mins, Servings: 6, Yield: 6 servings', 'https://www.allrecipes.com/thmb/aD3V-Ni7EZ3evk_8SLNXKl0KinA=/1500x0/filters:no_upscale():max_bytes(150000):strip_icc()/830949-6411b3840ec347c3886f175bfb7d5d11.jpg');
INSERT INTO public.recipes VALUES (717, 'Mango Overnight Oats', '10 mins', NULL, '3 hrs 10 mins', '1', NULL, '½ cup Quaker® Oats, ¼ cup low-fat milk, ⅓ cup low-fat plain yogurt, ⅛ teaspoon almond extract, ½ cup diced mango, 1 teaspoon honey, 1 teaspoon chia seeds', 'Add oats to your container of choice. Pour in low-fat milk and yogurt.
INSERT INTO public.recipes VALUES (718, 'Strawberry Mango Mesclun Salad', '15 mins', NULL, '15 mins', '12', NULL, '½ cup sugar, ¾ cup canola oil, 1 teaspoon salt, ¼ cup balsamic vinegar, 8 cups mixed salad greens, 2 cups sweetened dried cranberries, ½ pound fresh strawberries, quartered, 1  mango - peeled, seeded, and cubed, ½ cup chopped onion, 1 cup slivered almonds', 'Place sugar, oil, salt, and vinegar in a jar with a lid. Seal the jar and shake vigorously to mix.
INSERT INTO public.recipes VALUES (719, 'Tropical Mango-Pineapple-Berry Smoothie', '5 mins', NULL, '5 mins', '2', NULL, '1  mango - peeled, seeded, and diced, 1 cup frozen strawberries, 1 cup low-fat vanilla yogurt, 6 ounces pineapple juice, ½ cup frozen blueberries', 'Combine mango, frozen strawberries, yogurt, pineapple juice, and frozen blueberries in a blender; blend until smooth.', '4.5', 'https://www.allrecipes.com/recipe/270865/tropical-mango-pineapple-berry-smoothie/', '/Drinks Recipes/Smoothie Recipes/Strawberry/', 'Total Fat 2g 3%, Saturated Fat 1g 6%, Cholesterol 6mg 2%, Sodium 87mg 4%, Total Carbohydrate 57g 21%, Dietary Fiber 5g 18%, Total Sugars 46g, Protein 7g, Vitamin C 78mg 388%, Calcium 250mg 19%, Iron 1mg 8%, Potassium 692mg 15%', 'Prep Time: 5 mins, Total Time: 5 mins, Servings: 2', 'https://www.allrecipes.com/thmb/Ek9TzhD07iQKpaEnQqe1HDGmxJs=/1500x0/filters:no_upscale():max_bytes(150000):strip_icc()/351805-cb4a290765494384864382f7755e1c77.jpg');
INSERT INTO public.recipes VALUES (720, 'Bourbon-Mango Pulled Pork', '20 mins', '6 hrs', '6 hrs 20 mins', '10', '10 servings', '2  mangos, 1 (4 pound) pork shoulder roast , 2 tablespoons ground black pepper, 1 teaspoon kosher salt, 1 teaspoon chipotle chile powder, ¼ cup balsamic vinegar, 2 cups water, 1 teaspoon chipotle chile powder, 2 teaspoons honey, 1 (1.5 fluid ounce) jigger bourbon whiskey, 2 (12 ounce) bottles barbeque sauce', 'Peel the mangos and remove the pits. Place the pits into a slow cooker, then roughly chop the mango and set aside. Place the pork shoulder into the slow cooker, and season with the black pepper, kosher salt, and 1 teaspoon chipotle powder; pour in the balsamic vinegar and water.
INSERT INTO public.recipes VALUES (721, 'Chicken, Avocado and Mango Salad', '30 mins', NULL, '30 mins', '8', '8 servings', '2 tablespoons brown sugar, ¼ cup water, ⅓ cup lime juice, ½ cup chili garlic sauce, 4 cups shredded, cooked chicken, 2 medium mangos - peeled, seeded and diced, 2  avocados - peeled, pitted and diced, 1 (10 ounce) package spring lettuce mix', 'In a saucepan over medium-high heat, stir together the brown sugar and water. Bring to a boil, then pour into a medium bowl. Stir in the garlic chili sauce and lime juice. Set the dressing aside.
INSERT INTO public.recipes VALUES (733, 'Pineapple Stuffing', '5 mins', '1 hrs', '1 hrs 5 mins', '5', NULL, '½ cup margarine, 1 cup white sugar, 4  eggs, 1 (20 ounce) can crushed pineapple, drained, 5 slices white bread, cubed', 'Preheat the oven to 350 degrees F (175 degrees C). Grease a 9-inch baking pan.
INSERT INTO public.recipes VALUES (723, 'Brown Sugar and Pineapple Glazed Ham', '20 mins', '1 hrs 30 mins', '1 hrs 50 mins', '20', NULL, '1 (6 pound) fully-cooked, bone-in ham, 1  fresh pineapple, 2 (6 ounce) cans pineapple juice, 1 cup brown sugar', 'Preheat the oven to 325 degrees F (165 degrees C). Place ham, cut-side down, into a roasting pan.
INSERT INTO public.recipes VALUES (724, 'Jamaican Rum Punch', '10 mins', NULL, '10 mins', '8', '7 cups', '2 ½ cups pineapple juice, 2 ½ cups orange juice, 1 cup 151 proof rum (such as Bacardi®), ½ cup dark rum (such as Meyer''s®), ¼ cup coconut-flavored rum (such as Malibu®), ¼ cup fresh lime juice, 3 tablespoons grenadine syrup, 1  orange, sliced, 1  lime, sliced, 1  lemon, sliced', 'Stir pineapple juice, orange juice, 151 proof rum, dark rum, coconut-flavored rum, lime juice, and grenadine syrup together in a punch bowl. Float orange slices, lime slices, and lemon slices in the punch.
INSERT INTO public.recipes VALUES (725, 'T.G.I. Friday''s Jack Daniels Sauce', '10 mins', '1 hrs 45 mins', '1 hrs 55 mins', '8', '1 cup', '1 head garlic, 1 tablespoon olive oil, 1 ⅓ cups dark brown sugar, 1 cup pineapple juice, ⅔ cup water, ¼ cup teriyaki sauce, 1 tablespoon soy sauce, 3 tablespoons lemon juice, 3 tablespoons minced white onion, 1 tablespoon bourbon whiskey, 1 tablespoon crushed pineapple, ¼ teaspoon cayenne pepper', 'Preheat the oven to 325 degrees F (165 degrees C).
INSERT INTO public.recipes VALUES (726, 'Easy Pineapple Cake', '30 mins', '45 mins', '1 hrs 15 mins', '24', '1 9x13-inch cake', '2 cups all-purpose flour, 2 cups white sugar, 2 teaspoons baking soda, 2 large eggs, 1 (20 ounce) can crushed pineapple with juice, 1 teaspoon vanilla extract', 'Preheat the oven to 350 degrees F (175 degrees C). Grease a 9x13-baking dish.
INSERT INTO public.recipes VALUES (734, 'Grilled Pineapple', '10 mins', '5 mins', '45 mins', '12', NULL, '1  fresh pineapple - peeled, cored and cut into 1 inch rings, 3 tablespoons melted butter, ¼ teaspoon honey, 1 dash hot pepper sauce,   salt to taste', 'Place pineapple rings in a large resealable plastic bag. Add butter, honey, hot pepper sauce, and salt. Seal the bag and shake to coat evenly. Marinate for at least 30 minutes, or preferably overnight.
INSERT INTO public.recipes VALUES (727, 'Frog Eye Salad', '15 mins', '20 mins', '9 hrs 35 mins', '10', NULL, '1 ¾ cups unsweetened pineapple juice, 1 cup white sugar, 2  eggs, beaten, 2 tablespoons all-purpose flour, 2 ½ teaspoons salt, divided, 1 tablespoon lemon juice, 1 tablespoon vegetable oil, 1 (16 ounce) package acini di pepe pasta, 3 (11 ounce) cans mandarin oranges, drained, 2 (20 ounce) cans pineapple tidbits, drained, 1 (20 ounce) can crushed pineapple, drained, 1 (8 ounce) container frozen whipped topping, thawed, 1 cup miniature marshmallows, 1 cup shredded coconut', 'Combine pineapple juice, sugar, eggs, flour, and 1/2 teaspoon salt in a saucepan. Stir and cook over medium heat until thickened. Remove from heat; stir in lemon juice. Let cool to room temperature, about 1 hour.
INSERT INTO public.recipes VALUES (728, 'Pineapple Upside Down Cupcakes', '20 mins', '20 mins', '45 mins', '24', '24 cupcakes', '  cooking spray, ½ cup butter, melted, 1 ½ cups brown sugar, 24  maraschino cherries, 1 (20 ounce) can crushed pineapple, 1 (18.25 ounce) package pineapple cake mix (such as Duncan Hines® Pineapple Supreme), 1 ⅓ cups pineapple juice, ⅓ cup vegetable oil, 3  eggs, 1 tablespoon confectioners'' sugar for dusting, or as needed', 'Preheat the oven to 350 degrees F (175 degrees C). Move an oven rack to the middle of the oven. Spray 24 muffin cups with cooking spray.
INSERT INTO public.recipes VALUES (729, 'Brazilian Grilled Pineapple', '10 mins', '10 mins', '20 mins', '6', '6 wedges', '1 cup brown sugar, 2 teaspoons ground cinnamon, 1  pineapple - peeled, cored, and cut into 6 wedges', 'Preheat an outdoor grill for medium-high heat and lightly oil the grate.
INSERT INTO public.recipes VALUES (730, 'Ham with Pineapple', '20 mins', '4 hrs', '4 hrs 20 mins', '20', NULL, '1 (12 pound)  bone-in ham , ½ cup whole cloves, 1 (20 ounce) can pineapple rings in heavy syrup, 1 (12 fluid ounce) can or bottle lemon-lime flavored carbonated beverage, ½ cup packed brown sugar, 1 (4 ounce) jar chopped maraschino cherries', 'Preheat the oven to 325 degrees F (160 degrees C).
INSERT INTO public.recipes VALUES (731, 'Pineapple Upside-Down Cake in a Glass', '5 mins', NULL, '5 mins', '1', NULL, '  ice, 1 splash grenadine syrup, 3 ounces pineapple juice, 1 (1.5 fluid ounce) jigger cake-flavored vodka, 1  maraschino cherry', 'Fill a glass with ice.
INSERT INTO public.recipes VALUES (735, 'Pineapple Crisp', '15 mins', '40 mins', '55 mins', '12', '1 9x9-inch crisp', '2 (20 ounce) cans crushed pineapple, drained, 1 cup all-purpose flour, 1 cup brown sugar, 1 teaspoon baking powder, ½ teaspoon salt, 1  egg, ½ cup butter, melted, 1 teaspoon ground cinnamon', 'Preheat the oven to 350 degrees F (175 degrees C).
INSERT INTO public.recipes VALUES (736, 'Pineapple Angel Food Cake', '5 mins', '25 mins', '30 mins', '24', '1 9x13-inch cake', '  cooking spray, 1 (20 ounce) can crushed pineapple with juice, 1 (16 ounce) package angel food cake mix, 1 (12 ounce) container frozen whipped topping, thawed', 'Preheat the oven to 350 degrees F (175 degrees C). Spray a 9x13-inch pan with cooking spray.
INSERT INTO public.recipes VALUES (737, 'Easy Pineapple Chicken', '10 mins', '20 mins', '30 mins', '4', NULL, '3 tablespoons soy sauce, 3 tablespoons olive oil, divided, ½ teaspoon paprika,   salt to taste, 1 pound boneless, skinless chicken breast, cut into strips, 1  red bell pepper, cubed, 1 bunch scallions, trimmed and sliced into 1/2-inch lengths, 1 (12 ounce) can pineapple chunks, drained and juice reserved, 1 tablespoon cornstarch', 'Combine soy sauce, 2 tablespoons olive oil, paprika, and salt in a bowl. Add chicken strips and let marinate while preparing the remaining ingredients.
INSERT INTO public.recipes VALUES (738, 'Old Fashioned Pineapple Upside-Down Cake', '25 mins', '30 mins', '1 hrs', '12', '1 10-inch round cake', '½ cup butter, 1 cup packed light brown sugar, 1 (20 ounce) can sliced pineapple, 10  maraschino cherries, halved, 1 cup sifted cake flour, 1 teaspoon baking powder, ¼ teaspoon salt, 4 large eggs, 1 cup white sugar, 1 tablespoon butter, melted, 1 teaspoon almond extract', 'Preheat the oven to 325 degrees F (165 degrees C).
INSERT INTO public.recipes VALUES (739, 'Singapore Sling Cocktail', '5 mins', NULL, '5 mins', '1', NULL, '2 cups ice, divided, 4 fluid ounces pineapple juice, 1 ½ fluid ounces gin, ½ fluid ounce cherry-flavored brandy, ½ fluid ounce lime juice, ½ fluid ounce grenadine syrup, ¼ fluid ounce triple sec, ¼ fluid ounce Benedictine® liqueur, 1 slice fresh pineapple, 1  maraschino cherry', 'Fill a Collins glass with 1 cup ice and place in the freezer.
INSERT INTO public.recipes VALUES (740, 'Pineapple Upside-Down Bundt Cake', '30 mins', '35 mins', '1 hrs 15 mins', '12', '1 10-inch bundt cake', '  cooking spray with flour, ½ cup melted butter, ½ cup packed brown sugar, 1 (8 ounce) can pineapple rings, 1 (4 ounce) jar maraschino cherries, 1 (15.25 ounce) package yellow cake mix, 1 (3.5 ounce) package instant vanilla pudding mix, ¼ cup whole milk, or more as needed, ⅓ cup vegetable oil, 3 large eggs', 'Preheat the oven to 350 degrees F (175 degrees C). Grease a 10-inch fluted tube pan (such as Bundt) with cooking spray with flour.
INSERT INTO public.recipes VALUES (742, 'Hawaiian Meatballs', '20 mins', '30 mins', '50 mins', '4', NULL, '1 pound ground beef, ½ teaspoon ground ginger, ¼ teaspoon garlic powder, ¼ teaspoon ground black pepper', 'Make the meatballs: Mix ground beef, ginger, garlic powder, and black pepper together in a large bowl until well combined. Shape into 1 1/2-inch balls.
INSERT INTO public.recipes VALUES (743, 'Baked Pineapple Casserole', '10 mins', '1 hrs', '1 hrs 10 mins', '6', NULL, '1 cup white sugar, ½ cup unsalted butter, softened, 4 large eggs, 1 pinch ground cinnamon (Optional), 1 pinch ground nutmeg (Optional), 1 (20 ounce) can crushed pineapple with juice, 5 slices white bread, torn', 'Preheat the oven to 350 degrees F (175 degrees C). Grease a medium-sized casserole dish.
INSERT INTO public.recipes VALUES (744, 'Grandma''s Skillet Pineapple Upside-Down Cake', '15 mins', '45 mins', '1 hrs 10 mins', '12', '1 cake', '1 stick butter, 1 ½ cups packed brown sugar, 1 (20 ounce) can sliced pineapple, 1 (4 ounce) jar cherries, 1 ½ cups all-purpose flour, 2 ½ teaspoons baking powder, ½ teaspoon salt, 1 ½ cups white sugar, ½ cup butter, 2 large eggs, 1 cup milk, 2 teaspoons vanilla extract', 'Preheat the oven to 375 degrees F (190 degrees C).
INSERT INTO public.recipes VALUES (745, 'Auntie Midge''s Hawaiian Salad', '10 mins', NULL, '4 hrs 10 mins', '10', '10 servings', '1 (30 ounce) can fruit cocktail, drained thoroughly, 1 (20 ounce) can pineapple chunks, drained thoroughly, 1 (8 ounce) can mandarin oranges, drained thoroughly, 1 (10.5 ounce) package miniature marshmallows, 1 (24 ounce) container sour cream', 'Mix fruit cocktail, pineapple, mandarin oranges, and marshmallows together in a large bowl; add sour cream and stir to coat fruit completely.
INSERT INTO public.recipes VALUES (746, 'Pineapple Sweet and Sour Sauce', '10 mins', '20 mins', '30 mins', '24', '3 cups', '2 cups pineapple juice, divided, 3 tablespoons cornstarch, 1 cup white sugar, ¾ cup ketchup, or more to taste, ⅔ cup apple cider vinegar, 2 tablespoons soy sauce, or more to taste, 2 tablespoons crushed pineapple, or more to taste, 1 teaspoon garlic powder', 'Whisk 1/4 cup pineapple juice and cornstarch together in a small bowl until smooth.
INSERT INTO public.recipes VALUES (747, 'Thai Pineapple Chicken Curry', '15 mins', '35 mins', '50 mins', '6', NULL, '1 quart water, 2 cups uncooked jasmine rice, ¼ cup red curry paste, 2 (13.5 ounce) cans coconut milk, divided, 2  skinless, boneless chicken breast halves - cut into thin strips, 1 ½ cups sliced bamboo shoots, drained, ¼ cup white sugar, 3 tablespoons fish sauce, ½  red bell pepper, julienned, ½  green bell pepper, julienned, ½ small onion, chopped, 1 cup pineapple chunks, drained', 'Bring water and rice to a boil in a pot. Reduce heat to low, cover, and simmer for 25 minutes.
INSERT INTO public.recipes VALUES (748, 'Pineapple-Infused Vodka', '10 mins', NULL, '10 days 10 mins', '17', '17 servings', '1  fresh pineapple, peeled and sliced, 1 (750 milliliter) bottle vodka (such as Stolichnaya®)', 'Stack pineapple slices in a circle around the edges of a large glass jar, leaving the center open. Pour vodka into jar, completely covering pineapple. Seal jar and store in a cool, dark place for 10 days.
INSERT INTO public.recipes VALUES (749, 'Pineapple Pie', NULL, NULL, NULL, '8', '1 pie', '1 recipe pastry for a 9 inch double crust pie, ¾ cup white sugar, 3 tablespoons cornstarch, 1 (20 ounce) can crushed pineapple with juice, 1 tablespoon lemon juice, 2 tablespoons milk, 1 tablespoon white sugar', 'Preheat oven to 425 degrees F (220 degrees C).
INSERT INTO public.recipes VALUES (750, 'Pineapple Pork Chops', '15 mins', '35 mins', '50 mins', '4', '4 servings', '1 tablespoon olive oil, 4  boneless pork chops, 1 (14.5 ounce) can chicken broth, 2 tablespoons soy sauce, 1 tablespoon vinegar, 2 tablespoons brown sugar, 2 tablespoons cornstarch, ½ cup pineapple juice', 'Heat the olive oil in a skillet over medium heat, and brown the pork chops about 5 minutes on each side. Remove chops from the skillet, and set aside.
INSERT INTO public.recipes VALUES (751, 'Pineapple Upside Down Cake from DOLE®', '10 mins', '30 mins', '40 mins', '8', '8 servings', '1 (20 ounce) can DOLE® Pineapple Slices, 2 tablespoons margarine, melted, ¼ cup packed brown sugar, 8  maraschino cherries, 1 (9 ounce) package yellow cake mix', 'Spray pan with non-stick cooking spray. Drain pineapple.
INSERT INTO public.recipes VALUES (752, 'Angel Lush with Pineapple from DOLE®', '15 mins', NULL, '1 hrs 15 mins', '10', '10 servings', '1 (20 ounce) can DOLE® Crushed Pineapple, undrained, 1 (3.4 ounce) package instant vanilla pudding, 1 cup thawed whipped topping, 1 (10 ounce) package round angel food cake, cut into 3 layers,   Seasonal berries', 'Mix pineapple and dry pudding mix in medium bowl. Gently stir in whipped topping.
INSERT INTO public.recipes VALUES (753, 'Baked Ham with Sweet Glaze', '20 mins', '2 hrs 30 mins', '3 hrs', '20', '1 10-pound ham', '1 (10 pound) fully-cooked, bone-in ham, 4 cups boiling water, or as needed, 1 cup packed brown sugar, 2 tablespoons all-purpose flour, 2 tablespoons dry mustard powder, ¼ cup honey, 1 teaspoon fresh lemon juice, or as needed, 1 (20 ounce) can pineapple chunks, drained, 1 (10 ounce) jar maraschino cherries, drained,   toothpicks', 'Preheat oven to 400 degrees F (200 degrees C). Place ham on a rack set in a roasting pan, and carefully pour about 1/2 inch of boiling water into the pan beneath the ham.
INSERT INTO public.recipes VALUES (754, 'Zucchini Pineapple Bread I', '20 mins', '1 hrs', '1 hrs 20 mins', '24', '2 loaves', '4  eggs, 1 ½ cups white sugar, 2 teaspoons vanilla extract, 1 cup vegetable oil, 1 ½ teaspoons ground cinnamon, ¾ teaspoon ground nutmeg, 1 (8 ounce) can crushed pineapple, drained, 2 cups grated zucchini, 3 cups all-purpose flour, 1 teaspoon salt, 1 ½ teaspoons baking soda, 1 ½ teaspoons baking powder', 'Combine flour, baking powder, baking soda, and salt.
INSERT INTO public.recipes VALUES (755, 'Fresh Pineapple Salsa', '15 mins', NULL, '1 hrs 15 mins', '6', '6 servings', '1 cup finely chopped fresh pineapple, ¼ cup finely chopped red onion, ¼ cup red bell pepper, chopped, 1  jalapeno pepper, seeded and minced, 1 tablespoon finely chopped fresh cilantro, 1 tablespoon lime juice, 1 clove garlic, minced (Optional), ½ teaspoon white sugar, ½ teaspoon salt', 'Combine pineapple, red onion, bell pepper, jalapeno pepper, cilantro, lime juice, garlic, sugar, and salt. Stir to combine. Cover with plastic wrap and refrigerate for 1 hour so flavors can meld.', '4.9', 'https://www.allrecipes.com/recipe/265002/fresh-pineapple-salsa/', '/Appetizers and Snacks/Dips and Spreads Recipes/Salsa Recipes/', 'Total Fat 0g 0%, Sodium 195mg 8%, Total Carbohydrate 6g 2%, Dietary Fiber 1g 3%, Total Sugars 4g, Protein 0g, Vitamin C 24mg 120%, Calcium 8mg 1%, Iron 0mg 1%, Potassium 66mg 1%', 'Prep Time: 15 mins, Additional Time: 1 hrs, Total Time: 1 hrs 15 mins, Servings: 6, Yield: 6 servings', 'https://www.allrecipes.com/thmb/HrdNWc_Iya4lQ7A8fzVe6BM4eOQ=/1500x0/filters:no_upscale():max_bytes(150000):strip_icc()/5431286-bc030a45bdc542e2ae517273bc37eafe.jpg');
INSERT INTO public.recipes VALUES (756, 'Instant Pot® Ham', '10 mins', '50 mins', '1 hrs 10 mins', '8', '1 small ham', '1 (2 pound) frozen whole ham, 1 (16 ounce) can crushed pineapple, ¼ cup dark brown sugar, 2 tablespoons maple syrup, 1 tablespoon cornstarch, 2 tablespoons water, or as needed', 'Place ham on a trivet and set it inside a multi-functional pressure cooker (such as Instant Pot®). Pour crushed pineapple over ham. Sprinkle brown sugar and drizzle maple syrup on top. Secure the lid with vent closed.
INSERT INTO public.recipes VALUES (757, 'Hawaiian Cole Slaw', '10 mins', NULL, '10 mins', '16', '16 servings', '1 (8.5 ounce) package coleslaw mix, 1 (15 ounce) can crushed pineapple, drained, ½ cup finely chopped onion, ½ cup mayonnaise, ¼ cup apple cider vinegar, 2 tablespoons brown sugar, 1 teaspoon dried cilantro, ½ teaspoon salt, ¼ teaspoon ground black pepper', 'Mix coleslaw mix, pineapple, and onion together in a bowl.
INSERT INTO public.recipes VALUES (758, 'Delicious Pineapple Muffins', '15 mins', '30 mins', '45 mins', '16', '16 muffins', '2 cups all-purpose flour, ½ cup white sugar, 1 tablespoon baking powder, ½ teaspoon salt, 1 (8 ounce) can crushed pineapple, 1  egg, beaten, ¾ cup milk, ¼ cup butter, melted, ¼ cup butter, melted, ¼ teaspoon ground cinnamon, ⅓ cup packed brown sugar, ½ cup all-purpose flour', 'Preheat the oven to 375 degrees F (190 degrees C). Grease and flour muffin pans, or line with paper liners.
INSERT INTO public.recipes VALUES (759, 'Instant Pot Tacos al Pastor', '15 mins', '1 hrs', '9 hrs 30 mins', '12', NULL, '3 pounds pork butt, cut into 2-inch cubes, 2 cups pineapple juice, ¼ cup white vinegar, 1 medium orange, juiced, 1 medium lime, juiced, 1 cup chopped onion, 4 cloves garlic, chopped, 2  chipotle peppers in adobo sauce, 1 tablespoon chili powder, 1 teaspoon cumin, 1 ½ teaspoons salt, ½ teaspoon ground black pepper, 1 (1.41 ounce) package sazon seasoning with achiote,   vegetable oil as needed, 20 ounces pineapple chunks, drained, 12 (10 inch) flour tortillas, ½ cup chopped red onion,   pico de gallo salsa, 1 medium avocado, diced (Optional), ⅛ cup chopped cilantro, 1  lime, cut into wedges', 'Place pork in a large lidded container. Combine pineapple juice, vinegar, orange juice, lime juice, onion, garlic, chipotle peppers, chili powder, cumin, salt, pepper, and sazon in a blender; blend until smooth. Pour sauce over the pork and make sure all chunks of meat are covered. Seal the container and marinate for at least 8 hours or up to 24 hours.
INSERT INTO public.recipes VALUES (760, 'Baked Pineapple', '10 mins', '1 hrs', '1 hrs 10 mins', '7', '7 servings', '1 (20 ounce) can crushed pineapple, drained, 1 cup white sugar, 2 tablespoons cornstarch, ¼ cup cold water, 2  eggs, 1 tablespoon vanilla extract, 1 tablespoon butter, 1 teaspoon ground cinnamon', 'Preheat oven to 350 degrees F (175 degrees C). Grease a 9x9 inch baking dish.
INSERT INTO public.recipes VALUES (761, 'Easy Sweet and Sour Chicken', '10 mins', '15 mins', '25 mins', '4', '4 servings', '3 tablespoons all-purpose flour, ½ teaspoon garlic powder, ½ teaspoon salt, ½ teaspoon ground black pepper, 1 pound skinless, boneless chicken breast halves, cut into 1-inch cubes, 3 tablespoons vegetable oil, divided, 3  celery ribs, sliced, 2  green bell peppers, diced, 1  onion, chopped, ½ cup ketchup, ½ cup lemon juice, ½ cup crushed pineapple with syrup, ⅓ cup packed brown sugar', 'Combine flour, garlic powder, salt, and black pepper in a shallow dish.
INSERT INTO public.recipes VALUES (762, 'World''s Best Cream Cheese and Pineapple Dip', '10 mins', NULL, '10 mins', '24', '3 cups', '1 (8 ounce) package cream cheese, softened, 2 cups crushed pineapple, drained with juice reserved, 1 teaspoon onion powder, 2 cloves garlic, peeled and crushed', 'In a medium bowl, mix together cream cheese, crushed pineapple, onion powder and garlic. Mix in reserved juice from pineapple as desired. Chill in the refrigerator until serving.', '4.2', 'https://www.allrecipes.com/recipe/27011/worlds-best-cream-cheese-and-pineapple-dip/', '/Appetizers and Snacks/Dips and Spreads Recipes/Fruit Dip/', 'Total Fat 3g 4%, Saturated Fat 2g 11%, Cholesterol 10mg 3%, Sodium 28mg 1%, Total Carbohydrate 4g 1%, Dietary Fiber 0g 1%, Total Sugars 3g, Protein 1g, Vitamin C 2mg 10%, Calcium 11mg 1%, Iron 0mg 1%, Potassium 37mg 1%', 'Prep Time: 10 mins, Total Time: 10 mins, Servings: 24, Yield: 3 cups', 'https://www.allrecipes.com/thmb/Ta3CIJf61e6UGATkSZcv-ErR_Us=/1500x0/filters:no_upscale():max_bytes(150000):strip_icc()/4518834-fe5eebbf5d4345dc8e30fce9bf9cae3c.jpg');
INSERT INTO public.recipes VALUES (763, 'Precious Pineapple Cake', '15 mins', '20 mins', '1 hrs 35 mins', '12', '1 8-inch layer cake', '½ cup margarine, softened, 3 large eggs, 1 (18.25 ounce) package yellow cake mix, 1 (20 ounce) can crushed pineapple with juice, ½ cup chopped pecans', 'Preheat the oven to 350 degrees F (175 degrees C). Grease and flour three 8-inch round pans.
INSERT INTO public.recipes VALUES (764, 'Sweet and Sour Chicken III', '10 mins', '10 mins', '20 mins', '4', '4 servings', '1 pound skinless, boneless chicken breast meat - cubed, 2 tablespoons vegetable oil, ½ cup sliced green bell pepper, ½ cup sliced red bell pepper, 1 cup carrot strips, 1 clove garlic, minced, 1 tablespoon cornstarch, ¼ cup low sodium soy sauce, 1 (8 ounce) can pineapple chunks, juice reserved, 1 tablespoon vinegar, 1 tablespoon brown sugar, ½ teaspoon ground ginger', 'Brown chicken in oil in a large skillet over medium high heat. Add green bell pepper, red bell pepper, carrot and garlic and stir fry for 1 to 2 minutes.
INSERT INTO public.recipes VALUES (765, 'Ham and Pineapple Dinner', '20 mins', '15 mins', '35 mins', '4', '4 servings', '2 tablespoons butter, 2 ½ cups cooked and cubed ham, 2  green onions, chopped, 1 cup pineapple chunks, drained, 1 ⅓ cups pineapple juice, 4 teaspoons cider vinegar, 2 tablespoons brown sugar, 2 teaspoons prepared mustard, 2 tablespoons cornstarch', 'Melt the butter in a large skillet over medium heat. Saute the ham, onions and pineapple chunks in the butter for about 5 minutes.
INSERT INTO public.recipes VALUES (766, 'White Peachy Sangria', '30 mins', NULL, '8 hrs 30 mins', '20', '20 servings', '4 (750 milliliter) bottles moscato wine, 4 (12 fluid ounce) cans or bottles lemon-lime soda (such as Sprite®), 1 cup brandy, 1 cup peach schnapps, 2  fresh peaches, pitted and sliced, 1 (16 ounce) package fresh strawberries, sliced, 2  mangos - peeled, seeded, and sliced, ½  fresh pineapple - peeled, cored, and cut into chunks, 1 (6 ounce) container fresh raspberries', 'Stir moscato wine, lemon-lime soda, brandy, peach schnapps, peaches, strawberries, mangos, pineapple chunks, and raspberries together in a large container and chill 8 hours or overnight.', '4.9', 'https://www.allrecipes.com/recipe/223329/white-peachy-sangria/', '/Drinks Recipes/Sangria Recipes/', 'Total Fat 0g 0%, Sodium 24mg 1%, Total Carbohydrate 41g 15%, Dietary Fiber 2g 5%, Total Sugars 22g, Protein 1g, Vitamin C 30mg 148%, Calcium 23mg 2%, Iron 1mg 3%, Potassium 228mg 5%', 'Prep Time: 30 mins, Additional Time: 8 hrs, Total Time: 8 hrs 30 mins, Servings: 20, Yield: 20 servings', 'https://www.allrecipes.com/thmb/uz0pOWl7xju8N7kpWz_2HCIbhZE=/1500x0/filters:no_upscale():max_bytes(150000):strip_icc()/223329-White-Peachy-Sangria-Caelynne_5455009_original-4x3-1-8a93bc5db2404e3b84c49b8d671d9cbf.jpg');
INSERT INTO public.recipes VALUES (767, 'Pineapple Bread', '10 mins', '1 hrs', '1 hrs 20 mins', '12', '1 -9x5x3 inch loaf', '2  eggs, ½ cup melted butter, 1 cup white sugar, 1 cup crushed pineapple with juice, 1 teaspoon vanilla extract, 2 ½ cups all-purpose flour, 3 teaspoons baking powder, ½ teaspoon baking soda, ¾ teaspoon salt, ½ cup chopped walnuts', 'Preheat oven to 350 degrees F (175 degrees C). Grease one 9x5x3 inch loaf pan.
INSERT INTO public.recipes VALUES (1022, 'Strawberry Oatmeal Breakfast Smoothie', '5 mins', NULL, '5 mins', '2', NULL, '1 cup soy milk, ½ cup rolled oats, 14  frozen strawberries, 1  banana, broken into chunks, 1 ½ teaspoons white sugar (Optional), ½ teaspoon vanilla extract (Optional)', 'Blend soy milk, oats, strawberries, and banana in a blender until smooth. Add sugar and vanilla and blend again until smooth.
INSERT INTO public.recipes VALUES (768, 'Pineapple Glaze for Ham', '10 mins', '5 mins', '15 mins', '14', '3 cups', '1 (15.25 ounce) can sliced pineapple, drained with juice reserved, 1 (4 ounce) jar maraschino cherries, drained, 1 cup brown sugar', 'Before baking ham, place pineapple slices on ham with toothpicks and place cherries in center of pineapple.
INSERT INTO public.recipes VALUES (769, 'Sweet and Sour Pork Tenderloin', '20 mins', '35 mins', '55 mins', '4', '4 servings', '1 (1 1/4 pound) pork tenderloin, trimmed of silver skin,   salt and ground black pepper, ⅓ cup ketchup, ⅓ cup seasoned rice vinegar, 1 (8 ounce) can pineapple chunks, drained with juice reserved, 2 tablespoons brown sugar, 4 cloves garlic, minced, 2 teaspoons hot chili sauce (such as Sriracha®), 1 teaspoon soy sauce, 1 pinch red pepper flakes, 1 tablespoon vegetable oil, 1 teaspoon butter, ¼ cup chopped green onion (white part only), 2 tablespoons chopped green onion tops', 'Cut tenderloin into 4 pieces. Arrange in a single layer between two sheets of plastic wrap and pound with a meat mallet until each is about 1-inch thick. Generously season with salt and black pepper.
INSERT INTO public.recipes VALUES (770, 'Cranberry JELL-O Salad', '15 mins', NULL, '3 hrs 15 mins', '12', NULL, '2 cups boiling water, 2 (0.3 ounce) packages sugar-free cherry-flavored gelatin mix (such as Jell-O®), 1 (16 ounce) can jellied cranberry sauce, 1 (20 ounce) can crushed pineapple, drained, ½ cup chopped pecans', 'Combine boiling water and gelatin mix in a bowl; stir until gelatin is dissolved. Stir in cranberry sauce and crushed pineapple.
INSERT INTO public.recipes VALUES (771, 'Southern Pineapple Casserole', '10 mins', '30 mins', '40 mins', '12', '1 1/2 quart casserole', '1 (20 ounce) can pineapple chunks, 6 tablespoons all-purpose flour, ½ cup white sugar, or to taste, 2 cups shredded sharp Cheddar cheese, 1 (20 ounce) can crushed pineapple, drained, 40  buttery round crackers (such as Ritz®), crushed, ½ cup butter, melted, or to taste', 'Preheat an oven to 350 degrees F (175 degrees C).
INSERT INTO public.recipes VALUES (772, 'Rosa Marina Fruit Salad', '15 mins', '15 mins', '9 hrs', '24', '24 servings', '1 (16 ounce) package Rosa Marina (orzo) pasta, 2 (15 ounce) cans mandarin oranges, drained and juice reserved, 1 (16 ounce) can pineapple chunks, drained with juice reserved, 1 (16 ounce) can crushed pineapple, drained and juice reserved, 1 (4 ounce) jar maraschino cherries, drained and halved, ¾ cup white sugar, 2  large eggs, 3 tablespoons all-purpose flour, 1 (16 ounce) container whipped topping (such as Cool Whip®)', 'Bring a large pot of lightly salted water to a boil. Cook orzo in the boiling water, stirring occasionally until cooked through but firm to the bite, about 11 minutes. Drain and transfer to a large bowl. Add mandarin oranges, pineapple chunks, crushed pineapple, and maraschino cherries to orzo.
INSERT INTO public.recipes VALUES (849, 'Quick and Easy Guacamole', '10 mins', NULL, '10 mins', '4', '4 servings', '2  avocados - peeled, pitted, and diced, 2  green onions, chopped, 1 tablespoon chopped fresh cilantro, 1 teaspoon seasoned salt, 1 teaspoon ground black pepper, 1 teaspoon garlic, minced, ½  lime, juiced', 'Combine avocado, green onion, cilantro, seasoned salt, black pepper, garlic, and lime juice in a bowl; mash with a spoon or potato masher until mostly smooth with small chunks.', '4.7', 'https://www.allrecipes.com/recipe/223271/quick-and-easy-guacamole/', '/Appetizers and Snacks/Dips and Spreads Recipes/Guacamole Recipes/', 'Total Fat 15g 19%, Saturated Fat 2g 11%, Sodium 238mg 10%, Total Carbohydrate 10g 4%, Dietary Fiber 7g 25%, Total Sugars 1g, Protein 2g, Vitamin C 14mg 68%, Calcium 27mg 2%, Iron 1mg 5%, Potassium 532mg 11%', 'Prep Time: 10 mins, Total Time: 10 mins, Servings: 4, Yield: 4 servings', 'https://www.allrecipes.com/thmb/uZjj3uEaHSFSVOJz27fV9S9f-_A=/1500x0/filters:no_upscale():max_bytes(150000):strip_icc()/2233935-81ec07fcd6f543538f0fb8055510a32c.jpg');
INSERT INTO public.recipes VALUES (773, 'Hawaiian Chicken Kabobs', '10 mins', '20 mins', '2 hrs 30 mins', '8', '8 servings', '3 tablespoons soy sauce, 3 tablespoons brown sugar, 2 tablespoons sherry, 1 tablespoon sesame oil, ¼ teaspoon ground ginger, ¼ teaspoon garlic powder, 8  skinless, boneless chicken breast halves - cut into 2 inch pieces, 1 (20 ounce) can pineapple chunks, drained,   skewers', 'In a shallow glass dish, mix the soy sauce, brown sugar, sherry, sesame oil, ginger, and garlic powder. Stir the chicken pieces and pineapple into the marinade until well coated. Cover, and marinate in the refrigerator at least 2 hours.
INSERT INTO public.recipes VALUES (1057, 'Queen Elizabeth Cake I', '30 mins', '40 mins', '1 hrs 30 mins', '12', '9 to 13 x inch cake', '1 cup boiling water, 1 cup dates, pitted and chopped, ¼ cup butter, softened, 1 cup white sugar, 1  egg, 1 teaspoon vanilla extract, 1 ½ cups all-purpose flour, 1 teaspoon baking soda, 1 teaspoon baking powder, ½ teaspoon salt, ½ cup chopped walnuts, 1 cup flaked coconut, ⅔ cup packed brown sugar, 6 tablespoons butter, ¼ cup cream', 'Pour boiling water over dates in a small bowl, and let stand until cool.
INSERT INTO public.recipes VALUES (774, 'Slow Cooker Tacos al Pastor', '30 mins', '7 hrs', '7 hrs 30 mins', '10', '10 tacos', '⅔ large pineapple - peeled, cored, and chopped into small chunks, 1 small white onion, quartered, 1  chipotle peppers in adobo sauce, or more to taste, 2  dried guajillo chiles, stemmed and seeded, or more to taste, 1  dried chile de arbol pepper, stemmed and seeded, or more to taste, 3 cloves garlic, halved, 1 tablespoon minced fresh oregano, ½ cup orange juice, 2 tablespoons white vinegar, 2 tablespoons achiote powder, 2 teaspoons salt, 1 teaspoon ground cumin, 1 teaspoon lime zest, or to taste, ½ teaspoon ground ancho chile powder, ¼ teaspoon freshly ground black pepper, 1 (3 pound) boneless pork loin, cubed', 'Place pineapple, onion, chipotle peppers plus 1 1/2 teaspoons adobo sauce, guajillo chiles, chile de arbol, garlic, and oregano in a food processor. Blend until smooth. Transfer to a bowl and add orange juice, vinegar, achiote powder, salt, cumin, lime zest, chile powder, and black pepper. Mix sauce well.
INSERT INTO public.recipes VALUES (775, 'Hawaiian Pineapple Chicken', '15 mins', '50 mins', '1 hrs 5 mins', '6', '6 servings', '¼ cup butter, ⅓ cup ketchup, ¼ cup brown sugar, 2 teaspoons cornstarch, ¼ cup vinegar, 1 teaspoon salt, 1 teaspoon soy sauce, ½ teaspoon Worcestershire sauce, 1 (9 ounce) can crushed pineapple, 3 pounds assorted chicken pieces such as breasts, thighs, wings, and drumsticks', 'Preheat oven to 325 degrees F (165 degrees C).
INSERT INTO public.recipes VALUES (776, 'BBQ Teriyaki Pork Kabobs', '30 mins', '20 mins', '3 hrs 50 mins', '6', '6 servings', '3 tablespoons soy sauce, 3 tablespoons olive oil, 1 clove garlic, minced, ½ teaspoon crushed red pepper flakes,   salt and pepper to taste, 1 pound boneless pork loin, cut into 1 inch cubes, 1 (14.5 ounce) can low-sodium beef broth, 2 tablespoons cornstarch, 2 tablespoons soy sauce, 1 tablespoon brown sugar, 2 cloves garlic, minced, ¼ teaspoon ground ginger, 3  portobello mushrooms, cut into quarters, 1 large red onion, cut into 12 wedges, 12  cherry tomatoes, 12 bite-size chunks fresh pineapple', 'In a shallow dish, mix together 3 tablespoons soy sauce, olive oil, 1 clove minced garlic, red pepper flakes, salt, and pepper. Add pork cubes, and turn to coat evenly with marinade. Cover, and refrigerate for 3 hours.
INSERT INTO public.recipes VALUES (777, 'Air Fryer Roasted Pineapple', '5 mins', '15 mins', '20 mins', '2', '2 servings', '1  fresh pineapple', 'Preheat the air fryer to 375 degrees F (190 degrees C). Line the air fryer basket with parchment paper.
INSERT INTO public.recipes VALUES (778, 'Green Papaya Salad', '20 mins', NULL, '20 mins', '6', '6 servings', '3 cloves garlic, peeled, 3  Thai green chiles, 6  green beans, cut into 1 inch pieces, 1 large unripe papaya, peeled and cut into thin strips, 1  tomato, halved and seeded, 2 tablespoons fish sauce, 2 tablespoons lime juice, 1 teaspoon palm sugar, 2 tablespoons finely chopped unsalted, dry-roasted peanuts', 'Combine garlic, chiles, and green beans into a mortar and pound roughly. Add the papaya and pound again, to bruise the ingredients. Stir in fish sauce, lime juice, and sugar and pound again. Ad the tomato and pound to combine. Stir in the chopped peanuts and serve.
INSERT INTO public.recipes VALUES (779, 'Mango Papaya Salsa', '15 mins', NULL, '45 mins', '8', '8 servings', '1  mango - peeled, seeded and diced, 1  papaya - peeled, seeded and diced, 1 large red bell pepper, seeded and diced, 1  avocado - peeled, pitted and diced, ½  sweet onion, peeled and diced, 2 tablespoons chopped fresh cilantro, 2 tablespoons balsamic vinegar,   salt and pepper to taste', 'In a medium bowl, mix mango, papaya, red bell pepper, avocado, sweet onion, cilantro, and balsamic vinegar. Season with salt and pepper. Cover, and chill in the refrigerator at least 30 minutes before serving.', '4.7', 'https://www.allrecipes.com/recipe/37067/mango-papaya-salsa/', '/Appetizers and Snacks/Dips and Spreads Recipes/Salsa Recipes/Avocado Salsa Recipes/', 'Total Fat 4g 5%, Saturated Fat 1g 3%, Sodium 5mg 0%, Total Carbohydrate 11g 4%, Dietary Fiber 3g 11%, Total Sugars 7g, Protein 1g, Vitamin C 49mg 245%, Calcium 15mg 1%, Iron 0mg 2%, Potassium 274mg 6%', 'Prep Time: 15 mins, Additional Time: 30 mins, Total Time: 45 mins, Servings: 8, Yield: 8 servings', 'https://www.allrecipes.com/thmb/3GCOQruzLSeP9H8NVttMZ5LTjaE=/1500x0/filters:no_upscale():max_bytes(150000):strip_icc()/4529758-300f765f7681438e8c44059163b265ba.jpg');
INSERT INTO public.recipes VALUES (780, 'Fruit Batido', '10 mins', NULL, '10 mins', '6', '6 servings', '1 (12 fluid ounce) can evaporated milk, 1 cup chopped papaya, ¼ cup white sugar, or more to taste, 1 teaspoon vanilla extract, 1 pinch ground cinnamon, 1 tray ice cubes', 'Blend milk, papaya, sugar, vanilla extract, and cinnamon together in a blender until smooth; add ice and blend until slushy.', '4.0', 'https://www.allrecipes.com/recipe/238624/fruit-batido/', '/Drinks Recipes/Smoothie Recipes/', 'Total Fat 5g 6%, Saturated Fat 3g 15%, Cholesterol 18mg 6%, Sodium 69mg 3%, Total Carbohydrate 17g 6%, Dietary Fiber 1g 2%, Total Sugars 16g, Protein 4g, Vitamin C 16mg 78%, Calcium 174mg 13%, Iron 0mg 1%, Potassium 253mg 5%', 'Prep Time: 10 mins, Total Time: 10 mins, Servings: 6, Yield: 6 servings', 'https://www.allrecipes.com/thmb/Carh787ctDP3OdQyHmzkpgF0Uws=/1500x0/filters:no_upscale():max_bytes(150000):strip_icc()/4430276-4865e00ea7084ad4a7f91fb395178f2b.jpg');
INSERT INTO public.recipes VALUES (781, 'Papaya Surprise Smoothie', '10 mins', NULL, '10 mins', '2', '2 servings', '1  papaya - peeled, seeded and diced, 1  banana, peeled and sliced, ½ cup sliced fresh strawberries, ⅓ cup milk, ¼ cup sugar, 15  ice cubes', 'In a blender, blend the papaya, banana, strawberries, milk, sugar, and ice cubes until smooth.', '4.3', 'https://www.allrecipes.com/recipe/72701/papaya-surprise-smoothie/', '/Drinks Recipes/Smoothie Recipes/Strawberry/', 'Total Fat 1g 2%, Saturated Fat 1g 3%, Cholesterol 3mg 1%, Sodium 25mg 1%, Total Carbohydrate 55g 20%, Dietary Fiber 4g 15%, Total Sugars 43g, Protein 3g, Vitamin C 79mg 394%, Calcium 82mg 6%, Iron 1mg 3%, Potassium 600mg 13%', 'Prep Time: 10 mins, Total Time: 10 mins, Servings: 2, Yield: 2 servings', 'https://www.allrecipes.com/thmb/mn38jOTXNvuCcFDYbMOKT9VCYgM=/1500x0/filters:no_upscale():max_bytes(150000):strip_icc()/424733-c3c4ef85948442d58bb0a761ff219caf.jpg');
INSERT INTO public.recipes VALUES (782, 'Grilled Macadamia-Crusted Tuna with Papaya Salsa', '45 mins', '5 mins', '50 mins', '4', '4 tuna steaks', '2 cups diced papaya, ½  red onion, diced, 1  red bell pepper, diced, ¼ cup chopped fresh cilantro, 2 tablespoons lime juice, 1 clove garlic, minced, ¼ teaspoon hot chile paste, or to taste, 4 (6 ounce) tuna steaks, ¼ cup extra-virgin olive oil,   salt and pepper to taste, 3  eggs, ½ cup chopped macadamia nuts', 'Combine the papaya, onion, and red pepper in a bowl. Add the cilantro, lime juice, garlic, and hot chile paste. Toss to combine, then refrigerate until ready to serve.
INSERT INTO public.recipes VALUES (783, 'Papaya Bread', '25 mins', '1 hrs 15 mins', '2 hrs 30 mins', '10', '1 9x5-inch loaf', '2 large ripe papayas, 2 ½ cups all-purpose flour, 2 tablespoons poppy seeds, 1 teaspoon baking soda, 1 teaspoon salt, 1 ¼ cups white sugar, ½ cup unsalted butter, softened, 2 large eggs, ½ cup buttermilk, ½ cup guava juice, 1 tablespoon vanilla extract', 'Preheat the oven to 350 degrees F (175 degrees C). Grease a 9x5-inch loaf pan.
INSERT INTO public.recipes VALUES (784, 'Papaya Bruschetta', '20 mins', NULL, '20 mins', '8', '8 servings', '1 small papaya, 5 medium Roma (plum) tomatoes, diced, ½ medium red onion, diced, 1 medium red bell pepper, seeded and diced, ¼ cup chopped fresh basil leaves, 2 tablespoons white sugar, ¼ cup red wine vinegar, ¼ cup vegetable oil, ½ teaspoon mustard powder, 2 stalks green onions, chopped, 1 (16 inch) French baguette, cut into 1/2 inch pieces', 'Cut papaya in half and remove seeds. Reserve 2 tablespoons of seeds for the dressing. Peel and dice the papaya, and place in a medium bowl. Add tomatoes, red onion, red pepper and basil, and set aside.
INSERT INTO public.recipes VALUES (785, 'Tropical Island Fruit Salad', '30 mins', NULL, '30 mins', '14', '14 servings', '1  pineapple - peeled, cored, and cut into 1/2-inch cubes, 2  mangos - peeled, pitted, and cut into small cubes, 2  papayas - halved lengthwise, seeded, peeled, and cut into 1/2-inch cubes, 3  bananas, sliced', 'Toss pineapple, mangos, papayas, and bananas together in a large bowl.', '5.0', 'https://www.allrecipes.com/recipe/222534/tropical-island-fruit-salad/', '/Salad/Fruit Salad Recipes/', 'Total Fat 0g 0%, Saturated Fat 0g 1%, Sodium 2mg 0%, Total Carbohydrate 24g 9%, Dietary Fiber 3g 10%, Total Sugars 17g, Protein 1g, Vitamin C 69mg 344%, Calcium 22mg 2%, Iron 0mg 2%, Potassium 289mg 6%', 'Prep Time: 30 mins, Total Time: 30 mins, Servings: 14, Yield: 14 servings', 'https://www.allrecipes.com/thmb/efpd6zZLT51vTszSVnN8I21Szik=/1500x0/filters:no_upscale():max_bytes(150000):strip_icc()/876301-773d297aaf5443fd92884b79886b67a7.jpg');
INSERT INTO public.recipes VALUES (786, 'Pawpaw (Papaya) And Mango Punch', '10 mins', NULL, '10 mins', '8', '8 servings', '1 cup sliced mango, 1 cup diced, peeled papaya, 1 cup orange juice, ¼ cup lime juice, ¼ cup white sugar, or to taste, 1 teaspoon grated orange zest, 4 cups water', 'Place the mango and papaya into a blender. Cover, and puree until smooth; add the orange juice, lime juice, sugar, orange zest, and water. Blend well. Serve over crushed ice.', '5.0', 'https://www.allrecipes.com/recipe/173746/pawpaw-papaya-and-mango-punch/', '/Drinks Recipes/Smoothie Recipes/Orange/', 'Total Fat 0g 0%, Sodium 5mg 0%, Total Carbohydrate 15g 6%, Dietary Fiber 1g 3%, Total Sugars 13g, Protein 1g, Vitamin C 35mg 174%, Calcium 15mg 1%, Iron 0mg 1%, Potassium 150mg 3%', 'Prep Time: 10 mins, Total Time: 10 mins, Servings: 8, Yield: 8 servings', 'https://www.allrecipes.com/thmb/3CGDhT9yQR_VcrFFv3_o8YNAvE4=/1500x0/filters:no_upscale():max_bytes(150000):strip_icc()/239405-8883d43565cf421bb11c9f7a8e61bf1b.jpg');
INSERT INTO public.recipes VALUES (822, 'Carne Asada Tacos', '30 mins', '45 mins', '1 hrs 15 mins', '6', '6 servings', '1 ½ pounds boneless beef top sirloin, cut into thin bite-size slices, ½ teaspoon salt, 1 teaspoon freshly ground black pepper,   crushed red pepper to taste, 1  lime, 1 (28 ounce) can tomatillos, 2  fresh jalapeno peppers, seeded, 4 tablespoons canola oil, divided, 1 (10.5 ounce) can beef broth, 12 (6 inch) corn tortillas, ½ large onion, chopped, 2  tomatoes, chopped, 1  avocado - peeled, pitted and sliced, 1 bunch fresh cilantro, chopped, 1  lemon', 'Place sliced meat into a shallow bowl, and season with salt, black pepper, and crushed red pepper. Squeeze the lime juice over the meat, and turn until evenly coated. Cover, and refrigerate for 30 minutes.
INSERT INTO public.recipes VALUES (787, 'Green Papaya Salad (Som Tam Malakor)', '20 mins', '10 mins', '35 mins', '2', '2 servings', '¼ cup peanuts, 2  Thai chiles, chopped, 3 cloves garlic, 1 tablespoon dried shrimp, 1 tablespoon white sugar, 2 medium limes, juiced, 2 tablespoons fish sauce, 1 medium papaya - peeled, seeded, and sliced, 1 cup cherry tomatoes, halved, ¼ cup fresh green beans, cut into 1-inch pieces, ½ medium carrot, peeled and shredded,   salt and ground black pepper to taste', 'Preheat the oven to 350 degrees F (175 degrees C). Place peanuts on a baking sheet.
INSERT INTO public.recipes VALUES (788, 'Papaya Boats', '15 mins', NULL, '15 mins', '4', '4 servings', '1 cup fat-free plain yogurt, ¼ cup walnuts, ¼ cup raisins, 1 cup chopped fresh strawberries, 2  medium papayas, cut in half lengthwise and seeded, 2 tablespoons honey', 'In a bowl, mix the yogurt, walnuts, and raisins. Fold in the strawberries. Spoon the mixture into the centers of the papaya halves. Drizzle with honey to serve.', '4.4', 'https://www.allrecipes.com/recipe/72371/papaya-boats/', '/Desserts/Specialty Dessert Recipes/', 'Total Fat 5g 7%, Saturated Fat 1g 3%, Cholesterol 1mg 0%, Sodium 52mg 2%, Total Carbohydrate 33g 12%, Dietary Fiber 3g 11%, Total Sugars 26g, Protein 6g, Vitamin C 73mg 366%, Calcium 160mg 12%, Iron 1mg 4%, Potassium 537mg 11%', 'Prep Time: 15 mins, Total Time: 15 mins, Servings: 4, Yield: 4 servings', 'https://www.allrecipes.com/thmb/guz4wJD0AO--TbfnfjMULu50R3Y=/1500x0/filters:no_upscale():max_bytes(150000):strip_icc()/37285-cc52706d6be04d3bba8c737302f1fa4f.jpg');
INSERT INTO public.recipes VALUES (789, 'Mango Papaya Fruit Salad', '20 mins', NULL, '1 hrs 20 mins', '8', '8 servings', '¼ cup freshly squeezed lime juice, ¼ cup honey, 1 tablespoon finely grated lime zest, 1 tablespoon balsamic vinegar, 1 tablespoon brown sugar, 2  mangos, peeled and diced, or to taste, 1 large papaya, peeled and diced', 'Whisk lime juice, honey, lime zest, balsamic vinegar, and brown sugar together in a small bowl.
INSERT INTO public.recipes VALUES (790, 'Mexican Green Papaya Salad', '20 mins', NULL, '50 mins', '6', '6 servings', '¼ cup chopped fresh cilantro, or to taste, 3 cloves garlic, minced, or more to taste, 2  limes, juiced, 2 tablespoons olive oil, 1 tablespoon brown sugar, 1 pinch chili powder, or more to taste (Optional),   salt to taste', 'Blend cilantro, garlic, lime juice, olive oil, brown sugar, chili powder, and salt in a blender until smooth.
INSERT INTO public.recipes VALUES (791, 'Papaya-Stuffed Chicken and Basmati Rice', '30 mins', '1 hrs 20 mins', '1 hrs 50 mins', '4', '4 servings', '4  skinless, boneless chicken breast halves, 1  papaya, peeled, seeded and sliced, 1 pinch ground cinnamon, or to taste, ⅓ cup melted margarine, 1 cup crushed buttery round crackers (such as Ritz®), 1 tablespoon margarine, 1 cup basmati rice, 1 ½ cups water, 1 tablespoon margarine, 1 cup orange juice, 1 (8 ounce) can crushed pineapple in its own juice, 1 tablespoon brown sugar, ½ teaspoon ground cinnamon, 1 teaspoon ground nutmeg, 1 pinch cayenne pepper, 1 pinch salt and ground black pepper to taste', 'Preheat an oven to 350 degrees F (175 degrees C). Line a baking sheet with aluminum foil.
INSERT INTO public.recipes VALUES (792, 'Georgie''s Mango Papaya Salad', '15 mins', NULL, '15 mins', '6', '6 servings', '1  large mango - peeled, seeded and halved, 1  medium papaya - peeled, seeded and halved, 1  avocado - peeled, pitted and diced, 3 tablespoons balsamic vinegar, 1 tablespoon butter, ¼ cup blanched slivered almonds, 1 teaspoon brown sugar, 1 head romaine lettuce, torn into bite-size pieces,   salt to taste', 'Place half of the mango and half of the papaya into the container of a food processor or blender along with balsamic vinegar. Puree until smooth, and set aside.
INSERT INTO public.recipes VALUES (793, 'Thai-Inspired Confetti Salad', '35 mins', NULL, '35 mins', '4', '4 servings', '1  Roma tomato, chopped, 1 ½ cups fresh green beans, cut into 1/2 inch pieces, 1  cucumber, cut into 1/2 inch cubes, 1 ½ cups cubed papaya, 2 cloves cloves garlic, minced, 1  fresh Thai or Serrano chile, finely minced, 1  lemon, juiced, 2  limes, juiced, 2 tablespoons fish sauce, 1 tablespoon white sugar, ½ cup roasted peanuts, chopped, ¼ cup cilantro leaves, chopped', 'Combine tomato, beans, cucumber, and papaya in a large bowl. Toss with garlic and chile pepper.
INSERT INTO public.recipes VALUES (794, 'Baby Back Ribs with Papaya Sauce', '10 mins', '1 hrs 50 mins', '8 hrs', '4', '4 servings', '1 clove garlic, minced, 1 cup papaya - peeled, seeded and cubed, ½ cup water, ½ cup white wine, ½ cup honey, ¼ cup tomato paste, 4 pounds pork spareribs', 'Place the garlic, papaya, water, wine, honey, and tomato paste into a food processor. Pulse until until the mixture is finely chopped, about 15 seconds.
INSERT INTO public.recipes VALUES (795, 'Papaya Passion Smoothie', '10 mins', NULL, '10 mins', '6', '6 cups', '2 cups papaya - peeled, seeded and cubed, 2 cups milk, ¼ cup white sugar, ¼ cup sweetened condensed milk, 1 cup vanilla yogurt, 2 tablespoons cream cheese, 2 cups ice', 'Place papaya, milk, sugar, condensed milk, yogurt, cream cheese, and ice in a blender. Blend until smooth. Serve immediately.', '3.6', 'https://www.allrecipes.com/recipe/139660/papaya-passion-smoothie/', '/Breakfast and Brunch/Drinks/', 'Total Fat 5g 6%, Saturated Fat 3g 16%, Cholesterol 18mg 6%, Sodium 92mg 4%, Total Carbohydrate 29g 11%, Dietary Fiber 1g 3%, Total Sugars 28g, Protein 6g, Vitamin C 30mg 149%, Calcium 216mg 17%, Iron 0mg 1%, Potassium 385mg 8%', 'Prep Time: 10 mins, Total Time: 10 mins, Servings: 6, Yield: 6 cups', 'https://www.allrecipes.com/thmb/F0HJAjZuWd9PlFtWvcokydt6euk=/1500x0/filters:no_upscale():max_bytes(150000):strip_icc()/83355-6754aae0829b4ea6b5135d8ca71b34b0.jpg');
INSERT INTO public.recipes VALUES (796, 'Watermelon Fish Snack for Kids', '5 mins', NULL, '5 mins', '1', '1 serving', '1 small slice (0.5 oz) triangular slice of watermelon, 5  fresh blueberries, 1  small triangular slice of papaya', 'Place watermelon triangle on a plate with the pointed side facing to the left. Place 1 blueberry into the triangle for the fish eye. Place the other 4 blueberries above the fish''s mouth as if they are bubbles coming up.
INSERT INTO public.recipes VALUES (797, 'Cobb Salad', '20 mins', '10 mins', '30 mins', '6', NULL, '6 slices bacon, 3  eggs, 1 head iceberg lettuce, shredded, 3 cups chopped, cooked chicken meat, 2  tomatoes, seeded and chopped, ¾ cup blue cheese, crumbled, 3  green onions, chopped, 1  avocado - peeled, pitted and diced, 1 (8 ounce) bottle Ranch-style salad dressing', 'Place eggs in a saucepan and cover completely with cold water; bring to a boil, then cover and remove from heat. Let eggs sit for 10 to 12 minutes, then cool, peel and chop.
INSERT INTO public.recipes VALUES (798, 'Avocado Breakfast Sandwich', '10 mins', '6 mins', '16 mins', '1', NULL, '1 tablespoon olive oil, 2  large eggs,   salt and ground black pepper to taste, 1 tablespoon butter, softened, 2 slices Italian bread, 1 ounce Swiss cheese, sliced, 1 ounce Cheddar cheese, sliced, ½  ripe avocado, sliced', 'Heat olive oil in a skillet over medium heat. Crack eggs into skillet; cook for 1 to 2 minutes. Flip and cook egg until done, 2 to 5 minutes more. Transfer eggs to a plate and season with salt and pepper.
INSERT INTO public.recipes VALUES (799, 'Seven-Layer Dip', '20 mins', NULL, '20 mins', '64', '1 9x13-inch dish', '2  avocados - peeled, pitted and diced, ¼ cup chopped fresh cilantro, ¼ cup salsa, 1 ½ tablespoons fresh lime juice, ¼ teaspoon garlic salt,   ground black pepper to taste, 1 (8 ounce) container sour cream, 1 (1 ounce) package taco seasoning mix, 1 (16 ounce) can refried beans, 4  roma (plum) tomatoes, diced, 1 bunch green onions, finely chopped, 2 cups shredded Mexican-style cheese blend, 1 (2.25 ounce) can black olives - drained and finely chopped', 'Mash avocados in a medium bowl to desired consistency. Mix in cilantro, salsa, lime juice, garlic salt, and pepper. Set aside.
INSERT INTO public.recipes VALUES (800, 'Avocado Smoothie', '5 mins', NULL, '5 mins', '2', NULL, '1 cup milk, 1  ripe avocado, halved and pitted, ½ cup vanilla yogurt, 3 tablespoons honey, 8  ice cubes', 'Place milk, avocado, yogurt, and honey into a blender; add ice cubes and blend until smooth.', '4.4', 'https://www.allrecipes.com/recipe/199931/avocado-smoothie/', '/Drinks Recipes/Smoothie Recipes/', 'Total Fat 18g 23%, Saturated Fat 4g 21%, Cholesterol 13mg 4%, Sodium 101mg 4%, Total Carbohydrate 49g 18%, Dietary Fiber 7g 24%, Total Sugars 41g, Protein 9g, Vitamin C 11mg 55%, Calcium 264mg 20%, Iron 1mg 4%, Potassium 822mg 17%', 'Prep Time: 5 mins, Total Time: 5 mins, Servings: 2', 'https://www.allrecipes.com/thmb/L1EYMqyTtTrKQA_rtn6yE-AYLRY=/1500x0/filters:no_upscale():max_bytes(150000):strip_icc()/6737245-bfbe4d9f207e43d9bb0831dad5954b4c.jpg');
INSERT INTO public.recipes VALUES (801, 'Homemade Sushi', '40 mins', '25 mins', '1 hrs 5 mins', '8', '4 cut rolls', '1 ⅓ cups water, ⅔ cup uncooked short-grain white rice, 3 tablespoons rice vinegar, 3 tablespoons white sugar, 1 ½ teaspoons salt, 4 sheets nori seaweed sheets, ½ pound imitation crabmeat, flaked, 1  avocado - peeled, pitted, and sliced, ½  cucumber, peeled, cut into small strips, 2 tablespoons pickled ginger', 'Preheat the oven to 300 degrees F (150 degrees C).
INSERT INTO public.recipes VALUES (802, 'Avocado Salad', '10 mins', NULL, '10 mins', '6', NULL, '2  avocados - peeled, pitted and diced, 1  sweet onion, chopped, 1  green bell pepper, chopped, 1 large ripe tomato, chopped, ¼ cup chopped fresh cilantro, ½  lime, juiced,   salt and pepper to taste', 'Combine avocados, onion, bell pepper, tomato, cilantro, and lime juice in a large bowl. Gently toss until evenly coated. Season with salt and pepper.', '4.6', 'https://www.allrecipes.com/recipe/19960/avocado-salad/', '/Salad/Vegetable Salad Recipes/Avocado Salad Recipes/', 'Total Fat 10g 13%, Saturated Fat 2g 8%, Sodium 9mg 0%, Total Carbohydrate 10g 4%, Dietary Fiber 6g 20%, Total Sugars 3g, Protein 2g, Vitamin C 30mg 150%, Calcium 20mg 2%, Iron 1mg 3%, Potassium 474mg 10%', 'Prep Time: 10 mins, Total Time: 10 mins, Servings: 6', 'https://www.allrecipes.com/thmb/qN8HjL3tu6MKaPQqzQRlSPO_lQA=/1500x0/filters:no_upscale():max_bytes(150000):strip_icc()/8555902-avocado-salad-maria-collins-4x3-1-aac00e5486154d1290fa8576afb4bab8.jpg');
INSERT INTO public.recipes VALUES (803, 'Chocolate Avocado Pudding', '10 mins', NULL, '40 mins', '4', NULL, '2 large avocados - peeled, pitted, and cubed, ½ cup unsweetened cocoa powder, ½ cup brown sugar, ⅓ cup coconut milk, 2 teaspoons vanilla extract, 1 pinch ground cinnamon', 'Blend avocados, cocoa powder, brown sugar, coconut milk, vanilla, and cinnamon in a blender until smooth. Transfer pudding to a container with a lid, then refrigerate until chilled, about 30 minutes.', '4.3', 'https://www.allrecipes.com/recipe/234324/chocolate-avocado-pudding/', '/Desserts/Custards and Puddings/Chocolate Pudding Recipes/', 'Total Fat 26g 34%, Saturated Fat 7g 37%, Sodium 23mg 1%, Total Carbohydrate 46g 17%, Dietary Fiber 13g 48%, Total Sugars 28g, Protein 5g, Vitamin C 14mg 72%, Calcium 60mg 5%, Iron 3mg 17%, Potassium 935mg 20%', 'Prep Time: 10 mins, Additional Time: 30 mins, Total Time: 40 mins, Servings: 4', 'https://www.allrecipes.com/thmb/IM56aJLxzfgJ3gMH1ApDc4WgHLc=/1500x0/filters:no_upscale():max_bytes(150000):strip_icc()/5144775-f29a14325662460a8167a0f086cf2238.jpg');
INSERT INTO public.recipes VALUES (804, 'Traditional Mexican Guacamole', '10 mins', NULL, '10 mins', '4', NULL, '2  avocados, peeled and pitted, 1 cup chopped tomatoes, ¼ cup chopped onion, ¼ cup chopped cilantro, 2 tablespoons lemon juice, 1  jalapeno pepper, seeded and minced (Optional),   salt and ground black pepper to taste', 'Mash avocados in a bowl until creamy.
INSERT INTO public.recipes VALUES (805, 'Mexican Chicken Soup', '20 mins', '45 mins', '1 hrs 5 mins', '6', NULL, '1 ¼ pounds skinless, boneless chicken breast halves, 2 tablespoons taco seasoning mix, divided, 1 tablespoon vegetable oil, ½ cup chopped onions, ½ cup chopped celery, 2 teaspoons ground cumin, ¼ teaspoon ground black pepper, 3 (14 ounce) cans chicken broth, 1 cup water, 1 cup diced tomatoes, 1 tablespoon chopped fresh cilantro', 'Preheat the oven to 350 degrees F (175 degrees C).
INSERT INTO public.recipes VALUES (806, 'Roquefort Pear Salad', '25 mins', '10 mins', '35 mins', '6', NULL, '½ cup pecans, ¼ cup white sugar', 'Make the pecans: Combine pecans and sugar in a skillet over medium heat. Cook, stirring gently, until sugar has melted and pecans are caramelized, 5 to 7 minutes. Carefully transfer nuts onto a sheet of waxed paper to cool.
INSERT INTO public.recipes VALUES (807, 'Banana, Avocado, and Spinach Smoothie', '10 mins', NULL, '10 mins', '2', '2 servings', '1  banana, sliced, ½  avocado, peeled and sliced, ½ cup fresh spinach, ½ cup 1% milk, 6  ice cubes, 2 teaspoons honey, 1 teaspoon vanilla extract', 'Blend banana, avocado, spinach, milk, ice cubes, honey, and vanilla extract together in a blender until smooth.', '4.7', 'https://www.allrecipes.com/recipe/241365/banana-avocado-and-spinach-smoothie/', '/Breakfast and Brunch/Drinks/', 'Total Fat 8g 11%, Saturated Fat 2g 8%, Cholesterol 3mg 1%, Sodium 45mg 2%, Total Carbohydrate 28g 10%, Dietary Fiber 5g 18%, Total Sugars 14g, Protein 4g, Vitamin C 13mg 65%, Calcium 97mg 7%, Iron 1mg 4%, Potassium 604mg 13%', 'Prep Time: 10 mins, Total Time: 10 mins, Servings: 2, Yield: 2 servings', 'https://www.allrecipes.com/thmb/0MIU11-x-1QbuV0Ek1nScg-CyGs=/1500x0/filters:no_upscale():max_bytes(150000):strip_icc()/4481367-banana-avocado-and-spinach-smoothie-Yoly-4x3-1-e2a8692fc0bc4505a6eb2a88a7f744bc.jpg');
INSERT INTO public.recipes VALUES (808, 'Paleo Baked Eggs in Avocado', '10 mins', '15 mins', '25 mins', '2', NULL, '2 small eggs, 1  avocado, halved and pitted, 2 teaspoons chopped fresh chives, or to taste, 1 pinch dried parsley, or to taste, 1 pinch sea salt and ground black pepper to taste, 2 slices cooked bacon, crumbled', 'Preheat the oven to 425 degrees F (220 degrees C).
INSERT INTO public.recipes VALUES (809, 'Cucumber and Avocado Sushi', '35 mins', '25 mins', '1 hrs 5 mins', '6', '24 rolls', '1 ¼ cups water, 1 cup uncooked glutinous white rice (sushi rice), 3 tablespoons rice vinegar, 1 pinch salt, 4 sheets nori (dry seaweed), ½ medium cucumber, sliced into thin strips, 1 medium avocado - peeled, pitted and sliced', 'Combine water and rice in a saucepan and bring to a boil. Cover, reduce the heat to low, and simmer until rice is tender and water has been absorbed, about 20 minutes. Remove from the heat, stir in vinegar and salt, and set aside to cool for at least 5 minutes.
INSERT INTO public.recipes VALUES (810, 'Honduran Baleadas', '25 mins', '2 mins', '47 mins', '8', '8 servings', '2 cups all-purpose flour, 1 cup water, ½ cup vegetable oil, 1  egg, ½ teaspoon salt', 'Mix flour, water, vegetable oil, egg, and salt in a large bowl; knead until dough is smooth and no longer sticky.
INSERT INTO public.recipes VALUES (811, 'Mexican Shrimp Cocktail', '15 mins', NULL, '2 hrs 15 mins', '6', NULL, '2 pounds cooked shrimp, peeled and deveined, ½ cup finely chopped red onion, ¼ cup fresh cilantro, chopped, 1 tablespoon crushed garlic, 1 ½ cups tomato and clam juice cocktail, ¼ cup ketchup, ¼ cup fresh lime juice, ¼ cup prepared horseradish, 1 teaspoon hot pepper sauce, or to taste,   salt to taste, 1  ripe avocado - peeled, pitted and chopped', 'Place shrimp in a large bowl. Stir in red onion, cilantro, and garlic. Add tomato and clam juice, ketchup, lime juice, horseradish, and hot pepper sauce; mix well to combine. Season with salt. Gently stir in avocado. Cover, and refrigerate for 2 to 3 hours.', '4.7', 'https://www.allrecipes.com/recipe/87778/mexican-shrimp-cocktail/', '/Appetizers and Snacks/Seafood/Shrimp/', 'Total Fat 7g 9%, Saturated Fat 1g 6%, Cholesterol 295mg 98%, Sodium 711mg 31%, Total Carbohydrate 16g 6%, Dietary Fiber 3g 11%, Total Sugars 6g, Protein 33g, Vitamin C 19mg 94%, Calcium 84mg 6%, Iron 5mg 28%, Potassium 604mg 13%', 'Prep Time: 15 mins, Additional Time: 2 hrs, Total Time: 2 hrs 15 mins, Servings: 6', 'https://www.allrecipes.com/thmb/Fo4Z1qhO_nTsoiVBbKvnXzju3UM=/1500x0/filters:no_upscale():max_bytes(150000):strip_icc()/407547-bb87939406e149ffae12c6660ff5b139.jpg');
INSERT INTO public.recipes VALUES (812, 'Simple Avocado Milkshake', '10 mins', NULL, '10 mins', '3', '3 servings', '1 cup milk, 1  ripe avocado, peeled and pitted, 1  banana, cut into chunks, 3 tablespoons honey', 'Blend milk, avocado, banana, and honey together in a blender until smooth.', '4.7', 'https://www.allrecipes.com/recipe/237804/simple-avocado-milkshake/', '/Drinks Recipes/Shakes and Floats Recipes/', 'Total Fat 12g 15%, Saturated Fat 3g 13%, Cholesterol 7mg 2%, Sodium 39mg 2%, Total Carbohydrate 36g 13%, Dietary Fiber 6g 20%, Total Sugars 26g, Protein 5g, Vitamin C 10mg 52%, Calcium 106mg 8%, Iron 1mg 3%, Potassium 599mg 13%', 'Prep Time: 10 mins, Total Time: 10 mins, Servings: 3, Yield: 3 servings', 'https://www.allrecipes.com/thmb/M1qa_53hdC9RO2C0Quxy9wlOezY=/1500x0/filters:no_upscale():max_bytes(150000):strip_icc()/Simple-Avocado-Milkshake-by-France-C-7ad76e9eaeed44b59d174a3f7ac5dc2f.png');
INSERT INTO public.recipes VALUES (813, 'Avocado Tomatillo Salsa', '15 mins', NULL, '15 mins', '6', '1 -1/4 cup', '6 ounces fresh tomatillos - husked, rinsed, and halved, 1 tablespoon thinly sliced serrano chiles, or to taste, 1 large ripe avocado - halved, seeded, and flesh scooped out of peel, ¼ cup packed cilantro leaves, ½  lime, juiced,   salt to taste', 'Place tomatillos into a food processor. Add serrano pepper, avocado, cilantro, and lime juice. Season with salt to taste. Process until smooth; adjust seasoning. Transfer to a serving bowl.
INSERT INTO public.recipes VALUES (814, 'Avocado Mango Salsa', '20 mins', NULL, '20 mins', '8', '8 servings', '1  avocado - peeled, pitted and diced, 1  lime, juiced, 1  mango - peeled, seeded and diced, 1 small red onion, chopped, 1  habanero pepper, seeded and chopped, 1 tablespoon chopped fresh cilantro,   salt to taste', 'Place the avocado in a serving bowl, and mix with the lime juice. Mix in the mango, onion, habanero pepper, cilantro and salt.
INSERT INTO public.recipes VALUES (815, 'Filipino Avocado Milkshake', '5 mins', NULL, '5 mins', '2', '2 servings', '1  avocado - peeled, pitted, and cubed, 5 cubes  ice, 3 tablespoons white sugar, 1 ⅓ cups milk, 1 teaspoon fresh lemon or lime juice, 1 scoop vanilla ice cream', 'Place avocado, ice, sugar, milk, lemon juice, and ice cream into a blender. Puree until smooth.', '4.7', 'https://www.allrecipes.com/recipe/139425/filipino-avocado-milkshake/', '/Breakfast and Brunch/Drinks/', 'Total Fat 19g 24%, Saturated Fat 5g 25%, Cholesterol 18mg 6%, Sodium 84mg 4%, Total Carbohydrate 38g 14%, Dietary Fiber 7g 24%, Total Sugars 29g, Protein 8g, Vitamin C 12mg 59%, Calcium 218mg 17%, Iron 1mg 3%, Potassium 757mg 16%', 'Prep Time: 5 mins, Total Time: 5 mins, Servings: 2, Yield: 2 servings', 'https://www.allrecipes.com/thmb/d-YvB22kgzjN3TCMd9Cz4IUknnY=/1500x0/filters:no_upscale():max_bytes(150000):strip_icc()/3515697-filipino-avocado-milkshake-Josephine-Yuen-4x3-1-4e87b9b506de42bc8e306ebd8e45cdc7.jpg');
INSERT INTO public.recipes VALUES (816, 'Black Bean Avocado Salsa', '15 mins', NULL, '2 hrs 15 mins', '10', '10 servings', '1 (15 ounce) can black beans (such as Bush''s®), rinsed and drained, 1 (11 ounce) can whole kernel sweet corn, drained, 4  roma (plum) tomatoes, seeded and chopped, 1 small red bell pepper, diced, 1  jalapeno pepper, seeded and minced, ⅓ cup chopped fresh cilantro, ¼ cup diced red onion, ¼ cup fresh lime juice, 2 tablespoons red wine vinegar, 1 teaspoon salt, ½ teaspoon ground black pepper, 2  avocados, diced', 'Mix black beans, corn, tomatoes, red bell pepper, jalapeno pepper, cilantro, red onion, lime juice, vinegar, salt, and black pepper in a bowl; fold avocado into the mixture. Cover bowl with plastic wrap, putting it right on top of salsa; chill at least 2 hours.', '4.9', 'https://www.allrecipes.com/recipe/229020/black-bean-avocado-salsa/', '/Appetizers and Snacks/Dips and Spreads Recipes/Salsa Recipes/Corn Salsa Recipes/', 'Total Fat 6g 8%, Saturated Fat 1g 5%, Sodium 493mg 21%, Total Carbohydrate 19g 7%, Dietary Fiber 7g 25%, Total Sugars 3g, Protein 5g, Vitamin C 21mg 106%, Calcium 28mg 2%, Iron 1mg 8%, Potassium 471mg 10%', 'Prep Time: 15 mins, Additional Time: 2 hrs, Total Time: 2 hrs 15 mins, Servings: 10, Yield: 10 servings', 'https://www.allrecipes.com/thmb/Y7XOlshxEjuG4iADMcXbpCey0QA=/1500x0/filters:no_upscale():max_bytes(150000):strip_icc()/5889297-5575d9e6a70a402ca4e2b19ef34d0131.jpg');
INSERT INTO public.recipes VALUES (817, 'Spinach Salad with Chicken, Avocado, and Goat Cheese', '20 mins', NULL, '20 mins', '4', '4 servings', '¼ cup pine nuts, 8 cups chopped spinach, 1 cup halved cherry tomatoes, 1 ½ cups chopped cooked chicken , 1 large avocado - peeled, pitted, and sliced, ½ cup corn kernels, ⅓ cup crumbled goat cheese', 'Heat a small skillet over medium-high heat. Toast pine nuts in hot skillet until lightly browned and fragrant, 3 to 5 minutes.
INSERT INTO public.recipes VALUES (818, 'Best Guacamole', '5 mins', NULL, '1 hrs 5 mins', '16', '2 cups', '2  avocados, ½  lemon, juiced, 2 tablespoons chopped onion, ½ teaspoon salt, 2 tablespoons olive oil', 'Cut the avocados into halves. Remove the seeds, and scoop out the pulp into a small bowl. Use a fork to mash the avocado. Stir in lemon juice, onion, salt, and olive oil. Cover the bowl, and refrigerate for 1 hour before serving.
INSERT INTO public.recipes VALUES (819, 'Avocado Quick Bread', '20 mins', '1 hrs', '1 hrs 20 mins', '20', '2 - 9x5 inch loaves', '2 ⅔ cups all-purpose flour, 1 ½ teaspoons baking soda, 1 teaspoon baking powder, ¾ teaspoon salt, ¾ teaspoon ground cinnamon, ¾ teaspoon ground allspice, ½ cup butter, softened, 1 ⅞ cups white sugar, 3  eggs, 1 ½ cups mashed ripe avocado, ¾ cup buttermilk, ¾ cup chopped pecans, ½ cup raisins, 1 tablespoon grated orange zest', 'Preheat the oven to 350 degrees F (175 degrees C). Grease and flour two 9x5 inch loaf pans. Sift together the flour, baking soda, baking powder, salt, cinnamon and allspice. Set aside.
INSERT INTO public.recipes VALUES (820, 'Chicken Stuffed Baked Avocados', '10 mins', '8 mins', '18 mins', '8', '8 avocado halves', '4  avocados, halved and pitted, 2  cooked chicken breasts, shredded, 4 ounces cream cheese, softened, ¼ cup chopped tomatoes, ¼ teaspoon salt, ¼ teaspoon ground black pepper, 1 pinch cayenne pepper, ½ cup shredded Parmesan cheese, or more to taste', 'Preheat oven to 400 degrees F (200 degrees C).
INSERT INTO public.recipes VALUES (821, 'Mexican Pizza I', '17 mins', '30 mins', '50 mins', '4', '4 pizzas', '1 (16 ounce) can refried beans, 1 pound ground beef, 1 (1.25 ounce) package taco seasoning mix, 1 tablespoon vegetable oil, 4 (6 inch) corn tortillas, 8 ounces shredded Cheddar cheese, 8 tablespoons sour cream, 2  roma (plum) tomatoes, chopped, 2  green onion, chopped, 1 (4 ounce) can diced green chiles, drained, ½  avocado, diced, 1 tablespoon black olives, sliced', 'Heat the refried beans.
INSERT INTO public.recipes VALUES (823, 'Smoked Salmon Sushi Roll', '30 mins', NULL, '5 hrs', '6', '6 rolls', '2 cups Japanese sushi rice, 6 tablespoons rice wine vinegar, 6 sheets nori (dry seaweed), 1  avocado - peeled, pitted and sliced, 1  cucumber, peeled and sliced, 8 ounces smoked salmon, cut into long strips, 2 tablespoons wasabi paste', 'Soak rice for 4 hours. Drain rice and cook in a rice cooker with 2 cups of water. Rice must be slightly dry as vinegar will be added later.
INSERT INTO public.recipes VALUES (824, 'Avocado Deviled Eggs', '20 mins', NULL, '20 mins', '12', '12 servings', '6  hard-boiled eggs, peeled and halved, 1  avocado - peeled, pitted, and diced, 3 slices cooked turkey bacon, chopped, divided, 2 ½ tablespoons mayonnaise, 2 teaspoons lime juice, 1 clove garlic, crushed, ⅛ teaspoon cayenne pepper,   sea salt to taste, 1  jalapeno pepper, sliced (Optional), 1 dash hot sauce, or to taste (Optional)', 'Scoop egg yolks into a bowl; add avocado, 2/3 of chopped turkey bacon, mayonnaise, lime juice, garlic, cayenne pepper, and salt. Mash egg yolk mixture until filling is evenly combined.
INSERT INTO public.recipes VALUES (825, 'Mexican Chicken and Rice Soup (Sopa de Pollo y Arroz)', '25 mins', '45 mins', '1 hrs 10 mins', '8', '8 servings', '2 ½ quarts chicken stock, 2 pounds skin-on, bone-in whole chicken legs (drumsticks and thighs), 3  carrots, chopped, 1  white onion, chopped, 2 stalks celery, chopped, ¼ cup chopped fresh cilantro, 1 clove garlic, 1 tablespoon chopped fresh mint,   salt and ground black pepper to taste, 3 cups cooked rice, 1  avocado, peeled and chopped, 2  serrano peppers, minced, 2  limes, quartered', 'Bring stock to a boil in a large pot over high heat. Add chicken legs; return to a boil. Reduce heat, cover, and simmer for 10 minutes, skimming away foam that forms on the surface. Add carrots, onion, celery, cilantro, garlic, and mint.
INSERT INTO public.recipes VALUES (826, 'Easy Arugula Salad', '15 mins', NULL, '15 mins', '4', '4 servings', '4 cups young arugula leaves, rinsed and dried, 1 cup cherry tomatoes, halved, ¼ cup pine nuts, 2 tablespoons grapeseed oil or olive oil, 1 tablespoon rice vinegar,   salt to taste,   freshly ground black pepper to taste, ¼ cup grated Parmesan cheese, 1 large avocado - peeled, pitted and sliced', 'In a large plastic bowl with a lid, combine arugula, cherry tomatoes, pine nuts, oil, vinegar, and Parmesan cheese. Season with salt and pepper to taste. Cover, and shake to mix.
INSERT INTO public.recipes VALUES (827, 'California Roll Sushi', '45 mins', '15 mins', '1 hrs 30 mins', '8', '8 rolls', '1 cup uncooked short-grain white rice, 1 cup water, ¼ cup rice vinegar, 1 tablespoon white sugar, ½ cup imitation crabmeat, finely chopped, ¼ cup mayonnaise, 8 sheets nori (dry seaweed), 2 ½ tablespoons sesame seeds, 1  cucumber, cut into thin spears, 2  avocados - pitted, peeled, and sliced the long way', 'Wash the rice in several changes of water until the rinse water is no longer cloudy, drain well, and place in a covered pan or rice cooker with 1 cup water. Bring to a boil, reduce heat to a simmer, and cover the pan. Allow the rice to simmer until the top looks dry, about 15 minutes. Turn off the heat, and let stand for 10 minutes to absorb the rest of the water.
INSERT INTO public.recipes VALUES (828, 'Avocado Shrimp Ceviche-Estillo Sarita', '1 hrs 30 mins', NULL, '1 hrs 30 mins', '4', '4 servings', '2 pounds large shrimp - peeled, deveined and chopped, ¾ cup fresh lime juice, 5  roma (plum) tomatoes, diced, 1  white onion, chopped, ½ cup chopped fresh cilantro, 1 tablespoon Worcestershire sauce, 1 tablespoon ketchup, 1 teaspoon hot pepper sauce,   salt and pepper to taste, 1  avocado - peeled, pitted and diced, 16  saltine crackers', 'Place the shrimp and lime juice into a large bowl, and stir to coat. Let stand for about 5 minutes, or until shrimp are opaque. The lime juice will cook them. Mix in the tomatoes, onion, and cilantro until coated with lime juice; cover and refrigerate for 1 hour.
INSERT INTO public.recipes VALUES (829, 'Avocado Toast (Vegan)', '10 mins', NULL, '10 mins', '4', '4 toasts', '4 slices whole-grain bread, 1  avocado, halved and pitted, 2 tablespoons chopped fresh parsley, 1 ½ teaspoons extra-virgin olive oil, ½  lemon, juiced, ½ teaspoon salt, ½ teaspoon ground black pepper, ½ teaspoon onion powder, ½ teaspoon garlic powder', 'Toast bread in a toaster or toaster oven.
INSERT INTO public.recipes VALUES (830, 'Quesadillas I', '10 mins', '10 mins', '20 mins', '5', '5 servings', '10 (6 inch) corn tortillas, 2 cups shredded mozzarella cheese, 1 (2 ounce) can sliced black olives, 2  avocados - peeled, pitted and sliced, 2 teaspoons hot pepper sauce', 'Heat a large frying pan or griddle over a medium heat. Place one tortilla flat on the frying pan. After 1 minute flip the tortilla over. Sprinkle a little more than 1/4 cup cheese on the tortilla, followed by some olives, avocado, and hot pepper sauce. Place another tortilla on top to make a sandwich. Cover the quesadilla with a lid. After one minute, flip the quesadilla. When the cheese has melted on the inside, remove the quesadilla. Repeat with remaining ingredients.
INSERT INTO public.recipes VALUES (831, 'Avocado Toast with Egg', '5 mins', '5 mins', '10 mins', '2', '2 servings', '1 teaspoon butter, 2  eggs, 2 slices multigrain bread, 1  ripe avocado, pitted, peeled, 1 teaspoon lemon juice, or to taste, 1 pinch cayenne pepper,   sea salt to taste,   ground black pepper to taste', 'Melt butter in a skillet over medium-low heat. Crack eggs into the skillet side by side and cook until eggs are white on the bottom layer and firm enough to flip, 2 to 3 minutes. Flip eggs, trying not to crack the yolk, and cook until egg reaches desired doneness, 2 to 5 minutes more.
INSERT INTO public.recipes VALUES (832, 'Kale, Quinoa, and Avocado Salad with Lemon Dijon Vinaigrette', '25 mins', '15 mins', '40 mins', '4', '1 large salad', '⅔ cup quinoa, 1 ⅓ cups water, 1 bunch kale, torn into bite-sized pieces, ½  avocado - peeled, pitted, and diced, ½ cup chopped cucumber, ⅓ cup chopped red bell pepper, 2 tablespoons chopped red onion, 1 tablespoon crumbled feta cheese', 'Bring the quinoa and 1 1/3 cup water to a boil in a saucepan. Reduce heat to medium-low, cover, and simmer until the quinoa is tender, and the water has been absorbed, about 15 to 20 minutes. Set aside to cool.
INSERT INTO public.recipes VALUES (833, 'Awesome Turkey Sandwich', '10 mins', NULL, '10 mins', '1', '1 sandwich', '2 slices whole wheat bread, toasted (Optional), 1 tablespoon mayonnaise, 2 teaspoons Dijon-style prepared mustard, 3 slices smoked turkey breast, 2 tablespoons guacamole, ½ cup mixed salad greens, ¼ cup bean sprouts, ¼  avocado - peeled, pitted and sliced, 3 ounces Colby-Monterey Jack cheese, sliced, 2 slices tomato', 'Spread mayonnaise on one slice of toast, then spread mustard on the other. Arrange the sliced turkey on one side. Spread guacamole over the turkey. Pile on the salad greens, bean sprouts, avocado and cheese. Finish with tomato slices, then place the remaining slice of toast on top.', '4.2', 'https://www.allrecipes.com/recipe/34400/awesome-turkey-sandwich/', '/Meat and Poultry/Turkey/Turkey Breast/', 'Total Fat 57g 73%, Saturated Fat 25g 124%, Cholesterol 124mg 41%, Sodium 1988mg 86%, Total Carbohydrate 41g 15%, Dietary Fiber 9g 31%, Total Sugars 3g, Protein 38g, Vitamin C 22mg 111%, Calcium 94mg 7%, Iron 4mg 21%, Potassium 928mg 20%', 'Prep Time: 10 mins, Total Time: 10 mins, Servings: 1, Yield: 1 sandwich', 'https://www.allrecipes.com/thmb/lR5Ci00nwGYS35KJ_kVMlc9IYOE=/1500x0/filters:no_upscale():max_bytes(150000):strip_icc()/120683-13e65a3f0d984411a784bb01379d3302.jpg');
INSERT INTO public.recipes VALUES (834, 'Grilled Avocados', '10 mins', '5 mins', '15 mins', '8', '8 servings', '¼ cup olive oil, or as needed, 1 pinch ground chipotle pepper, or more to taste, 1 pinch chili powder, or more to taste , 4  avocados, halved and pitted', 'Preheat grill for medium heat and lightly oil the grate.
INSERT INTO public.recipes VALUES (835, 'Taco Salad III', '15 mins', '15 mins', '30 mins', '8', '8 servings', '16 ounces lean ground beef, 1 (1.25 ounce) package taco seasoning mix, 1 head iceberg lettuce, shredded, 1  red onion, sliced, 1 bunch green onions, chopped, 1 (15 ounce) can pinto beans, drained, 1 (15 ounce) can kidney beans, drained, 2 large tomatoes, chopped, 1  avocados - peeled, pitted, and cubed, 8 ounces shredded Cheddar cheese, 1 (16 ounce) package corn chips, 1 (16 ounce) bottle Catalina salad dressing', 'Prepare the ground beef as directed by taco seasoning package and set aside.
INSERT INTO public.recipes VALUES (836, 'Vegetarian Tortilla Soup', '15 mins', '40 mins', '55 mins', '12', '12 servings', '2 tablespoons vegetable oil, 1 (1 pound) package frozen pepper and onion stir fry mix, 2 cloves garlic, minced, 3 tablespoons ground cumin, 1 (28 ounce) can crushed tomatoes, 3 (4 ounce) cans chopped green chile peppers, drained, 4 (14 ounce) cans vegetable broth,   salt and pepper to taste, 1 (11 ounce) can whole kernel corn, 12 ounces tortilla chips, 1 cup shredded Cheddar cheese, 1  avocado - peeled, pitted and diced', 'Heat the oil in a large pot over medium heat. Stir in the pepper and onion stir fry mix, garlic, and cumin, and cook 5 minutes, until vegetables are tender. Mix in the tomatoes and chile peppers. Pour in the broth, and season with salt and pepper. Bring to a boil, reduce heat to low, and simmer 30 minutes.
INSERT INTO public.recipes VALUES (837, 'Easy Keto Beef Tacos', '20 mins', '18 mins', '50 mins', '4', '4 servings', '2 cups shredded Cheddar cheese, 1 pound ground beef, ½ package taco seasoning mix, ½ teaspoon salt, ¼ teaspoon ground black pepper, 1  avocado, diced, 1 cup shredded lettuce, ½ cup shredded Cheddar cheese, ½ cup tomatoes, diced', 'Preheat oven to 350 degrees F (175 degrees C). Line 2 baking sheets with parchment paper or silicone mat.
INSERT INTO public.recipes VALUES (838, 'Turkey Avocado Panini', '17 mins', '8 mins', '25 mins', '2', '2 sandwiches', '½  ripe avocado, ¼ cup mayonnaise, 2  ciabatta rolls, 1 tablespoon olive oil, divided, 2 slices provolone cheese, 1 cup whole fresh spinach leaves, divided, ¼ pound thinly sliced mesquite smoked turkey breast, 2  roasted red peppers, sliced into strips', 'Mash the avocado and the mayonnaise together in a bowl until thoroughly mixed.
INSERT INTO public.recipes VALUES (839, 'Corn and Avocado Salsa', '30 mins', '5 mins', '35 mins', '4', '4 cups', '3 ears fresh corn, husks and silks removed, 2  avocados - peeled, pitted, and cubed, 1  red onion, finely diced, 1  red bell pepper, seeded and diced, 1 tablespoon minced garlic, 1 tablespoon ground cumin, 1 teaspoon crushed red pepper flakes, ¼ cup chopped fresh cilantro, ⅓ cup red wine vinegar, 2 tablespoons olive oil, ¼ cup fresh lime juice,   salt and black pepper to taste', 'Place the corn in a large pot with enough water to cover, and bring to a boil. Cook until kernels are tender but crisp, about 5 minutes. Drain, and cool in cold water. Use a knife to scrape kernels from the cobs.
INSERT INTO public.recipes VALUES (840, 'Harvest Salad', '15 mins', NULL, '15 mins', '6', '6 servings', '½ cup chopped walnuts, 1 bunch spinach, rinsed and torn into bite-size pieces, ½ cup dried cranberries, ½ cup crumbled blue cheese, 2  tomatoes, chopped, 1  avocado - peeled, pitted and diced, ½  red onion, thinly sliced, 2 tablespoons red raspberry jam (with seeds), 2 tablespoons red wine vinegar, ⅓ cup walnut oil,   freshly ground black pepper to taste,   salt to taste', 'Preheat oven to 375 degrees F (190 degrees C). Arrange walnuts in a single layer on a baking sheet. Toast in oven for 5 minutes, or until nuts begin to brown.
INSERT INTO public.recipes VALUES (841, 'Warm Shrimp Salad', '10 mins', '15 mins', '25 mins', '3', '2 to 4 servings', '1 pound medium shrimp - peeled and deveined, 2 tablespoons butter, 2  lemons, juiced, 2 heads butter lettuce, 2  tomatoes, chopped, 1  avocado - peeled, pitted and diced, 2 stalks celery, chopped, 1  cucumber, cleaned and chopped, ½ cup shredded carrots, ⅓ cup vinaigrette salad dressing', 'In a large saute pan melt butter over medium heat. Add the shrimp and lemon juice, cook until shrimp just turn pink. Remove from heat and drain.
INSERT INTO public.recipes VALUES (842, 'Avocado Soup with Chicken and Lime', '10 mins', '20 mins', '30 mins', '4', '4 servings', '4 (6 inch) corn tortillas, julienned, 1 ½ tablespoons olive oil, 1  white onion, sliced thinly, 8 cloves garlic, thinly sliced, 4  fresh jalapeno peppers, sliced, 8 ounces skinless, boneless chicken breast halves - cut into thin strips, 1 quart chicken broth, ¼ cup fresh lime juice, 1  tomato, seeded and diced,   salt and ground black pepper to taste, 1  avocado - peeled, pitted and diced, ¼ cup chopped fresh cilantro', 'Preheat oven to 400 degrees F (200 degrees C). Arrange tortilla strips on a baking sheet.
INSERT INTO public.recipes VALUES (843, 'Meyer Lemon Avocado Toast', '10 mins', '3 mins', '13 mins', '2', '2 servings', '2 slices whole grain bread, ½  avocado, 2 tablespoons chopped fresh cilantro, or more to taste, 1 teaspoon Meyer lemon juice, or to taste, ¼ teaspoon Meyer lemon zest, 1 pinch cayenne pepper, 1 pinch fine sea salt, ¼ teaspoon chia seeds', 'Toast bread slices to desired doneness, 3 to 5 minutes.
INSERT INTO public.recipes VALUES (844, 'Mexican Baked Fish', '15 mins', '15 mins', '30 mins', '6', '6 servings', '1 ½ pounds cod, 1 cup salsa, 1 cup shredded sharp Cheddar cheese, ½ cup coarsely crushed corn chips, 1  avocado - peeled, pitted and sliced, ¼ cup sour cream', 'Preheat oven to 400 degrees F (200 degrees C). Lightly grease one 8x12 inch baking dish.
INSERT INTO public.recipes VALUES (845, 'Easy Never Forgotten Guacamole', '10 mins', NULL, '40 mins', '16', '2 cups', '3  avocados - peeled, pitted and diced, 1 tablespoon sour cream, 2 (3 ounce) packages cream cheese, softened, 2 tablespoons salsa, 1 pinch salt, 1 dash ground black pepper, 1 dash garlic salt, 1 dash onion powder', 'In a small bowl, mix together the avocados, sour cream, cream cheese and salsa. Blend to desired consistency.
INSERT INTO public.recipes VALUES (846, 'Avocado Dressing', '10 mins', NULL, '10 mins', '12', '1 1/2 cups', '1  avocado, peeled and pitted, ½ cup plain yogurt, ¼ cup extra-virgin olive oil, 3 tablespoons lemon juice, 2 cloves garlic, 1 teaspoon sea salt, ¼ teaspoon hot pepper sauce, ⅛ teaspoon ground black pepper', 'Blend avocado, yogurt, olive oil, lemon juice, garlic, sea salt, hot sauce, and black pepper together in a blender until smooth.', '4.6', 'https://www.allrecipes.com/recipe/241148/avocado-dressing/', '/Side Dish/Sauces and Condiments/Salad Dressing Recipes/Yogurt Dressing Recipes/', 'Total Fat 7g 9%, Saturated Fat 1g 6%, Cholesterol 1mg 0%, Sodium 158mg 7%, Total Carbohydrate 3g 1%, Dietary Fiber 1g 4%, Total Sugars 1g, Protein 1g, Vitamin C 4mg 19%, Calcium 22mg 2%, Iron 2mg 11%, Potassium 113mg 2%', 'Prep Time: 10 mins, Total Time: 10 mins, Servings: 12, Yield: 1 1/2 cups', 'https://www.allrecipes.com/thmb/7VJZ0XH7YERsj96u4A69F7RHYPw=/1500x0/filters:no_upscale():max_bytes(150000):strip_icc()/2140127-99b8621483404f3fb8ede68144ccf6f0.jpg');
INSERT INTO public.recipes VALUES (847, 'Avocado Egg Salad', '20 mins', NULL, '20 mins', '6', '3 cups', '6  hard-boiled eggs, peeled, 2  avocados - peeled, pitted, and cubed, ½ cup minced red onion, 3 tablespoons chopped sweet pickles, 1 tablespoon prepared yellow mustard, ⅓ cup mayonnaise,   salt and pepper to taste', 'Mash the eggs with a fork in a mixing bowl to break up. Add the avocado, onion, pickle, mustard, and mayonnaise. Gently smash the ingredients together until blended. Season to taste with salt and pepper.', '4.6', 'https://www.allrecipes.com/recipe/170446/avocado-egg-salad/', '/Salad/Egg Salad Recipes/', 'Total Fat 25g 32%, Saturated Fat 5g 23%, Cholesterol 217mg 72%, Sodium 189mg 8%, Total Carbohydrate 9g 3%, Dietary Fiber 5g 18%, Total Sugars 3g, Protein 8g, Vitamin C 8mg 39%, Calcium 42mg 3%, Iron 1mg 6%, Potassium 418mg 9%', 'Prep Time: 20 mins, Total Time: 20 mins, Servings: 6, Yield: 3 cups', 'https://www.allrecipes.com/thmb/62ZI9xBfxdjifXHMO3qpgx449LE=/1500x0/filters:no_upscale():max_bytes(150000):strip_icc()/5752004-32562a92b5aa4b9884fb854d03db5f10.jpg');
INSERT INTO public.recipes VALUES (848, 'Absolutely Amazing Ahi', '10 mins', '15 mins', '25 mins', '6', '6 servings', '¾ pound sashimi grade tuna steak, diced, ½ cup diced cucumber, 1  avocados - peeled, pitted and diced, ¼ cup chopped green onion, 1 ½ teaspoons red pepper flakes, 1 tablespoon toasted sesame seeds, 1 ½ teaspoons lemon juice, 2 teaspoons sesame oil, ½ cup soy sauce', 'In a medium bowl, combine the tuna, cucumber, avocado, green onion, red pepper flakes and sesame seeds. Pour in the lemon juice, sesame oil and soy sauce, and stir carefully to blend so as not to mash the avocado. Place this bowl into a larger bowl that has been filled with ice. Chill in the refrigerator for 15 minutes, but no longer - the terrific freshness of the fish will be lost.
INSERT INTO public.recipes VALUES (850, 'Mexican Botana Platter', '40 mins', '40 mins', '1 hrs 20 mins', '12', '12 servings', '2 pounds beef skirt steak, 2 pounds boneless chicken thighs, 2 teaspoons fajita seasoning, 2 ½ teaspoons garlic powder, divided, 2 cups refried beans,   salt to taste,   lemon pepper to taste, 4  avocados - peeled, pitted, and mashed, 1 cup corn oil, 24  corn tortillas, 1 medium green bell pepper, chopped, 1 medium onion, chopped, ⅓ bunch cilantro, chopped, 1 (16 ounce) package shredded American cheese, 12 ounces sour cream, 2 large tomatoes, chopped, 4  pickled jalapeno peppers, sliced (Optional)', 'Preheat oven to 350 degrees F (175 degrees C).
INSERT INTO public.recipes VALUES (851, 'Salsa Salad', '30 mins', NULL, '30 mins', '6', '6 servings', '4 large ripe tomatoes, cut into bite-size pieces, 1 bunch cilantro, stems cut off and leaves coarsely chopped, 1 large green bell pepper, cut into bite-size pieces, 1 large red bell pepper, cut into bite-size pieces , 2  jalapeno peppers, finely chopped, 3  green onions, chopped, ½  sweet red onion, chopped, 2 large avocados, pitted and cut into bite-sized pieces, 1  lime, juiced, ½ teaspoon salt, or to taste', 'In a large salad bowl, lightly mix the tomatoes, cilantro, green and red bell peppers, jalapeno peppers, green onions, and sweet red onion until thoroughly combined. Gently toss with avocado pieces, and squeeze lime juice over the salad. Sprinkle with salt to serve.', '4.6', 'https://www.allrecipes.com/recipe/218645/salsa-salad/', '/Salad/Vegetable Salad Recipes/Tomato Salad Recipes/', 'Total Fat 14g 18%, Saturated Fat 2g 11%, Sodium 214mg 9%, Total Carbohydrate 18g 7%, Dietary Fiber 10g 34%, Total Sugars 7g, Protein 4g, Vitamin C 90mg 452%, Calcium 43mg 3%, Iron 1mg 8%, Potassium 952mg 20%', 'Prep Time: 30 mins, Total Time: 30 mins, Servings: 6, Yield: 6 servings', 'https://www.allrecipes.com/thmb/4fIdGwm91i-GiDqA-ksNk-XaepU=/1500x0/filters:no_upscale():max_bytes(150000):strip_icc()/4048362-9632b714f93342f0afd34fad64632c3f.jpg');
INSERT INTO public.recipes VALUES (852, 'Avocado Dessert', '20 mins', '20 mins', '40 mins', '4', '4 servings', '1  avocado, peeled and pitted, ½ cup milk, ¼ cup white sugar, ½ teaspoon vanilla extract', 'Mash avocado with an electric mixer, or use a food processor. Blend in the milk, sugar and vanilla until smooth. Chill for about 20 minutes before serving.', '4.1', 'https://www.allrecipes.com/recipe/80784/avocado-dessert/', '/Desserts/Custards and Puddings/', 'Total Fat 8g 10%, Saturated Fat 2g 8%, Cholesterol 2mg 1%, Sodium 16mg 1%, Total Carbohydrate 18g 7%, Dietary Fiber 3g 12%, Total Sugars 14g, Protein 2g, Vitamin C 5mg 26%, Calcium 42mg 3%, Iron 0mg 2%, Potassium 291mg 6%', 'Prep Time: 20 mins, Cook Time: 20 mins, Total Time: 40 mins, Servings: 4, Yield: 4 servings', 'https://www.allrecipes.com/thmb/w4d8xF9BQ9Kc4JhkZeT-Mcf89pE=/1500x0/filters:no_upscale():max_bytes(150000):strip_icc()/7673551-8e0b87ffc5754fb887b70dd8e953f4a2.jpg');
INSERT INTO public.recipes VALUES (853, 'Black Bean Breakfast Bowl', '10 mins', '5 mins', '15 mins', '2', '2 servings', '2 tablespoons olive oil, 4  eggs, beaten, 1 (15 ounce) can black beans, drained and rinsed, 1  avocado, peeled and sliced, ¼ cup salsa,   salt and ground black pepper to taste', 'Heat olive oil in a small pan over medium heat. Cook and stir eggs until eggs are set, 3 to 5 minutes.
INSERT INTO public.recipes VALUES (854, 'Avocado Cream Sauce', '15 mins', '10 mins', '25 mins', '4', '4 servings', '2  avocados, 2 cloves garlic, ½  lime, juiced, or to taste, 2 tablespoons chopped green onions, 1 tablespoon chopped fresh cilantro, ½ tablespoon chopped fresh tarragon, 2 tablespoons butter, ¼ cup heavy cream,   salt to taste', 'Combine avocados, garlic, lime juice, green onions, cilantro, and tarragon in a food processor; puree until smooth.
INSERT INTO public.recipes VALUES (855, 'Mean Green Guacamole Salsa', '10 mins', '10 mins', '20 mins', '12', '12 servings', '10  fresh tomatillos, husks removed, 2  fresh jalapeno peppers, stems removed, 1 bunch fresh cilantro, stems trimmed, 3  avocados, peeled and pitted, 1 tablespoon garlic powder,   salt to taste', 'Bring a pot of water to a boil and stir in tomatillos and jalapenos. Boil until tomatillos turn bright green and soft, about 10 minutes.
INSERT INTO public.recipes VALUES (856, 'Apricot Pork Tenderloin', '10 mins', '45 mins', '55 mins', '6', '6 servings', '2 pounds pork tenderloin, ¼ cup softened butter,   salt and pepper to taste, 1 teaspoon ground thyme, 2 teaspoons garlic powder, 1 (18 ounce) jar apricot preserves, 2 tablespoons honey, or to taste, ¼ cup dry sherry', 'Preheat an oven to 350 degrees F (175 degrees C).
INSERT INTO public.recipes VALUES (857, 'Apricot Pie', '25 mins', '35 mins', '2 hrs', '8', '1 9-inch pie', '2 ½ cups all-purpose flour, 1 teaspoon salt, 1 cup butter-flavored shortening, 6 tablespoons water, or as needed, 1 cup white sugar, ¼ cup all-purpose flour, ¼ teaspoon ground cinnamon, 1 teaspoon lemon juice, 5 cups fresh apricots, pitted and quartered , 1 teaspoon sugar for sprinkling, or as desired', 'Preheat oven to 425 degrees F (220 degrees C).
INSERT INTO public.recipes VALUES (858, 'Apricot Brown Sugar Ham', NULL, '2 hrs', '2 hrs', '15', NULL, '1 (10 pound) fully-cooked spiral cut ham, ⅔ cup brown sugar, ⅓ cup apricot jam, 1 teaspoon dry mustard powder', 'Preheat the oven to 275 degrees F (135 degrees C).
INSERT INTO public.recipes VALUES (859, 'Fresh Apricot Cobbler', '20 mins', '40 mins', '1 hrs', '12', '12 servings', '1 cup water, ¾ cup white sugar, 1 tablespoon cornstarch, ¼ teaspoon ground cinnamon, ⅛ teaspoon ground nutmeg, 6 cups halved fresh apricots, 1 tablespoon butter', 'Preheat oven to 400 degrees F (200 degrees C).
INSERT INTO public.recipes VALUES (860, 'Apricot-Glazed Pork Chops', '10 mins', '10 mins', '20 mins', '4', '4 servings', '⅓ cup apricot preserves, ⅓ cup fruity white wine, such as Gewurztraminer, ½ teaspoon ground ginger,   salt and pepper to taste, 2 tablespoons olive oil, 4  boneless pork chops, 1/2 inch thick ', 'Mix the apricot preserves, wine, and ground ginger together in a small bowl; set aside.
INSERT INTO public.recipes VALUES (861, 'Dried Apricot Jam', NULL, '20 mins', '1 hrs 50 mins', '144', '10 cups', '4 ½ cups dried apricots, 4 ½ cups boiling water, 1 teaspoon vanilla extract, 1 (1.75 ounce) package powdered fruit pectin, 7 cups white sugar, ¼ cup lemon juice', 'Soak apricots in boiling water in a bowl until hydrated, about 30 minutes. Blend apricots, remaining water, and vanilla extract in a food processor, working in batches, until blended but still slightly chunky.
INSERT INTO public.recipes VALUES (862, 'Slow Cooker Chicken Tagine', '15 mins', '5 hrs', '5 hrs 15 mins', '8', '8 servings', '8  skinless, boneless chicken thighs, 2 large onions, thinly sliced, 4 large carrots, thinly sliced, ½ cup raisins, ½ cup dried apricots, chopped, 2 cups chicken broth, 2 tablespoons tomato paste, 2 tablespoons lemon juice, 2 tablespoons all-purpose flour, 2 teaspoons garlic salt, 2 teaspoons ground cumin, 1 ½ teaspoons ground ginger, 1 teaspoon ground cinnamon, 1 teaspoon Hungarian paprika, 1 teaspoon ground black pepper, 3 cups water, 2 cups couscous , 1 tablespoon butter', 'Layer chicken thighs, onions, carrots, raisins, and apricots in a slow cooker.
INSERT INTO public.recipes VALUES (863, 'Apricot Chutney', '15 mins', '1 hrs 5 mins', '1 hrs 20 mins', '50', '3 1/4 cups', '½ whole head garlic, ¼ teaspoon olive oil, 1 large onion, chopped, 1 tablespoon olive oil, 3 cups apricot preserves, 1 cup white vinegar, 2 teaspoons ground ginger, ½ teaspoon cayenne pepper, ½ teaspoon salt', 'Preheat oven to 450 degrees F (230 degrees C).
INSERT INTO public.recipes VALUES (864, 'Apricot Cream Cheese Thumbprints', '15 mins', '15 mins', '2 hrs 30 mins', '84', '7 dozen', '1 ½ cups butter, softened, 1 ½ cups white sugar, 1 (8 ounce) package cream cheese, softened, 2  eggs, 2 tablespoons lemon juice, 1 ½ teaspoons lemon zest, 4 ½ cups all-purpose flour, 1 ½ teaspoons baking powder, 1 cup apricot preserves, ⅓ cup confectioners'' sugar for decoration', 'In a large bowl, cream together the butter, sugar, and cream cheese until smooth. Beat in the eggs one at a time, then stir in the lemon juice and lemon zest. Combine the flour and baking powder; stir into the cream cheese mixture until just combined. Cover, and chill until firm, about 1 hour.
INSERT INTO public.recipes VALUES (865, 'Moroccan Beef and Lentil Stew', '15 mins', '1 hrs 20 mins', '1 hrs 35 mins', '6', NULL, '2 tablespoons vegetable oil, 2  carrots, chopped, 1  celery stalk, chopped, 1  onion, chopped, 4 cloves garlic, minced, 1 ½ pounds chuck roast, cut into 1-inch cubes, 1 teaspoon salt, or to taste, 1 teaspoon ground turmeric, 1 teaspoon onion powder, 1 teaspoon garlic powder, ½ teaspoon ground black pepper, or to taste, ½ teaspoon ground cinnamon, ½ teaspoon ground ginger, ½ teaspoon ground cumin, ½ teaspoon ground coriander, ¼ teaspoon ground allspice, 3 tablespoons tomato paste, 4 cups low-sodium beef broth, 1 tablespoon molasses, 2  bay leaves, 1 cup dried red lentils, ½ cup dried apricots, chopped, ½  lemon, juiced', 'Heat oil in a Dutch oven over medium heat. Add carrots, celery, and onion; cook until slightly softened, about 3 minutes. Stir in garlic and cook for 1 minute.
INSERT INTO public.recipes VALUES (866, 'Dried Apricot Pie', '30 mins', '1 hrs', '1 hrs 30 mins', '8', '1 pie', '18 ounces dried apricots, 1 ¾ cups water, 1 tablespoon cornstarch, 1 tablespoon orange liqueur , 1 ¾ cups white sugar, 1 recipe pastry for a 9 inch double crust pie', 'Preheat oven to 400 degrees F (205 degrees C).
INSERT INTO public.recipes VALUES (867, 'Instant Pot Chicken Tagine with Apricots and Chickpeas', '15 mins', '35 mins', '1 hrs', '6', NULL, '1 tablespoon olive oil, 4  skin-on, bone-in chicken thighs, 1 large onion, sliced, 3 cloves garlic, minced, 1 teaspoon ground cinnamon, 1 teaspoon ground cumin, 1 teaspoon ground turmeric, 1 teaspoon red pepper flakes, 1 pinch saffron, 1 (15 ounce) can diced tomatoes, 1 cup chicken broth, ⅓ cup halved dried apricots,   salt and ground black pepper to taste, 1 (15 ounce) can chickpeas, rinsed and drained, 2 tablespoons chopped fresh mint', 'Turn on a multi-functional pressure cooker (such as Instant Pot) and select Saute function. Place olive oil in the hot cooker and fry chicken thighs until browned, 2 to 3 minutes per side. Remove chicken from the inner pot and set aside.
INSERT INTO public.recipes VALUES (868, 'Fruity Couscous Salad', '15 mins', NULL, '15 mins', '8', NULL, '1 ⅓ cups dry couscous, 2 cups boiling water, ⅔ cup sweetened dried cranberries, ⅔ cup slivered almonds, ½ cup packed dried apricots, chopped, 3 medium scallions, thinly sliced with greens, 1 teaspoon cumin,   salt and ground black pepper to taste', 'Place couscous in a bowl and pour boiling water over top. Gently stir, then cover and let sit for 5 minutes.
INSERT INTO public.recipes VALUES (869, 'Moroccan Chicken Tagine', '20 mins', '1 hrs 50 mins', '2 hrs 10 mins', '6', NULL, '¼ cup ground cinnamon, ¼ cup ground cumin, 2 tablespoons ground turmeric, 2 tablespoons ground coriander, 2 tablespoons ground ginger, 2 tablespoons crushed dried mint, 1 tablespoon salt, 2 teaspoons ground black pepper', 'Make the spice mix: Mix cinnamon, cumin, turmeric, coriander, ginger, mint, salt, and pepper together in a bowl. Measure out 1/2 cup spice mix and set remaining mix aside for another use.
INSERT INTO public.recipes VALUES (870, 'Simple Apricot-Glazed Meatloaf', '10 mins', '1 hrs', '1 hrs 15 mins', '6', '1 9x5-inch meatloaf', '1 ½ pounds ground beef, 1 cup bread crumbs, 1 small onion, minced, 1 large egg, beaten, 2 cloves garlic, minced, 1 ½ tablespoons apricot preserves, 1 tablespoon kosher salt, 1 ½ teaspoons freshly ground black pepper', 'Preheat the oven to 350 degrees F (175 degrees C).
INSERT INTO public.recipes VALUES (871, 'Apricot Chicken Curry', '30 mins', '40 mins', '1 hrs 10 mins', '4', '4 servings', '8  chicken drumsticks,   salt and pepper to taste, 2 tablespoons olive oil, 3 cloves garlic, minced, ½ teaspoon red pepper flakes, or to taste, 4 cups apricot nectar, 1 teaspoon cornstarch, or as needed, 1 tablespoon water, 3 tablespoons Madras curry powder, 1 cup dried apricots, 1 large onion, roughly chopped, 1 large green bell pepper, roughly chopped, 4  carrots, thinly sliced, 1  fresh green chile pepper, minced (Optional), ½ cup chopped water chestnuts (Optional)', 'Preheat an oven to 350 degrees F (175 degrees C). Season the chicken drumsticks with salt and pepper.
INSERT INTO public.recipes VALUES (872, 'Apricot Leather', '30 mins', '6 hrs', '6 hrs 30 mins', '14', NULL, '1 teaspoon lemon juice, 2 cups pitted and diced fresh apricots, ½ cup white sugar', 'Preheat the oven to 150 degrees F (165 degrees C), or the lowest setting you have.
INSERT INTO public.recipes VALUES (873, 'Fresh Apricot Crisp', '15 mins', '35 mins', '50 mins', '6', NULL, '4 cups apricot halves, ¼ cup white sugar, ¾ cup brown sugar, ½ cup all-purpose flour, ½ cup butter, ¾ cup rolled oats', 'Preheat the oven to 350 degrees F (175 degrees C).
INSERT INTO public.recipes VALUES (874, 'Apricot Lentil Soup', '15 mins', '50 mins', '1 hrs 5 mins', '6', '6 servings', '3 tablespoons olive oil, 1  onion, chopped, 2 cloves garlic, minced, ⅓ cup dried apricots, 1 ½ cups red lentils, 5 cups chicken stock, 3  roma (plum) tomatoes - peeled, seeded and chopped, ½ teaspoon ground cumin, ½ teaspoon dried thyme,   salt to taste,   ground black pepper to taste, 2 tablespoons fresh lemon juice', 'Saute onion, garlic, and apricots in olive oil. Add lentils and stock. Bring to a boil, then reduce heat and simmer 30 minutes.
INSERT INTO public.recipes VALUES (875, 'Oat-Free and Gluten-Free Granola Bars (Clean Eating)', '10 mins', '3 mins', '2 hrs 13 mins', '20', '20 bars', '1 ¼ cups almonds, divided, 1 ¼ cups sunflower seeds, divided, 2 cups shredded unsweetened coconut, 1 cup diced dried apricots, 1 ½ cups coconut oil, ½ cup honey, ¼ cup ground cinnamon, or as needed, 1 teaspoon vanilla extract, ½ teaspoon salt', 'Place 3/4 cups almonds and 3/4 cups sunflower seeds into a food processor; chop until nuts are in 1/4-inch pieces, 1 to 2 minutes. Remove from food processor and pour in a bowl. Place the remaining almonds and sunflower seeds into the food processor; roughly chop into larger pieces, about 1 minute. Mix remaining nuts, seeds, shredded coconut, and dried apricot into the 1/4-inch nuts until fruit and nut mixture is combined.
INSERT INTO public.recipes VALUES (876, 'Honey Apricot Pork Chops', '15 mins', '20 mins', '35 mins', '4', '4 servings', '4  boneless pork chops,   Kosher salt and fresh cracked pepper to taste, 1 tablespoon olive oil, 2 tablespoons honey, 4  fresh apricots, pitted and cut into wedges, 3 cloves garlic, minced, or to taste, 1 teaspoon chopped fresh parsley', 'Pat the pork chops dry with paper towels, and sprinkle both sides with salt and black pepper. Heat olive oil in a skillet over medium-high heat, and brown the chops well on both sides, about 5 minutes per side.
INSERT INTO public.recipes VALUES (877, 'Apricot Cookies', NULL, NULL, NULL, '24', '4 dozen', '1 cup butter, 1 cup white sugar, 3 cups all-purpose flour, 1 teaspoon baking powder, ½ teaspoon salt, 1  egg, 1 teaspoon vanilla extract, 1 cup apricot preserves, ⅓ cup confectioners'' sugar for decoration', 'Preheat oven to 350 degrees F (175 degrees C).
INSERT INTO public.recipes VALUES (878, 'Apricot Danish Coffee Cake', '20 mins', '30 mins', '50 mins', '15', '1 10x15 inch jellyroll pan', '1 (18.25 ounce) package white cake mix, 3  eggs, 1 ½ cups sour cream, 1 (15 ounce) can apricot halves, drained, 1 tablespoon butter, ½ cup slivered almonds, 1 (8 ounce) package cream cheese, 2 tablespoons milk, ⅔ cup confectioners'' sugar, 2 teaspoons water', 'Preheat oven to 350 degrees F (175 degrees C). Grease and flour a 10x15 inch jellyroll pan. Set aside 1/2 cup of the dry cake mix.
INSERT INTO public.recipes VALUES (879, 'Apricot Muffins', '15 mins', '15 mins', '30 mins', '12', '12 muffins', '1 cup chopped dried apricots, 1 cup boiling water, 2 cups all-purpose flour, ¾ cup white sugar, 1 teaspoon baking soda, ½ teaspoon salt, ¼ cup melted butter, ¼ cup vegetable oil, 1 cup buttermilk, 1  egg', 'Preheat the oven to 400 degrees F (200 degrees C). Grease a 12 cup muffin pan, or line with paper muffin cups. Place apricots into a small bowl, and pour the boiling water over them. Let stand for 5 minutes.
INSERT INTO public.recipes VALUES (882, 'Apricot Brandy Pound Cake III', '30 mins', '1 hrs', '1 hrs 30 mins', '15', '1 to 10 - inch tube pan', '3 cups sifted all-purpose flour, ¼ teaspoon baking soda, ½ teaspoon salt, 1 cup sour cream, ½ teaspoon rum flavored extract, 1 teaspoon orange extract, ¼ teaspoon almond extract, ½ teaspoon lemon extract, 1 teaspoon vanilla extract, ½ cup apricot brandy, 1 cup butter, 3 cups white sugar, 6  eggs', 'Preheat oven to 325 degrees F (165 degrees C). Grease and flour a 10 inch tube pan. Mix together the flour, baking soda and salt. Set aside.
INSERT INTO public.recipes VALUES (883, 'Moroccan Lamb Stew with Apricots', '30 mins', '1 hrs 55 mins', '2 hrs 25 mins', '4', '4 servings', '2 pounds boneless leg of lamb, cut into 1-inch cubes, 2 teaspoons ground coriander, 1 teaspoon ground cumin, 1 teaspoon sweet paprika, ½ teaspoon cayenne pepper, ½ teaspoon ground cardamom, ½ teaspoon ground turmeric, 2 teaspoons kosher salt, 2 tablespoons olive oil, 2 cups finely chopped onion, 4 cloves garlic, minced, 1 tablespoon minced fresh ginger root, 2 (3 inch) cinnamon sticks, 2 cups low-sodium chicken stock, 1 cup dried apricots, halved, 2 (3 inch) orange peel strips, 1 tablespoon honey, ¼ cup chopped fresh cilantro, ¼ cup toasted pine nuts', 'Combine lamb, coriander, cumin, paprika, cayenne, cardamom, turmeric, and salt in a large bowl; toss together until lamb is evenly coated.
INSERT INTO public.recipes VALUES (884, 'Apricot Nectar Cake II', NULL, NULL, NULL, '12', '1 -10 inch Bundt or tube pan', '1 (18.25 ounce) package yellow cake mix, 4  eggs, ¾ cup vegetable oil, ¾ cup apricot nectar, ⅓ cup hot water, 2 cups confectioners'' sugar, 6 tablespoons lemon juice, 1 (3 ounce) package lemon flavored Jell-O® mix', 'Preheat oven to 350 degrees F (175 degrees C). Grease one 10 inch tube or Bundt pan.
INSERT INTO public.recipes VALUES (885, 'Homemade Apricot Jam', '10 mins', '10 mins', '1 day 20 mins', '56', '7 cups', '2 ½ pounds fresh apricots, pitted and finely chopped, ⅓ cup lemon juice, 5 ¾ cups white sugar, ½ teaspoon butter, 1 (1.75 ounce) package powdered fruit pectin', 'Stir apricots, lemon juice, and sugar together in a large pot over medium heat; add butter to reduce foaming. Bring apricot mixture to a rolling boil, stirring constantly. Quickly stir in pectin; return to a full boil until pectin is dissolved, 1 minute. Remove from heat and skim off any foam with a metal spoon.
INSERT INTO public.recipes VALUES (890, 'Apricot Noodle Kugel', '25 mins', '45 mins', '1 hrs 10 mins', '12', '12 servings', '1 (8 ounce) package wide egg noodles, ¼ cup butter, softened, 1 (3 ounce) package cream cheese, softened, 3  eggs, beaten, ½ cup white sugar, 1 teaspoon vanilla extract, 1 cup apricot nectar, 1 cup milk, ½ cup golden raisins (Optional), 1 ½ cups cornflake crumbs, ½ cup butter, softened, ¼ cup white sugar, 1 teaspoon vanilla extract, 1 teaspoon ground cinnamon', 'Preheat oven to 350 degrees F (175 degrees C). Lightly grease a 9x9 inch baking pan.
INSERT INTO public.recipes VALUES (886, 'Apricot-Glazed Pork Ribs', '10 mins', '1 hrs 40 mins', '9 hrs 50 mins', '12', '12 servings', '3 ½ pounds baby back pork ribs, 1 (16 ounce) jar apricot preserves, ⅓ cup soy sauce, ¼ cup packed light brown sugar, 2 teaspoons garlic powder,   aluminum foil,   salt and ground black pepper to taste', 'Place ribs in a large roasting pan. Whisk together apricot preserves, soy sauce, brown sugar, and garlic powder until blended. Pour apricot marinade over ribs, cover, and place in the refrigerator, 8 hours to overnight.
INSERT INTO public.recipes VALUES (887, 'Energy Bars', '15 mins', '20 mins', '1 hrs 35 mins', '9', '9 bars', '2  eggs, 1 large ripe banana, mashed, 1 cup quick-cooking rolled oats, ½ cup unsalted raw sunflower seeds, ½ teaspoon ground cinnamon, ½ cup nonfat dry milk powder, ½ cup chopped pitted dates, ½ cup raisins, ½ cup chopped walnuts, ½ cup chopped dried apricots, ½ cup toasted wheat germ, ⅓ cup pure maple syrup, ¼ cup whole-wheat pastry flour', 'Preheat an oven to 350 degrees F (175 degrees C). Lightly oil a 9x13-inch baking dish.
INSERT INTO public.recipes VALUES (888, 'Apricot Chicken with Balsamic Vinegar', '25 mins', '30 mins', '55 mins', '8', '8 servings', '2 tablespoons extra-virgin olive oil, 2 pounds chicken breast tenderloins, cut into bite-size pieces,   salt and pepper to taste, 1 large onion, chopped (Optional), ¼ cup balsamic vinegar, or to taste, 20  dried apricots, 1 cup chicken stock, 1 cup apricot preserves, 1 tablespoon chopped fresh thyme, 3 tablespoons chopped fresh flat-leaf parsley (Optional)', 'Heat the olive oil in a large skillet with a lid over medium-high heat. Season the chicken with salt and pepper, and cook in the hot oil until golden brown around the edges, but still pink in the center, about 5 minutes. Stir in the onion, and cook for about 3 minutes more. Pour in the balsamic vinegar, bring it to a simmer, and allow it to reduce for a few minutes.
INSERT INTO public.recipes VALUES (889, 'Apricot Cheesecake', '40 mins', '1 hrs 8 mins', '8 hrs 48 mins', '12', '12 servings', '1 ⅓ cups almond flour, 3 tablespoons brown sugar, 2 tablespoons sliced almonds, chopped, 2 tablespoons butter, melted', 'Preheat oven to 350 degrees F (175 degrees C). Line a 9-inch springform pan with parchment paper.
INSERT INTO public.recipes VALUES (891, 'Great-Grandmother Bubbie''s Hamantaschen', '20 mins', '30 mins', '2 hrs 50 mins', '36', '3 dozen', '2 cups pitted prunes, cooked, drained and mashed, 2 cups dried apricots, cooked drained and mashed, 3  eggs, 1 cup white sugar, ½ cup safflower oil, 1  lemon, zested, 1  orange, zested, 4 cups unbleached all-purpose flour, 2 teaspoons baking powder, 1 tablespoon lemon juice, ½ cup chopped walnuts, ⅓ cup white sugar, or to taste', 'Place prunes and apricots into a large pot filled with water and bring to a rolling boil over high heat. Cook the fruit uncovered, stirring occasionally, until the fruit is tender, about 15 minutes. Drain fruit in a colander and mash together in a bowl using a fork. Set aside.
INSERT INTO public.recipes VALUES (892, 'Apricot and Cranberry Stuffed Roast Pork Loin With Port Wine Pan Sauce', NULL, NULL, NULL, '16', '16 servings', '3 tablespoons olive oil, 16  whole peeled garlic cloves, 2 tablespoons minced garlic cloves , 1 (8 pound) whole boneless pork loin, patted dry, at room temperature,   Salt and freshly ground pepper, 3 tablespoons minced fresh rosemary (snip with scissors), divided, 16  dried apricots (or similar amount of your favorite dried fruit), ⅓ cup dried cranberries', 'Adjust oven rack to upper-middle position and heat oven to 250 degrees. Heat oil in a small skillet over medium-low heat. Add whole garlic cloves and cook, stirring occasionally, until soft and golden, about 5 minutes. Remove with a slotted spoon; reserve oil.
INSERT INTO public.recipes VALUES (893, 'Apricot Salsa', '40 mins', NULL, '2 hrs 40 mins', '15', '5 cups', '3 cups chopped fresh apricot, 1 cup shallots, julienned , ½ cup chopped green bell pepper, ½ cup chopped red bell pepper, ½ cup chopped fresh pineapple, ¼ cup chopped cherry tomatoes, 1  habanero pepper, seeded and minced, 2 cloves garlic, minced, 1 teaspoon minced fresh cilantro, ½ teaspoon cumin, ¼ cup fresh lime juice', 'Mix the apricots, shallots, green bell pepper, red bell pepper, pineapple, cherry tomatoes, habanero pepper, garlic, cilantro, cumin, and lime juice together in a bowl; refrigerate at least 2 hours before serving.', '4.8', 'https://www.allrecipes.com/recipe/215113/apricot-salsa/', '/Appetizers and Snacks/Dips and Spreads Recipes/Salsa Recipes/', 'Total Fat 0g 0%, Sodium 3mg 0%, Total Carbohydrate 7g 3%, Dietary Fiber 1g 4%, Total Sugars 4g, Protein 1g, Vitamin C 19mg 95%, Calcium 12mg 1%, Iron 0mg 2%, Potassium 156mg 3%', 'Prep Time: 40 mins, Additional Time: 2 hrs, Total Time: 2 hrs 40 mins, Servings: 15, Yield: 5 cups', 'https://www.allrecipes.com/thmb/KsGNodede5KG8Lq9dRbH42fa8qw=/1500x0/filters:no_upscale():max_bytes(150000):strip_icc()/7823062-fda405f2a49a45de8a0bc54b04749dd6.jpg');
INSERT INTO public.recipes VALUES (894, 'Streamline Hungarian Torte', '20 mins', '1 hrs 10 mins', '1 hrs 30 mins', '32', '1 -11x17 inch torte', '2 cups chopped walnuts, 1 teaspoon ground cinnamon, ¾ cup white sugar, ¼ cup warm water (110 degrees F/45 degrees C), 1 (.25 ounce) envelope active dry yeast, 1 teaspoon white sugar, 4  egg yolks, ½ cup sour cream, 1 ⅓ cups butter or margarine, softened, 4 ½ cups all-purpose flour, 1 (16 ounce) jar apricot preserves, 4  egg whites, ⅔ cup white sugar', 'Preheat oven to 350 degrees F (175 degrees C). Grease an 11x17 inch jelly roll pan. Mix together the walnuts, ground cinnamon, and 3/4 cup of sugar in a medium bowl and set aside.
INSERT INTO public.recipes VALUES (895, 'Capirotada (Mexican Dessert)', '15 mins', '1 hrs', '1 hrs 15 mins', '16', '1 9x13-inch pudding', '3 cups water, 16 ounces piloncillo (Mexican brown sugar cone), chopped, 3  cinnamon sticks, 2 tablespoons raw sugar, 2 tablespoons vanilla extract, ¼ teaspoon ground cloves, ¼ cup butter, 1 (18 ounce) loaf French bread, sliced, 1 ½ cups shredded Monterey Jack cheese, 1 ½ cups chopped walnuts, ½ cup raisins, ½ cup chopped dried apricots', 'Preheat the oven to 350 degrees F (175 degrees C).
INSERT INTO public.recipes VALUES (896, 'Apricot Glazed Chicken', NULL, NULL, NULL, '5', '4 to 6 servings', '6  skinless, boneless chicken breasts, 1 (10.75 ounce) can  low-sodium chicken broth, ¾ cup apricot preserves, 1 tablespoon light soy sauce, 1 tablespoon cornstarch, 1 tablespoon water', 'Spray a large skillet with nonstick cooking spray. Brown chicken in heated skillet.
INSERT INTO public.recipes VALUES (897, 'Cranberry Sauce with Apricots, Raisins, and Orange', '10 mins', '15 mins', '8 hrs 25 mins', '24', '24 servings', '1 cup orange juice, 1 cup water, 4 cups fresh cranberries, ¾ cup sugar, 1 cup chopped dried apricots, 1 cup golden raisins, 1 tablespoon grated orange zest', 'In a large saucepan over medium heat, mix the orange juice, water, cranberries, sugar, apricots, raisins, and orange zest. Stir constantly until sugar has dissolved, about 5 minutes. Bring to a boil, and cook 10 minutes, or until cranberries have burst. Remove from heat, and chill at least 8 hours, or overnight, before serving cold.', '4.9', 'https://www.allrecipes.com/recipe/60280/cranberry-sauce-with-apricots-raisins-and-orange/', '/Side Dish/Sauces and Condiments/Sauces/Cranberry Sauce Recipes/', 'Total Fat 0g 0%, Sodium 2mg 0%, Total Carbohydrate 19g 7%, Dietary Fiber 2g 6%, Total Sugars 15g, Protein 1g, Vitamin C 8mg 41%, Calcium 10mg 1%, Iron 0mg 2%, Potassium 151mg 3%', 'Prep Time: 10 mins, Cook Time: 15 mins, Additional Time: 8 hrs, Total Time: 8 hrs 25 mins, Servings: 24, Yield: 24 servings', 'https://www.allrecipes.com/thmb/_iuMkQkiEoBWbjPuqhQj0bX8m_8=/1500x0/filters:no_upscale():max_bytes(150000):strip_icc()/301591-5b1612bbb2364cdc98d34e3d8ef7731b.jpg');
INSERT INTO public.recipes VALUES (898, 'Apricot Glazed Carrots', '15 mins', '10 mins', '25 mins', '8', '8 servings', '2 pounds carrots, peeled and diagonally sliced, 3 tablespoons butter, melted, ⅓ cup apricot preserves, ¼ teaspoon ground nutmeg, ¼ teaspoon salt, 1 teaspoon orange zest, 2 teaspoons fresh lemon juice,   chopped fresh parsley for garnish', 'Add carrots to a pot of lightly salted water, and bring to a low boil. Simmer until carrots are tender. Drain.
INSERT INTO public.recipes VALUES (899, 'Fruit-Stuffed Pork Loin', '20 mins', '1 hrs 40 mins', '2 hrs', '8', '1 stuffed pork loin roast', '¾ cup chopped pitted prunes, ¾ cup chopped dried apricots, 1 tablespoon grated fresh ginger , 1 teaspoon grated orange zest, ½ teaspoon ground cumin, ½ teaspoon ground cinnamon,   salt and ground black pepper to taste, 1 (4 pound) boneless pork loin roast, butterflied , ¼ cup packed brown sugar, 2 teaspoons all-purpose flour, 2 teaspoons cider vinegar, 1 teaspoon ground cumin, 1 teaspoon mustard powder, ½ cup water, 1 teaspoon cornstarch, 1 tablespoon water', 'Preheat oven to 325 degrees F (165 degrees C).
INSERT INTO public.recipes VALUES (900, 'Apricot-Pecan Sweet Potatoes', '20 mins', '45 mins', '1 hrs 5 mins', '8', '1 9x13-inch casserole', '3 pounds sweet potatoes, peeled and cut into chunks, 1 cup packed brown sugar, 5 teaspoons cornstarch, ¼ teaspoon salt, ⅛ teaspoon ground cinnamon, 1 cup apricot nectar, ½ cup hot water, 2 teaspoons grated orange peel, 2 tablespoons butter, ½ cup chopped pecans', 'Place the sweet potatoes into a large pot and cover with water. Bring to a boil over high heat, then reduce heat to medium-low, cover, and simmer until tender, about 20 minutes. Drain and allow to steam dry for a minute or two.
INSERT INTO public.recipes VALUES (901, 'Ma Lipo''s Apricot-Glazed Turkey with Roasted Onion and Shallot Gravy', '30 mins', '4 hrs 30 mins', '5 hrs 30 mins', '30', '30 servings', '1 cup apricot nectar, 1 cup apricot preserves, 2 tablespoons minced fresh ginger root, 1 tablespoon honey, ¾ cup unsalted butter, softened, 3 tablespoons chopped fresh sage, 1 ½ teaspoons salt, 1 teaspoon ground black pepper, 2 tablespoons unsalted butter, 3  onions, thinly sliced, 6 ounces thinly sliced shallots, 22 pounds whole turkey, 2 cups low-sodium chicken broth, 1 teaspoon chopped fresh thyme, ½ teaspoon dried sage, 2 cups low-sodium chicken broth,   salt and pepper to taste', 'Combine apricot nectar, preserves, ginger, and honey in a small saucepan and bring to boil. Reduce heat to medium-low, and simmer until thickened and reduced to 1-1/4 cups, about 15 minutes.
INSERT INTO public.recipes VALUES (902, 'Apricot Glazed Ham', '10 mins', '1 hrs 55 mins', '2 hrs 5 mins', '14', '1 to 8 - pound ham', '1 (8 pound) fully-cooked, bone-in ham, ¼ cup whole cloves (Optional), ½ cup apricot preserves, 3 tablespoons honey mustard', 'Preheat the oven to 350 degrees F (175 degrees C).
INSERT INTO public.recipes VALUES (903, 'Apricot Brandy and Peach Schnapps Pound Cake', '40 mins', '1 hrs 15 mins', '1 hrs 55 mins', '12', '12 servings', '3 cups white sugar, 1 cup butter, softened, 6  eggs, beaten, 3 cups all-purpose flour, ¼ teaspoon baking soda, ½ teaspoon salt, 1 cup sour cream, ¼ cup apricot brandy, 1 teaspoon lemon zest, 1 cup white sugar, ½ cup peach schnapps, 1 cup water, 1 teaspoon lemon zest, 1 cup apricot preserves, ½ cup apricot brandy, 1 teaspoon lemon zest, ½ cup almonds', 'Butter and flour one angle food tube cake pan. Preheat oven to 325 degrees F (175 degrees C).
INSERT INTO public.recipes VALUES (905, 'Southern Apricot Chicken', NULL, NULL, NULL, '12', '12 servings', '12  boneless, skinless chicken breast halves, 1 cup apricot preserves, 1 cup sour cream, 2 tablespoons Dijon mustard,   salt and pepper to taste', 'Preheat the oven to 350 degrees F (175 degrees C). Arrange the chicken pieces in a single layer in the bottom of a 9x13 inch baking dish.
INSERT INTO public.recipes VALUES (906, 'Spicy Air Fryer Pork Chops with Apricot Glaze', '15 mins', '15 mins', '3 hrs', '4', '4 servings', '4 cups water, 2 tablespoons kosher salt, 2 tablespoons white sugar, 4 (5 ounce) bone-in center loin pork chops, about 3/4-inch thick, 1 teaspoon chili powder, or to taste, 1 teaspoon onion powder, ½ teaspoon salt, ¼ teaspoon white pepper', 'Combine water, salt, and sugar in a bowl and stir until the crystals are dissolved. Add pork chops, cover, and refrigerate for at least 2 hours, or up to 4 hours.
INSERT INTO public.recipes VALUES (907, 'Boozy Apricot Jam', '30 mins', '5 mins', '8 hrs 35 mins', '144', '9 half-pint jars', '3 ½ pounds firm-ripe apricots, halved and pitted, 1 (1.75 ounce) package fruit pectin (such as Sure-Jell Premium Fruit Pectin®), 7 cups white sugar, ⅓ cup apricot brandy', 'Inspect 9 half-pint jars for cracks and rings for rust, discarding any defective ones. Immerse in simmering water until jam is ready. Wash new, unused lids and rings in warm soapy water.
INSERT INTO public.recipes VALUES (908, 'Espresso Biscotti', '25 mins', '1 hrs', '1 hrs 25 mins', '24', '24 biscotti', '¼ cup unsalted butter, ¾ cup white sugar, 3  eggs, 1 teaspoon vanilla extract, 3 ¼ cups pastry flour, 1 teaspoon ground cinnamon, 1 teaspoon baking powder, 1 teaspoon instant espresso powder, 2 teaspoons grated orange zest, ½ cup chocolate chips, ½ cup dried apricots, ½ cup dried cranberries, ½ cup slivered almonds, 1  egg white, lightly beaten', 'Preheat oven to 350 degrees F (175 degrees C). Grease a cookie sheet or line it with parchment paper.
INSERT INTO public.recipes VALUES (909, 'Apricot Balls', '15 mins', NULL, '15 mins', '12', '12 servings', '½ pound dried apricots, ½ cup brown sugar, ½ cup flaked coconut, ½ (14 ounce) can sweetened condensed milk, 1 cup flaked coconut for rolling', 'Mince apricots in a food processor. Place in a bowl and toss with brown sugar. Stir in 1/2 cup coconut and condensed milk. Shape into 1 inch balls and roll in coconut. Keep refrigerated.', '3.9', 'https://www.allrecipes.com/recipe/25647/apricot-balls/', '/Desserts/Cookies/No-Bake Cookie Recipes/', 'Total Fat 9g 12%, Saturated Fat 8g 38%, Cholesterol 6mg 2%, Sodium 30mg 1%, Total Carbohydrate 33g 12%, Dietary Fiber 3g 12%, Total Sugars 29g, Protein 3g, Vitamin C 1mg 4%, Calcium 67mg 5%, Iron 1mg 6%, Potassium 356mg 8%', 'Prep Time: 15 mins, Total Time: 15 mins, Servings: 12, Yield: 12 servings', 'https://www.allrecipes.com/thmb/KYt9s0KDbqcWGrECqhsl8gTCKzI=/1500x0/filters:no_upscale():max_bytes(150000):strip_icc()/4602520-1949ffddbba54bb68d97176986d66288.jpg');
INSERT INTO public.recipes VALUES (910, 'Nectarine Jam', '20 mins', '20 mins', '1 day 40 mins', '40', NULL, '4 pounds nectarines - peeled, pitted, and chopped, 2 tablespoons lemon juice, 3 cups sugar, 1 (1.75 ounce) package fruit pectin (such as Sure-Jell® Pectin Light for less or no sugar), 3 drops almond extract, or to taste', 'Inspect five (1/2-pint) jars for cracks and rings for rust; discard any defective ones. Immerse the jars and rings in simmering water until jam is ready. Wash new, unused lids and rings in warm soapy water.
INSERT INTO public.recipes VALUES (911, 'Nectarine Pie', NULL, NULL, NULL, '8', '1 to 9 - inch pie', '⅔ cup white sugar, 4 tablespoons all-purpose flour, ½ teaspoon ground cinnamon, 1 cup heavy whipping cream, ¼ teaspoon almond extract, 5  nectarines, 1 (9 inch) unbaked pie shell', 'Preheat oven to 400 degrees F (205 degrees C). Place a large pot of water over high heat, and bring to a boil.
INSERT INTO public.recipes VALUES (912, 'Summer Fruit Salad with a Lemon, Honey, and Mint Dressing', '20 mins', NULL, '1 hrs 20 mins', '8', '8 servings', '4 cups cubed seeded watermelon, 2 cups sliced fresh strawberries, 2 large  fresh peaches, cut into cubes, 2 large  nectarines, cut into cubes, 1  red Anjou pear, cut into cubes, 1 cup seedless grapes, halved, 2  lemons, juiced, ¼ cup minced fresh mint (chocolate mint preferred), ½  lemon, zested, 1 tablespoon honey (fireweed honey preferred)', 'Combine watermelon, strawberries, peaches, nectarines, pear, and grapes in a large mixing bowl.
INSERT INTO public.recipes VALUES (913, 'Chef John''s Nectarine Salsa', '20 mins', NULL, '50 mins', '6', '2 cups', '1 cup finely diced nectarine, ½ cup finely diced red bell pepper, ⅓ cup finely diced onions, 2 tablespoons finely diced jalapeno pepper, 1 tablespoon chopped fresh cilantro, 1 tablespoon fresh lime juice, 2 teaspoons olive oil, ½ teaspoon salt, plus more to taste , 1 pinch cayenne pepper, 1 pinch freshly ground black pepper', 'Combine nectarines, bell pepper, onions, jalapeno pepper, and cilantro in a bowl. Stir in lime juice, olive oil, salt, and cayenne pepper.
INSERT INTO public.recipes VALUES (914, 'Easy Grilled Nectarines', '5 mins', '5 mins', '10 mins', '4', '4 servings', '4  fresh nectarines, pitted and halved, 2 tablespoons melted unsalted butter, 4 tablespoons brown sugar', 'Brush each nectarine half with 1/4 tablespoon melted butter and sprinkle with 1/2 tablespoon brown sugar.
INSERT INTO public.recipes VALUES (915, 'Fabulous Fruit Salad', '20 mins', NULL, '20 mins', '4', '4 servings', '1  red apple, cored and chopped, 1  Granny Smith apple, cored and chopped, 1  nectarine, pitted and sliced, 2 stalks celery, chopped, ½ cup dried cranberries, ½ cup chopped walnuts, 1 (8 ounce) container nonfat lemon yogurt', 'In a large bowl, combine red apple, Granny Smith apple, nectarine, celery, dried cranberries, and walnuts. Mix in yogurt. Chill until ready to serve.', '4.6', 'https://www.allrecipes.com/recipe/14187/fabulous-fruit-salad/', '/Salad/Fruit Salad Recipes/Cranberry Salad Recipes/', 'Total Fat 10g 13%, Saturated Fat 1g 5%, Cholesterol 1mg 0%, Sodium 55mg 2%, Total Carbohydrate 37g 14%, Dietary Fiber 4g 15%, Total Sugars 30g, Protein 6g, Vitamin C 6mg 32%, Calcium 128mg 10%, Iron 1mg 4%, Potassium 387mg 8%', 'Prep Time: 20 mins, Total Time: 20 mins, Servings: 4, Yield: 4 servings', 'https://www.allrecipes.com/thmb/z9VQO3AkEahWW1O2UwmJu7s02c0=/1500x0/filters:no_upscale():max_bytes(150000):strip_icc()/614043-3e08febe0e784968ad84516105ea8de2.jpg');
INSERT INTO public.recipes VALUES (916, 'Summer Fruit Salad with Whipped Cream', '30 mins', '10 mins', '40 mins', '8', '8 servings', '⅓ cup water, 5 tablespoons white sugar, ¼ cup raspberry-flavored liqueur (such as Chambord®), 2 tablespoons fresh lemon juice', 'Stir water, 5 tablespoons sugar, 1/4 cup raspberry-flavored liqueur, and lemon juice together in a saucepan over medium-low heat. Bring the mixture to a boil, reduce heat to low, and simmer, stirring frequently, until the sugar dissolves completely, about 8 minutes. Set aside to cool.
INSERT INTO public.recipes VALUES (917, 'Spinach, Nectarine, and Halloumi Salad', '20 mins', '5 mins', '25 mins', '4', '4 servings', '3 tablespoons white wine vinegar, 3 tablespoons extra-virgin olive oil, 3 teaspoons honey, 1 teaspoon Dijon mustard, ¼ teaspoon salt, ¼ teaspoon ground black pepper, ¼ teaspoon dried basil, 4 cups baby spinach, 1  nectarine, pitted and sliced, ¼ cup sliced almonds, toasted, 2 tablespoons thinly sliced red onion, 2 tablespoons thinly sliced red bell pepper, 1 (8.8 ounce) package halloumi cheese, sliced into 1/2-inch strips', 'Whisk vinegar, olive oil, honey, mustard, salt, pepper, and basil together in a medium bowl. Set vinaigrette aside.
INSERT INTO public.recipes VALUES (948, 'Oatmeal Chocolate Coconut Macaroons', '15 mins', '5 mins', '20 mins', '15', '15 macaroons', '2 cups quick-cooking oats, 1 cup shredded coconut, ¼ cup unsweetened cocoa powder, 2 cups white sugar, ½ cup butter, ½ cup milk', 'Mix together oats, coconut, and cocoa powder in a large bowl.
INSERT INTO public.recipes VALUES (918, 'Grilled Pork Chops with Fresh Nectarine Salsa', '25 mins', '8 mins', '33 mins', '4', '4 servings', '2  nectarines, pitted and diced, 1  ripe tomato, seeded and diced, ¼ cup diced onion, 2 tablespoons chopped fresh cilantro, 2 tablespoons fresh lime juice, ¼ teaspoon crushed red pepper flakes, or to taste,   salt to taste, 1 teaspoon ground cumin, 1 teaspoon chili powder,   salt and ground black pepper to taste, 2 tablespoons olive oil, 8 (4 ounce) boneless pork loin chops', 'Preheat an outdoor grill for medium-high heat. Lightly oil grate, and set 4 inches from the heat.
INSERT INTO public.recipes VALUES (919, 'Flavored Water', '15 mins', NULL, '2 hrs 15 mins', '8', '2 liters', '½ small cucumber, sliced thin, ½  nectarine, pitted and chopped, ½  lemon, sliced, ½  lemon, juiced, ½  lime, sliced, ½  lime, juiced, 4 slices ginger root, peeled, or more to taste, 10  melissa leaves (lemon balm), or more to taste, 2 quarts water, 1 drop liquid stevia, or to taste', 'Place cucumber, nectarine, lemon slices, lemon juice, lime slices, lime juice, ginger, and melissa leaves in a large pitcher; mash gently with a wooden spoon. Pour in water, stir, and refrigerate until flavors blend, 2 hours to overnight. Strain; serve over ice.', '5.0', 'https://www.allrecipes.com/recipe/246155/flavored-water/', '/Drinks Recipes/', 'Total Fat 0g 0%, Sodium 8mg 0%, Total Carbohydrate 2g 1%, Dietary Fiber 1g 2%, Total Sugars 1g, Protein 0g, Vitamin C 8mg 39%, Calcium 16mg 1%, Iron 0mg 1%, Potassium 53mg 1%', 'Prep Time: 15 mins, Additional Time: 2 hrs, Total Time: 2 hrs 15 mins, Servings: 8, Yield: 2 liters', 'https://www.allrecipes.com/thmb/5i4We_W0OE_ae8gL8kbAPaT4rGc=/1500x0/filters:no_upscale():max_bytes(150000):strip_icc()/3407928-1c5cdfbc03ea4dfcb5a503d1f0339131.jpg');
INSERT INTO public.recipes VALUES (920, 'Peach and Nectarine Crumble', '20 mins', '30 mins', '1 hrs 5 mins', '10', '1 9-inch baking pan', '3 cups soft peaches, or as needed, 3 cups soft nectarines, or as needed, ½ cup white sugar (Optional), 3 tablespoons cornstarch, 1 teaspoon vanilla extract (Optional)', 'Preheat oven to 375 degrees F (190 degrees C). Grease a 9-inch baking pan.
INSERT INTO public.recipes VALUES (921, 'Caramelized Nectarine', '5 mins', '2 mins', '7 mins', '2', '2 servings', '1  nectarine, 2 tablespoons white sugar, 2 tablespoons plain yogurt', 'Cut nectarine all the way around and twist open. Remove pit. Sprinkle sugar on the cut side of each nectarine half.
INSERT INTO public.recipes VALUES (922, 'Vegan Overnight Oats with Chia Seeds and Fruit', '5 mins', '5 mins', '8 hrs 10 mins', '2', '2 servings', '1 ⅓ cups almond milk, 2  ripe bananas, mashed, 1 ¼ cups rolled oats, ¾ cup water, 4 tablespoons chia seeds, ½ teaspoon ground cinnamon, ¼ cup fresh blueberries, ¼ cup fresh blackberries, 1  nectarine, peeled and diced', 'Combine almond milk, bananas, oats, water, chia seeds, and cinnamon in a jar or airtight container; stir together. Cover and refrigerate, 8 hours to overnight.
INSERT INTO public.recipes VALUES (976, 'Coconut Pie', NULL, NULL, NULL, '8', '1 -9-inch pie', '1 cup white sugar, 2 tablespoons all-purpose flour, ½ cup butter, 3  eggs, 1 teaspoon vanilla extract, 1 cup milk, 1 cup flaked coconut, 1 recipe pastry for a 9 inch single crust pie', 'Mix flour with sugar. Cream in butter and eggs. Mix in vanilla and milk until well combined. Fold in coconut. Pour into prepared pie crust.
INSERT INTO public.recipes VALUES (923, 'Nectarine Upside-Down Cake', '20 mins', '35 mins', '1 hrs 15 mins', '10', '1 9-inch cake', '3 tablespoons butter, at room temperature, ¼ cup brown sugar (such as muscovado), 4  fresh nectarines, sliced into bite-size pieces', 'Preheat oven to 340 degrees F (170 degrees C). Place butter in a 9-inch round cake pan and melt in the oven as it preheats.
INSERT INTO public.recipes VALUES (924, 'Nectarine Salsa', '10 mins', '10 mins', '25 mins', '2', '2 servings', '2  nectarines, pitted and chopped, ¼ medium red onion, finely chopped, ¼ cup balsamic vinegar, 1 teaspoon white sugar, ½ teaspoon dried cilantro, ½ teaspoon kosher salt,   freshly ground black pepper to taste', 'In a bowl, mix the nectarines, onion, vinegar, sugar, cilantro, salt, and pepper. Allow to sit 5 minutes.
INSERT INTO public.recipes VALUES (925, 'Caribbean Chicken', '15 mins', '30 mins', '45 mins', '4', '4 servings', '1 teaspoon paprika, 1 teaspoon onion powder, 1 teaspoon garlic powder, 1 teaspoon dried parsley, ½ teaspoon dried oregano, 1 teaspoon salt, 1 teaspoon pepper, 4  boneless, skinless chicken breast halves, ¼ cup duck sauce, ¼ cup marinara sauce, 1 teaspoon mango hot sauce, ¾ cup fresh pink grapefruit juice, divided, 1 cup Italian seasoned bread crumbs, 1  ripe nectarine, pitted and sliced', 'Preheat oven to 375 degrees F (190 degrees C). Line a baking dish with parchment paper.
INSERT INTO public.recipes VALUES (926, 'Grilled Honey-Nectarine Ricotta Toast', '10 mins', '10 mins', '25 mins', '2', '2 servings', '1 teaspoon olive oil, 1 large nectarine, pitted and cut into 8 wedges, 2 thick slices crusty bread, 2 tablespoons olive oil, ¼ cup whole-milk ricotta cheese, 1 tablespoon crushed sliced almonds, 2 leaves fresh mint, minced, 2 teaspoons honey, or to taste', 'Preheat an outdoor grill for medium-high heat and lightly oil grate.
INSERT INTO public.recipes VALUES (947, 'Tembleque Puerto Rican Coconut Pudding', '10 mins', '5 mins', '3 hrs 15 mins', '6', '6 4-ounce servings', '2 (14 ounce) cans coconut milk, ¾ cup sugar, ¼ teaspoon kosher salt, ½ cup cornstarch, 1 pinch ground cinnamon', 'Stir together coconut milk, sugar, and salt in a saucepan. Spoon 3 to 4 tablespoons coconut milk mixture into a small bowl and stir in cornstarch until dissolved; pour into the saucepan. Bring mixture to a boil while stirring constantly; cook until smooth and thick, about 5 minutes.
INSERT INTO public.recipes VALUES (927, 'Apple and Nectarine Pie', '30 mins', '1 hrs', '2 hrs 30 mins', '8', '1 9-inch pie', '  cooking spray, 4  apples - peeled, cored and sliced, peel reserved, ½ cup white sugar, ½ cup light brown sugar, ½ cup water, ¼ cup brandy, 1 teaspoon ground cinnamon, 1 teaspoon vanilla extract, 1  pastry for 9-inch double-crust pie, ½ (8.5 ounce) package corn muffin mix (such as Jiffy®), ¼ cup milk, 4  nectarines, peeled and sliced', 'Preheat oven to 425 degrees F (220 degrees C). Grease a 9-inch deep-dish pie plate.
INSERT INTO public.recipes VALUES (928, 'Nectarine Blush', '2 mins', '2 mins', '4 mins', '2', '2 cups', '2  nectarines, pitted and chopped, 2 tablespoons brown sugar, 1 cup buttermilk', 'Place the nectarines, brown sugar and buttermilk in the bowl of a blender and blend until smooth. Serve immediately.', '4.3', 'https://www.allrecipes.com/recipe/142435/nectarine-blush/', '/Drinks Recipes/Smoothie Recipes/', 'Total Fat 2g 2%, Saturated Fat 1g 4%, Cholesterol 5mg 2%, Sodium 132mg 6%, Total Carbohydrate 34g 12%, Dietary Fiber 2g 8%, Total Sugars 30g, Protein 6g, Vitamin C 9mg 43%, Calcium 162mg 12%, Iron 1mg 3%, Potassium 476mg 10%', 'Prep Time: 2 mins, Cook Time: 2 mins, Total Time: 4 mins, Servings: 2, Yield: 2 cups', 'https://www.allrecipes.com/thmb/7Kv75JZPS7D7YtLmy1OEylZv7Yk=/1500x0/filters:no_upscale():max_bytes(150000):strip_icc()/918074-2a1ea06dfec043d5b3a39707e4d0d482.jpg');
INSERT INTO public.recipes VALUES (929, 'Summer Nectarine, Tomato, and Cucumber Salad', '20 mins', NULL, '20 mins', '4', '2 cups', '2  tomatoes, cut into chunks, ½  cucumber - peeled, seeded, and diced, 1 large ripe nectarine, diced, 3 tablespoons chopped fresh cilantro, 1 tablespoon olive oil, 3 tablespoons crumbled goat cheese', 'Mix tomatoes, cucumber, nectarine, and cilantro together in a bowl. Stir in olive oil gently. Sprinkle goat cheese over salad.', '4.0', 'https://www.allrecipes.com/recipe/258418/summer-nectarine-tomato-and-cucumber-salad/', '/Salad/Vegetable Salad Recipes/', 'Total Fat 5g 7%, Saturated Fat 2g 8%, Cholesterol 4mg 1%, Sodium 32mg 1%, Total Carbohydrate 8g 3%, Dietary Fiber 2g 6%, Total Sugars 6g, Protein 2g, Vitamin C 12mg 62%, Calcium 27mg 2%, Iron 1mg 3%, Potassium 286mg 6%', 'Prep Time: 20 mins, Total Time: 20 mins, Servings: 4, Yield: 2 cups', 'https://www.allrecipes.com/thmb/BC_HXJfqgPv3rZ1-TFqsWHTG51k=/1500x0/filters:no_upscale():max_bytes(150000):strip_icc()/9307952-dcb6a696b6044ef99a76794b127a55b2.jpg');
INSERT INTO public.recipes VALUES (930, 'Sticky Orange Chicken with Nectarines', '20 mins', '10 mins', '30 mins', '4', '4 chicken breast halves', '½ cup orange juice, ¼ cup light soy sauce, 2 tablespoons buckwheat honey, 2 tablespoons hot sauce, 2 tablespoons brown sugar, 2 teaspoons chopped fresh ginger, 2 teaspoons chopped fresh garlic, 3 tablespoons all-purpose flour,   salt and ground black pepper to taste, 1 pinch Italian seasoning, 4  skinless, boneless chicken breast halves, 1 tablespoon extra-virgin olive oil, or as needed, 2  nectarines, sliced', 'Mix orange juice, soy sauce, honey, hot sauce, brown sugar, ginger, and garlic together in a small bowl to make the sauce.
INSERT INTO public.recipes VALUES (931, 'Nectarine-Raspberry Crumble', '20 mins', '50 mins', '1 hrs 10 mins', '6', '6 servings', '3 ½ pounds nectarines, 1 (6 ounce) container fresh raspberries, 2 tablespoons white sugar, ¾ cup brown sugar, 7 tablespoons unsalted butter, room temperature and cut into chunks, ¾ cup all-purpose flour, ½ cup rolled oats, 1 teaspoon ground cinnamon, ½ teaspoon ground nutmeg, ¼ teaspoon salt', 'Preheat the oven to 375 degrees F (190 degrees C).
INSERT INTO public.recipes VALUES (932, 'Nectarine Bars', '20 mins', '55 mins', '1 hrs 45 mins', '12', '1 9x13-inch baking pan', '2 cups all-purpose flour, 1 ½ cups white sugar, divided, ½ cup butter, 3  nectarines, sliced, divided, 1 tablespoon cornstarch, 2  eggs', 'Preheat oven to 350 degrees F (175 degrees C).
INSERT INTO public.recipes VALUES (933, 'Summer Salad with Burrata, Tomatoes, and Nectarines', '15 mins', NULL, '15 mins', '4', '4 servings', '3  nectarines, pitted and chopped, 2 large heirloom tomatoes, chopped, 2 (4 ounce) balls Burrata cheese, cut into 3/4-inch pieces, 2 tablespoons fresh basil, chopped, or to taste', 'Combine nectarines, tomatoes, burrata cheese, and basil in a bowl.
INSERT INTO public.recipes VALUES (934, 'Drupey Pie', '1 hrs', '50 mins', '1 hrs 50 mins', '8', '1 to 9 - inch pie', '2 cups all-purpose flour, 1 teaspoon salt, .79100000858307 cup butter, 7 tablespoons ice water, 2 cups pitted sour cherries, 3  nectarines, pitted and chopped, 3  fresh apricots, pitted and sliced, ⅝ cup turbinado sugar, 1 pinch ground cinnamon, 1 tablespoon cornstarch, 2 tablespoons all-purpose flour, 2 tablespoons butter, cut into pieces, 1 teaspoon water, 1  egg yolk', 'Preheat oven to 425 degrees F (220 degrees C). Place cherries, nectarines and apricots into a colander to drain off any excess liquid.
INSERT INTO public.recipes VALUES (935, 'Fresh Fruit Basket Cobbler', '20 mins', '20 mins', '1 hrs', '8', '1 8x13-inch dish', '2 cups sliced fresh peaches, 2 cups sliced fresh nectarines, 2 cups pitted and quartered plums, 1 teaspoon cornstarch, 1 cup currant jelly, ½ teaspoon apple pie spice, ⅛ teaspoon white pepper, 1 (16.3 ounce) can refrigerated flaky biscuits (such as Pillsbury Grands!®), ¼ cup white sugar, ¼ teaspoon ground cinnamon', 'Preheat oven to 350 degrees F (175 degrees C). Spray an 8x13-inch baking dish with cooking spray.
INSERT INTO public.recipes VALUES (936, 'Summer Fruit Salad II', '25 mins', NULL, '1 hrs 25 mins', '12', '6 cups', '3 cups cubed (1-inch) seedless watermelon, 1 large white peach, pitted and cut into small cubes, 1 large nectarine, pitted and cut into small cubes, 1  black plum, pitted and cut into small cubes, 1 cup fresh blueberries, ½ cup seedless red grapes, halved, ½ cup shredded coconut, 1 teaspoon ground cinnamon, ½ cup nondairy whipped topping (Optional)', 'Gently toss the watermelon, peach, nectarine, plum, blueberries, and grapes together in a large bowl. Sprinkle the coconut and cinnamon over the fruit mixture and lightly stir to mix. Cover the bowl with plastic wrap and chill in refrigerator at least 1 hour before serving. Top with whipped topping as desired.', '4.7', 'https://www.allrecipes.com/recipe/215586/summer-fruit-salad-ii/', '/Salad/Fruit Salad Recipes/Blueberry Salad Recipes/', 'Total Fat 2g 2%, Saturated Fat 2g 8%, Sodium 11mg 0%, Total Carbohydrate 12g 4%, Dietary Fiber 1g 5%, Total Sugars 9g, Protein 1g, Vitamin C 7mg 36%, Calcium 9mg 1%, Iron 0mg 2%, Potassium 140mg 3%', 'Prep Time: 25 mins, Additional Time: 1 hrs, Total Time: 1 hrs 25 mins, Servings: 12, Yield: 6 cups', 'https://www.allrecipes.com/thmb/UQvmLYw7EX-lT2TOlI9iiAtPI9s=/1500x0/filters:no_upscale():max_bytes(150000):strip_icc()/855858-e382c9d6dd754b209f2148664e4ba50c.jpg');
INSERT INTO public.recipes VALUES (937, 'KK''s Three Fruit Cobbler', '15 mins', '25 mins', '40 mins', '8', '1 9x13-inch dish', '3  nectarines, pitted and cut into bite-size pieces, 3  tart plums, pitted and cut into bite-size pieces, ½ pint fresh raspberries, 1 cup all-purpose flour, ¾ cup white sugar, ¼ cup packed brown sugar, 1 teaspoon ground ginger, ½ teaspoon ground cinnamon, ⅔ cup cold unsalted butter', 'Preheat oven to 350 degrees F (175 degrees C).
INSERT INTO public.recipes VALUES (938, 'Fresh Nectarine Cake with Blackberries', '20 mins', '45 mins', '1 hrs 10 mins', '8', '1 9-inch cake', '½ cup unsalted butter, at room temperature, 2  eggs, ½ cup white sugar, 1 pinch salt, 1 ½ cups all-purpose flour, 1 ¼ teaspoons baking powder, 1 tablespoon milk, or more as needed (Optional), 3  fresh nectarines - peeled, halved, and pitted, or more to taste, 1 (6 ounce) container fresh blackberries, or more to taste, 1 tablespoon confectioners'' sugar', 'Preheat the oven to 350 degrees F (175 degrees C). Grease a 9-inch springform pan.
INSERT INTO public.recipes VALUES (939, 'Seven Layer Bars', '15 mins', '25 mins', '1 hrs', '36', '3 dozen bar cookies', '½ cup unsalted butter, 1 ½ cups graham cracker crumbs, 1 cup semisweet chocolate chips, 1 cup butterscotch chips, 1 cup chopped walnuts, 1 (14 ounce) can sweetened condensed milk, 1 ⅓ cups shredded coconut', 'Preheat the oven to 350 degrees F (175 degrees C).
INSERT INTO public.recipes VALUES (940, 'Nanaimo Bars', '30 mins', NULL, '30 mins', '16', '1 8x8-inch pan', '1 cup butter, softened, divided, 5 tablespoons unsweetened cocoa powder, ¼ cup white sugar, 1  egg, beaten, 1 ¾ cups graham cracker crumbs, 1 cup flaked coconut, ½ cup finely chopped almonds (Optional), 3 tablespoons heavy cream, 2 tablespoons custard powder, 2 cups confectioners'' sugar, 4 (1 ounce) squares semisweet baking chocolate, 2 teaspoons butter', 'In the top of a double boiler, combine 1/2 cup softened butter, cocoa powder, and sugar. Stir occasionally until melted and smooth. Beat in egg and stir until thick, 2 to 3 minutes.
INSERT INTO public.recipes VALUES (941, 'German Chocolate Cake Frosting', '5 mins', '15 mins', '20 mins', '12', NULL, '1 cup evaporated milk, 1 cup brown sugar, ½ cup butter, 3  egg yolks, 1 teaspoon vanilla extract, 1 ⅓ cups flaked coconut, 1 cup chopped pecans', 'Combine evaporated milk, brown sugar, butter, egg yolks, and vanilla in a saucepan over medium heat. Cook, stirring constantly, at a low boil until mixture turns a light caramel color and thickens, about 10 minutes.
INSERT INTO public.recipes VALUES (942, 'Frog Eye Salad', '15 mins', '20 mins', '9 hrs 35 mins', '10', NULL, '1 ¾ cups unsweetened pineapple juice, 1 cup white sugar, 2  eggs, beaten, 2 tablespoons all-purpose flour, 2 ½ teaspoons salt, divided, 1 tablespoon lemon juice, 1 tablespoon vegetable oil, 1 (16 ounce) package acini di pepe pasta, 3 (11 ounce) cans mandarin oranges, drained, 2 (20 ounce) cans pineapple tidbits, drained, 1 (20 ounce) can crushed pineapple, drained, 1 (8 ounce) container frozen whipped topping, thawed, 1 cup miniature marshmallows, 1 cup shredded coconut', 'Combine pineapple juice, sugar, eggs, flour, and 1/2 teaspoon salt in a saucepan. Stir and cook over medium heat until thickened. Remove from heat; stir in lemon juice. Let cool to room temperature, about 1 hour.
INSERT INTO public.recipes VALUES (943, 'Gingerbread Cookie Frosting', '10 mins', NULL, '10 mins', '4', '1/2 cup', '1 cup confectioners'' sugar, ¼ cup milk, or as needed, 10 drops food coloring', 'Sift confectioners'' sugar into a small bowl. Stir in enough milk to make a smooth but not too runny consistency.
INSERT INTO public.recipes VALUES (944, 'Coconut Poke Cake', '30 mins', '1 hrs', '2 hrs', '24', '1 9x13-inch cake', '1 (18.25 ounce) package white cake mix, 1 (14 ounce) can cream of coconut, 1 (14 ounce) can sweetened condensed milk, 1 (16 ounce) package frozen whipped topping, thawed, 1 (8 ounce) package flaked coconut', 'Prepare and bake white cake mix in a 9x13-inch dish according to package directions. While cake is still hot, poke holes with a utility fork all over the top.
INSERT INTO public.recipes VALUES (945, 'Coconut Shrimp', '15 mins', '10 mins', '55 mins', '6', '24 coconut shrimp', '¾ cup all-purpose flour, divided, ⅔ cup beer, 1 large egg, 1 ½ teaspoons baking powder, 2 cups flaked coconut, 24  medium raw shrimp, shelled, deveined, with tails attached, 3 cups oil for frying', 'Line a baking sheet with wax paper; set aside.
INSERT INTO public.recipes VALUES (946, 'Chia Coconut Pudding with Coconut Milk', '10 mins', NULL, '30 mins', '6', NULL, '2 cups sweetened coconut milk, 6 tablespoons unsweetened coconut milk, 1 tablespoon agave nectar, or more to taste, ½ teaspoon vanilla extract, ¼ teaspoon ground cinnamon, 1 pinch salt, ½ cup chia seeds, ½ cup diced fresh strawberries (Optional)', 'Whisk together sweetened and unsweetened coconut milks, agave nectar, vanilla extract, cinnamon, and salt in a bowl; stir in chia seeds. Allow mixture to soak until thickened, at least 20 minutes, or cover the bowl with plastic wrap and refrigerate overnight.
INSERT INTO public.recipes VALUES (949, 'No-Bake Chocolate Coconut Cookies', '10 mins', '10 mins', '20 mins', '24', '24 cookies', '3 cups quick cooking oats, 1 cup sweetened flaked coconut, 2 cups white sugar, ½ cup unsweetened cocoa powder, ½ cup milk, ½ cup margarine', 'Line a baking sheet with waxed paper.
INSERT INTO public.recipes VALUES (950, 'Irish Potato Candy', '20 mins', NULL, '30 mins', '60', '5 dozen', '4 ounces cream cheese, softened, ¼ cup butter, softened, 4 cups confectioners'' sugar, 1 teaspoon vanilla extract, 2 ½ cups flaked coconut, 1 tablespoon ground cinnamon', 'Beat cream cheese and butter together in a large bowl until smooth. Add confectioners'' sugar and vanilla; beat until smooth. Mix in flaked coconut.
INSERT INTO public.recipes VALUES (951, 'Incredibly Delicious Italian Cream Cake', '30 mins', '30 mins', '1 hrs 25 mins', '12', '1 3-layer', '1 cup buttermilk, 1 teaspoon baking soda, ½ cup butter, ½ cup shortening, 2 cups white sugar, 5 large eggs, 1 teaspoon vanilla extract, 1 cup flaked coconut, 1 teaspoon baking powder, 2 cups all-purpose flour', 'Preheat the oven to 350 degrees F (175 degrees C). Grease three 9-inch round cake pans.
INSERT INTO public.recipes VALUES (952, 'Coconut Custard Pie', '10 mins', '40 mins', '50 mins', '8', '1 9-inch pie', '1 ½ cups white sugar, ½ cup butter, 2 large eggs, 2 tablespoons all-purpose flour, 1 cup milk, 1 cup flaked coconut, 1 teaspoon vanilla extract, 1 (9 inch) unbaked pie crust, 1 tablespoon flaked coconut', 'Preheat the oven to 350 degrees F (175 degrees C).
INSERT INTO public.recipes VALUES (953, 'Air Fryer Coconut Shrimp', '30 mins', '15 mins', '45 mins', '6', NULL, '½ cup all-purpose flour, 1 ½ teaspoons ground black pepper, 2 large eggs, ⅔ cup unsweetened flaked coconut, ⅓ cup panko bread crumbs, 12 ounces uncooked medium shrimp, peeled and deveined,   cooking spray, ½ teaspoon kosher salt, divided, ¼ cup honey, ¼ cup lime juice, 1  serrano chile, thinly sliced, 2 teaspoons chopped fresh cilantro', 'Stir together flour and pepper in a shallow dish. Lightly beat eggs in a second shallow dish. Stir together coconut and panko in a third shallow dish.
INSERT INTO public.recipes VALUES (954, 'Chococonut Chip Cookies', '10 mins', '10 mins', '20 mins', '72', '6 dozen', '1 cup butter, 1 cup white sugar, ½ cup light brown sugar, 2  eggs, 1 teaspoon vanilla extract, 2 ¼ cups all-purpose flour, 1 teaspoon baking soda, 1 teaspoon salt, 2 cups semisweet chocolate chips, 2 cups flaked coconut', 'Preheat the oven to 375 degrees F (190 degrees C).
INSERT INTO public.recipes VALUES (955, 'Five Flavor Pound Cake', '25 mins', '1 hrs 35 mins', '2 hrs 10 mins', '14', '1 10-inch tube pan', '3 cups all-purpose flour, ½ teaspoon baking powder, 1 cup milk, 1 teaspoon coconut extract, 1 teaspoon rum flavored extract, 1 teaspoon butter flavored extract, 1 teaspoon lemon extract, 1 teaspoon vanilla extract, 3 cups white sugar, 1 cup butter, softened, ½ cup shortening, 5 large eggs, beaten', 'Preheat the oven to 325 degrees F (165 degrees C). Grease a 10-inch tube pan.
INSERT INTO public.recipes VALUES (956, 'Moist Carrot Cake', '30 mins', '40 mins', '1 hrs 10 mins', '12', '1 9x13-inch pan', '2 cups all-purpose flour, 2 ½ teaspoons ground cinnamon, 2 teaspoons baking powder, 1 ½ teaspoons baking soda, 1 teaspoon salt, 2 cups white sugar, 1 ½ cups vegetable oil, 4 large eggs, 2 ¾ cups shredded carrots, 1 (8 ounce) can crushed pineapple, drained, 1 cup flaked coconut, ¾ cup chopped walnuts', 'Preheat the oven to 325 degrees F (165 degrees C). Grease and flour a 9x13-inch pan.
INSERT INTO public.recipes VALUES (957, 'Impossible Coconut Pie', '10 mins', '40 mins', '55 mins', '8', '1 9-inch pie', '2 cups milk, ¾ cup white sugar, ½ cup baking mix, ¼ cup unsalted butter, softened, 4 large eggs, 1 ½ teaspoons vanilla extract, 1 cup flaked coconut (Optional)', 'Preheat the oven to 350 degrees F (175 degrees C). Grease a 9-inch pie plate.
INSERT INTO public.recipes VALUES (958, 'Ginataang Manok (Chicken Cooked in Coconut Milk)', '5 mins', '50 mins', '55 mins', '6', NULL, '3 tablespoons canola oil, ½ cup sliced fresh ginger, 1 (5 pound) whole chicken, cut into pieces,   salt and ground black pepper to taste, 2 (14 ounce) cans coconut milk, 1 (10 ounce) package frozen chopped spinach, thawed and drained', 'Heat oil in a large skillet over medium heat and stir in ginger. Cook and stir until fragrant and lightly browned. Remove ginger and set aside.
INSERT INTO public.recipes VALUES (959, 'Coquito', '5 mins', '10 mins', '8 hrs 15 mins', '10', NULL, '1 (12 fluid ounce) can evaporated milk, 2 large egg yolks, beaten, 1 (14 ounce) can cream of coconut, 1 (14 ounce) can sweetened condensed milk, ½ cup white rum, ½ cup water, 1 teaspoon vanilla extract, ½ teaspoon ground cinnamon, ¼ teaspoon ground cloves', 'Combine evaporated milk and egg yolks in the top of a double boiler over simmering water. Cook over the simmering water, stirring constantly, until mixture is thick enough to coat the back of a spoon, and reaches a temperature of 160 degrees F (71 degrees C).
INSERT INTO public.recipes VALUES (960, 'Maja Blanca', '15 mins', '1 hrs 10 mins', '2 hrs 55 mins', '12', '12 slices', '2 cups thin coconut milk, 3 tablespoons white sugar', 'Make the latik: Bring coconut milk to a boil in a saucepan over medium heat. Cook, stirring constantly, until oil begins to separate from the milk, about 30 minutes. Skim and reserve oil in a bowl.
INSERT INTO public.recipes VALUES (961, 'Oatmeal Chocolate Coconut Chewy', NULL, NULL, NULL, '30', '5 dozen', '1 cup butter, softened, 1 ¼ cups packed brown sugar, ½ cup white sugar, 2  eggs, 2 tablespoons milk, 2 teaspoons vanilla extract, 1 ¾ cups all-purpose flour, 1 teaspoon baking soda, ½ teaspoon salt (Optional), 3 cups rolled oats, 2 cups semisweet chocolate chips, 1 cup chopped walnuts (Optional), 1 cup shredded coconut', 'Preheat oven to 375 degrees F (190 degrees C).
INSERT INTO public.recipes VALUES (962, 'Hello Dollies I', '15 mins', '30 mins', '45 mins', '24', '2 dozen', '2 cups graham cracker crumbs, ¼ cup white sugar, ½ cup butter, melted, 1 cup semisweet chocolate chips, 1 cup flaked coconut, 1 cup chopped pecans, 1 (14 ounce) can sweetened condensed milk', 'Preheat oven to 325 degrees F (165 degrees C).
INSERT INTO public.recipes VALUES (963, 'Haystacks I', NULL, NULL, NULL, '24', '4 dozen', '2 cups white sugar, ⅓ cup unsweetened cocoa powder, ½ cup milk, ½ cup butter, 3 ½ cups quick cooking oats, 1 cup flaked coconut, ½ cup chopped peanuts, 1 pinch salt', 'In a saucepan bring sugar, cocoa, milk and butter or margarine to a boil. Remove from heat.
INSERT INTO public.recipes VALUES (977, 'Coconut Cream Pie I', '15 mins', NULL, '1 hrs 15 mins', '8', '1 to 9 - inch pie', '1 (9 inch) pie shell, baked, 1 (5 ounce) package instant vanilla pudding mix, 1 ½ cups milk, 1 ½ cups flaked coconut, 1 (8 ounce) container frozen whipped topping, thawed', 'In a large bowl, combine the pudding mix and milk until the pudding mixture thickens. Fold 1 cup of coconut and half of the nondairy whipped topping into the pudding. Pour the combination into the prepared pie crust.
INSERT INTO public.recipes VALUES (964, 'Cream Cheese Fruit Salad', '15 mins', NULL, '1 hrs 15 mins', '8', '8 servings', '1 (8 ounce) package cream cheese, ¼ cup white sugar, or to taste, 1 (12 ounce) container frozen whipped topping, thawed, 3  bananas, peeled and sliced, 1 (15.25 ounce) can crushed pineapple, drained, 1 (15.25 ounce) can fruit cocktail, drained, 1 large Jonagold apple, peeled and chopped, ½ cup sweetened flaked coconut, 1 (4 ounce) jar maraschino cherries, drained and halved (Optional), ½ cup chopped pecans (Optional), ½ cup golden raisins (Optional)', 'Beat the cream cheese and sugar together in a large bowl. On high speed, beat in the whipped topping. Fold in the bananas, pineapple, fruit cocktail, apple, and coconut. If desired, mix in the maraschino cherries, pecans, and raisins. Pour the salad into a serving bowl, and chill 1 hour before serving.', '4.8', 'https://www.allrecipes.com/recipe/137346/cream-cheese-fruit-salad/', '/Salad/Fruit Salad Recipes/Apple Salad Recipes/', 'Total Fat 27g 35%, Saturated Fat 17g 86%, Cholesterol 31mg 10%, Sodium 111mg 5%, Total Carbohydrate 61g 22%, Dietary Fiber 5g 16%, Total Sugars 46g, Protein 5g, Vitamin C 12mg 61%, Calcium 54mg 4%, Iron 1mg 7%, Potassium 486mg 10%', 'Prep Time: 15 mins, Additional Time: 1 hrs, Total Time: 1 hrs 15 mins, Servings: 8, Yield: 8 servings', 'https://www.allrecipes.com/thmb/Jxf9fOspeG37h-0Zn3YMPzwv25A=/1500x0/filters:no_upscale():max_bytes(150000):strip_icc()/4463976-760a09d107f04bd3865cfa3554416523.jpg');
INSERT INTO public.recipes VALUES (965, 'Coconut Oil Popcorn', '5 mins', '5 mins', '10 mins', '2', '2 large servings', '2 tablespoons coconut oil, ¼ cup unpopped popcorn,   sea salt to taste', 'Place popcorn and oil in a 3-quart pot over medium heat and cover the pot with a lid. Shake the pot constantly as popcorn pops. When popping slows to a few seconds in-between pops, after about 3 to 5 minutes, remove pot from heat and pour popcorn into a large bowl. Season with sea salt.', '4.9', 'https://www.allrecipes.com/recipe/241449/coconut-oil-popcorn/', '/Appetizers and Snacks/Snacks/Popcorn Recipes/', 'Total Fat 15g 19%, Saturated Fat 13g 63%, Sodium 161mg 7%, Total Carbohydrate 19g 7%, Dietary Fiber 4g 13%, Total Sugars 0g, Protein 3g, Calcium 3mg 0%, Iron 3mg 14%, Potassium 74mg 2%', 'Prep Time: 5 mins, Cook Time: 5 mins, Total Time: 10 mins, Servings: 2, Yield: 2 large servings', 'https://www.allrecipes.com/thmb/SJSbFVjT_x3KEA29mmX_VHd5_uQ=/1500x0/filters:no_upscale():max_bytes(150000):strip_icc()/3598265-58680f01b1c541af8721b76c7b40b1cf.jpg');
INSERT INTO public.recipes VALUES (966, 'Thirty Day Friendship Cake', '1 hrs', '1 hrs', '19 days 19 hrs 2 mins', '48', '2 9x13-inch cakes', '  2 cups Friendship Fruit Starter, 1 (15 ounce) can sliced peaches with juice, 2 ½ cups white sugar, 1 (15 ounce) can pineapple chunks with juice, ½ cup white sugar, 2 (10 ounce) jars maraschino cherries, 2 ½ cups white sugar, 2 (18.25 ounce) packages yellow cake mix, 2 (3.4 ounce) packages instant vanilla pudding mix, 1 ⅓ cups vegetable oil, 8  eggs, 2 cups golden raisins, 2 cups chopped walnuts, 2 cups flaked coconut', 'Day One: In a large glass jar or bowl, combine 2 cups of the starter with 1 can of the sliced peaches and their juice (each slice chopped into 4 pieces). Add 2 1/2 cups of the white sugar and stir once every day for 10 days. When not stirring mixture, keep it covered with a paper towel, foil, or a loose lid. Let sit at room temperature. Don''t refrigerate it or cover it airtight. A pan of water underneath the jar or bowl will keep the ants out.
INSERT INTO public.recipes VALUES (967, 'Granola Bars', '15 mins', '25 mins', '1 hrs 40 mins', '8', NULL, '  cooking spray, 2 cups rolled oats, ½ cup shredded coconut, ½ cup honey, 2 tablespoons creamy peanut butter, 1 teaspoon vanilla extract, ⅛ teaspoon salt', 'Preheat the oven to 325 degrees F (165 degrees C). Grease a 9-inch square baking dish.
INSERT INTO public.recipes VALUES (968, 'Earthquake Cake II', NULL, NULL, NULL, '24', '1 - 9x13 inch pan', '1 cup flaked coconut, 1 cup chopped pecans, 1 (18.25 ounce) package German chocolate cake mix, 1 (8 ounce) package cream cheese, 4 cups confectioners'' sugar, ½ cup butter, 1 teaspoon vanilla extract', 'Preheat oven to 350 degrees F (175 degrees C). Lightly grease the bottom and sides of one 9 x 13 inch baking pan.
INSERT INTO public.recipes VALUES (969, 'Coconut Jasmine Rice', '5 mins', '25 mins', '30 mins', '6', NULL, '1 (14 ounce) can coconut milk, 1 ¼ cups water, 1 teaspoon white sugar, 1 pinch salt, 1 ½ cups jasmine rice', 'Stir coconut milk, water, sugar, and salt together in a saucepan over medium heat until sugar dissolves.
INSERT INTO public.recipes VALUES (970, 'Umm Ali', '10 mins', '30 mins', '40 mins', '8', '8 servings', '1 (17.25 ounce) package frozen puff pastry, thawed, 5 cups milk, 1 cup white sugar, 1 teaspoon vanilla extract, ¼ cup raisins, ¼ cup slivered almonds, ¼ cup pine nuts, ¼ cup chopped pistachio nuts, ¼ cup sweetened, flaked coconut', 'Preheat the oven to 400 degrees F (200 degrees C). Unroll the puff pastry sheets, and place flat on a baking sheet. Bake for 15 minutes in the preheated oven, or until puffed and golden brown.
INSERT INTO public.recipes VALUES (971, 'Lamingtons', '25 mins', '30 mins', '1 day 1 hrs 55 mins', '24', '24 servings', '2 cups all-purpose flour, 4 teaspoons baking powder, ⅛ teaspoon salt, ½ cup butter, room temperature, ¾ cup white sugar, 1 teaspoon vanilla extract, 2  eggs, room temperature, ½ cup milk', 'Preheat oven to 375 degrees F (190 degrees C). Grease and flour an 8x12-inch pan.
INSERT INTO public.recipes VALUES (972, 'Coconut Pecan Frosting II', NULL, '15 mins', '15 mins', '12', '2 1/2 cups', '1 cup evaporated milk, 1 cup white sugar, 3  egg yolks, ½ cup butter, 1 teaspoon vanilla extract, 1 ½ cups flaked coconut, 1 cup chopped pecans', 'In a saucepan over medium heat, combine milk, sugar, egg yolks, butter and vanilla. Cook, stirring frequently, until thickened. Remove from heat and stir in coconut and pecans.', '4.9', 'https://www.allrecipes.com/recipe/26014/coconut-pecan-frosting-ii/', '/Desserts/Frostings and Icings/', 'Total Fat 20g 25%, Saturated Fat 9g 46%, Cholesterol 78mg 26%, Sodium 105mg 5%, Total Carbohydrate 25g 9%, Dietary Fiber 2g 6%, Total Sugars 23g, Protein 3g, Vitamin C 1mg 3%, Calcium 70mg 5%, Iron 1mg 3%, Potassium 142mg 3%', 'Cook Time: 15 mins, Total Time: 15 mins, Servings: 12, Yield: 2 1/2 cups', 'https://www.allrecipes.com/thmb/u8Iaonw3w1kjf_ZD6-a1wO2qIJQ=/1500x0/filters:no_upscale():max_bytes(150000):strip_icc()/4502860-402b963e50a741c59b31bd245e873bc3.jpg');
INSERT INTO public.recipes VALUES (973, 'Bionicos (Mexican Fruit Bowls)', '30 mins', NULL, '30 mins', '4', '4 fruit bowls', '⅓ cup plain yogurt, ⅓ cup sweetened condensed milk, ⅓ cup Mexican crema, 1 teaspoon vanilla extract', 'Mix yogurt, sweetened condensed milk, and crema in a bowl. Add vanilla extract and stir until well incorporated.
INSERT INTO public.recipes VALUES (974, 'Queen Elizabeth Cake I', '30 mins', '40 mins', '1 hrs 30 mins', '12', '9 to 13 x inch cake', '1 cup boiling water, 1 cup dates, pitted and chopped, ¼ cup butter, softened, 1 cup white sugar, 1  egg, 1 teaspoon vanilla extract, 1 ½ cups all-purpose flour, 1 teaspoon baking soda, 1 teaspoon baking powder, ½ teaspoon salt, ½ cup chopped walnuts, 1 cup flaked coconut, ⅔ cup packed brown sugar, 6 tablespoons butter, ¼ cup cream', 'Pour boiling water over dates in a small bowl, and let stand until cool.
INSERT INTO public.recipes VALUES (975, 'Sweet Coconut Rice', '5 mins', '20 mins', '25 mins', '4', '4 servings', '1 ½ cups long-grain white rice, 1 (14 ounce) can coconut milk, 1 ¼ cups water, 1 teaspoon white sugar, or more to taste, 1 tablespoon shredded coconut, or to taste (Optional)', 'Stir rice, coconut milk, and water together in a saucepan. Dissolve sugar into the liquid.
INSERT INTO public.recipes VALUES (978, 'Instant Pot Coconut Curry Chicken', '15 mins', '35 mins', '1 hrs 5 mins', '4', NULL, '1 tablespoon coconut oil, 1 medium onion, chopped, 3 tablespoons curry powder, or to taste, divided, 2 cloves garlic, chopped, 1 (14.5 ounce) can diced tomatoes, drained, 1 (8 ounce) can tomato sauce, ½ cup chicken broth, 2 tablespoons white sugar, 2 pounds chicken breasts,   salt to taste,   ground black pepper to taste, 1 (14 ounce) can coconut milk', 'Turn on a multi-functional pressure cooker (such as Instant Pot) and select Sauté function. Add coconut oil; when hot, add onion and cook for 1 minute. Add 2 tablespoons curry powder and garlic. Mix well and cook for 2 minutes. Turn off Sauté function. Stir in diced tomatoes, tomato sauce, chicken broth, and sugar.
INSERT INTO public.recipes VALUES (979, 'Coconut Lime Rice', '5 mins', '30 mins', '40 mins', '2', '2 cups', '1 cup basmati rice, 1 tablespoon coconut oil, 1 teaspoon butter, ¼ cup flaked coconut, 1 cup coconut milk, 1 cup chicken broth,   salt, to taste, 1  lime, zested and juiced,   ground black pepper, to taste', 'Rinse rice until the water runs clear; drain. Heat coconut oil and butter in a large skillet over medium-high heat. Cook and stir rice and coconut flakes for 3 to 4 minutes. Stir in the lime juice, then add the coconut milk, chicken broth, salt and lime zest. Bring to a low boil, then cover and reduce heat to low. Cook for 20 minutes. Remove from heat and keep covered for 5 minutes. Fluff with fork and season with pepper.', '4.6', 'https://www.allrecipes.com/recipe/202656/coconut-lime-rice/', '/Side Dish/Rice Side Dish Recipes/', 'Total Fat 37g 47%, Saturated Fat 32g 159%, Cholesterol 5mg 2%, Sodium 56mg 2%, Total Carbohydrate 85g 31%, Dietary Fiber 4g 14%, Total Sugars 4g, Protein 10g, Vitamin C 11mg 56%, Calcium 42mg 3%, Iron 5mg 26%, Potassium 323mg 7%', 'Prep Time: 5 mins, Cook Time: 30 mins, Additional Time: 5 mins, Total Time: 40 mins, Servings: 2, Yield: 2 cups', 'https://www.allrecipes.com/thmb/MpasIhVWGvNpWWnL9jyoiMeKhZQ=/1500x0/filters:no_upscale():max_bytes(150000):strip_icc()/385615-9da05b0ae96c4ac4bd9d3c74c0ff1e19.jpg');
INSERT INTO public.recipes VALUES (981, 'Flan de Coco (Coconut Flan)', '10 mins', '1 hrs', '9 hrs 10 mins', '12', '12 servings', '1 ½ cups white sugar, 1 (14 ounce) can sweetened condensed milk, 1 (12 fluid ounce) can evaporated milk, ½ cup milk, 6  eggs, ½ cup fresh shredded coconut', 'Preheat oven to 350 degrees F (175 degrees C).
INSERT INTO public.recipes VALUES (982, 'Sweet Coconut Oatmeal', '5 mins', '20 mins', '25 mins', '3', '3 servings', '1 (14 ounce) can coconut milk, 1 cup rolled oats, 2 tablespoons honey, ¼ cup coconut flakes (Optional), 2 tablespoons brown sugar, or more to taste, 1 teaspoon ground cinnamon', 'Bring coconut milk to a gentle boil in a small saucepan over medium-low heat. Stir in oats and honey; lower heat and simmer until milk has mostly been absorbed, about 15 minutes.
INSERT INTO public.recipes VALUES (983, 'No Crust Coconut Pie', NULL, NULL, NULL, '8', '1 pie', '4  eggs, beaten, ¼ cup butter, ½ cup self-rising flour, 1 teaspoon vanilla extract, 1 ¾ cups white sugar, 2 cups milk, 7 ounces flaked coconut', 'Preheat oven to 325 degrees F (165 degrees C).
INSERT INTO public.recipes VALUES (984, 'Coconut Coconut Milk Cake', '15 mins', '45 mins', '1 hrs', '24', '24 servings', '2 cups white sugar, 1 cup butter, softened, 4  eggs, separated, 1 cup unsweetened shredded coconut, 2 cups all-purpose flour, 2 tablespoons baking powder, 1 teaspoon salt, 1 (14 ounce) can coconut milk', 'Preheat oven to 350 degrees F (175 degrees C). Grease a 9x13-inch cake pan.
INSERT INTO public.recipes VALUES (985, '5 Cup Salad', '10 mins', '5 hrs', '5 hrs 10 mins', '8', '8 servings', '1 cup mini marshmallows, 1 cup shredded coconut, 1 cup drained mandarin oranges, 1 cup drained pineapple chunks, 1 cup sour cream', 'Mix marshmallows, coconut, oranges, pineapple, and sour cream together in a bowl. Cover and refrigerate until flavors blend, 5 to 6 hours.', '4.7', 'https://www.allrecipes.com/recipe/230038/5-cup-salad/', '/Salad/Fruit Salad Recipes/Orange Salad Recipes/', 'Total Fat 9g 11%, Saturated Fat 6g 31%, Cholesterol 13mg 4%, Sodium 51mg 2%, Total Carbohydrate 19g 7%, Dietary Fiber 1g 5%, Total Sugars 15g, Protein 2g, Vitamin C 14mg 70%, Calcium 42mg 3%, Iron 0mg 2%, Potassium 156mg 3%', 'Prep Time: 10 mins, Cook Time: 5 hrs, Total Time: 5 hrs 10 mins, Servings: 8, Yield: 8 servings', 'https://www.allrecipes.com/thmb/3Tlyw9rPNyxEmgKLwlQGvewO_Qg=/1500x0/filters:no_upscale():max_bytes(150000):strip_icc()/4503262-5-cup-salad-Becky-Evertz-4x3-1-9c28c8842c3248e89c9ae9a4375fa010.jpg');
INSERT INTO public.recipes VALUES (986, 'Creamy Coconut Milk Rice Pudding', '10 mins', '45 mins', '55 mins', '10', NULL, '3 cups water, 1 ½ cups basmati rice, 3 cups coconut milk, 1 ½ cups raw sugar, ½ teaspoon sea salt, 1 cup whole milk, 2  eggs, beaten, ¼ cup unsalted butter, 1 tablespoon vanilla extract, 2 teaspoons ground cinnamon, 1 teaspoon ground nutmeg, 1 (15 ounce) can sliced peaches, drained and chopped (Optional), 1 cup raisins, or more to taste (Optional)', 'Bring water and rice to a boil in a saucepan. Reduce heat to medium-low, cover, and simmer until rice is tender and liquid has been absorbed, about 20 minutes.
INSERT INTO public.recipes VALUES (987, 'Mango Bread', '20 mins', '1 hrs', '1 hrs 30 mins', '16', '2 8x4x2-inch loaves', '2 cups all-purpose flour, 2 teaspoons baking soda, 2 teaspoons ground cinnamon, ½ teaspoon salt, 3  eggs, ¾ cup softened butter, 1 ¼ cups white sugar, 1 teaspoon vanilla extract, 2 cups chopped mango, ½ cup shredded coconut, ¼ cup chopped walnuts', 'Preheat oven to 350 degrees F (175 degrees C). Grease and flour 2 loaf pans.
INSERT INTO public.recipes VALUES (988, 'Chewy Coconut Bibingka (Filipino Rice Cake)', '15 mins', '45 mins', '1 hrs 20 mins', '24', '24 servings', '1 (13.5 ounce) can coconut milk, 1 (14 ounce) can sweetened condensed milk, 1 stick butter, melted, 4  eggs, 2 (12 ounce) jars macapuno strings in heavy syrup, 2 ½ cups sweet rice flour (mochiko), 1 cup packed brown sugar, 1 tablespoon vanilla extract', 'Preheat the oven to 350 degrees F (175 degrees C). Butter a 12x17-inch rimmed baking sheet.
INSERT INTO public.recipes VALUES (989, 'Ono Butter Mochi', '5 mins', '1 hrs', '1 hrs 5 mins', '12', '1 - 9x13 inch pan', '1 pound mochiko (glutinous rice flour), 2 ½ cups white sugar, 1 teaspoon baking powder, ½ cup butter, melted, 3 cups whole milk, 5  eggs, 1 teaspoon vanilla extract, 1 cup sweetened, flaked coconut', 'Preheat the oven to 350 degrees F (175 degrees C). Grease a 9x13 inch baking dish.
INSERT INTO public.recipes VALUES (990, 'Swedish Chocolate Balls (or Coconut Balls)', '20 mins', NULL, '2 hrs 20 mins', '48', '48 servings', '4 cups regular rolled oats , 1 ¼ cups white sugar, ½ cup unsweetened cocoa powder, 1 cup butter or margarine, softened, 2 tablespoons strong coffee, 1 teaspoon vanilla extract, 2 (1 ounce) squares unsweetened baking chocolate, melted, ⅓ cup coconut flakes', 'Mix the oats, sugar, and cocoa together in a bowl. Add the butter, and use your hands to mix the ingredients together to make a thick dough. Mix in the coffee, vanilla, and chocolate until thoroughly blended.
INSERT INTO public.recipes VALUES (991, 'Willard Family German Chocolate Cake', '30 mins', '50 mins', '2 hrs 20 mins', '10', '1 3-layer cake', '1 (4 ounce) package sweet baking chocolate (such as Baker''s German''s Sweet Chocolate®) - broken into pieces, ½ cup boiling water, 1 cup margarine, softened, 2 cups white sugar, 4  eggs, separated, 1 teaspoon vanilla extract, 2 ½ cups sifted all purpose flour, 1 teaspoon baking soda, ½ teaspoon salt, 1 cup buttermilk, 1 cup evaporated milk, 1 cup white sugar, 3  egg yolks, ¼ cup margarine, 1 teaspoon vanilla extract, 1 ⅓ cups sweetened flake coconut, 1 cup chopped pecans', 'Preheat oven to 350 degrees F (175 degrees C). Grease and flour 3 8-inch cake pans and line bottoms with parchment paper.
INSERT INTO public.recipes VALUES (992, 'Coconut Cream Pound Cake', '15 mins', '1 hrs 20 mins', '1 hrs 45 mins', '16', '1 10-inch tube cake', '1 cup butter, softened, 1 (8 ounce) package cream cheese, softened, 3 cups white sugar, 6  eggs, 1 teaspoon coconut extract, 3 cups all-purpose flour, ½ teaspoon baking powder, 2 cups flaked coconut', 'Preheat the oven to 325 degrees F (165 degrees C). Grease and flour a 10-inch tube pan.
INSERT INTO public.recipes VALUES (993, 'No-Bake Chocolate-Oatmeal Drop Cookies', '5 mins', '5 mins', '1 hrs 10 mins', '20', '20 cookies', '½ cup milk, 2 cups white sugar, ½ cup butter, ½ cup cocoa powder , 3 cups quick oats, ½ cup shredded coconut, ½ cup peanut butter, 1 teaspoon vanilla extract', 'Mix milk, sugar, butter, and cocoa powder in a large saucepan and bring to a rolling boil. Boil, stirring frequently, for about 1 minute. Remove from heat and add oats, coconut, peanut butter, and vanilla. Mix thoroughly.
INSERT INTO public.recipes VALUES (996, 'Coconut-Cream Cheese Frosting', '15 mins', NULL, '15 mins', '20', '5 1/2 cups', '1 (8 ounce) package cream cheese, softened, ½ cup unsalted butter, softened, 4 cups confectioners'' sugar, 2 tablespoons heavy cream, ½ teaspoon salt, ½ teaspoon coconut flavoring, 1 teaspoon vanilla extract, ½ cup sweetened shredded coconut, 1 cup sweetened shredded coconut, toasted', 'Beat the cream cheese and butter in a mixer bowl until light and fluffy. Gradually add the confectioners'' sugar, one cup at a time, alternating with heavy cream. Beat in the salt, coconut flavoring, and vanilla extract. Continue beating until mixture is smooth and spreadable. Add additional confectioners'' sugar if necessary to thicken the frosting, or more cream to thin. Stir in the coconut. If desired, spoon toasted coconut evenly over frosted cake.', '4.8', 'https://www.allrecipes.com/recipe/142715/coconut-cream-cheese-frosting/', '/Desserts/Frostings and Icings/Cream Cheese/', 'Total Fat 11g 14%, Saturated Fat 7g 36%, Cholesterol 27mg 9%, Sodium 109mg 5%, Total Carbohydrate 28g 10%, Dietary Fiber 1g 2%, Total Sugars 27g, Protein 1g, Calcium 12mg 1%, Iron 0mg 1%, Potassium 37mg 1%', 'Prep Time: 15 mins, Total Time: 15 mins, Servings: 20, Yield: 5 1/2 cups', 'https://www.allrecipes.com/thmb/zIQ_g1v5kckOrxPBLP9EqGgABzw=/1500x0/filters:no_upscale():max_bytes(150000):strip_icc()/397474-20486c67fcdf4ded957b026a1e995ced.jpg');
INSERT INTO public.recipes VALUES (997, 'Anzac Biscuits (Australian Coconut-Oat Cookies)', NULL, NULL, NULL, '12', '2 dozen', '1 cup quick cooking oats, ¾ cup flaked coconut, 1 cup all-purpose flour, 1 teaspoon baking soda, 1 cup white sugar, ½ cup butter, 1 tablespoon golden syrup, 2 tablespoons boiling water', 'Mix oats, flour, sugar and coconut together.
INSERT INTO public.recipes VALUES (998, 'Cranberry Pumpkin Cookies', '20 mins', '15 mins', '35 mins', '36', '3 dozen', '1 cup white sugar, ½ cup butter, softened, 1 cup solid pack pumpkin puree, 1 large egg, 1 teaspoon vanilla extract, 2 ¼ cups all-purpose flour, 2 teaspoons baking powder, 1 teaspoon baking soda, 1 teaspoon ground cinnamon, ½ teaspoon salt, 1 cup halved fresh cranberries, ½ cup chopped walnuts, 1 tablespoon orange zest', 'Preheat the oven to 375 degrees F (190 degrees C). Grease two cookie sheets.
INSERT INTO public.recipes VALUES (1019, 'Fresh Raspberry Sauce', '5 mins', '5 mins', '55 mins', '12', '3 cups', '1 ½ pounds fresh raspberries, ¼ cup white sugar, 1 tablespoon water, or as needed (Optional), 2 teaspoons lemon juice, or more to taste', 'Combine raspberries, sugar, water, and lemon juice in a saucepan over medium heat; cook and stir until raspberries break down, sugar dissolves, and sauce is heated through, 3 to 7 minutes.
INSERT INTO public.recipes VALUES (999, 'To Die For Blueberry Muffins', '15 mins', '20 mins', '35 mins', '8', '8 large muffins', '1 ½ cups all-purpose flour, ¾ cup white sugar, 2 teaspoons baking powder, ½ teaspoon salt, ⅓ cup vegetable oil, 1  egg, ⅓ cup milk, or more as needed, 1 cup fresh blueberries', 'Preheat the oven to 400 degrees F (200 degrees C). Grease 8 muffin cups or line with paper liners.
INSERT INTO public.recipes VALUES (1000, 'Perfect Summer Fruit Salad', '25 mins', '5 mins', '3 hrs 30 mins', '10', NULL, '⅔ cup fresh orange juice, ⅓ cup fresh lemon juice, ⅓ cup packed brown sugar, ½ teaspoon grated orange zest, ½ teaspoon grated lemon zest, 1 teaspoon vanilla extract', 'For the sauce: Bring orange juice, lemon juice, brown sugar, orange zest, and lemon zest to a boil in a saucepan over medium-high heat. Reduce heat to medium-low and simmer until slightly thickened, about 5 minutes. Remove from heat and stir in vanilla extract. Set aside to cool.
INSERT INTO public.recipes VALUES (1001, 'Strawberry Jam', '20 mins', '20 mins', '40 mins', '40', '5 cups', '2 pounds fresh strawberries, hulled, 4 cups white sugar, ¼ cup lemon juice', 'Crush strawberries in a wide bowl in batches until you have 4 cups of mashed berries.
INSERT INTO public.recipes VALUES (1002, 'Strawberry Pretzel Salad', '20 mins', '2 hrs 10 mins', '2 hrs 30 mins', '12', '1 9x13-inch dish', '2 cups crushed pretzels, ¾ cup butter, melted, 3 tablespoons white sugar, 1 (8 ounce) package cream cheese, softened, 1 cup white sugar, 1 (8 ounce) container frozen whipped topping, thawed, 2 (3 ounce) packages strawberry flavored Jell-O®, 2 cups boiling water, 2 (10 ounce) packages frozen strawberries', 'Preheat the oven to 400 degrees F (200 degrees C).
INSERT INTO public.recipes VALUES (1020, 'Strawberry Freezer Jam', '10 mins', '10 mins', '1 day 30 mins', '80', '5 pints', '2 cups crushed fresh strawberries, 4 cups sugar, 1 (1.75 ounce) package dry pectin, ¾ cup water', 'Mix crushed strawberries with sugar in a bowl, and let stand for 10 minutes.
INSERT INTO public.recipes VALUES (1003, 'Homemade Blueberry Pie', '25 mins', '50 mins', '1 hrs 15 mins', '8', '1 pie', '¾ cup white sugar, 3 tablespoons cornstarch, ½ teaspoon ground cinnamon, ¼ teaspoon salt, 4 cups fresh blueberries, 1 (14.1 ounce) package double-crust pie pastry, thawed, 1 tablespoon butter', 'Set an oven rack to the lowest position and preheat the oven to 375 degrees F (190 degrees C).
INSERT INTO public.recipes VALUES (1004, 'Supreme Strawberry Topping', '10 mins', '20 mins', '30 mins', '4', NULL, '1 pint fresh strawberries, hulled and halved, ⅓ cup white sugar, 1 teaspoon vanilla (Optional)', 'Combine strawberries, sugar, and vanilla in a saucepan over medium-high heat. Cook, stirring occasionally, until mixture sizzles and juice begins to form.
INSERT INTO public.recipes VALUES (1005, 'Crustless Cranberry Pie', '15 mins', '40 mins', '55 mins', '8', '1 9-inch pie', '1 cup all-purpose flour, 1 cup white sugar, ¼ teaspoon salt, 2 cups cranberries, ½ cup chopped walnuts, ½ cup butter, melted, 2 large eggs, beaten, 1 teaspoon almond extract', 'Preheat the oven to 350 degrees F (175 degrees C). Grease a 9-inch pie pan.
INSERT INTO public.recipes VALUES (1006, 'Apple-Cranberry Crisp', '25 mins', '40 mins', '1 hrs 5 mins', '8', '1 8-inch crisp', '2 pounds Granny Smith apples - peeled, cored and thinly sliced, ¾ cup cranberries, ¼ cup white sugar, 1 tablespoon ground cinnamon, 1 teaspoon ground nutmeg', 'Preheat the oven to 375 degrees F (190 degrees C.) Butter an 8-inch square baking dish.
INSERT INTO public.recipes VALUES (1007, 'Blueberry Smoothie', '5 mins', NULL, '5 mins', '2', NULL, '1 cup blueberries (frozen or fresh), 1 (8 ounce) container plain yogurt, ¾ cup 2% reduced-fat milk, 2 tablespoons white sugar, ½ teaspoon vanilla extract, ⅛ teaspoon ground nutmeg', 'Blend blueberries, yogurt, milk, sugar, vanilla, and nutmeg in a blender until frothy, scraping down the sides of the blender if needed.
INSERT INTO public.recipes VALUES (1008, 'Baked Oatmeal', '10 mins', '40 mins', '50 mins', '8', NULL, '3 cups rolled oats, 1 cup brown sugar, 2 teaspoons ground cinnamon, 2 teaspoons baking powder, 1 teaspoon salt, 2  eggs, 1 cup milk, ½ cup melted butter, 2 teaspoons vanilla extract, ¾ cup dried cranberries', 'Preheat the oven to 350 degrees F (175 degrees C).
INSERT INTO public.recipes VALUES (1009, 'Strawberry Pie', '15 mins', '15 mins', '3 hrs 30 mins', '8', '1 9-inch pie', '1 quart fresh strawberries, hulled, 1 (9 inch) pie crust, baked, 1 cup white sugar, 3 tablespoons cornstarch, ¾ cup water, ½ cup heavy whipping cream', 'Arrange 1/2 of strawberries in baked pastry shell. Place remaining strawberries in a medium saucepan.
INSERT INTO public.recipes VALUES (1010, 'Blackberry Pie', '40 mins', '40 mins', '2 hrs 20 mins', '8', '1 9-inch pie', '4 cups fresh blackberries, ¾ cup white sugar, divided, ½ cup all-purpose flour, 1 (9 inch) double crust ready-to-use pie crust, 2 tablespoons milk', 'Preheat the oven to 425 degrees F (220 degrees C).
INSERT INTO public.recipes VALUES (1011, 'Easy Cranberry Orange Relish', '10 mins', NULL, '2 hrs 10 mins', '8', NULL, '1 medium navel orange, 1 (12 ounce) package fresh cranberries, ½ cup white sugar, ⅛ teaspoon ground cinnamon', 'Grate 2 teaspoons of zest from orange; discard remaining peel and pith from orange. Divide orange into sections.
INSERT INTO public.recipes VALUES (1012, 'Overnight Blueberry French Toast', '15 mins', '55 mins', '9 hrs 40 mins', '10', '1 9x13-inch casserole', '12 slices day-old bread, cut into 1-inch cubes, 2 (8 ounce) packages cream cheese, cut into 1 inch cubes, 1 cup fresh blueberries, 12  eggs, beaten, 2 cups milk, 1 teaspoon vanilla extract, ⅓ cup maple syrup', 'Prepare casserole: Lightly grease a 9x13-inch baking dish. Arrange 1/2 of the bread cubes in the dish and top with cream cheese cubes. Sprinkle blueberries over the cream cheese, then top with remaining bread cubes.
INSERT INTO public.recipes VALUES (1013, 'Chocolate-Covered Strawberries', '15 mins', '5 mins', '20 mins', '24', NULL, '16 ounces milk chocolate chips, 2 tablespoons shortening,   toothpicks, 1 pound fresh strawberries with leaves', 'Melt chocolate and shortening in a double boiler, stirring occasionally until smooth.
INSERT INTO public.recipes VALUES (1014, 'Rhubarb and Strawberry Pie', '20 mins', '35 mins', '1 hrs 25 mins', '8', '1 9-inch pie', '1 cup white sugar, ½ cup all-purpose flour, 1 pound rhubarb, cut into 1/4 inch slices, 2 pints strawberries, hulled and quartered, 1 recipe pastry for a 9 inch double crust pie, 2 tablespoons butter, 1 large egg yolk, 2 tablespoons white sugar', 'Preheat oven to 400 degrees F (200 degrees C).
INSERT INTO public.recipes VALUES (1015, 'Easy Small-Batch Blueberry Jam', '5 mins', '30 mins', '35 mins', '16', '1 cup', '4 cups fresh blueberries, 1 cup white sugar, 1 tablespoon fresh lemon juice, 1 pinch ground cinnamon (Optional)', 'Mix blueberries, sugar, lemon juice, and cinnamon in a saucepan. Cook, stirring constantly, over medium heat until thickened, about 30 minutes.', '4.7', 'https://www.allrecipes.com/recipe/239514/easy-small-batch-blueberry-jam/', '/Side Dish/Sauces and Condiments/Canning and Preserving Recipes/Jams and Jellies Recipes/', 'Total Fat 0g 0%, Sodium 0mg 0%, Total Carbohydrate 18g 7%, Dietary Fiber 1g 3%, Total Sugars 16g, Protein 0g, Vitamin C 4mg 20%, Calcium 3mg 0%, Iron 0mg 1%, Potassium 30mg 1%', 'Prep Time: 5 mins, Cook Time: 30 mins, Total Time: 35 mins, Servings: 16, Yield: 1 cup', 'https://www.allrecipes.com/thmb/6_lTcQ_vVXFBdwqqFCQ7JkIAZNA=/1500x0/filters:no_upscale():max_bytes(150000):strip_icc()/5115974-easy-small-batch-blueberry-jam-Kim-4x3-1-01c688e5e8cb41ae855381532ea6d546.jpg');
INSERT INTO public.recipes VALUES (1016, 'Melt in Your Mouth Blueberry Cake', '25 mins', '50 mins', '1 hrs 15 mins', '12', '1 8-inch square cake', '½ cup butter, ¾ cup white sugar, divided, ¼ teaspoon salt, 1 teaspoon vanilla extract, 2  egg yolks, 1 ½ cups all-purpose flour, 1 teaspoon baking powder, ⅓ cup milk, 1 ½ cups fresh blueberries, 1 tablespoon all-purpose flour, 2  egg whites, 1 tablespoon white sugar', 'Preheat the oven to 350 degrees F (175 degrees C). Grease and flour an 8-inch pan.
INSERT INTO public.recipes VALUES (1017, 'Raspberry and Almond Shortbread Thumbprints', '30 mins', '15 mins', '45 mins', '36', '3 dozen', '1 cup butter, softened, ⅔ cup white sugar, 1 ¼ teaspoons almond extract, divided, 2 cups all-purpose flour, ½ cup seedless raspberry jam, ½ cup confectioners'' sugar, 1 teaspoon milk', 'Preheat the oven to 350 degrees F (175 degrees C).
INSERT INTO public.recipes VALUES (1018, 'Todd''s Famous Blueberry Pancakes', '10 mins', '15 mins', '1 hrs 25 mins', '6', '12 pancakes', '1 ¼ cups all-purpose flour, 1 tablespoon baking powder, 1 ¼ teaspoons white sugar, ½ teaspoon salt, 1 cup milk, 1  egg, ½ tablespoon butter, melted, ½ cup frozen blueberries, thawed', 'Sift flour, baking powder, sugar, and salt together in a large bowl. Combine milk and egg in a small bowl. Stir egg mixture into flour mixture until just combined. Stir in melted butter, then fold in blueberries. Set aside for 1 hour.
INSERT INTO public.recipes VALUES (1023, 'Strawberry Spinach Salad', '10 mins', NULL, '1 hrs 20 mins', '4', NULL, '½ cup white sugar, ½ cup olive oil, ¼ cup distilled white vinegar, 2 tablespoons sesame seeds, 1 tablespoon poppy seeds, 1 tablespoon minced onion, ¼ teaspoon paprika, ¼ teaspoon Worcestershire sauce', 'Make dressing: Whisk together sugar, oil, vinegar, sesame seeds, poppy seeds, onion, paprika, and Worcestershire in a medium bowl. Cover and chill for 1 hour.
INSERT INTO public.recipes VALUES (1024, 'Basic Fruit Smoothie', '10 mins', NULL, '10 mins', '4', NULL, '1 quart strawberries, hulled, 2  fresh peaches - peeled, pitted, and sliced, 1  banana, broken into chunks, 2 cups ice, 1 cup orange-peach-mango juice', 'Combine strawberries, peaches, and banana in a blender; blend until smooth. Add ice and pour in juice; blend again to desired consistency.
INSERT INTO public.recipes VALUES (1025, 'Fruit Pizza', '25 mins', '10 mins', '1 hrs 35 mins', '10', '1 fruit pizza', '1 ¼ cups all-purpose flour, 1 teaspoon cream of tartar, ½ teaspoon baking soda, ¼ teaspoon salt, ½ cup butter, softened, 1 ¼ cups white sugar, divided, 1 large egg, 1 (8 ounce) package cream cheese, 2 teaspoons vanilla extract, ½ cup fresh blueberries, or more to taste, ½ cup sliced fresh strawberries, or more to taste, ½ cup sliced banana, or more to taste', 'Preheat the oven to 350 degrees F (175 degrees C).
INSERT INTO public.recipes VALUES (1026, 'Virgin Strawberry Daiquiri', '5 mins', NULL, '5 mins', '1', NULL, '2 large strawberries, hulled, ¼ cup white sugar, ¾ cup chilled lemon-lime soda, 1 tablespoon lemon juice, 4 cubes  ice', 'Combine strawberries, sugar, lemon-lime soda, and lemon juice in the container of a blender. Add ice and blend until smooth.
INSERT INTO public.recipes VALUES (1027, 'Strawberry Shortcake', '30 mins', '20 mins', '50 mins', '8', '1 8-inch round cake', '3 pints fresh strawberries, ½ cup white sugar, 2 ¼ cups all-purpose flour, 4 teaspoons baking powder, 2 tablespoons white sugar, ¼ teaspoon salt, ⅓ cup shortening, 1  egg, ⅔ cup milk, 2 cups whipped heavy cream', 'Slice the strawberries and toss them with 1/2 cup of white sugar. Set aside.
INSERT INTO public.recipes VALUES (1044, 'Fresh Cranberry Sauce', NULL, '20 mins', '20 mins', '16', NULL, '1 cup water, 1 cup white sugar, 1 (12 ounce) package fresh cranberries (such as Ocean Spray®)', 'Bring water to a boil in a saucepan; add sugar and cook until sugar is dissolved, about 5 minutes.
INSERT INTO public.recipes VALUES (1028, 'Strawberry Cheesecake', '1 hrs', '50 mins', '11 hrs', '12', NULL, '1 ¼ cups graham cracker crumbs, ⅓ cup butter, melted, ¼ cup white sugar, 2 teaspoons ground cinnamon', 'Make crust: Combine graham cracker crumbs, butter, sugar, and cinnamon in a bowl; mix well. Press onto the bottom of an ungreased 9-inch springform pan. Place in the refrigerator to chill for 30 minutes.
INSERT INTO public.recipes VALUES (1029, 'Easy Strawberry Vinaigrette', '10 mins', NULL, '10 mins', '7', NULL, '8 ounces frozen strawberries, 2 tablespoons honey, 2 tablespoons apple cider vinegar, 2 tablespoons olive oil, ¼ teaspoon salt, ¼ teaspoon ground black pepper', 'Blend strawberries, honey, apple cider vinegar, olive oil, salt, and black pepper together in a blender until smooth.', '4.8', 'https://www.allrecipes.com/recipe/238180/easy-strawberry-vinaigrette/', '/Side Dish/Sauces and Condiments/Salad Dressing Recipes/Vinaigrette Dressing Recipes/', 'Total Fat 4g 5%, Saturated Fat 1g 3%, Sodium 71mg 3%, Total Carbohydrate 8g 3%, Dietary Fiber 1g 3%, Protein 0g, Vitamin C 13mg 66%, Calcium 6mg 0%, Iron 0mg 2%, Potassium 55mg 1%', 'Prep Time: 10 mins, Total Time: 10 mins, Servings: 7', 'https://www.allrecipes.com/thmb/0d6ET-3QEwdReu1nVhoq6kKbfF4=/1500x0/filters:no_upscale():max_bytes(150000):strip_icc()/1945445-bea6d81a49ae463c9062288f78d292ed.jpg');
INSERT INTO public.recipes VALUES (1030, 'Strawberry Cake Filling', '5 mins', '10 mins', '45 mins', '28', '3 to 3 1/2 cups', '1 cup water, 3 tablespoons cornstarch, 2 ½ cups frozen strawberries, thawed and cut into bite size pieces, ¾ cup white sugar', 'Whisk water and cornstarch together in a large saucepan. Stir in strawberries and sugar.
INSERT INTO public.recipes VALUES (1031, 'The Ultimate Berry Crumble', '15 mins', '40 mins', '1 hrs 25 mins', '8', '1 2-quart baking dish', '2 cups all-purpose flour, ¾ cup white sugar, ¾ teaspoon baking powder, ¼ teaspoon fine salt, ¾ cup frozen unsalted butter, 2 large egg yolks, 1 ½ teaspoons vanilla extract, 1 teaspoon apple cider vinegar, or as needed', 'Preheat the oven to 375 degrees F (190 degrees C).
INSERT INTO public.recipes VALUES (1032, 'B and L''s Strawberry Smoothie', '5 mins', NULL, '5 mins', '2', NULL, '8  strawberries, hulled, ½ cup skim milk, ½ cup plain yogurt, 3 tablespoons white sugar, 2 teaspoons vanilla extract, 6 cubes  ice, crushed', 'Combine strawberries, milk, yogurt, sugar, and vanilla in a blender. Add ice and blend until smooth and creamy.
INSERT INTO public.recipes VALUES (1037, 'Raspberry Jam without Pectin', '5 mins', '20 mins', '8 hrs 30 mins', '56', '7 8-ounce jars', '4 cups mashed raspberries, 4 cups white sugar, 1 tablespoon freshly squeezed lemon juice', 'Bring raspberries to a boil in a very large pot. Cook for 4 minutes. Add sugar and lemon juice; stir well. Bring back to a boil, stirring constantly. Cook for another 4 minutes.
INSERT INTO public.recipes VALUES (1033, 'Creamy Strawberry Crepes', '30 mins', '30 mins', '1 hrs', '6', '12 filled crepes', '¾ cup all-purpose flour, ½ cup milk, ½ cup water, 3  eggs, 3 tablespoons butter, melted, ½ teaspoon salt, 1 ¼ cups sifted confectioners'' sugar, 1 (8 ounce) package cream cheese, softened, 1 tablespoon lemon juice, 1 teaspoon lemon zest, ½ teaspoon vanilla extract, 1 cup heavy cream, whipped, 4 cups sliced strawberries', 'Place flour, milk, water, eggs, melted butter, and salt into a blender; blend until smooth and set aside.
INSERT INTO public.recipes VALUES (1034, 'Awesome Sausage, Apple and Cranberry Stuffing', '15 mins', '15 mins', '1 hrs 30 mins', '10', NULL, '3 ¾ cups cubed white bread, 1 ½ cups cubed whole wheat bread, 1 pound ground turkey sausage, 1 cup chopped onion, ¾ cup chopped celery, 2 ½ teaspoons dried sage, 1 ½ teaspoons dried rosemary, ½ teaspoon dried thyme, 1  Golden Delicious apple, cored and chopped, ¾ cup dried cranberries, ⅓ cup minced fresh parsley, 1  cooked turkey liver, finely chopped, ¾ cup turkey stock, 4 tablespoons unsalted butter, melted', 'Preheat the oven to 350 degrees F (175 degrees C).
INSERT INTO public.recipes VALUES (1035, 'Strawberry Muffins', '15 mins', '25 mins', '50 mins', '8', '8 muffins', '½ cup milk, ¼ cup canola oil, 1 large egg, 1 ¾ cups all-purpose flour, ½ cup white sugar, 2 teaspoons baking powder, ½ teaspoon salt, 1 cup chopped strawberries', 'Preheat the oven to 375 degrees F (190 degrees C) Line 8 standard-sized muffin cups with paper liners.
INSERT INTO public.recipes VALUES (1036, 'Cranberry Orange Bread', '15 mins', '1 hrs', '1 hrs 25 mins', '8', '1 loaf', '2 cups flour, ¾ cup white sugar, 1 ½ teaspoons baking powder, ¾ teaspoon salt, ½ teaspoon baking soda, ¼ cup unsalted butter, cut into pieces and softened, ¾ cup orange juice, 1 tablespoon grated orange zest, 1 large egg, beaten, 1 cup chopped cranberries, ½ cup chopped walnuts (Optional)', 'Preheat the oven to 350 degrees F (175 degrees C). Grease an 8 1/2x4 1/2-inch loaf pan.
INSERT INTO public.recipes VALUES (1078, 'Date Nut Pinwheel Cookies I', NULL, NULL, NULL, '24', '4 dozen', '1 ½ cups pitted dates, ¼ cup white sugar, 1 pinch salt, 1 ¼ cups water, 1 teaspoon lemon zest, 4 teaspoons lemon juice, ⅔ cup finely chopped walnuts, 3 ½ cups all-purpose flour, 1 ½ teaspoons baking powder, ¼ teaspoon baking soda, ¾ teaspoon salt, ¾ cup butter, ½ cup white sugar, 1 cup packed brown sugar, 2  eggs, 1 ½ teaspoons vanilla extract', 'Chop pitted dates in food chopper. Place dates into small saucepan and add 1/4 cup sugar, dash of salt, and 1 1/4 cups of water. Cook, stirring constantly until mixture is of a soft consistency. Remove from heat.
INSERT INTO public.recipes VALUES (1038, 'Cocktail Meatballs', '20 mins', '1 hrs 20 mins', '1 hrs 40 mins', '10', NULL, '1 pound lean ground beef, ½ cup bread crumbs, 3 tablespoons minced onion, 2 tablespoons water, 1 large egg, 1 (8 ounce) can jellied cranberry sauce, ¾ cup chili sauce, 1 tablespoon brown sugar, 1 ½ teaspoons lemon juice', 'Preheat the oven to 350 degrees F (175 degrees C).
INSERT INTO public.recipes VALUES (1039, 'Simple Strawberry Syrup', '5 mins', '20 mins', '25 mins', '15', NULL, '1 cup water, 1 cup white sugar, 2 cups quartered strawberries', 'Combine water and sugar in a saucepan over medium-high heat; stir until sugar is dissolved. Mix strawberries into saucepan and bring to a boil; boil for 10 minutes.
INSERT INTO public.recipes VALUES (1040, 'Blueberry Tea Cocktail', '5 mins', NULL, '5 mins', '1', NULL, '1 fluid ounce amaretto liqueur, 1 fluid ounce orange liqueur (such as Grand Marnier®), 4 fluid ounces orange pekoe tea, or more to taste', 'Combine amaretto and orange liqueurs in a brandy snifter or glass. Pour in hot tea.', '5.0', 'https://www.allrecipes.com/recipe/222557/blueberry-tea-cocktail/', '/Drinks Recipes/Cocktail Recipes/', 'Total Fat 0g 0%, Sodium 7mg 0%, Total Carbohydrate 27g 10%, Total Sugars 24g, Calcium 0mg 0%, Iron 0mg 1%, Potassium 53mg 1%', 'Prep Time: 5 mins, Total Time: 5 mins, Servings: 1', 'https://www.allrecipes.com/thmb/cGvNp5aZCAzVfKiM0UxJ5L22h3E=/1500x0/filters:no_upscale():max_bytes(150000):strip_icc()/1476401-c330ac76bd6e430b97dc27a8093ed21f.jpg');
INSERT INTO public.recipes VALUES (1041, 'Easy Strawberry Shortcake', '15 mins', NULL, '30 mins', '6', NULL, '1 quart fresh strawberries, sliced, ¼ cup white sugar, 1 (12 ounce) package prepared sponge cake dessert cups, 1 (7 ounce) can whipped cream, or to taste', 'Place strawberries in a bowl; add sugar and stir to coat. Cover and refrigerate until sugar has dissolved, about 15 minutes.
INSERT INTO public.recipes VALUES (1042, 'Cheesecake-Stuffed Strawberries', '20 mins', NULL, '20 mins', '20', NULL, '1 (8 ounce) package cream cheese, softened, ½ cup confectioners'' sugar, ½ teaspoon vanilla extract, 1 pint fresh strawberries, hulled and cored, 3  graham crackers, crushed, or as needed', 'Beat cream cheese, confectioners'' sugar, and vanilla extract together in a bowl until smooth; spoon into a piping bag or a resealable bag with a corner snipped.
INSERT INTO public.recipes VALUES (1043, 'Best Strawberry Cake from Scratch', '15 mins', '25 mins', '50 mins', '14', '1 2-layer 9-inch cake', '2 cups white sugar, 1 cup butter, softened, 1 (3 ounce) package strawberry flavored Jell-O®, 4 large eggs (room temperature), 2 ¾ cups sifted cake flour, 2 ½ teaspoons baking powder, 1 cup whole milk, room temperature, ½ cup strawberry puree made from frozen sweetened strawberries, 1 tablespoon vanilla extract', 'Preheat the oven to 350 degrees F (175 degrees C). Grease and flour two 9-inch round cake pans.
