INSERT INTO public.recipes VALUES (1047, 'Cranberry Orange Cookies', '20 mins', '15 mins', '35 mins', '48', '48 cookies', '1 cup unsalted butter, softened, 1 cup white sugar, ½ cup packed brown sugar, 1 large egg, 2 tablespoons orange juice, 1 teaspoon grated orange zest, 2 ½ cups all-purpose flour, ½ teaspoon baking soda, ½ teaspoon salt, 2 cups chopped cranberries, ½ cup chopped walnuts (Optional)', 'Preheat the oven to 375 degrees F (190 degrees C).
INSERT INTO public.recipes VALUES (1048, 'Easy Blueberry Cobbler', '10 mins', '1 hrs', '1 hrs 10 mins', '8', '1 8-inch cobbler', '½ cup butter, 1 cup self-rising flour, 1 cup white sugar, 1 cup milk, 4 cups fresh blueberries', 'Preheat the oven to 350 degrees F (175 degrees C). Place butter in an 8-inch, square baking dish.
INSERT INTO public.recipes VALUES (1049, 'White Chocolate Raspberry Cheesecake', '25 mins', '1 hrs 10 mins', '9 hrs 35 mins', '16', '1 9-inch cheesecake', '1 cup chocolate cookie crumbs, ¼ cup butter, melted, 3 tablespoons white sugar', 'Make crust: Mix together cookie crumbs, melted butter, and sugar in a medium bowl. Press mixture into the bottom of a 9-inch springform pan.
INSERT INTO public.recipes VALUES (1050, 'Delicious Raspberry Oatmeal Cookie Bars', '15 mins', '35 mins', '50 mins', '9', '1 8x8-inch pan', '1 cup all-purpose flour, 1 cup rolled oats, ½ cup packed light brown sugar, ¼ teaspoon baking soda, ⅛ teaspoon salt, ½ cup butter, softened, ¾ cup seedless raspberry jam', 'Preheat the oven to 350 degrees F (175 degrees C). Grease an 8x8-inch square pan; line with greased foil.
INSERT INTO public.recipes VALUES (1051, 'Cranberry Pistachio Biscotti', '25 mins', '45 mins', '1 hrs 20 mins', '36', '36 cookies', '¾ cup white sugar, ¼ cup light olive oil, 2 teaspoons vanilla extract, ½ teaspoon almond extract, 2 large eggs, 1 ¾ cups all-purpose flour, 1 teaspoon baking powder, ¼ teaspoon salt, 1 ½ cups pistachio nuts, ½ cup dried cranberries', 'Preheat the oven to 300 degrees F (150 degrees C). Line a cookie sheet with parchment paper.
INSERT INTO public.recipes VALUES (1052, 'Strawberry Pie Filling', '5 mins', '20 mins', '25 mins', '8', NULL, '1 cup mashed strawberries, ¾ cup water, or more if needed, ¾ cup white sugar, 3 tablespoons cornstarch, 1 tablespoon lemon juice, ¼ teaspoon salt, 4 cups sliced strawberries', 'Combine mashed strawberries and water in a saucepan; bring to a boil and simmer for about 3 minutes.
INSERT INTO public.recipes VALUES (1053, 'Blueberry Simple Syrup', '15 mins', '20 mins', '35 mins', '12', '1 1/2 cups', '1 cup blueberries, 1 cup warm water, 1 cup white sugar, 1 teaspoon lemon juice', 'Mix blueberries, water, and sugar together using a whisk in a small saucepan over low heat until sugar is dissolved, about 5 minutes. Increase heat to medium and bring a gentle boil, stirring often, until syrup is thickened, about 15 minutes.
INSERT INTO public.recipes VALUES (1054, 'Jamie''s Cranberry Spinach Salad', '10 mins', '5 mins', '15 mins', '8', NULL, '1 tablespoon butter, ¾ cup almonds, blanched and slivered, 1 pound spinach, rinsed and torn into bite-size pieces, 1 cup dried cranberries', 'Melt butter in a medium saucepan over medium heat. Cook and stir almonds in butter until lightly toasted. Remove from heat and let cool.
INSERT INTO public.recipes VALUES (1055, 'Food for the Gods', NULL, NULL, NULL, '18', '3 dozen', '1 ¼ cups sifted all-purpose flour, ½ teaspoon baking powder, ½ teaspoon baking soda, ¼ teaspoon salt, 1 cup dates, pitted and chopped, 1 cup butter, 1 cup white sugar, 1 cup packed brown sugar, 3  eggs, 1 cup chopped walnuts', 'Preheat oven to 350 degrees F (180 degrees C).
INSERT INTO public.recipes VALUES (1058, 'Low-Sugar Date Brownies', '10 mins', '20 mins', '50 mins', '16', '16 brownies', '1 cup pitted Deglet Noor dates, 1 cup hot water, ½ cup unsalted butter, softened, 2  large eggs, 2 teaspoons vanilla extract, ⅓ cup whole wheat flour, ⅓ cup unsweetened cocoa powder, ½ teaspoon baking soda, ¼ teaspoon salt, ½ cup bittersweet chocolate chips (Optional)', 'Place dates in a small bowl and pour in hot water. Soak for 10 to 15 minutes.
INSERT INTO public.recipes VALUES (1059, 'Date Nut Bread', '40 mins', '1 hrs', '1 hrs 40 mins', '24', '2 loaves', '1 ½ cups dates, pitted and chopped, 2 ¼ cups boiling water, 3 teaspoons baking soda, 1 cup chopped walnuts, 2 cups white sugar, 3 tablespoons margarine, 2  eggs, beaten, 1 teaspoon salt, 4 ½ cups all-purpose flour, 1 teaspoon vanilla extract', 'Combine baking soda with the boiling water. Soak the dates in the water and baking soda solution for 30 minutes.
INSERT INTO public.recipes VALUES (1060, 'Date Balls', '20 mins', '5 mins', '25 mins', '24', '2 dozen cookies', '1 (8 ounce) package pitted dates, chopped, 1 cup white sugar, ½ cup butter or margarine, 3 cups crispy rice cereal, 1 cup chopped pecans, 1 teaspoon vanilla extract, ½ cup confectioners'' sugar, or as needed', 'Place dates, sugar, and margarine in a large saucepan over low heat; cook and stir until sugar dissolves. Remove from heat and fold in crispy rice cereal, pecans, and vanilla extract until evenly mixed.
INSERT INTO public.recipes VALUES (1061, 'Sticky Toffee Pudding Cake', '25 mins', '30 mins', '1 hrs 5 mins', '9', '1 8-inch cake', '1 ¾ cups pitted, chopped dates, 1 teaspoon baking soda, ¾ cup boiling water, ⅓ cup butter, ¾ cup white sugar, 2  eggs, beaten, 1 ⅛ cups self-rising flour, ¾ cup packed brown sugar, ⅓ cup butter, ⅔ cup evaporated milk, 1 teaspoon vanilla extract', 'Preheat oven to 350 degrees F (175 degrees C). Grease an 8-inch square baking dish.
INSERT INTO public.recipes VALUES (1062, 'Date Nut Loaf Cake', '20 mins', '1 hrs', '1 hrs 30 mins', '12', '1 - 9x5 inch loaf pan', '1 cup dates, pitted and chopped, 1 cup water, ½ cup butter, 1 cup white sugar, 1 teaspoon baking soda, 1 ½ cups all-purpose flour, 1  egg, beaten, 1 teaspoon vanilla extract, 1 cup chopped walnuts, ¼ cup butter, ⅓ cup heavy cream, ½ cup brown sugar', 'Preheat oven to 350 degrees F (175 degrees C). Grease and flour a 9x5 inch loaf pan. In a saucepan over medium heat, bring dates and water to a boil. Stir in 1/2 cup butter and 1 cup sugar until melted. Remove from heat and stir in baking soda. Let cool for 10 minutes.
INSERT INTO public.recipes VALUES (1063, 'Mother''s Applesauce Cake', '30 mins', '1 hrs 30 mins', '3 hrs', '16', '1 tube cake', '3 ½ cups all-purpose flour, ½ teaspoon salt, 2 teaspoons ground cinnamon, 1 teaspoon ground cloves, 3 teaspoons baking soda, ½ cup butter, 2 cups packed brown sugar, 2  eggs, beaten, 3 cups unsweetened applesauce, ½ cup raisins, ½ cup dates, pitted and chopped, 1 cup chopped walnuts, ½ cup butter, 1 cup packed brown sugar, ¼ cup milk, 1 teaspoon vanilla extract, 2 cups sifted confectioners'' sugar', 'Preheat oven to 300 degrees F (150 degrees C). Grease and flour a tube pan.
INSERT INTO public.recipes VALUES (1064, 'Devils on Horseback', '30 mins', '15 mins', '1 hrs', '20', '20 stuffed dates', '20  wooden toothpicks, ¼ cup reduced-sodium soy sauce, ½ teaspoon ground ginger, ¾ cup dark brown sugar, 20  dates, pitted and left whole, 20  whole smoked almonds, 10  bacon slices, cut in half crosswise', 'Preheat oven to 400 degrees F (200 degrees C). Soak the toothpicks in a bowl of water. Grease a 9x13-inch baking dish.
INSERT INTO public.recipes VALUES (1065, 'Coconut Date Balls', '10 mins', '5 mins', '25 mins', '24', '2 dozen', '2  eggs, beaten, 1 cup white sugar, 1 cup chopped dates, 1 teaspoon vanilla extract, 1 tablespoon butter, 3 cups crispy rice cereal, 1 cup flaked coconut', 'In a medium saucepan over medium heat, combine the eggs sugar and dates. Bring to a boil, stirring occasionally, and boil for 5 minutes. Remove from heat and stir in the butter and vanilla. Mix in crispy rice cereal. Butter hands and roll the mixture into walnut sized balls. Roll the balls in coconut. Serve.', '4.6', 'https://www.allrecipes.com/recipe/25786/coconut-date-balls/', '/Desserts/Cookies/No-Bake Cookie Recipes/', 'Total Fat 2g 2%, Saturated Fat 1g 7%, Cholesterol 17mg 6%, Sodium 45mg 2%, Total Carbohydrate 18g 6%, Dietary Fiber 1g 3%, Total Sugars 14g, Protein 1g, Vitamin C 2mg 12%, Calcium 5mg 0%, Iron 1mg 7%, Potassium 61mg 1%', 'Prep Time: 10 mins, Cook Time: 5 mins, Additional Time: 10 mins, Total Time: 25 mins, Servings: 24, Yield: 2 dozen', 'https://www.allrecipes.com/thmb/18JznNSeLDQ8aG-Am677miWaoIA=/1500x0/filters:no_upscale():max_bytes(150000):strip_icc()/3796080-ec43595c66c7408a8d9e8adb570b3e11.jpg');
INSERT INTO public.recipes VALUES (1066, 'Ma''amoul (Lebanese Date Cookies)', '45 mins', '30 mins', '9 hrs 35 mins', '48', '4 dozen', '2 cups semolina flour, 1 cup all-purpose flour, ½ teaspoon ground mahlab, ½ teaspoon salt, 1 cup clarified butter, at room temperature, 5 tablespoons milk, 2 tablespoons white sugar, 1 teaspoon active dry yeast, 4 tablespoons orange blossom water, or more as needed, 10 tablespoons date paste (such as Ziyad®), cut into small pieces, 2 tablespoons powdered sugar, or to taste', 'Mix semolina flour, all-purpose flour, mahlab, and salt together in a large bowl. Work clarified butter into the dry ingredients with your fingertips until thoroughly incorporated. Cover bowl and let dough rest at room temperature, 8 hours to overnight.
INSERT INTO public.recipes VALUES (1067, 'Sugar-Free Date Cookies', '15 mins', '15 mins', '30 mins', '18', '18 cookies', '1 cup chopped dates, ¼ cup chopped pecans, ¼ cup water, ½  very ripe banana, mashed, 1 large egg, lightly beaten, 2 tablespoons butter, melted, ½ teaspoon vanilla extract, 1 cup all-purpose flour, 1 teaspoon baking powder, 1 teaspoon cinnamon, ¼ teaspoon salt', 'Preheat the oven to 350 degrees F (175 degrees C). Line a baking sheet with parchment paper.
INSERT INTO public.recipes VALUES (1068, 'Energy Balls without Peanut Butter', '20 mins', NULL, '2 hrs 20 mins', '45', '45 balls', '1 cup rolled oats, ½ cup pumpkin seeds, ½ cup walnuts, ½ cup pecans, 15  pitted Medjool dates, ½ cup brown rice syrup, 1 cup mini chocolate chips, ½ cup shredded coconut, ½ cup raisins, ¼ cup sunflower seeds', 'Burst oats into a coarse meal in the bowl of a food processor. Add pumpkin seeds, walnuts, and pecans; pulse 10 to 15 times, until chunks are desired size.
INSERT INTO public.recipes VALUES (1069, 'Date Loaf Cake', '25 mins', '45 mins', '1 hrs 10 mins', '12', '1 - 9x5 inch loaf pan', '1 cup dates, pitted and chopped, 1 cup dark brown sugar, ¼ cup margarine, 1 cup boiling water, 1 ¾ cups self-rising flour, 1 teaspoon baking soda, 2 teaspoons vanilla extract', 'Preheat oven to 400 degrees F (200 degrees C). Grease and flour a 9x5 inch loaf pan.
INSERT INTO public.recipes VALUES (1070, 'Bacon Wrapped Dates', '10 mins', '15 mins', '25 mins', '16', '16 appetizer servings', '16  fresh or dried pitted dates, such as Medjool, 16  smoked almonds, 8 thick slices applewood-smoked bacon, halved crosswise,   Reynolds Wrap® Aluminum Foil', 'Preheat oven to 400 degrees F. Cut a slit in each date. Place almonds inside slits. Press together the dates to close slits. Wrap each date with a piece of bacon.
INSERT INTO public.recipes VALUES (1071, 'Matrimonial Bars', NULL, NULL, NULL, '24', '1 -13x9 inch baking pan', '1 ¾ cups quick cooking oats, 1 ¾ cups all-purpose flour, 1 cup packed brown sugar, 1 cup butter, 1 teaspoon salt, 1 teaspoon baking soda, 2 cups dates, pitted and chopped, ½ cup water, ½ cup white sugar', 'Preheat oven to 350 degrees F (175 degrees C). Grease one 13x9 inch baking pan.
INSERT INTO public.recipes VALUES (1072, 'Walnut Date Balls', '20 mins', NULL, '1 hrs 20 mins', '12', '24 date balls', '2 cups walnuts, 2 cups pitted Medjool dates, 1 cup shredded coconut, 1 tablespoon sesame oil, 1 teaspoon sea salt, 1 teaspoon vanilla extract', 'Process walnuts, dates, coconut, sesame oil, sea salt, and vanilla extract together in a food processor until combined. Roll date mixture into bite-size balls; refrigerate until firm, about 1 hour.', '4.8', 'https://www.allrecipes.com/recipe/244155/walnut-date-balls/', '/Desserts/Nut Dessert Recipes/Walnut Dessert Recipes/', 'Total Fat 14g 18%, Saturated Fat 3g 14%, Sodium 165mg 7%, Total Carbohydrate 28g 10%, Dietary Fiber 4g 15%, Total Sugars 22g, Protein 4g, Vitamin C 0mg 2%, Calcium 29mg 2%, Iron 3mg 14%, Potassium 292mg 6%', 'Prep Time: 20 mins, Additional Time: 1 hrs, Total Time: 1 hrs 20 mins, Servings: 12, Yield: 24 date balls', 'https://www.allrecipes.com/thmb/6L3XV9QG2XXT6_FTayvnOUmUVg8=/1500x0/filters:no_upscale():max_bytes(150000):strip_icc()/3697280-walnut-date-balls-mommyluvs2cook-4x3-1-5363bac331c34fb2976c73af30c6aaea.jpg');
INSERT INTO public.recipes VALUES (1073, 'Date Nut Pinwheel Cookies II', NULL, NULL, NULL, '60', '5 dozen', '1 cup butter (at room temperature), 2 cups packed brown sugar, 3  eggs, 1 teaspoon vanilla extract, 1 teaspoon ground cinnamon, ¼ teaspoon salt, ½ teaspoon baking soda, 4 ½ cups all-purpose flour, 8 ounces dates, pitted and chopped, 1 cup finely chopped pecans, ½ cup water, ½ cup white sugar', 'Cream the butter and brown sugar together in a mixing bowl until smooth. Add the eggs, one at a time, beating well after each addition. Stir in the vanilla. Sift the cinnamon, salt, baking soda, and flour together in a second mixing bowl. Slowly stir the flour mixture into the egg mixture until evenly blended.
INSERT INTO public.recipes VALUES (1074, 'Date and Nut Bars', NULL, NULL, NULL, '12', '2 dozen', '⅓ cup boiling water, 2 cups dates, pitted and chopped, ½ cup shortening, 1 cup white sugar, ⅛ teaspoon ground cinnamon, ¾ teaspoon salt, ⅛ teaspoon ground nutmeg, 2  eggs, 1 cup all-purpose flour, ¼ teaspoon baking soda, ½ cup chopped walnuts, ¼ cup confectioners'' sugar', 'In a small bowl, pour boiling water over dates, and set aside to cool. Preheat oven to 325 degrees F (165 degrees C). Grease a 10x10 inch baking pan.
INSERT INTO public.recipes VALUES (1075, 'Bacon and Date Appetizer', '30 mins', '5 mins', '35 mins', '6', '6 servings', '1 (8 ounce) package pitted dates, 4 ounces almonds, 1 pound sliced bacon', 'Preheat the broiler.
INSERT INTO public.recipes VALUES (1076, 'Cherry Winks', NULL, NULL, NULL, '30', '5 dozen', '¾ cup shortening, 1 cup white sugar, 2  eggs, 2 tablespoons milk, 1 teaspoon vanilla extract, 2 ¼ cups sifted all-purpose flour, 1 teaspoon baking powder, ½ teaspoon baking soda, ½ teaspoon salt, 1 cup chopped pecans, 1 cup dates, pitted and chopped, ⅓ cup maraschino cherries, chopped, 2 ½ cups crushed cornflakes cereal, 10  maraschino cherries, quartered', 'Preheat oven to 375 degrees F (190 degrees C). Lightly grease baking sheets.
INSERT INTO public.recipes VALUES (1077, 'Pecan Pie Energy Bites', '15 mins', '10 mins', '25 mins', '12', '12 2-inch balls', '1 cup pecan halves, ⅓ cup rolled oats, 1 cup pitted Medjool dates, ⅛ teaspoon ground cinnamon, ¼ teaspoon kosher salt, ¼ teaspoon vanilla extract, 1 tablespoon maple syrup', 'Preheat the oven to 350 degrees F (175 degrees C). Line a baking sheet with parchment paper.
INSERT INTO public.recipes VALUES (1079, 'Eggless Date Cake', NULL, NULL, NULL, '8', '1 loaf', '¾ cup milk, 18  dates, pitted and left whole, ½ cup brown sugar, ½ cup vegetable oil, 1 teaspoon vanilla extract (Optional), 1 cup all-purpose flour, 1 teaspoon baking soda, 1 teaspoon ground cinnamon (Optional), ¼ cup chopped walnuts (Optional)', 'Heat milk in a saucepan until almost boiling and stir in dates; let soak for several hours, refrigerated. For best flavor, refrigerate dates and milk overnight.
INSERT INTO public.recipes VALUES (1080, 'Coconut Date Bars', '10 mins', NULL, '40 mins', '4', '4 servings', '⅓ cup slivered almonds, ½ cup flaked coconut, 10  pitted dates, or to taste, ¼ cup cashews, or to taste, 1 teaspoon coconut oil', 'Blend almonds and coconut in a food processor; add dates and pulse until combined. Add cashews and coconut oil; pulse until mixture is thick and sticks together. Transfer to a sheet of waxed paper; form into a square, folding sides of waxed paper over the top. Refrigerate until solid, at least 30 minutes.', '4.7', 'https://www.allrecipes.com/recipe/230870/coconut-date-bars/', '/Desserts/Cookies/Fruit Cookie Recipes/Date/', 'Total Fat 17g 22%, Saturated Fat 9g 44%, Sodium 61mg 3%, Total Carbohydrate 23g 8%, Dietary Fiber 5g 17%, Total Sugars 15g, Protein 5g, Vitamin C 0mg 2%, Calcium 38mg 3%, Iron 1mg 8%, Potassium 304mg 6%', 'Prep Time: 10 mins, Additional Time: 30 mins, Total Time: 40 mins, Servings: 4, Yield: 4 servings', 'https://www.allrecipes.com/thmb/3nGgR_2dzKOqDHsJA8M-lHj5hy0=/1500x0/filters:no_upscale():max_bytes(150000):strip_icc()/5560798-coconut-date-bars-Kim-4x3-1-71d4d3bf677d4e8aa5b1176b74956994.jpg');
INSERT INTO public.recipes VALUES (1081, 'Great-Grandma Cathy''s Date Loaf Candy', '10 mins', '20 mins', '8 hrs 30 mins', '10', '10 servings', '2 cups white sugar, 1 cup milk, ¼ cup butter, 1 cup chopped dates, 1 cup chopped pecans, 1 teaspoon vanilla extract', 'Stir sugar, milk, and butter together in a saucepan; bring to a boil without stirring once the boiling begins. Heat until a small amount of syrup dropped into cold water forms a rigid ball or until the mixture reaches 250 degrees F (120 degrees C), about 20 minutes. Immediately remove saucepan from heat and stir dates, pecans, and vanilla into the milk mixture.
INSERT INTO public.recipes VALUES (1082, 'Power Cookies', '15 mins', '15 mins', '30 mins', '18', '18 cookies', '4 cups rolled oats, 1 (15 ounce) can cannellini beans, drained and rinsed, ½ cup white sugar, ½ cup brown sugar, 1 teaspoon vanilla extract, 1 teaspoon baking powder, 1 teaspoon baking soda, 1 teaspoon ground cinnamon, ½ cup chopped pitted dates, ½ cup flaked coconut, ½ cup raisins, ½ cup chopped walnuts', 'Preheat the oven to 325 degrees F (165 degrees C). Grease cookie sheets. Grind the oats in a blender until resembling coarse flour.
INSERT INTO public.recipes VALUES (1083, 'Reshteh Polo (Persian Noodle Rice)', '35 mins', '1 hrs 10 mins', '3 hrs 35 mins', '10', '10 servings', '1 cup basmati rice, 3 ½ tablespoons kosher salt, divided, ¼ teaspoon saffron threads, 2 tablespoons boiling water, ½ (8 ounce) package roasted noodles, ¼ cup grapeseed oil,   kosher salt to taste (such as Diamond Crystal®), 2 medium gold potatoes, sliced into quarter rounds, ¼ cup boiling water, 2 tablespoons unsalted butter, melted, 3 tablespoons unsalted butter, 6  Medjool dates, pitted and quartered, ½ cup golden raisins, rinsed and drained, ¼ teaspoon ground cinnamon', 'Place rice in a medium bowl and cover with tepid water. Gently swish it around with your finger to activate the starches, then tip the bowl to drain water. Repeat this process until water runs clear, about 7 rinses. Cover rice with cold water, add 1/2 tablespoon salt, stir gently, and soak for 1 hour. Drain rice without rinsing.
INSERT INTO public.recipes VALUES (1084, 'Paleo Almond Date Cookies', '25 mins', '15 mins', '50 mins', '24', '2 dozen', '2 ½ cups blanched almond flour, 1 cup pitted and chopped dates, ½ cup chopped dried cherries, ½ cup chopped walnuts, 2 tablespoons chia seeds, or more to taste, ½ teaspoon baking soda, ½ teaspoon sea salt, ½ cup coconut oil, 1  egg, 2 tablespoons maple syrup, 1 tablespoon vanilla extract', 'Preheat oven to 350 degrees F (175 degrees C). Line 2 baking sheets with parchment paper.
INSERT INTO public.recipes VALUES (1085, 'Date-Nut Balls', '15 mins', '10 mins', '30 mins', '48', '4 dozen balls', '14 tablespoons butter, 1 cup pitted chopped dates, 1 cup white sugar, 2 cups crispy rice cereal (such as Rice Krispies®), 1 cup chopped pecans, 2 tablespoons confectioners'' sugar, or as needed', 'Melt butter in a saucepan over medium heat; cook and stir dates and white sugar in melted butter until thick and golden brown, 10 to 15 minutes. Remove saucepan from heat.
INSERT INTO public.recipes VALUES (1086, 'Jamaica Cake', NULL, NULL, NULL, '14', '1 - 13x9 inch pan', '2 cups white sugar, 1 ½ cups vegetable oil, 1 ½ cups chopped pecans, 3 cups all-purpose flour, 2  bananas, peeled and diced, 3  eggs, 1 (20 ounce) can crushed pineapple with juice, 1 teaspoon vanilla extract, 1 teaspoon salt, 1 teaspoon baking soda', 'Mix together sugar, vegetable oil, pecans, flour, and bananas in a 13 x 9 inch pan. Stir in the eggs, pineapple (with juice), vanilla, salt and baking soda. Mix well. Do not mash the bananas.
INSERT INTO public.recipes VALUES (1087, 'Best Hot Sauce', '10 mins', '20 mins', '30 mins', '100', '2 cups', '10  fresh hot chile peppers, stems removed, 1  onion, coarsely chopped, ¼ cup pitted fresh dates, or more to taste, ¼ cup fresh basil leaves, ¼ cup fresh parsley leaves, 1  roma (plum) tomato, roughly chopped, 2 tablespoons beef bouillon powder, 4  garlic cloves, ½ cup vegetable oil, or as needed,   salt to taste, 1 squeeze lemon juice', 'Place peppers, onion, dates, basil, parsley, tomato, bouillon powder, and garlic in the bowl of a food processor; pour in the oil. Pulse mixture until finely chopped, adding more oil if needed to thin; season with salt.
INSERT INTO public.recipes VALUES (1088, 'Moist Date Nut Bread', '15 mins', '50 mins', '1 hrs 35 mins', '12', '1 9x5-inch loaf', '2 ½ cups chopped dates, ¼ cup butter, 1 cup boiling water, ½ cup packed brown sugar, 1 large egg, 1 ½ cups all-purpose flour, 1 teaspoon baking soda, 1 teaspoon baking powder, 1 teaspoon salt, 1 cup chopped walnuts', 'Preheat the oven to 350 degrees F (175 degrees F). Grease and flour a 9x5-inch loaf pan.
INSERT INTO public.recipes VALUES (1089, 'Chef John''s Chocolate Energy Bars', '15 mins', NULL, '3 hrs', '12', '12 bars', '2 cups pitted Medjool dates, roughly chopped, 2 cups raw cashews, 1 cup raw or roasted unsalted almonds, ¾ cup high-quality unsweetened cocoa powder (such as Guittard® Cocoa Rouge), 2 tablespoons coconut oil, melted, ½ cup unsweetened shredded coconut, 2 teaspoons vanilla extract, 1 tablespoon cold espresso, or more as needed (or water), ½ teaspoon kosher salt, ½ pinch cayenne pepper', 'Place cashews, almonds, coconut, dates, cocoa, coconut oil, vanilla, cold coffee, cayenne and salt in the bowl of a food processor. Pulse on and off to start. Process about 1 minute; check to ensure mixture is sticky and moist enough to stick together. Add more coffee if needed. Continue to process until mixture becomes a chunky mass.
